const TOPICS=[
  {id:'all',label:'All Lectures'},
  {id:'l1',label:'Lecture 1: The Leadership Covenant'},
  {id:'l2',label:'Lecture 2: Solution-Focused Leadership'},
  {id:'l3',label:'Lecture 3: Leading Transformation'},
  {id:'l4',label:'Lecture 4: Boardroom Ethics & Governance'},
  {id:'l5',label:'Lecture 5: Non-Profit Leadership & Social Change'},
  {id:'l6',label:'Lecture 6: Team Leadership & Dynamics'},
  {id:'l7',label:'Lecture 7: Ethics & Anti-Corruption'},
  {id:'l8',label:'Lecture 8: Conflict Management & Negotiation'},
];

const QB=[
{id:1,topic:'l1',type:'mcq',text:'According to Dr David Oyedepo\'s definition in Lecture 1, leadership is fundamentally about:',opts:['Holding a title or rank in an organisation','Taking the lead in meeting needs in a given field','Managing and controlling people effectively','Inheriting authority from a predecessor'],ans:1,exp:'Oyedepo defines leadership as "taking the lead in a given task... taking the lead in meeting the needs." Leadership IS accomplishing a feat, NOT occupying a seat.'},
{id:2,topic:'l1',type:'mcq',text:'The lecture explicitly states that leadership is NOT:',opts:['Taking the lead in one\'s field','Accomplishing a feat','A position inherited or assigned','Value addition to one\'s environment'],ans:2,exp:'The lecture distinguishes leadership from positions that are inherited or assigned. Genuine leadership must be earned through performance.'},
{id:3,topic:'l1',type:'mcq',text:'Myth 1 states "Leaders are born." The lecture\'s rebuttal is:',opts:['Some people are naturally gifted with leadership traits','No one is born a lawyer or engineer — leadership capacity is developed, not inherited genetically','Great leaders are chosen by God from birth','Leadership is a spiritual gift that cannot be taught'],ans:1,exp:'Just as no one is born a lawyer, no one is born a leader. Leadership capacity is developed through deliberate effort.'},
{id:4,topic:'l1',type:'mcq',text:'Myth 2 is "Leadership can be inherited." Dr Oyedepo\'s question used to demolish this myth is:',opts:['"Can you inherit a university degree?"','"Can anyone inherit the world heavyweight championship?"','"Can a king\'s son run a nation without training?"','"Can wisdom be passed from father to son?"'],ans:1,exp:'Oyedepo: "Can anyone inherit the world heavyweight championship?" Great titles must be earned — always. They cannot be transferred.'},
{id:5,topic:'l1',type:'mcq',text:'Myth 3 says "Leadership is a position." The lecture argues leadership is actually:',opts:['A rank confirmed by election or appointment','The product of outstanding contribution in a field','A spiritual calling reserved for few','A function of seniority and experience'],ans:1,exp:'Leadership is "the product of outstanding contribution in a field." Great leaders are those who change the world, not those with chains of degrees.'},
{id:6,topic:'l1',type:'mcq',text:'The lecture identifies Africa\'s number one problem as, according to an African Head of State:',opts:['Corruption','Poverty','Leadership — repeated three times intentionally','Lack of infrastructure'],ans:2,exp:'When Dr Oyedepo asked the president of a leading African nation, the reply was: "Number 1, Leadership. Number 2, Leadership. Number 3, Leadership." The repetition was deliberate.'},
{id:7,topic:'l1',type:'mcq',text:'The lecture clarifies that Africa\'s leadership crisis is not political — it is:',opts:['Economic','Developmental — specifically a lack of trained, purposeful leaders','Military','Religious'],ans:1,exp:'The crisis is developmental — not a lack of resources or geography, but a lack of "trained, purposeful leaders."'},
{id:8,topic:'l1',type:'mcq',text:'The five covenant terms in Lecture 1 are drawn from which scriptural passage?',opts:['Proverbs 22:29','Ecclesiastes 10:5–18','Joshua 1:8','Daniel 1:17'],ans:1,exp:'The lecture explicitly states: "Ecc 10:5–18 provides 5 non-negotiable terms that govern leadership emergence and sustained impact."'},
{id:9,topic:'l1',type:'mcq',text:'The Bible is described in the lecture as:',opts:['A helpful guide for moral living','The most reliable text on leadership','A historical document with leadership examples','A devotional handbook'],ans:1,exp:'The lecture calls the Bible "the most reliable text on leadership." Each covenant term is both a condition and a key.'},
{id:10,topic:'l1',type:'fill',text:'According to the lecture, "Covenant means this is what you must _______ to get what you must _______."',dropdowns:[['do', 'have', 'say', 'know'], ['do', 'have', 'say', 'know']],ans:['do', 'have'],exp:'Oyedepo\'s definition of Covenant: "Covenant means this is what you must do to get what you must have... it is like a deal."'},
{id:11,topic:'l1',type:'mcq',text:'The five covenant terms in sequential order are:',opts:['Wisdom, Vision, Diligence, Sacrifice, Self-Discipline','Vision, Wisdom, Self-Discipline, Diligence, Sacrifice','Diligence, Wisdom, Vision, Sacrifice, Self-Discipline','Sacrifice, Diligence, Self-Discipline, Vision, Wisdom'],ans:1,exp:'Table in Lecture 1: 1-Vision, 2-Wisdom, 3-Self-Discipline, 4-Diligence, 5-Sacrifice.'},
{id:12,topic:'l1',type:'mcq',text:'Term 1, Vision, is defined in the lecture as:',opts:['Having a dream about the future','A discovery of God\'s plan and purpose for one\'s life and mission on earth','Setting ambitious targets for career advancement','A roadmap created by strategic planning'],ans:1,exp:'Oyedepo: "Vision is a discovery of God\'s plan and purpose for one\'s life... not about having a dream... [but] locating God\'s dream for one\'s life."'},
{id:13,topic:'l1',type:'mcq',text:'Vision answers one primary question, according to the lecture. That question is:',opts:['"What can I get?"','"How do I become successful?"','"What must I do?"','"Where do I want to go?"'],ans:2,exp:'"What must I do?" — not "What can I get?" Vision is mission-driven clarity about the problem you exist to solve.'},
{id:14,topic:'l1',type:'mcq',text:'The lecture distinguishes leaders from workers by stating:',opts:['Leaders have higher qualifications','Leaders are purpose-driven while workers are profit-driven','Leaders are appointed while workers are hired','Leaders manage resources while workers use them'],ans:1,exp:'Leaders are purpose-driven; workers are profit-driven. A person chasing money builds for today; a person chasing a mission builds for generations.'},
{id:15,topic:'l1',type:'mcq',text:'"A lack of vision will make a slave out of any prince. A lack of vision will make a peasant out of a king." This is attributed to:',opts:['Abraham Lincoln','Mike Murdock','Dr David O Oyedepo','Mother Teresa'],ans:2,exp:'This is a direct quote from Dr David O Oyedepo, used to dramatise the cost of going without vision.'},
{id:16,topic:'l1',type:'mcq',text:'Which of the following is listed as a pathway through which leaders discover their vision?',opts:['Academic research','Divine Encounter, Passion, and Gifting','Market opportunity analysis','Peer consultation'],ans:1,exp:'Three pathways to vision: 1. Divine Encounter (Moses at the burning bush; Paul on the road to Damascus). 2. Passion (Nehemiah\'s restlessness). 3. Gifting (what you do effortlessly that creates value for others).'},
{id:17,topic:'l1',type:'mcq',text:'The lecture describes Nehemiah\'s vision as arising from:',opts:['A divine vision in the night','A divine encounter at the temple','Restlessness about Jerusalem\'s broken walls — that restlessness WAS his assignment','A direct command from the Persian king'],ans:2,exp:'"Nehemiah had no vision — only restlessness about Jerusalem\'s broken walls. That restlessness was his assignment." Passion is a pointer to the problem you\'re created to solve.'},
{id:18,topic:'l1',type:'mcq',text:'The lecture says: "Every person carries a _______ deposit. Develop it and deploy it — this is your lane."',opts:['financial','spiritual','divine','intellectual'],ans:2,exp:'Under Pathway 3 (Gifting): "Every person carries a divine deposit. Develop it and deploy it — this is your lane."'},
{id:19,topic:'l1',type:'mcq',text:'Term 2, Wisdom, is defined as:',opts:['Common sense applied to difficult problems','Not common sense; it is acquired sense — applied knowledge in your field','Spiritual revelation given to chosen leaders','Natural intelligence enhanced by education'],ans:1,exp:'Oyedepo: "Wisdom is not common sense; wisdom is acquired sense." Wisdom = applied knowledge in your field. It is the principal raw material for the making of a leader.'},
{id:20,topic:'l1',type:'mcq',text:'How does the lecture differentiate Vision from Wisdom?',opts:['Vision is spiritual; Wisdom is intellectual','Vision tells you WHERE to go; Wisdom teaches you HOW to get there and how to stay there','Vision is given by God; Wisdom comes from study','Vision is the destination; Wisdom is the map'],ans:1,exp:'The lecture: "Vision tells you where to go. Wisdom teaches you how to get there — and how to stay there."'},
{id:21,topic:'l1',type:'mcq',text:'The three tools that build wisdom, per the lecture, are:',opts:['Prayer, fasting, and meditation','Reading, Mentorship (Laddership), and Meditation / Thinking Through','Study, observation, and practice','Coaching, conferences, and case studies'],ans:1,exp:'Three Tools: 1. Reading, 2. Mentorship — Laddership, 3. Meditation & Thinking Through.'},
{id:22,topic:'l1',type:'mcq',text:'The quote "What you read is not profitable until it is digested, just like what you eat is not profitable until it undergoes the digestive process" is by:',opts:['Abraham Lincoln','Mike Murdock','Jim Rohn','Dr David Oyedepo'],ans:3,exp:'This is Dr Oyedepo\'s metaphor for Meditation & Thinking Through — the third tool for building wisdom.'},
{id:23,topic:'l1',type:'mcq',text:'Michael Faraday\'s case study illustrates which covenant term?',opts:['Vision','Self-Discipline','Wisdom','Sacrifice'],ans:2,exp:'Faraday had virtually no formal education but devoured scientific texts and surpassed his mentor. Used to show that wisdom built through relentless learning creates leaders.'},
{id:24,topic:'l1',type:'mcq',text:'The lecture describes the knowledge marketplace using Faraday\'s story as:',opts:['Competitive and exclusive','Accessible only to the educated','Having no apartheid — what you lack in schooling you can compensate for in learning','Determined by social background'],ans:2,exp:'"Faraday is proof that the knowledge marketplace has no apartheid. What he lacked in schooling, he more than compensated for in learning."'},
{id:25,topic:'l1',type:'mcq',text:'Benjamin Franklin appears under which covenant term, and specifically because he:',opts:['Had vision beyond his era','Sacrificed lunch money on books as a printing apprentice — exemplifying wisdom through self-learning','Led with diligence in public service','Showed self-discipline by waking up at 5am daily'],ans:1,exp:'Franklin is used under Wisdom: only 2 years of formal schooling but spent his lunch money on books daily. He invested in himself when no one else would.'},
{id:26,topic:'l1',type:'mcq',text:'Term 3, Self-Discipline, is defined as:',opts:['Following a strict daily schedule','Possessing a sense of mission in the pursuit of life — operating as demanded, not as convenient','Abstaining from harmful habits','Submitting to institutional rules'],ans:1,exp:'Oyedepo: "Self-discipline is possessing a sense of mission in the pursuit of life... operating as demanded, not as convenient in the pursuit of any given task."'},
{id:27,topic:'l1',type:'mcq',text:'The Jim Rohn quote on Self-Discipline states:',opts:['"Discipline is the bridge between goals and accomplishment"','"Success is nothing more than a few simple disciplines"','"There are two types of pain — the pain of discipline and the pain of regret. Discipline weighs ounces while regret weighs tonnes"','"We must all suffer one of two things: the pain of discipline or the pain of regret"'],ans:2,exp:'Jim Rohn\'s exact quote as rendered: "There are two types of pain — the pain of discipline and the pain of regret. Discipline weighs ounces while regret weighs tonnes."'},
{id:28,topic:'l1',type:'mcq',text:'Which of the following is a practical expression of self-discipline per the lecture?',opts:['Attending every conference in your field','Operating WITHOUT supervision','Publishing research regularly','Seeking feedback from superiors'],ans:1,exp:'Three expressions: (1) Operating without supervision, (2) Investing time rather than spending or squandering it, (3) Being a law to oneself in pursuit of a desired goal.'},
{id:29,topic:'l1',type:'mcq',text:'The four zones every leader must govern under Self-Discipline are:',opts:['Vision, Wisdom, Time, Resources','Self-Management, Time Management, Task Management, Resource Management','Focus, Finance, Family, Faith','Spiritual, Mental, Physical, Social'],ans:1,exp:'4 Zones: (1) Self-Management, (2) Time Management, (3) Task Management, (4) Resource Management.'},
{id:30,topic:'l1',type:'mcq',text:'The "Uniform Principle" illustrated through Einstein, Jobs, and Obama teaches:',opts:['Leaders should dress professionally to command respect','They wore the same outfit daily to eliminate trivial decisions and protect mental energy for what truly mattered','Simplicity in appearance reflects simplicity in character','Uniforms build team identity'],ans:1,exp:'Einstein: same grey suit (focus on physics). Jobs: black turtleneck + blue jeans (eliminate decision fatigue). Obama: grey or blue suits only (preserve mental energy for consequential choices).'},
{id:31,topic:'l1',type:'mcq',text:'Dr Oyedepo\'s personal example of self-discipline cited in the lecture is:',opts:['Reading 5 books every month','Being absent from the church platform only 20 times in about 2,000 Sundays — 99.8% of the time at his duty post','Starting work at 5am every day','Fasting every Monday for decades'],ans:1,exp:'Oyedepo: "I cannot remember being off the church platform 20 times on Sundays in about 2,000 Sundays — 99.8% of the time at my duty post."'},
{id:32,topic:'l1',type:'mcq',text:'"Protect the Core or Lose Everything" warns that:',opts:['Leaders must invest in personal branding','Neglecting the core to chase complements is the most common cause of stalled leadership potential','Leaders should delegate peripheral tasks aggressively','Focus on weaknesses rather than strengths'],ans:1,exp:'The doctor who lets the vegetable garden become his focus loses medicine. Neglecting the core for complements stalls leadership potential.'},
{id:33,topic:'l1',type:'mcq',text:'Term 4, Diligence, is described as the:',opts:['Spiritual discipline of daily prayer','Engine that converts vision into reality; every accomplishment is at the cost of commitment','Natural outcome of having a good mentor','Social skill of building influential relationships'],ans:1,exp:'Oyedepo: "Nothing works without someone at work." Without diligence, vision is a balloon dream — inflated but weightless.'},
{id:34,topic:'l1',type:'mcq',text:'The "Law of Diligence" in the lecture is drawn from:',opts:['Proverbs 22:29','Genesis 8:22 — the covenant of seedtime and harvest','Ecclesiastes 9:10','Philippians 4:13'],ans:1,exp:'"You cannot withdraw more than you deposit." The covenant of seedtime and harvest — Gen 8:22 — is universal and inescapable.'},
{id:35,topic:'l1',type:'mcq',text:'R.G. LeTourneau\'s case study illustrates diligence because he:',opts:['Founded a university with no formal education','Was a roadside mechanic who, through diligent observation and committed work, invented the Digger and supplied over 50% of earth-moving equipment worldwide','Sacrificed his presidency to pursue his calling','Read 10,000 books over his lifetime'],ans:1,exp:'"Diligent observation + committed work = world-changing innovation. No university. No family wealth. Just a workshop and a relentless work ethic."'},
{id:36,topic:'l1',type:'mcq',text:'The "Small Beginners End Up as Heroes" table pairs Cosmas Maduka (Coscharis) with:',opts:['Started with ₦300 in spare parts; became one of Africa\'s wealthiest men','Started with a small-town store; built Walmart','Went bankrupt on first venture; built a global food brand','Started as a school dropout; became a tech billionaire'],ans:0,exp:'Cosmas Maduka: ₦300 in spare parts → one of Africa\'s wealthiest men. Sam Walton → small-town store → Walmart (2.2m employees). Henry Heinz → bankrupt → global Heinz Ketchup brand.'},
{id:37,topic:'l1',type:'mcq',text:'The lecture\'s principle "A Great Coach Cannot Make a Star" teaches that:',opts:['Great coaches are unnecessary','A coach provides opportunity, not results — the difference is always the player\'s level of commitment','Leadership is innate and coaching cannot develop it','Mentors are overrated'],ans:1,exp:'Under the same coach some become stars, others stay average. "The difference is never the coach — it is always the player\'s level of commitment." Even Christ had a son of perdition among his protégés.'},
{id:38,topic:'l1',type:'mcq',text:'Term 5, Sacrifice, is defined as:',opts:['Accidental suffering in pursuit of goals','Intentional — giving up something of present value for something of greater future value','Taking on more work than peers','Random hardship on the leadership journey'],ans:1,exp:'"There is no star without a scar, and the scar of every star is sacrifice." Sacrifice is intentional — giving up something of present value for something of greater future value.'},
{id:39,topic:'l1',type:'mcq',text:'The difference between Diligence and Sacrifice, as the lecture frames it, is:',opts:['Diligence is physical; Sacrifice is financial','Diligence does your best; Sacrifice goes BEYOND your best','Diligence is consistent; Sacrifice is occasional','Diligence is individual; Sacrifice is collective'],ans:1,exp:'"Diligence Does Your Best. Sacrifice Goes Beyond It." Sacrifice is the 5th and highest covenant term — where stars are separated from the merely diligent.'},
{id:40,topic:'l1',type:'mcq',text:'"Global impact in any field is at a global cost to the beneficiary." This implies:',opts:['Only wealthy people can achieve global impact','No world-changer runs a normal schedule or lives a normal lifestyle — the greater the intended impact, the greater the sacrifice required','Leadership is unfair to those with limited resources','Global impact is reserved for those with superior education'],ans:1,exp:'Dr Oyedepo: "Global impact in any field is at a global cost to the beneficiary." No world-changer has normal habits. The greater the impact, the greater the sacrifice. "There is no free lunch at the top."'},
{id:41,topic:'l1',type:'mcq',text:'Albert Einstein\'s sacrifice example involves:',opts:['Sacrificing personal wealth to fund research','Declining the presidency of Israel to stay with physics — the assignment for which he was uniquely prepared','Sacrificing sleep for 20 years to produce his theories','Giving away all his patents'],ans:1,exp:'Einstein declined the presidency of Israel. He stayed with physics — his core assignment. Billy Graham similarly refused a university named after him and political appointments.'},
{id:42,topic:'l1',type:'mcq',text:'The case study of James Owen illustrates sacrifice through a four-word formula given by his coach:',opts:['Vision, Wisdom, Discipline, Diligence','Determination, Dedication, Discipline, Sacrifice','Focus, Commitment, Consistency, Courage','Passion, Purpose, Practice, Patience'],ans:1,exp:'Coach gave 4 words: Determination, Dedication, Discipline, Sacrifice. James Owen followed them faithfully — 3 gold medals at the 1923 Berlin Olympics; long jump record unbroken for 22 years.'},
{id:43,topic:'l1',type:'mcq',text:'The lecture concludes that the only real variable between those who rise and those who remain is:',opts:['Educational background and family wealth','Natural talent and IQ','The consistent, disciplined, sacrificial application of the 5 covenant terms over time','Geographical location and political connections'],ans:2,exp:'"Not talent — everyone has a brain of equal potential. Not luck — seedtime and harvest is law. Not background — Faraday, Franklin, LeTourneau prove otherwise. The difference is the consistent, disciplined, sacrificial application of the 5 covenant terms over time."'},
{id:44,topic:'l1',type:'mcq',text:'Decision-making in the lecture is described as:',opts:['A skill that can be delegated','Best done by committee','The responsibility of every leader — non-transferable, and the point where covenant terms become lived reality','An outcome of spiritual discernment alone'],ans:2,exp:'"Decision-making is the responsibility of every leader. It is non-transferable — it cannot be delegated. It is the point where covenant terms become lived reality."'},
{id:45,topic:'l1',type:'short',text:'According to Lecture 1, what is the "principal raw material" for building and developing leadership capacity?',ans:'Wisdom',exp:'Wisdom is defined as "acquired sense" and is the principal raw material for the making of a leader.'},
{id:46,topic:'l1',type:'short',text:'According to the covenant framework, what personal quality is the key variable that determines star performance under the same coach?',ans:'Commitment',exp:'A coach provides opportunity, not results. Under the same coach, the difference in outcome is always the player\'s level of commitment.'},
{id:47,topic:'l1',type:'short',text:'Neglecting the core assignment to chase complements is the most common cause of what leadership outcome?',ans:'Stalled Potential',exp:'Neglecting the core to chase complements leads to stalled leadership potential.'},
{id:48,topic:'l1',type:'fill',text:'The lecture states: "Schooling is but for a _______, but learning is for a _______." (Dr David Oyedepo)',dropdowns:[['season', 'lifetime', 'reason', 'day'], ['season', 'lifetime', 'reason', 'day']],ans:['season', 'lifetime'],exp:'Schooling is seasonal, but true learning is a lifelong pursuit.'},
{id:49,topic:'l1',type:'fill',text:'The law of diligence states: "You cannot _______ more than you _______." — from the covenant of seedtime and harvest (Gen 8:22).',dropdowns:[['deposit', 'withdraw', 'invest', 'spend'], ['deposit', 'withdraw', 'invest', 'spend']],ans:['withdraw', 'deposit'],exp:'You cannot withdraw more than you deposit. Seedtime must precede harvest.'},
{id:50,topic:'l1',type:'fill',text:'Oyedepo says: "You don\'t grow big to manage _______; you _______ well to grow big."',dropdowns:[['well', 'manage', 'organize', 'grow'], ['well', 'manage', 'organize', 'grow']],ans:['well', 'manage'],exp:'Good stewardship/management of current resources is the prerequisite for growth.'},
{id:51,topic:'l1',type:'multi',text:'Select ALL three pathways to discovering your vision as listed in Lecture 1:',opts:['Divine Encounter','Passion','Academic qualification','Gifting','Peer recommendation'],ans:[0,1,3],exp:'Three pathways: (1) Divine Encounter — a defining calling moment, (2) Passion — the restlessness pointing to the problem you\'re created to solve, (3) Gifting — what you do effortlessly that creates value for others.'},
{id:52,topic:'l1',type:'multi',text:'Select ALL three tools for building wisdom identified in Lecture 1:',opts:['Prayer','Reading','Mentorship / Laddership','Fasting','Meditation and Thinking Through'],ans:[1,2,4],exp:'Three tools: (1) Reading, (2) Mentorship/Laddership, (3) Meditation & Thinking Through.'},
{id:53,topic:'l1',type:'multi',text:'Which of the following are listed as practical expressions of self-discipline in Lecture 1?',opts:['Operating without supervision','Investing time rather than spending or squandering it','Attending every seminar in your field','Being a law to oneself in pursuit of a desired goal','Seeking constant feedback from others'],ans:[0,1,3],exp:'Three expressions: operating without supervision; investing time rather than spending/squandering; being a law to oneself in pursuit of a desired goal.'},
{id:54,topic:'l1',type:'multi',text:'Which figures appear in the "Small Beginners End Up as Heroes" table?',opts:['Cosmas Maduka (Coscharis)','Sam Walton (Walmart)','Henry Heinz','R.G. LeTourneau','Benjamin Franklin'],ans:[0,1,2],exp:'Cosmas Maduka, Sam Walton, and Henry Heinz. LeTourneau and Franklin appear under separate case studies.'},
{id:55,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] Amara is a young doctor invited to run for local government chairperson. The position pays well but would significantly reduce her time in the hospital. Using the covenant framework, what should she consider?',opts:['She should accept because leadership should be applied broadly','This tests the "Protect the Core" principle — she risks losing medicine if she lets political ambition become her focus','She should accept only if the role advances the medical field','This tests Vision — she needs to discover a new calling'],ans:1,exp:'"Protect the Core or Lose Everything." A medical doctor who lets the vegetable garden become his focus loses medicine. Amara\'s core is medicine; the political role is a complement. Neglecting the core is the most common cause of stalled leadership potential.'},
{id:56,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] Bola, a 24-year-old graduate, says: "I am just waiting for my father to hand over his company to me." Which leadership myth does this reflect, and what is the lecture\'s response?',opts:['Myth 1 — Leaders are born; capacity is developed','Myth 2 — Leadership can be inherited; "Can anyone inherit the world heavyweight championship?" It must be earned, always','Myth 3 — Leadership is a position; leaders are products of outstanding contribution','This is a Vision problem, not a leadership myth'],ans:1,exp:'Myth 2: "Leadership can be inherited." Oyedepo: "Can anyone inherit the world heavyweight championship?" Great titles must be earned — always. Leadership is accomplishing a feat, not occupying an inherited seat.'},
{id:57,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] Chidi has a good salary job and an opportunity aligned with his passion for solving rural health access. He says he will start "when conditions are perfect." Which covenant principle is most relevant?',opts:['Wisdom — he needs to acquire more knowledge first','Sacrifice — he must give up present comfort for future value; postponement is a form of disbelief in his own vision','Self-Discipline — he must manage his time better','Vision — he hasn\'t discovered his true assignment'],ans:1,exp:'"Postponement is a form of disbelief in your own vision." Sacrifice means giving up something of present value (stability) for something of greater future value (impact). Small beginnings + faithful diligence = extraordinary outcomes.'},
{id:58,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] Emeka graduated top of his class but has no clear sense of what problem he wants to spend his life solving. He asks: "How do I find my vision?" Which response BEST reflects Lecture 1\'s teaching?',opts:['Set ambitious five-year goals based on market demand','Examine: a defining encounter that moved you, a deep restlessness about an unmet need, and what you do effortlessly that creates value — these are the three pathways to vision','Take the highest-paying job offer and vision will emerge through experience','Pray and fast until God reveals your assignment in a dream'],ans:1,exp:'Three pathways to vision: Divine Encounter (a defining calling moment), Passion/Restlessness (the problem that keeps you awake), and Gifting (what you do effortlessly that creates value). Examining all three surfaces where one\'s mission lies.'},
{id:59,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] Tunde runs a thriving agribusiness but rarely reads books in his field, has no mentor, and makes decisions on instinct alone. Using covenant Term 2, what is his primary leadership risk?',opts:['He is violating Diligence — not working hard enough','He is neglecting Wisdom — the "principal raw material for the making of a leader" — through failure to read, seek mentorship, or think deeply about his field','He is violating Sacrifice because he is not paying the price','He lacks Vision because he has no clear mission statement'],ans:1,exp:'Wisdom is built through reading, mentorship, and deep thinking. Without continuous wisdom acquisition, the lecture warns: "The moment learning stops → relevance begins to decay."'},
{id:60,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] A student who wants to be a communications leader says: "I don\'t need self-discipline — my passion will carry me." Using Lecture 1, how would you evaluate this?',opts:['Correct — passion is the most reliable driver of sustained performance','Partially correct — passion initiates but self-discipline sustains; the lecture defines discipline as operating as DEMANDED, not as convenient','Incorrect only because passion leads to burnout without rest','Correct — passion is one of the three pathways to vision and drives all other terms'],ans:1,exp:'Passion can initiate, but self-discipline sustains. Oyedepo defines self-discipline as "operating as demanded, not as convenient." Jim Rohn: "Discipline weighs ounces while regret weighs tonnes." The test of discipline is whether you operate WITHOUT supervision.'},
{id:61,topic:'l1',type:'short',applied:true,text:'[APPLIED] Dr Oyedepo states: "It is paying the abnormal price that makes a world-changer." What is the covenant term for this?',ans:'Sacrifice',exp:'Sacrifice is the fifth and highest covenant term. It is the intentional exchange of present value for greater future value.'},
{id:62,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] A young lecturer consistently shows up to all her classes, prepares materials even when students don\'t appreciate it, and never needs supervision to perform her duties. Which covenant term does this BEST illustrate?',opts:['Diligence — she is putting in all she has got','Self-Discipline — she is operating as demanded, not as convenient, and without supervision','Sacrifice — she is going beyond her best','Vision — she clearly knows where she is going'],ans:1,exp:'Self-discipline = operating as demanded, not as convenient; being a law to oneself; operating without supervision. The lecturer does not need external motivation — she is internally governed. This matches the definition of self-discipline precisely.'},
{id:63,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] An entrepreneur keeps accepting speaking invitations, board memberships, NGO chairmanships — all worthwhile — but his product development has stalled. What covenant principle MOST directly addresses this?',opts:['Vision — he needs to rediscover his original mission','Sacrifice — he needs to sacrifice his social life','Protect the Core: neglecting the core assignment to chase complements is the most common cause of stalled leadership potential','Diligence — he simply needs to work harder'],ans:2,exp:'"Protect the Core or Lose Everything." Every leader has one assignment that generates all others. Chasing complements — even valuable ones — at the expense of the core stalls leadership potential.'},
{id:64,topic:'l1',type:'fill',text:'The lecture states that "_______ beginnings + faithful _______ = extraordinary outcomes," based on Cosmas Maduka, Sam Walton, and Henry Heinz.',dropdowns:[['small', 'large', 'gradual', 'rapid'], ['diligence', 'discipline', 'sacrifice', 'vision']],ans:['small', 'diligence'],exp:'Extraordinary outcomes are built sequentially through small beginnings and faithful, consistent diligence.'},
{id:65,topic:'l1',type:'mcq',text:'The Personal Covenant Commitment table\'s Wisdom row asks for:',opts:['The mentor you most admire','The knowledge gap you must close','The daily schedule you will maintain','The sacrifice you are willing to make'],ans:1,exp:'Personal Covenant Commitment table: Vision = the problem I exist to solve; Wisdom = the knowledge gap I must close; Discipline = the daily habit I will build; Diligence = the task I will pursue this week; Sacrifice = what I am willing to give up.'},
{id:66,topic:'l1',type:'mcq',text:'"Leaders are simply need-meeters!" is attributed to:',opts:['Abraham Lincoln','Jim Rohn','Mike Murdock','Dr Oyedepo'],ans:3,exp:'"Leaders are simply need-meeters!" — Dr Oyedepo. Appears under Vision, distinguishing leaders (purpose-driven, meeting needs) from workers (profit-driven).'},
{id:67,topic:'l1',type:'mcq',text:'Mike Murdock is cited in the lecture with the quote:',opts:['"Sacrifice is the price of greatness"','"Passion is a pointer to the problem you\'re created to solve"','"Wisdom is not what you know but what you do with what you know"','"Vision without diligence is a daydream"'],ans:1,exp:'Mike Murdock under Pathway 2 (Passion): "...Passion is a pointer to the problem you\'re created to solve."'},
{id:68,topic:'l1',type:'mcq',text:'The lecture\'s Time Management principle states: "One year = only 8,736 hours." The key insight is:',opts:['Time management is primarily about productivity apps','Time is an asset of equality — while some invest it, others squander it','A leader needs at least 10,000 hours to master any skill','The 24-hour day is insufficient for ambitious leaders'],ans:1,exp:'"Time is an asset of equality; while some invest it, others squander it." One year = 8,736 hours. The leadership question is whether you invest that time or lose it.'},
{id:69,topic:'l1',type:'mcq',text:'Task Management (Focus) is quoted as: "Only those who stay focused on their task end up as ___________."',opts:['managers','authorities','front-liners','directors'],ans:2,exp:'"Only those who stay focused on their task end up as front-liners." Protect your core assignment fiercely.'},
{id:70,topic:'l1',type:'mcq',text:'The lecture\'s key question for Sacrifice reflection is:',opts:['What have you built that will outlast you?','What is one thing you know you need to sacrifice — a habit, a distraction, an association — to fully pursue your vision?','How much are you currently earning?','Who has sacrificed most for your success?'],ans:1,exp:'"What Are You Holding On To?" The reflection asks: "What is one thing you know you need to sacrifice to fully pursue your vision? Be honest. Write it down. The act of naming it is the beginning of releasing it."'},
{id:71,topic:'l1',type:'mcq',text:'The lecture\'s conclusion that "the playing field is more level than you think" is because:',opts:['Technology has democratised opportunity','Not talent, not luck, not background — the difference is the consistent, disciplined, sacrificial application of the 5 covenant terms over time','Government policy has created equal access to education','Social media has given everyone a platform'],ans:1,exp:'"Not talent — everyone has a brain of equal potential. Not luck — seedtime and harvest is law. Not background — Faraday, Franklin, LeTourneau prove otherwise. The difference is the consistent, disciplined, sacrificial application of the 5 covenant terms."'},
{id:72,topic:'l1',type:'mcq',applied:true,text:'[APPLIED] A final-year student says: "I am not yet disciplined because I am still young and growing." Using Lecture 1, how would you respond?',opts:['This is reasonable — discipline develops naturally with age','The lecture says discipline is about possessing a sense of mission in pursuing any task; it does not require age but decision — the pain of discipline is lighter than the pain of regret; discipline starts with the choice to be a law to oneself today','The student is correct — self-discipline is the fourth covenant term and comes after vision and wisdom','The lecture only applies to established leaders, not students'],ans:1,exp:'Self-discipline does not wait for age. It is a decision: "operating as demanded, not as convenient." Jim Rohn: discipline weighs ounces while regret weighs tonnes. The four zones are applicable at any career stage.'},
{id:73,topic:'l1',type:'mcq',text:'The lecture\'s definition of "Laddership" under wisdom tools means:',opts:['Leading from the bottom of an organisation upward','Every leader rises on the shoulders of those before them — mentorship as the ladder of leadership growth','Building a network of people beneath you who you mentor','A form of distributed leadership'],ans:1,exp:'"Mentorship — Laddership: Every leader rises on the shoulders of those before them." Laddership = using mentors as a ladder for your own growth.'},
{id:74,topic:'l1',type:'match',text:'Match each Instrument of the Supernatural to its description:',left:['The Word', 'Faith', 'The Name of Jesus', 'Prayer & Fasting'],right:['The source of divine power and revelation', 'The shield that quenches all fiery darts', 'The name above all names that forces knee bending', 'The discipline that subdues the flesh and elevates spirit'],ans:[0, 1, 2, 3],exp:'The Word is the source of divine power; Faith is the shield that quenches all fiery darts; The Name of Jesus is the name above all names that forces knee bending; Prayer & Fasting is the discipline that subdues the flesh and elevates the spirit.'},
{id:75,topic:'l1',type:'match',text:'Match each Covenant Term from Lecture 1 with its correct definition:',left:['Vision', 'Wisdom', 'Self-Discipline', 'Diligence', 'Sacrifice'],right:['Knowing where you are going', 'Learning what it takes to get there', 'Submitting to the demands of the journey', 'Putting in all you have got', 'Going the extra mile'],ans:[0, 1, 2, 3, 4],exp:'Vision = knowing where you are going; Wisdom = learning what it takes; Self-Discipline = submitting to journey demands; Diligence = putting in all you\'ve got; Sacrifice = going the extra mile.'},
{id:76,topic:'l2',type:'mcq',text:'Lecture 2 describes every leader as carrying a lens. The two types of lenses are:',opts:['Macro and micro','Problem-focused (PF) and Solution-focused (SF)','Reactive and proactive','Internal and external'],ans:1,exp:'Leaders habitually see situations through either a problem-focused or solution-focused lens. The difference is not personality — it is discipline of attention.'},
{id:77,topic:'l2',type:'mcq',text:'The Problem-Focused (PF) lens operates on the logic of:',opts:['What you focus on grows','Identify what\'s wrong → Diagnose → Fix — over time creating a problem-saturated environment','Celebrate wins before addressing challenges','Lead with strengths, then address weaknesses'],ans:1,exp:'PF lens: Identify → Diagnose → Fix. Creates a problem-saturated environment where difficulties are always spotlighted, strengths become invisible, and people feel perpetually inadequate.'},
{id:78,topic:'l2',type:'mcq',text:'The core premise of the Solution-Focused (SF) lens is:',opts:['Ignore problems until they resolve themselves','Celebrate every achievement regardless of quality','What you focus on grows — begin with a different premise','Diagnosis must precede every intervention'],ans:2,exp:'The SF lens begins with: "What you focus on grows." Instead of spotlighting problems, it surfaces what is already working and amplifies those moments.'},
{id:79,topic:'l2',type:'mcq',text:'The "Two Managers, Same Team" scenario concludes with:',opts:['Manager A is more effective because problems must be confronted directly','Manager B produces better outcomes by asking what was working in moments of success','Both approaches are equally valid depending on context','Manager A\'s approach is more professional and accountable'],ans:1,exp:'Manager A: "Let\'s go through what went wrong" → team becomes defensive, blame, demoralised. Manager B: "There were moments this quarter where things clicked — what was happening then?" → room shifts, ownership emerges, solutions surface. "The difference is not personality — it is discipline of attention."'},
{id:80,topic:'l2',type:'mcq',text:'Solution-focused thinking originated from which discipline and location?',opts:['Organisational psychology, Harvard in the 1970s','Brief therapy, Milwaukee in the 1980s by Steve de Shazer and Insoo Kim Berg at the Brief Family Therapy Center','Management consulting, McKinsey in the 1990s','Military leadership training, West Point in the 1960s'],ans:1,exp:'Developed in Milwaukee, 1980s by Steve de Shazer and Insoo Kim Berg, founded at the Brief Family Therapy Center.'},
{id:81,topic:'l2',type:'mcq',text:'The core insight from de Shazer and Berg\'s original work is:',opts:['Problems must be fully understood before they can be solved','You do not need to fully understand a problem to help someone move past it — identify where things are already working and amplify those moments','The therapist must diagnose before prescribing','All solutions are discovered by the expert, not the client'],ans:1,exp:'Core insights: (1) You do not need to fully understand a problem to help someone move past it, (2) Identify where things are already working and amplify those moments, (3) Shift from "Problem Talk" to "Solution Talk" — language shapes what becomes possible.'},
{id:82,topic:'l2',type:'mcq',text:'By the 1990s, who formalised the SF framework into the SIMPLE model?',opts:['Berg and de Shazer','Heath and Heath','Jackson and McKergow','Jerry Sternin'],ans:2,exp:'Jackson & McKergow formalised the SIMPLE framework, bringing rigour and structure to what had been largely a clinical model.'},
{id:83,topic:'l2',type:'mcq',text:'What does each letter in the SIMPLE framework stand for?',opts:['S-Solutions; I-Innovation; M-Measurement; P-People; L-Leadership; E-Excellence','S-Solutions not problems; I-In-between (progress already happening); M-Make use of what\'s there; P-Possibilities (future-focused); L-Language shapes reality; E-Every case is different','S-Strategy; I-Insight; M-Motivation; P-Plan; L-Learning; E-Evaluation','S-Strength; I-Iteration; M-Metrics; P-Purpose; L-Leverage; E-Execution'],ans:1,exp:'SIMPLE: S=Solutions not problems; I=In-between (progress already happening); M=Make use of what\'s there; P=Possibilities (future-focused); L=Language shapes reality; E=Every case is different.'},
{id:84,topic:'l2',type:'mcq',text:'Assumption 1 of the SF approach states:',opts:['Every problem has an external solution','Every team has strengths — the answer is already in the room','Teams must be restructured before they can improve','Problems must be catalogued before solutions are explored'],ans:1,exp:'"Every Team Has Strengths: The answer is already in the Room." Jackson & McKergow: "Make use of what\'s there." The question is never whether people have what it takes — it is whether those capacities are being seen and activated.'},
{id:85,topic:'l2',type:'mcq',text:'The SF leader\'s job, according to Assumption 1, is to:',opts:['Import new talent and external expertise','Surface and amplify existing strengths, competencies, relationships, and small wins — not import from outside','Diagnose team weaknesses and design remediation programmes','Build a strengths inventory database'],ans:1,exp:'"SF leader\'s job: surface and amplify — not import from outside." Look for existing: Competencies, Relationships, and Small wins and successes.'},
{id:86,topic:'l2',type:'mcq',text:'Assumption 2 states "Small Changes Create Momentum." The core principle is:',opts:['Large structural changes are the only way to shift culture','Small behavioural shifts, once noticed and reinforced, ripple outward — the next useful step is enough','Leaders should plan comprehensive 5-year transformation roadmaps','Change is only meaningful when it affects the entire system simultaneously'],ans:1,exp:'De Shazer & Berg: small behavioural shifts ripple outward. Jackson & McKergow: "small actions, big effects." "You do not need to solve the whole problem to start moving in the right direction. The next useful step is enough."'},
{id:87,topic:'l2',type:'mcq',text:'Assumption 3 is "If It\'s Working, Do More of It." The lecture calls this finding the:',opts:['Competitive advantage','Bright spots — exceptions to the problem that already contain the seeds of the solution','Root cause','Performance baseline'],ans:1,exp:'Heath & Heath (Switch, 2010): find the "bright spots." Bright Spots = Exceptions to the problem that already contain the seeds of the solution.'},
{id:88,topic:'l2',type:'mcq',text:'The lecture describes Bright Spots as "not wishful thinking" but rather:',opts:['A positive mindset strategy','A disciplined analytical move that fast-tracks action','A marketing technique for highlighting achievements','A motivational tool for low-performing teams'],ans:1,exp:'"Not wishful thinking — a disciplined analytical move that fast-tracks action."'},
{id:89,topic:'l2',type:'mcq',text:'Jerry Sternin\'s work in Vietnam reduced childhood malnutrition by:',opts:['Analysing causes and prescribing nutritional supplements','Finding families whose children were already thriving and replicating what they did differently — 65% of children better nourished within 6 months','Launching a government campaign explaining proper diet','Partnering with international NGOs to import food aid'],ans:1,exp:'Sternin did not analyse causes — he found families whose children were already thriving and asked what they were doing differently. Result: 65% of children better nourished within 6 months. "Task of the SF Leader: Don\'t explain the problem — Understand the exception."'},
{id:90,topic:'l2',type:'mcq',text:'Assumption 4 is "The Future Is Co-Created." This means:',opts:['The leader writes the vision and the team executes it','People move more sustainably toward outcomes they articulate themselves — the leader is a co-author, not a scriptwriter','The future is determined by external market forces','Teams should vote on all decisions democratically'],ans:1,exp:'Berg & de Shazer: "people move more sustainably toward outcomes they articulate themselves." The most capable teams participated in imagining that future. SF leadership is fundamentally collaborative.'},
{id:91,topic:'l2',type:'mcq',text:'The lecture explicitly states that SF Leadership is NOT:',opts:['A structured leadership methodology','Ignoring problems, toxic positivity, or avoiding accountability and difficult conversations','A coaching tool for team conversations','A framework for performance conversations'],ans:1,exp:'SF is NOT: (X) Ignoring problems or pretending they don\'t exist, (X) Toxic positivity or forced optimism, (X) Avoiding accountability or difficult conversations.'},
{id:92,topic:'l2',type:'mcq',text:'Tool 1 — The Miracle Question (MQ) — was developed by:',opts:['Jackson and McKergow','Jerry Sternin','de Shazer and Berg','Heath and Heath'],ans:2,exp:'The Miracle Question was developed by de Shazer and Berg. It is the foundational SF tool for shifting people from problem ownership to preferred-future authorship.'},
{id:93,topic:'l2',type:'mcq',text:'The original form of the Miracle Question is:',opts:['"If you could change one thing, what would it be?"','"Suppose tonight, while you sleep, a miracle happens and the problem is solved. When you wake up — what would be different?"','"Imagine you are at your best — what does that look like?"','"What would success look like for your team in one year?"'],ans:1,exp:'Original form: "Suppose tonight, while you sleep, a miracle happens and the problem is solved. When you wake up — what would be different?" Purpose: shift people from problem ownership to preferred-future authorship.'},
{id:94,topic:'l2',type:'mcq',text:'De Shazer\'s insight about the Miracle Question is:',opts:['Vague goals produce vague effort — specificity makes progress measurable and motivating','The MQ works only in clinical settings','The question should be asked only in crisis','The MQ replaces all other diagnostic tools'],ans:0,exp:'De Shazer: "Vague goals produce vague effort — specificity makes progress measurable and motivating." Berg added: "People stop defending their stuck position and start describing a future they genuinely want."'},
{id:95,topic:'l2',type:'mcq',text:'The MQ case study involved a logistics company leadership team. What happened after the MQ was introduced?',opts:['The team disbanded and reformed with new members','In 40 minutes, the team described a good working day in specific detail, identified 3 concrete differences from the present, and those 3 differences became action priorities — no consultant had surfaced this clarity in months of workshops','The team requested more data and analysis before acting','The facilitator was asked to design a culture programme'],ans:1,exp:'"Stalemate to Clarity in 40 minutes." The MQ unlocked 3 concrete differences that became action priorities. No culture consultant had surfaced this clarity in months of workshops.'},
{id:96,topic:'l2',type:'mcq',text:'Tool 2 — Scaling Questions (SQ) — uses which core question format?',opts:['"On a scale of 1 to 5, how satisfied are you?"','"On a scale of 1 to 10, where 10 is the best it could be; where are things right now?"','"Rate your performance from poor to excellent"','"How does your performance compare to last quarter?"'],ans:1,exp:'"On a scale of 1 to 10, where 10 is the best it could be; where are things right now?" Developed by de Shazer & Berg to bypass the need for a full problem analysis.'},
{id:97,topic:'l2',type:'mcq',text:'Which is the FIRST follow-up question in the Scaling Question sequence?',opts:['"What would a 10 look like?"','"What makes it a 4 and not a 1?" — to surface what\'s already working','"What would need to happen to get from 4 to 5?"','"Who is responsible for the current score?"'],ans:1,exp:'Follow-up 1: "What makes it a 4 and not a 1?" — surfaces what\'s already working. Follow-up 2: "What would a 5 look like?" — generates a specific, achievable next step. Follow-up 3: "What would need to happen to get from 4 to 5?" — shifts ownership to the coachee.'},
{id:98,topic:'l2',type:'mcq',text:'Scaling Questions are described as particularly effective because they:',opts:['Provide objective performance data over time','Create safe traction — giving people a vocabulary for progress without requiring them to claim total success or admit total failure','Replace formal performance management systems','Allow leaders to quantify team motivation precisely'],ans:1,exp:'"Scaling gives people a vocabulary for progress without requiring them to claim total success or admit total failure." Particularly effective where blame culture makes honest self-assessment difficult.'},
{id:99,topic:'l2',type:'mcq',text:'Tool 3 — Exception-Finding (EF) — is built around which core question?',opts:['"What is the biggest obstacle you are facing?"','"Tell me about a time when the problem didn\'t happen — or happened less. What was different?"','"What did you do wrong last time?"','"How would an ideal situation look in 5 years?"'],ans:1,exp:'"Tell me about a time when the problem didn\'t happen — or happened less. What was different?" Exceptions are rarely random — they contain the seeds of the solution.'},
{id:100,topic:'l2',type:'mcq',text:'The hospital department Exception-Finding case study resolved:',opts:['Conflict through restructuring and separating the two nurses permanently','Chronic conflict between two senior nurses affecting the whole ward — conflict frequency and intensity dropped significantly within six weeks after both nurses independently named the same exception','The issue through formal HR disciplinary procedures','The conflict by bringing in an external mediator'],ans:1,exp:'Both nurses independently named the same exception: a challenging patient case requiring close collaboration. SF Intervention: create more opportunities for complex case work. Conflict dropped significantly within six weeks.'},
{id:101,topic:'l2',type:'mcq',text:'Tool 4 — Strengths Amplification — distinguishes between:',opts:['Formal and informal praise','Generic praise ("Great job!") — quickly discounted — and SF Compliments: Specific, Observed, connected to Outcome','Public and private recognition','Peer and supervisor feedback'],ans:1,exp:'Generic Praise: "Great job!" — quickly discounted. SF Compliment: Specific, Observed, connected to Outcome. Example: "When the brief arrived at short notice, you reorganised priorities without being asked — and without visible panic. That calm initiative keeps us credible with clients."'},
{id:102,topic:'l2',type:'mcq',text:'Naming a strength with an SF Compliment achieves what the lecture calls:',opts:['Performance documentation','Co-constructing Competence — naming a strength helps the person begin to identify as someone who has it, making the behaviour more likely to recur','Public accountability','Peer benchmarking'],ans:1,exp:'"Co-constructing Competence — naming a strength helps the person begin to identify as someone who has it. Makes the behaviour more likely to recur."'},
{id:103,topic:'l2',type:'mcq',text:'The "Four SF Tools at a Glance" table correctly pairs the Miracle Question with which Primary Effect?',opts:['Creates movement without full diagnosis','Surfaces existing solutions','Anchors and reinforces competence','Clarifies the preferred future'],ans:3,exp:'MQ → Clarifies the preferred future. Scaling Questions → Creates movement without full diagnosis. Exception-Finding → Surfaces existing solutions. Strengths Amplification → Anchors and reinforces competence.'},
{id:104,topic:'l2',type:'mcq',text:'The Rider, Elephant, and Path metaphor. The Rider represents:',opts:['The emotional mind — needs motivation and a vivid destination','The rational mind — needs direction and a clear plan','The environment — needs to make right behaviour easier','The leader who directs the change'],ans:1,exp:'Rider = Rational mind — needs direction and a clear plan. Elephant = Emotional mind — needs motivation and a vivid destination. Path = Environment — needs to make right behaviour easier.'},
{id:105,topic:'l2',type:'mcq',text:'The lecture argues that most change management addresses only the Rider. The SF tools address all three as follows:',opts:['MQ → Rider; SQ → Elephant; EF → Path','MQ → Elephant (vivid, appealing destination); SQ → Rider (manageable next step); EF → Path (shaped by revealing favourable terrain)','MQ → Path; SQ → Elephant; EF → Rider','All three tools primarily address the Rider'],ans:1,exp:'MQ → Elephant (vivid, appealing destination); SQ → Rider (manageable next step); EF → Path (shaped by revealing favourable terrain). Most change programmes address ONLY the Rider — plans, processes, cascades. Meanwhile the Elephant stampedes.'},
{id:106,topic:'l2',type:'mcq',text:'The lecture\'s phrase "Find the Feeling" refers to:',opts:['Conducting emotional intelligence assessments','Don\'t ARGUE people into change; help them EXPERIENCE the pull of a possible future','Identifying which emotion is blocking team progress','Using empathy to build rapport before feedback'],ans:1,exp:'"Find the Feeling — Don\'t ARGUE people into change; help them experience the pull of a possible future." This is the Elephant side of change — emotional motivation that sustains movement even when plans are incomplete.'},
{id:107,topic:'l2',type:'mcq',text:'The "Reframing the Conversation on Performance" section: the SF approach uses:',opts:['Lead with the performance gaps; be direct about failures','"There are things not working — and I think we both know that. But let\'s spend most of our time on what a better situation would look like — and what needs to change to get there"','Review KPIs together and identify missed targets','Ask the employee to self-rate their performance before giving feedback'],ans:1,exp:'This reframing increases the likelihood of behavioural change — the person leaves with a direction, not a verdict.'},
{id:108,topic:'l2',type:'mcq',text:'The SF Stand-Up ritual changes team meetings by shifting the opening question from:',opts:['Objectives to key results','Problem-focused questions ("What\'s blocking us?", "What went wrong?") to SF questions ("What\'s gone well since we last met?", "What\'s our clearest next step forward?")','Individual to team check-ins','Formal reports to informal discussions'],ans:1,exp:'SF Stand-Up: "What\'s gone well since we last met?" and "What\'s our clearest next step forward?" It takes no additional time — 5 minutes. Repeated over weeks: shifts collective attention, confidence, and momentum.'},
{id:109,topic:'l2',type:'mcq',text:'The SF Retrospective restructures post-mortems around which three questions?',opts:['What went wrong? Who caused it? How do we prevent recurrence?','What worked well? What made it work? What would we carry forward?','What were our targets? Did we meet them? What is the remediation plan?','What did leadership do right? What did the team do wrong? What is the gap?'],ans:1,exp:'SF Retrospective: (1) What worked well? (2) What made it work? (3) What would we carry forward? Shifts from "what failed and who caused it" to "what succeeded and how do we replicate it." Same learning — far less defensiveness — far more ownership.'},
{id:110,topic:'l2',type:'mcq',text:'The restructuring case study shows resistance softened because:',opts:['Management explained the business case more clearly','Staff were given more time to adjust','Staff became co-authors of it — their ideas were reflected in the final restructuring plan','External consultants validated the change strategy'],ans:2,exp:'The SF approach asked: "What would this department look like at its best in five years?" and "What do we already have that we\'d want to build on?" Staff ideas were reflected in the final plan. Resistance softened not because the change became easier, but because staff became co-authors of it.'},
{id:111,topic:'l2',type:'mcq',text:'The lecture distinguishes "Being SF" from "Doing SF." Being SF means:',opts:['Using SF tools whenever a situation calls for it','Habitually looking for strengths, exceptions, and preferred futures as a default way of seeing — making SF thinking instinctive','Attending SF training workshops regularly','Applying the MQ in all one-to-one conversations'],ans:1,exp:'"Doing SF" = applying tools when a situation calls for it. "Being SF" = habitually looking for strengths, exceptions, and preferred futures as a default way of seeing. "The goal: make solution-focused thinking instinctive."'},
{id:112,topic:'l2',type:'mcq',text:'Building SF Habits requires which three design choices?',opts:['SF stand-ups, SF retrospectives, and regular check-ins using scaling questions as a progress habit','MQ workshops, EF training, and strengths mapping exercises','Team-building events, away-days, and culture surveys','360-degree feedback, coaching sessions, and wellbeing programmes'],ans:0,exp:'Building SF Habits: (1) Team rituals making SF questions the default (SF stand-up, SF retrospective), (2) Meeting structures opening with strengths before problems, (3) Regular check-ins using scaling questions as a progress habit.'},
{id:113,topic:'l2',type:'mcq',text:'The lecture identifies situations where SF has clear limits. Which is one of them?',opts:['Employee motivation conversations','Succession planning discussions','Technical problem-solving — a safety defect needs root-cause analysis','Team goal-setting sessions'],ans:2,exp:'When SF Has Limits: (X) Technical problem-solving — safety defect needs root-cause analysis; (X) Rigorous accountability — discriminatory conduct needs direct investigation; (X) Financial forensics — irregularity demands diagnosis, not preferred-future thinking.'},
{id:114,topic:'l2',type:'mcq',text:'The risk of "Premature SF" occurs when:',opts:['A leader uses SF tools too frequently','Reaching for SF tools too early when a team is grieving, carrying justified anger, or processing a significant failure — it can feel DISMISSIVE','SF tools are applied without proper training','A leader uses Scaling Questions before the Miracle Question'],ans:1,exp:'"Don\'t reach for the Miracle Question too quickly." There is a distinction between "not dwelling on problems" and "dismissing them." Skilled SF leaders read the emotional temperature of the room.'},
{id:115,topic:'l2',type:'mcq',text:'"Even Great Questions Fail Inside Bad Systems." SF tools are blunted in systems that:',opts:['Lack a formal coaching culture','Consistently punish initiative, reward blame over learning, and discourage honest conversation','Are in growth mode with little time for reflection','Are led by Problem-Focused managers at the top'],ans:1,exp:'SF tools are blunted in systems that punish initiative, reward blame over learning, and discourage honest conversation. "Redesigning the environment is as important as motivating the Rider and engaging the Elephant."'},
{id:116,topic:'l2',type:'mcq',text:'The Cultural Considerations slide warns that SF tools\' assumptions about personal agency:',opts:['Are universally applicable across all cultural settings','Do not translate uniformly across all cultural settings — collective decision-making may be the norm, deferring to authority may make "what do you want?" feel presumptuous, indirect communication may require adapting question language','Are only relevant in Western organisational settings','Should be abandoned in favour of culturally specific leadership models'],ans:1,exp:'"SF tools were built in a specific context — hold them with flexibility." In some contexts: collective decision-making is the norm; deferring to authority makes "what do you want?" feel presumptuous; indirect communication requires adapting question language.'},
{id:117,topic:'l2',type:'mcq',text:'The lecture states that SF leadership complements Adaptive Leadership by:',opts:['Both using the same diagnostic tools','Both engaging people in authoring their own solutions','Both focusing on vision and strategic planning','Both requiring formal certification'],ans:1,exp:'SF and Other Frameworks: Transformational leadership — both orient toward an inspiring shared future. Adaptive leadership — both engage people in authoring their own solutions. Servant leadership — both centre the needs and strengths of those being led. SF sharpens the quality of conversations within these frameworks.'},
{id:118,topic:'l2',type:'mcq',text:'The Dr David Oyedepo quote used in the closing section of Lecture 2 is:',opts:['"Vision without sacrifice is just a daydream"','"There is no star without a scar, and the scar of every star is sacrifice. Doing one\'s best is diligence; going beyond one\'s best is sacrifice"','"The knowledge marketplace has no apartheid"','"You don\'t grow big to manage well; you manage well to grow big"'],ans:1,exp:'Slide 27 (The Cost of Sustained Leadership): "There is no star without a scar, and the scar of every star is sacrifice. Doing one\'s best is diligence; going beyond one\'s best is sacrifice." — Dr David Oyedepo. Used to show SF optimism must be paired with genuine commitment and sacrifice.'},
{id:119,topic:'l2',type:'short',text:'Which form of Solution-Focused practice has solution-focused thinking as a default way of seeing rather than occasional tool deployment?',ans:'Being SF',exp:'Being SF means solution-focused thinking has become a default way of seeing: habitually looking for strengths, exceptions, and preferred futures.'},
{id:120,topic:'l2',type:'short',text:'In the Rider, Elephant, and Path framework, which part represents the rational mind that needs clear direction?',ans:'Rider',exp:'The Rider is the rational mind. Elephant is the emotional mind. Path is the environment.'},
{id:121,topic:'l2',type:'fill',text:'The lecture states: "The difference is not personality — it is _______ of _______." (from the Two Managers scenario)',dropdowns:[['discipline', 'quality', 'focus', 'direction'], ['attention', 'vision', 'action', 'mindset']],ans:['focus', 'attention'],exp:'The difference is not personality, but a deliberate discipline of attention.'},
{id:122,topic:'l2',type:'fill',text:'Jackson & McKergow described the SF approach as producing "small _______, big _______."',dropdowns:[['actions', 'steps', 'gains', 'ideas'], ['effects', 'results', 'outcomes', 'impacts']],ans:['actions', 'effects'],exp:'Small changes/actions cascade into big effects and outcomes.'},
{id:123,topic:'l2',type:'fill',text:'The task of the SF leader is: "Don\'t _______ the problem — _______ the exception."',dropdowns:[['explain', 'analyze', 'discuss', 'solve'], ['understand', 'find', 'use', 'create']],ans:['explain', 'understand'],exp:'Understand the exception to find the seeds of the solution, rather than trying to explain the problem in depth.'},
{id:124,topic:'l2',type:'multi',text:'Select ALL four SF Tools listed in Lecture 2:',opts:['The Miracle Question','SWOT Analysis','Scaling Questions','Exception-Finding','Performance Review','Strengths Amplification'],ans:[0,2,3,5],exp:'The four SF tools: (1) Miracle Question, (2) Scaling Questions, (3) Exception-Finding, (4) Strengths Amplification.'},
{id:125,topic:'l2',type:'multi',text:'Select ALL that correctly describe what SF Leadership IS (not what it is NOT):',opts:['Ignoring problems to stay positive','Engaging people in co-authoring the preferred future','Making space for acknowledgement before pivoting to possibility','Toxic positivity and forced optimism','Surfacing and amplifying existing team strengths','Avoiding difficult conversations'],ans:[1,2,4],exp:'SF IS: engaging people in co-authoring the preferred future, making space for acknowledgement (skilled SF leaders read emotional temperature), surfacing and amplifying existing strengths.'},
{id:126,topic:'l2',type:'multi',text:'Which situations are OUTSIDE the optimal use of SF tools, per the lecture?',opts:['Team motivation conversations','Technical problem-solving requiring root-cause analysis','Rigorous accountability for discriminatory conduct','Employee goal-setting sessions','Financial forensics where an irregularity demands diagnosis'],ans:[1,2,4],exp:'SF has limits: technical problem-solving (safety defects need root-cause analysis), rigorous accountability (discriminatory conduct needs direct investigation), financial forensics (irregularities demand diagnosis).'},
{id:127,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A head of department opens a Monday meeting with: "Let\'s go through the list of targets we missed last week." Using Lecture 2, which lens is being applied, and what are the predictable consequences?',opts:['Solution-Focused lens — the team will rally around the identified problems','Problem-Focused lens — the team becomes defensive, conversation circles around blame, and people leave demoralised','Adaptive lens — the team will adapt to the challenges identified','Servant leadership lens — the leader is putting the team\'s needs first'],ans:1,exp:'Manager A\'s approach (Problem-Focused lens): lead with what went wrong → team becomes defensive → blame → demoralised. The PF lens creates a problem-saturated environment over time.'},
{id:128,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A media organisation is struggling with poor content quality. The head of content says: "We need to find out why our team is producing bad work." An SF consultant suggests a different question. Which BEST reflects an SF reframe?',opts:['"Let us conduct a root-cause analysis of quality failures over the past 6 months"','"Which editions or segments have performed best — and what was different about how those were produced?"','"Which team member has the lowest performance rating?"','"We need an external quality audit to identify systemic problems"'],ans:1,exp:'SF reframe — Exception-Finding: instead of "why is this failing?" ask "where is it already working — and why?" Finding the bright spots — exceptions to the problem that already contain the seeds of the solution — is more actionable than analysing failures.'},
{id:129,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A supervisor gives feedback: "You\'re a great communicator!" The team member shrugs it off. Using Tool 4 (Strengths Amplification), which feedback would be MORE effective?',opts:['"You always know the right thing to say"','"I\'ve noticed that in the last three client briefings, when conflict arose, you asked questions instead of giving opinions — that shifted the tone every time and kept us on track"','"Your communication skills are a strength the whole team has noticed"','"You handle difficult conversations better than most — keep it up"'],ans:1,exp:'SF Compliment = Specific, Observed, connected to Outcome. The specific, observed compliment names the exact behaviour, the context, and the outcome. This co-constructs competence — the person begins to identify as someone who does this well.'},
{id:130,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A faculty meeting is going in circles about declining student attendance. One lecturer says: "Some departments have high attendance — what are they doing differently?" Which SF tool is this lecturer instinctively applying?',opts:['The Miracle Question','Scaling Questions','Exception-Finding (Bright Spots)','Strengths Amplification'],ans:2,exp:'Exception-Finding: instead of "why is attendance low?" the lecturer asks about the exception — departments where attendance is high. Bright Spots = exceptions to the problem that already contain the seeds of the solution.'},
{id:131,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A team used to blame culture is having their first SF check-in. The manager asks: "On a scale of 1 to 10, where would you rate team cohesion right now?" Someone says "4." What is the ideal SF follow-up?',opts:['"Who is responsible for it being so low?"','"What would it take to get it to a 10 immediately?"','"What makes it a 4 and not a 1?" — to surface what\'s already working','"So you think the team is failing?"'],ans:2,exp:'"What makes it a 4 and not a 1?" is the first SF follow-up in the Scaling Question sequence. It surfaces what is already working — especially powerful in blame cultures where people are not accustomed to naming progress.'},
{id:132,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A communications organisation undergoing restructuring has holding information sessions — but resistance is hardening. Using Lecture 2, what is the SF alternative?',opts:['Hold more information sessions with clearer data','Discipline those who are publicly resistant','Facilitate conversations asking: "What would this department look like at its best in five years?" and "What do we already have that we\'d want to build on?" — making staff co-authors of the change','Bring in an external change management consultant'],ans:2,exp:'The restructuring case study: resistance softened not because the change became easier, but because staff became co-authors of it. Information alone argues to the Rider; SF engages the Elephant.'},
{id:133,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A student leader notices her study group is always focused on what they don\'t understand and members leave sessions feeling discouraged. Which SF ritual would have the most immediate impact?',opts:['Introduce a grading system to track progress','Start each session with "What has clicked for each of us since our last meeting?" before moving to challenges','Hold individual sessions to diagnose each member\'s weaknesses','Ask the group to write detailed analysis of what they don\'t understand'],ans:1,exp:'SF Stand-Up applied to a study group: opening with "What has clicked?" shifts collective attention from problems to progress. Takes no additional time. Repeated over sessions, it shifts the group\'s confidence and momentum.'},
{id:134,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A journalism lecturer giving feedback begins: "This is excellent — especially your sourcing in paragraphs 3 and 5 which adds credibility. That\'s the standard I want across the whole piece. Let\'s look at how we get the introduction to do the same work." Which SF tool is she applying?',opts:['Miracle Question — she is asking about a preferred future','Exception-Finding — she is finding where the article already works and using it as a model for the rest','Scaling Questions — she is quantifying the quality','Generic Praise — she is avoiding the real issue'],ans:1,exp:'Exception-Finding + Strengths Amplification: she identifies where the article already works (bright spot: paragraphs 3 and 5) and uses that exception as the model for improvement. "Understand the exception."'},
{id:135,topic:'l2',type:'short',applied:true,text:'[APPLIED] In a final-year project group with high conflict, which Solution-Focused tool is best used to co-construct a preferred future?',ans:'Miracle Question',exp:'The Miracle Question (MQ) is used to shift the team from problem ownership to preferred-future authorship.'},
{id:136,topic:'l2',type:'mcq',text:'Which of the following is listed as a key reference in Lecture 2?',opts:['Covey, S. (1989). The 7 Habits of Highly Effective People','De Shazer, S. (1988). Clues: Investigating Solutions in Brief Therapy. Norton','Senge, P. (1990). The Fifth Discipline','Goleman, D. (1995). Emotional Intelligence'],ans:1,exp:'References include: De Shazer (1988). Clues: Norton; Berg & Szabó (2005). Brief Coaching for Lasting Solutions. Norton; Jackson & McKergow (2002). The Solutions Focus. Nicholas Brealey; Heath & Heath (2010). Switch; Oyedepo (2024). Leadership Ideology: A Covenant Perspective.'},
{id:137,topic:'l2',type:'mcq',text:'The SIMPLE framework is attributed to:',opts:['De Shazer and Berg','Heath and Heath','Jackson and McKergow','Jerry Sternin'],ans:2,exp:'Jackson, P.Z. & McKergow, M. (2002). The Solutions Focus. Nicholas Brealey. They formalised the SIMPLE framework.'},
{id:138,topic:'l2',type:'mcq',text:'The closing conclusion of Lecture 2 presents SF leadership through three categories. What does "Attention" mean in this context?',opts:['Being attentive to team needs through active listening','SF leadership is a disciplined reorientation of attention — from problems to possibilities','Paying attention to KPIs and performance metrics','Focusing leadership attention on the most urgent crises'],ans:1,exp:'Closing slide: Attention = SF leadership is a disciplined reorientation of attention — from problems to possibilities. Habits = SF culture is built through small, consistent habits embedded in team rhythms. Action = A demanding practice insisting on co-creation and sustained commitment.'},
{id:139,topic:'l2',type:'mcq',text:'The concluding questions of Lecture 2 are:',opts:['"How do you solve the biggest problems your team faces?" and "Who are you becoming as a leader?"','"What would your leadership look like at its best?" and "What\'s one thing already moving in that direction?"','"What are the biggest threats to your organisation?" and "How will you address them?"','"What skills do you need to develop?" and "What is your development plan?"'],ans:1,exp:'Slide 37 (Conclusion): "What would your leadership look like at its best? What\'s one thing already moving in that direction?" These two questions embody the entire SF approach — preferred future + existing bright spot.'},
{id:140,topic:'l2',type:'mcq',text:'Which correctly pairs all four SF tools with their primary effects?',opts:['MQ→Clarifies preferred future; SQ→Creates movement without full diagnosis; EF→Surfaces existing solutions; SA→Anchors and reinforces competence','MQ→Surfaces existing solutions; SQ→Anchors competence; EF→Clarifies preferred future; SA→Creates movement','MQ→Creates movement; SQ→Clarifies preferred future; EF→Anchors competence; SA→Surfaces solutions','MQ→Anchors competence; SQ→Surfaces solutions; EF→Creates movement; SA→Clarifies future'],ans:0,exp:'The Four SF Tools At a Glance: MQ → Clarifies preferred future. SQ → Creates movement without full diagnosis. EF → Surfaces existing solutions. SA → Anchors and reinforces competence.'},
{id:141,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A lecturer returns 50 student essays with detailed feedback on every error. Most students feel discouraged. Using Lecture 2, what would an SF-informed feedback approach look like?',opts:['Give no critical feedback to protect student confidence','Return essays with only a numerical grade','For each essay, identify one thing that was already working well (specific, observed, connected to quality), and anchor one clear next step — so students leave with a direction, not a verdict','Hold group feedback sessions where students critique each other'],ans:2,exp:'SF Strengths Amplification applied to academic feedback: Specific + Observed + Outcome. Identify the bright spot — where the essay is already doing what good writing does — and use it as the reference point for improvement. The student leaves with a direction, not a verdict.'},
{id:142,topic:'l2',type:'mcq',text:'The "Apply Scaling — Right Now" exercise at the end of Lecture 2 asks participants to:',opts:['Identify the problem, analyse the root cause, design a solution, implement it','Reflect on a current leadership challenge: place it on a 1–10 scale, identify what makes it that number and not lower, describe one step up in concrete terms, and name a small action they could take this week to move it by one point','Define their vision, identify their knowledge gap, build their daily discipline','List team strengths, weaknesses, opportunities, and threats'],ans:1,exp:'Slide 33: (1) Where on a 1–10 scale right now? (2) What makes it that number and not lower? (3) What would one step up look like in concrete, specific terms? (4) What small action could you take this week to move it by one point? Scaling Question applied to self-directed leadership development.'},
{id:143,topic:'l2',type:'mcq',text:'The "SF Commitment This Week" slide offers four starting options. Which is NOT listed?',opts:['Open your next team meeting with "What\'s gone well?"','Use a scaling question in your next one-to-one','Conduct a full team strengths mapping exercise and present it to leadership','Ask "When has this gone better?" the next time a problem is raised'],ans:2,exp:'The four SF commitments: open next meeting with "What\'s gone well?", use a scaling question in your next one-to-one, ask "When has this gone better?" the next time a problem is raised, give one specific observed strength-based compliment.'},
{id:144,topic:'l2',type:'mcq',text:'The lecture presents Dr David Oyedepo\'s quote at the "Cost" slide. The implication for SF leadership is:',opts:['SF is easy because it focuses on strengths rather than problems','Solution-focused optimism at its best is not a comfortable philosophy — it is a demanding one that insists on action, not just possibility; the preferred future the MQ surfaces will not arrive without genuine commitment','The MQ eliminates the need for hard work by clarifying direction quickly','SF leaders are more relaxed because they focus on what works'],ans:1,exp:'"Solution-focused optimism at its best is not a comfortable philosophy. It is a demanding one — that insists on action, not just possibility." The preferred future will not arrive without genuine commitment. SF leaders must model the discipline and effort they help their teams towards.'},
{id:145,topic:'l2',type:'short',text:'Which performance conversation approach is more likely to produce lasting behavioural change by engaging the Elephant and co-authorship?',ans:'Solution-Focused',exp:'The Solution-Focused performance conversation reframes the discussion to focus on what a better situation looks like, engaging the Elephant.'},
{id:146,topic:'l2',type:'mcq',text:'Lecture 2 was delivered by:',opts:['Pst Chibuike Nwafor','Prof Evans Osabuohien','Dr David Oyedepo','Jackson McKergow'],ans:1,exp:'Lecture 2 (Solution-Focused Leadership in Practice) was delivered by Prof Evans Osabuohien, as shown on the title slide of the DLD221 lecture.'},
{id:147,topic:'l2',type:'mcq',text:'"Finding Your Bright Spots" exercise asks participants to think of a moment in the last month when their challenge was less acute. The four questions posed include:',opts:['Why did things go wrong? Who helped? What resources were missing? What would you do differently?','What was different about that moment? What did YOU do differently? What did the TEAM do differently? What would it take to create more moments like that one?','What were your targets? Did you meet them? What held you back? Who else was involved?','What strength did you demonstrate? What feedback did you receive? How did you grow? What is your next goal?'],ans:1,exp:'Finding Your Bright Spots: (1) What was different about that moment? (2) What did YOU do differently? (3) What did the TEAM do differently? (4) What would it take to create more moments like that one? Jackson & McKergow: "Every team has resources that are being underused. Your job is to find them."'},
{id:148,topic:'l2',type:'mcq',text:'De Shazer\'s phrase "Problem Talk" vs "Solution Talk" emphasises:',opts:['Problems should never be discussed in organisations','The type of language a leader uses shapes what becomes possible — sustained focus on problems creates a problem-saturated reality; shifting to solution talk opens new possibilities','Solutions can only emerge after problems are fully diagnosed','Solution talk is a communication style used only in coaching, not leadership'],ans:1,exp:'Core insight from de Shazer: shift from "Problem Talk" to "Solution Talk." Language shapes what becomes possible. This is also the "L" in SIMPLE: Language shapes reality.'},
{id:149,topic:'l2',type:'mcq',applied:true,text:'[APPLIED] A newly appointed editor notices her newsroom is highly creative when covering social impact stories but struggles with political reporting. Using an SF approach, her FIRST move should be:',opts:['Hire a political reporter from a competitor outlet','Commission a training programme on political journalism for all staff','Ask: "When have we produced political coverage we were proud of? What was different about how we approached it?" — finding the exception to build from','Announce minimum standards for political reporting and monitor compliance'],ans:2,exp:'Exception-Finding: instead of diagnosing the deficit, find the bright spot. Even in a newsroom that struggles with political reporting, there will have been at least one edition or story where it worked. That exception contains the seeds of the solution.'},
{id:150,topic:'l2',type:'mcq',text:'The lecture\'s position on SF leadership and accountability is that SF:',opts:['Avoids accountability to protect psychological safety','Simply holds that understanding a problem in depth is not a prerequisite for solving it — SF does NOT avoid accountability or difficult conversations; it reframes HOW those conversations happen','Eliminates the need for formal performance management','Replaces accountability with a strengths-only focus'],ans:1,exp:'Jackson & McKergow: "SF simply holds that understanding a problem in depth is not a prerequisite for solving it." SF is NOT avoiding accountability — it reframes how those conversations happen. Focus energy on what a better situation looks like and what is already moving that way.'},
{id:151,type:'mcq',applied:true,text:'[APPLIED] A legacy consumer electronics corporation is witnessing a rapid market shift toward cloud-integrated software solutions. While their engineers recently developed a groundbreaking web-connected product, the executive board decides to shelve the project to avoid cannibalizing their traditional hardware sales, mirroring the strategic inaction that led to Kodak\'s downfall in 2012. Based on the Kodak case study in the lecture, what is the core lesson regarding the risk of organizational transformation?',ans:1,exp:'As documented in the lecture, Kodak invented the digital camera in 1975 but failed to transform, filing for bankruptcy in 2012. The key organizational lesson is that \'the greater risk is almost always in standing still.\' Even if a company has the technical capabilities, failure to change its business model and operational mindset leads to obsolescence.',topic:'l3',opts:['A. The risk of transformation is primarily financial, as new technologies require capital expenditure that disrupts short-term shareholder value.', 'B. The greater risk is almost always in standing still, as failing to transform leads to total obsolescence even if the company holds key patents or invented the technology.', 'C. Transforming too early is more dangerous than transforming too late, because early adopters bear the cost of market education.', 'D. A firm should only transform when its primary products experience a double-digit decline in market share for three consecutive years.']},
{id:152,type:'mcq',applied:true,text:'[APPLIED] A corporate leader is attempting to overhaul the legacy enterprise resource planning (ERP) system of a major manufacturing plant. The employees are highly comfortable with the existing manual entry sheets and do not see the need for change. In reference to the Piper Alpha disaster of 1988, what is the leader\'s primary task in this initiating phase?',ans:2,exp:'The Piper Alpha disaster serves as a metaphor for the \'Burning Platform.\' The lecture teaches that transformation begins when people genuinely believe the present state is unsustainable. The leader\'s first task is helping the organization feel—not just understand—why change is non-negotiable, establishing urgency.',topic:'l3',opts:['A. Design a highly detailed training program to teach technical skills before explaining the reasons for the ERP system rollout.', 'B. Establish a system of immediate disciplinary actions for employees who refuse to use the new ERP system.', 'C. Help the organization feel—not just understand—why staying in the current state is unsustainable and dangerous.', 'D. Focus on maintaining a comfortable environment so that employee morale does not drop during the structural transition.']},
{id:153,type:'mcq',applied:true,text:'[APPLIED] A technology corporation has experienced flat growth, toxic internal competition due to a \'stack ranking\' performance system, and a general cultural attitude of intellectual arrogance. The newly appointed CEO decides to pivot the corporate philosophy to mirror the Satya Nadella Microsoft turnaround. Which of the following strategic actions aligns with this cultural redirection?',ans:1,exp:'Under Satya Nadella, Microsoft shifted its culture from toxic stack ranking to a growth mindset, moving from a \'know-it-all\' to a \'learn-it-all\' philosophy, which helped grow its market cap from ~$300 billion to over $2 trillion.',topic:'l3',opts:['A. Standardizing stack ranking to identify the bottom 10% of performers more aggressively and encourage competition.', 'B. Transitioning the organizational mindset from a \'know-it-all\' culture to a \'learn-it-all\' culture centered on growth and collaboration.', 'C. Prioritizing mobile hardware development over cloud services to capture the consumer devices market.', 'D. Maintaining the existing vision statement but restructuring the executive team to reduce operational overhead.']},
{id:154,type:'mcq',applied:true,text:'[APPLIED] The CEO of a regional financial institution holds weekly transformation review meetings. For the first three months, only the CEO\'s direct reports attend, leading an external advisor to observe that the meetings have become an \'echo chamber\'. Applying the bank CEO case study from the lecture, how should the coalition be expanded?',ans:1,exp:'In the bank CEO case study, the coalition was expanded by reserving seats for middle and operational layer employees (rather than their managers). Within 6 months, the most creative and practical ideas came from those chairs, proving that coalition is built by inclusion, not mandate.',topic:'l3',opts:['A. By issuing a mandate that all middle managers must read the minutes of the weekly meetings and submit written feedback.', 'B. By reserving seats in the meetings for representatives from the middle and operational layers, excluding their direct managers, to foster direct dialogue.', 'C. By replacing the direct reports with external consultants who specialize in large-scale change management.', 'D. By reducing the frequency of the meetings to monthly sessions to prevent discussion fatigue among the executive team.']},
{id:155,type:'mcq',applied:true,text:'[APPLIED] In 2008, Starbucks was experiencing a loss of its organizational \'soul\' due to rapid, growth-obsessed expansion. Upon returning as CEO, Howard Schultz closed all U.S. stores for a day of retraining at a cost of $6 million. How does this decision illustrate the principles of servant leadership and transformation?',ans:2,exp:'Schultz\'s decision to close all stores for retraining at a cost of $6 million was a major act of modeling sacrifice. Leaders who model the sacrifice they ask of others earn a fundamentally different level of trust, which is key to servant leadership during transformation.',topic:'l3',opts:['A. It demonstrated financial opportunism by using a tax write-off to cover operational retraining costs.', 'B. It signaled that the leader was unwilling to take personal responsibility, shifting the blame of the drift onto the frontline store partners.', 'C. It was a symbolic and practical act of modeling the sacrifice asked of others, reinforcing what the transformation stood for despite short-term costs.', 'D. It showed that communication is best handled through top-down broadcasts rather than engaging directly with frontline staff.']},
{id:156,type:'mcq',applied:true,text:'[APPLIED] An analyst is comparing two major organizational turnarounds from the same decade: the South African Revenue Service (SARS) under Pravin Gordhan and Sears Holdings. What key factor explains the success of SARS and the failure of Sears Holdings based on the case studies in the lecture?',ans:1,exp:'The case studies show that SARS succeeded because of a clear institutional purpose, leadership stability, people investment, honest communication, and long-term discipline. Conversely, Sears Holdings failed due to no clear vision, leadership instability, culture of fear, sporadic communication, and short-term financial engineering fixes.',topic:'l3',opts:['A. SARS focused on financial engineering and cost-cutting, whereas Sears Holdings invested heavily in staff dignity and a clear purpose.', 'B. SARS had consistent leadership stability and a clear institutional purpose, while Sears Holdings suffered from leadership instability and a culture of fear.', 'C. SARS utilized sporadic and reactive communication, while Sears Holdings maintained an honest and purposeful dialogue with all staff.', 'D. SARS frequently pivoted its long-term strategy to capture short-term market wins, whereas Sears Holdings stayed the course for a decade.']},
{id:157,type:'mcq',applied:false,text:'John Kotter defines six tests of a strong transformation vision. If a leader creates a vision that is highly focused and guides decisions effectively, but is so rigid that it does not allow for adjustment in the face of changing market conditions, which of the six tests has the vision failed?',ans:2,exp:'Kotter\'s six tests of a strong vision are: Imaginable, Desirable, Feasible, Focused, Flexible, and Communicable. A vision that does not allow room for adjustment fails the \'Flexible\' test.',topic:'l3',opts:['A. Desirable', 'B. Feasible', 'C. Flexible', 'D. Communicable']},
{id:158,type:'mcq',applied:true,text:'[APPLIED] A logistics company introduces a new automated warehouse sorting system. The management holds town halls explaining why the change is necessary (Awareness) and provides intensive technical training (Knowledge). However, warehouse workers refuse to use the new system, fearing it will eventually automate them out of their jobs. According to the ADKAR model, where is the primary change gap?',ans:1,exp:'The employees know why the change is happening (Awareness) and how to do it (Knowledge), but they lack the personal motivation or willingness to support the change due to fear of job loss. This represents a gap in \'Desire\' (D), which requires engagement and incentives/reassurance.',topic:'l3',opts:['A. Awareness', 'B. Desire', 'C. Ability', 'D. Reinforcement']},
{id:159,type:'mcq',applied:true,text:'[APPLIED] A healthcare clinic rolls out a new digital patient record database. The nurses understand why the system is needed (Awareness), want to adopt it to reduce paperwork (Desire), and have attended a 2-hour classroom seminar explaining the software features (Knowledge). However, when patients arrive, the nurses struggle to input the data in real-time, resulting in long delays. According to ADKAR, what is the missing element and its corresponding solution?',ans:2,exp:'The nurses have the knowledge (they understand how it works in theory from the seminar) but lack the \'Ability\' (A) to implement it in practice in real-time. The solution for an Ability gap is coaching and practice.',topic:'l3',opts:['A. Awareness; more email broadcasts and town halls.', 'B. Knowledge; another classroom seminar on software features.', 'C. Ability; hands-on coaching, practice, and physical support.', 'D. Reinforcement; performance-based incentives and recognition.']},
{id:160,type:'mcq',applied:false,text:'William Bridges distinguishes between \'change\' and \'transition\' in his work on managing organizational shifts. Which of the following statements best captures the core difference between these two concepts according to Bridges?',ans:1,exp:'As quoted in the lecture, Bridges states: \'It is not the change itself that people resist — it is the transition, the internal psychological reorientation the change demands.\' Change is situational/external, whereas transition is internal/psychological.',topic:'l3',opts:['A. Change is the internal psychological reorientation people go through, whereas transition is the external, situational event.', 'B. Change is situational and external, while transition is the internal psychological reorientation that the change demands.', 'C. Change takes 5 to 10 years to implement, whereas transition can be accomplished in a single day.', 'D. Change is always initiated by middle management, while transition is mandated from the top-down.']},
{id:161,type:'mcq',applied:true,text:'[APPLIED] During a merger of two engineering departments, several senior engineers express strong resistance. They are unhappy that they will no longer have direct decision-making authority over project budgets, even though their salaries and job titles remain unchanged. According to the psychological fears of loss outlined in the lecture, what is the primary source of their resistance?',ans:2,exp:'The senior engineers are losing direct decision-making authority over budgets, which represents a \'Loss of Status or Authority\' (even though their titles and pay are constant). This is a primary source of human resistance to change.',topic:'l3',opts:['A. Loss of Competence', 'B. Loss of Security', 'C. Loss of Status or Authority', 'D. Loss of Relationships']},
{id:162,type:'mcq',applied:true,text:'[APPLIED] A school principal wants to introduce a new online grading and feedback system. A small group of highly resistant, senior teachers (Laggards) openly criticize the tool. The principal decides to spend 80% of their change management energy and time in one-on-one meetings trying to convince these senior teachers to adopt the system first. Applying Everett Rogers\' Diffusion of Innovations, evaluate this strategy.',ans:2,exp:'According to the Diffusion of Innovations model, transformation momentum is built through the early majority (by converting and elevating early adopters/influencers), not through wasting early energy trying to convert the most resistant laggards.',topic:'l3',opts:['A. This is highly effective because converting the most resistant members first guarantees that the rest of the school will follow.', 'B. This is ineffective; the principal should ignore the early adopters and focus entirely on the late majority.', 'C. This is ineffective; momentum is built through the early majority, and energy should not be wasted trying to convert laggards early.', 'D. This is effective because laggards represent the largest percentage of adopters in any organization.']},
{id:163,type:'mcq',applied:false,text:'Stephen Covey\'s inside-out principle is central to understanding the leader\'s inner world during a transformation. According to this principle, what is the likely outcome if a leader\'s internal values do not undergo genuine personal transformation?',ans:1,exp:'The lecture states that organizational transformation not undergirded by genuine personal transformation in its leaders will eventually be exposed as cosmetic. What a leader truly values will always surface under pressure (inside-out principle).',topic:'l3',opts:['A. The transformation will succeed faster because the leader can focus purely on structural adjustments.', 'B. The organizational transformation will eventually be exposed as cosmetic, as the leader\'s true values will surface under pressure.', 'C. The leader will earn a higher level of trust because they are protecting their personal ego and authority.', 'D. The organization will experience immediate alignment since internal values have no bearing on operational efficiency.']},
{id:164,type:'mcq',applied:false,text:'Dr. David Oyedepo outlines five attitudes that define a leader\'s impact and altitude in life. Which of the following questions corresponds to the leader\'s \'Attitude to Work\'?',ans:1,exp:'According to the lecture table, the leadership question for \'Attitude to Work\' is: \'Do you work to be made, or only to be paid?\'',topic:'l3',opts:['A. Is your purpose anchored beyond yourself?', 'B. Do you work to be made, or only to be paid?', 'C. Do you see life as a gift for giving?', 'D. Does money serve your mission, or drive it?']},
{id:165,type:'mcq',applied:false,text:'Robert Greenleaf introduced the concept of Servant Leadership in 1970, which is highly applicable to leading transformation. According to Greenleaf and the lecture, what is the defining characteristic of servant leadership?',ans:1,exp:'Servant leadership means seeing oneself as a servant first. As quoted by Dr. Oyedepo, \'Leaders are called to spend and be spent towards the well-being of the led and not for the sake of material gains.\'',topic:'l3',opts:['A. Delegating all difficult decisions to subordinates to avoid personal liability.', 'B. Seeing oneself as a servant first, focusing on the well-being and growth of the led rather than personal material gains.', 'C. Focusing purely on financial metrics to serve the shareholders\' interest above all else.', 'D. Leading from a distance to allow the organization to self-organize without executive interference.']},
{id:166,type:'mcq',applied:false,text:'In the book \'Good to Great,\' Jim Collins discusses Level 5 Leadership. What paradoxical combination of qualities defines a Level 5 Leader?',ans:1,exp:'Jim Collins found that Level 5 leaders possess a paradoxical combination of deep personal humility and fierce professional will. Both Collins and Dr. Oyedepo conclude that character is the foundation of sustained impact.',topic:'l3',opts:['A. High professional arrogance and deep personal humility.', 'B. Deep personal humility and fierce professional will.', 'C. Strong command-and-control authority and financial engineering skills.', 'D. Deep personal empathy and weak professional execution.']},
{id:167,type:'mcq',applied:false,text:'Jim Rohn is quoted in the lecture regarding the personal discipline required of leaders. How does Rohn compare the pain of discipline with the pain of regret?',ans:2,exp:'The quote from Jim Rohn is: \'There are 2 types of pain — the pain of discipline and the pain of regret. Discipline weighs ounces while regret weighs tonnes.\'',topic:'l3',opts:['A. The pain of discipline weighs tonnes, while the pain of regret weighs ounces.', 'B. The pain of discipline and the pain of regret are equal in their psychological weight.', 'C. The pain of discipline weighs ounces, while the pain of regret weighs tonnes.', 'D. Discipline is painless, whereas regret is the only source of true leadership pain.']},
{id:168,type:'mcq',applied:false,text:'Edgar Schein\'s model of organizational culture contains three distinct levels. If a researcher examines a company and notes that its physical office layout is completely open-plan and features modern collaboration areas, which of Schein\'s levels is the researcher observing?',ans:1,exp:'Visible Artefacts represent what you see and observe in an organization, such as a new org chart or open offices. This corresponds to Level 1 in Schein\'s model.',topic:'l3',opts:['A. Espoused Values', 'B. Visible Artefacts', 'C. Underlying Assumptions', 'D. Redefined Vision']},
{id:169,type:'mcq',applied:true,text:'[APPLIED] A fintech entrepreneur wants to build a global digital banking platform. Instead of launching savings accounts, investment products, cryptocurrency trading, and credit cards simultaneously, the entrepreneur decides to follow Jeff Bezos\' sequential growth model at Amazon. What is the correct sequence of action based on this principle?',ans:1,exp:'Jeff Bezos built Amazon in sequence: Bookstore -> Marketplace -> AWS. The lesson is to resist the temptation to change everything at once, building the credibility and capability that each phase generates.',topic:'l3',opts:['A. Launch all services at once to capture maximum market share before competitors can react.', 'B. Launch a single, simple core service, establish capability and credibility, and then expand in disciplined phases.', 'C. Focus entirely on financial engineering to inflate valuation before building any actual product.', 'D. Delegate the core service to external vendors while the internal team works on long-term futuristic research.']},
{id:170,type:'mcq',applied:true,text:'[APPLIED] An educational institution is attempting to modernize its curriculum. However, the transformation committee begins launching projects for online learning, international campuses, sports facility upgrades, and corporate executive education all at once, leading to fragmented energy and stalled progress. What is this phenomenon called in the lecture, and how should it be corrected?',ans:1,exp:'The lecture defines \'Transformation Drift\' as a state where energy is scattered across too many simultaneous initiatives. Leaders must guard against the \'here-and-there syndrome\' by defining the core assignment and protecting it fiercely.',topic:'l3',opts:['A. Continuous Innovation; corrected by hiring more project managers.', 'B. Transformation Drift (or here-and-there syndrome); corrected by defining the core shift and protecting it fiercely.', 'C. Incremental Change; corrected by abandoning the transformation and returning to the status quo.', 'D. Coalition Drift; corrected by replacing the executive board with junior staff.']},
{id:171,type:'mcq',applied:true,text:'[APPLIED] Pravin Gordhan led the transformation of the South African Revenue Service (SARS) from 1998 to 2008, raising compliance from under 50% to over 90%. According to the lecture, what role did staff dignity play in this success?',ans:1,exp:'Under Pravin Gordhan, SARS invested deeply in staff dignity and institutional purpose, contrasting with the culture of fear and financial engineering that caused the failure of Sears Holdings.',topic:'l3',opts:['A. It was secondary to the implementation of strict, top-down compliance software and penalties.', 'B. It was a core differentiator, involving deep investment in staff dignity and institutional purpose rather than a culture of fear.', 'C. It was ignored in favor of frequent leadership changes to keep staff on edge.', 'D. It was replaced by financial engineering and cost-reduction audits to maximize collection.']},
{id:172,type:'mcq',applied:true,text:'[APPLIED] A retail CEO wants to launch a major business model transformation. To establish urgency, the CEO sends a 150-page slide deck containing market share metrics and quarterly profit declines to all store employees. Despite this, employees show no change in behavior. What mistake did the CEO make according to the organizational principles of urgency?',ans:1,exp:'The lecture notes that a leader\'s first task is helping the organization feel—not just understand—why change is non-negotiable. Urgency is the spark; logical data sheets alone do not create the emotional spark needed to ignite change.',topic:'l3',opts:['A. The CEO should have sent the slide deck twice daily to ensure compliance.', 'B. The CEO failed to make the organization feel—not just understand—why staying in the current state is the real risk.', 'C. The CEO should have offered immediate financial bonuses to anyone who read the slides.', 'D. The CEO did not include a new organizational chart in the slide deck.']},
{id:173,type:'mcq',applied:true,text:'[APPLIED] A hospital administrator wants to transition nurses to a new electronic health record system. To do this quickly, the administrator mandates that anyone who does not use the new system within a week will face salary deductions. While compliance is achieved, the nurses exhibit high passive resistance and data entry errors. How does Kotter\'s Step 4 explain this outcome?',ans:0,exp:'Kotter\'s Step 4 focuses on \'Enlisting a volunteer army.\' The lecture states: \'Compliance achieved through pressure will not sustain transformation. Willing participants will.\' Forced compliance leads to passive resistance and failure.',topic:'l3',opts:['A. Compliance achieved through pressure will not sustain transformation; willing participants (a volunteer army) are required.', 'B. The administrator should have increased the salary deductions to eliminate all passive resistance.', 'C. Urgency was not created because the administrator did not use a burning platform metaphor.', 'D. The guiding coalition was too large and should have been limited to C-suite executives.']},
{id:174,type:'mcq',applied:true,text:'[APPLIED] A government agency claims to be transforming into a modern, agile service provider. However, the agency maintains a legacy policy where every external publication requires sign-offs from seven different departments. According to Kotter\'s 8-step model, which step is currently being blocked?',ans:2,exp:'Kotter\'s Step 5 is \'Remove barriers,\' which involves dismantling structural, procedural, and cultural obstacles—even entrenched ones. The seven-department sign-off policy is a procedural barrier that blocks transformation.',topic:'l3',opts:['A. Step 1: Create urgency', 'B. Step 3: Form a strategic vision', 'C. Step 5: Remove barriers', 'D. Step 8: Institute the change']},
{id:175,type:'mcq',applied:true,text:'[APPLIED] An engineering director leading an agile transition wants to establish credibility and momentum. The director selects a small, high-profile project, applies agile methods, and successfully delivers it two weeks early, showing clear metrics of improvement. According to Kotter, what is the role of this action?',ans:1,exp:'Step 6 of Kotter\'s model is \'Generate short-term wins.\' Early visible success builds credibility and momentum. Without these wins, transformation stalls.',topic:'l3',opts:['A. It is Step 7: Sustain acceleration, indicating that the transformation is complete.', 'B. It represents Step 6: Generate short-term wins, which builds credibility and momentum to prevent the transformation from stalling.', 'C. It is Step 2: Build a guiding coalition, showing that only engineers can lead the change.', 'D. It is a distraction from the long-term vision and should be avoided.']},
{id:176,type:'mcq',applied:false,text:'In Kotter\'s Step 7 (Sustain acceleration), what is the primary risk that leaders must manage after achieving initial successes or short-term wins?',ans:0,exp:'Step 7 warns leaders not to declare victory too early. Wins should be used to press deeper and sustain acceleration, not to signal completion. Declaring victory too early allows the old culture to re-assert itself.',topic:'l3',opts:['A. Declaring victory too early, which leads to regression and loss of momentum.', 'B. Spending too much energy on training instead of communication.', 'C. Dismantling the guiding coalition prematurely to save costs.', 'D. Rewriting the vision statement to make it more complex.']},
{id:177,type:'mcq',applied:false,text:'According to Kotter\'s Step 8 (Institute the change), when is a transformation truly complete and embedded within the organization?',ans:1,exp:'Step 8 (\'Institute the change\') means embedding new behaviors in systems, norms, and stories until they become \'the way we do things.\' Until this happens, the change is not permanent.',topic:'l3',opts:['A. Immediately after the C-suite approves the new corporate logo and vision statement.', 'B. When the new behaviors are embedded in systems, norms, and stories, becoming \'the way we do things\' here.', 'C. Once the company registers its first quarterly profit increase following the change.', 'D. When the laggards are successfully terminated from the organization.']},
{id:178,type:'mcq',applied:false,text:'Dr. David Oyedepo warns transformation leaders about two specific internal traps: \'not trusting others\' and \'fear of a fall.\' What is the main organizational consequence of these traps?',ans:1,exp:'The lecture states: \'"Not trusting others" and "fear of a fall" can paralyse leaders as much as followers.\' This paralysis prevents the formation of the collaborative guiding coalition that is necessary for transformation.',topic:'l3',opts:['A. They force the leader to delegate too much, resulting in a loss of control.', 'B. They paralyze the leader and prevent the building of the coalition that transformation demands.', 'C. They accelerate the transformation by making the leader highly independent.', 'D. They eliminate resistance by ensuring the leader makes all decisions unilaterally.']},
{id:179,type:'mcq',applied:false,text:'In the discussion of vision, the lecture notes that without a clear picture of a different and better future, an organization does not experience transformation. What term is used to describe change that occurs without this guiding vision?',ans:1,exp:'As stated in the lecture: \'Without that picture [vision], what you have is not transformation — It is disruption without Destination.\' A transformation must be guided by a clear and purposeful vision.',topic:'l3',opts:['A. Cosmetic Change', 'B. Disruption without Destination', 'C. Incremental Adjustment', 'D. Level 5 Drift']},
{id:180,type:'mcq',applied:false,text:'The \'Communication Covenant\' outlines three non-negotiables in transformation communication. Which of the following compares Winston Churchill\'s wartime communications to these principles?',ans:1,exp:'The lecture notes that Churchill\'s wartime communications were not optimistic; they were honest. Honesty built trust, demonstrating the non-negotiable of \'Courage\' (telling the truth, including the uncomfortable parts).',topic:'l3',opts:['A. Churchill used euphemisms to shield citizens from the harsh reality of war, maintaining morale.', 'B. Churchill\'s communication was characterized by honesty and courage, sharing uncomfortable truths, which built deep public trust.', 'C. Churchill relied entirely on one-way broadcasts, refusing to establish mechanisms for public feedback.', 'D. Churchill changed the vision statement daily to keep the public engaged.']},
{id:181,type:'mcq',applied:false,text:'According to Edgar Schein\'s Organisational Culture Model, what is the relationship between Level 1 (Visible Artefacts) and Level 3 (Underlying Assumptions)?',ans:1,exp:'Visible Artefacts (Level 1) are what you see, but Underlying Assumptions (Level 3) are what people actually do and how decisions get made under pressure. True transformation is only complete when it reaches the third level. Changing Level 1 does not guarantee Level 3 shifts.',topic:'l3',opts:['A. Level 1 always dictates Level 3, meaning a new office layout will immediately change people\'s deepest beliefs.', 'B. Level 3 represents the true culture (how decisions are made under pressure), which may conflict with the superficial indicators of Level 1.', 'C. Level 1 and Level 3 are independent and never interact during a transformation process.', 'D. Level 3 is fast to change (within a week), while Level 1 takes 5 to 10 years to establish.']},
{id:182,type:'mcq',applied:false,text:'Dr. David Oyedepo writes about the personal cost of transformation: \'There is no star without a scar, and the scar of every star is sacrifice.\' In the context of leadership, what does this sacrifice entail?',ans:1,exp:'As documented in the lecture, the sacrifice dimension of leadership includes being misunderstood, blamed for discomfort, losing valued people who will not make the journey, and staying the course when instincts say retreat.',topic:'l3',opts:['A. Sacrificing the financial health of the organization to protect the leader\'s salary.', 'B. Making a prior, deliberate decision to pay the price of being misunderstood, blamed, and losing people who won\'t make the journey.', 'C. Sacrificing the guiding coalition to ensure that the leader receives all the credit for successes.', 'D. Sacrificing corporate ethics to achieve short-term project deadlines.']},
{id:183,type:'mcq',applied:true,text:'[APPLIED] A retail chain\'s management is frustrated because employees are not using the newly installed digital inventory logs, despite weekly corporate emails detailing the software\'s benefits. The management assumes this is a communication problem. According to the ADKAR diagnostic, what is the likely error in this assumption?',ans:1,exp:'The ADKAR section notes: \'Most transformation failures are misdiagnosed. Leaders assume a Communication Problem when the real gap is in ability or reinforcement.\' Sending more emails does not fix desire, knowledge, or ability gaps.',topic:'l3',opts:['A. They need to send the emails daily instead of weekly to increase Awareness.', 'B. They are misdiagnosing the issue as a communication gap when the real gap lies in employee Desire, Knowledge, or Ability.', 'C. They should replace the emails with a performance ranking system to force compliance.', 'D. They should hire external auditors to monitor inventory manually.']},
{id:184,type:'mcq',applied:false,text:'According to Everett Rogers\' Adopter Categories, which group of individuals represents the \'Early Adopters\' and what is the recommended strategy for a transformation leader to engage them?',ans:1,exp:'Early Adopters are \'credible influencers\' who should be converted and elevated to help build momentum across the organization, influencing the Early Majority.',topic:'l3',opts:['A. The first to embrace anything new; welcome them early in the process.', 'B. Credible influencers; convert and elevate them to build momentum.', 'C. Skeptical individuals who need proof; show them concrete results before engaging.', 'D. Highly resistant members who will never change; ignore them entirely to save energy.']},
{id:185,type:'mcq',applied:false,text:'Jim Collins argues that durably great companies are led by Level 5 Leaders. How does the professional will of a Level 5 Leader manifest during a multi-year organizational transformation?',ans:1,exp:'Professional will is characterized by a fierce resolve to deliver the desired goal rather than what is convenient. Level 5 leaders combine this will with deep personal humility.',topic:'l3',opts:['A. By frequently changing the corporate vision to match quarterly stock fluctuations.', 'B. By maintaining a fierce resolve to deliver the desired long-term goal, regardless of how difficult or inconvenient it is.', 'C. By delegating all major transformation decisions to external consulting firms.', 'D. By isolating themselves from the frontline workers to maintain an aura of authority.']},
{id:186,type:'mcq',applied:true,text:'[APPLIED] During a shift from mainframe computers to cloud native infrastructure, a senior software architect feels anxious because their decade of mainframe expertise is no longer the primary driver of department success. The architect begins to criticize the cloud migration. According to Bridges\' Transition Model, how should the leader address this resistance?',ans:1,exp:'The architect is experiencing a \'Loss of Competence\'—a fear of not knowing how to work in the new system. Leaders must recognize this transition and address it with training, coaching, and support.',topic:'l3',opts:['A. Mandate that the architect pass a cloud certification within 3 days or face termination.', 'B. Recognize that the architect is experiencing a \'Loss of Competence\' (fear of not knowing how to work in the new system) and provide coaching and retraining.', 'C. Ignore the architect\'s complaints since they are just a single individual.', 'D. Return to the mainframe system to keep the architect happy and avoid conflict.']},
{id:187,type:'mcq',applied:false,text:'Dr. David Oyedepo defines the leader\'s \'Attitude to Money\' as a key factor in leadership altitude. What is the correct alignment between money and mission in a successful transformation?',ans:1,exp:'According to the lecture, the attitude to money is: \'Does money serve your mission, or drive it?\' In successful leadership, money serves the mission rather than driving it.',topic:'l3',opts:['A. Money should drive the mission, meaning the leader only pursues projects with immediate financial paybacks.', 'B. Money should serve the mission, ensuring that financial resources are utilized to achieve the long-term transformation purpose.', 'C. Money should be ignored entirely, as financial metrics have no place in servant leadership.', 'D. The leader\'s primary goal should be personal enrichment to establish status.']},
{id:188,type:'mcq',applied:true,text:'[APPLIED] A multinational manufacturing company compiles its new safety vision into a 45-page technical manual filled with legal jargon, regulatory codes, and dense statistics. Which of Kotter\'s Six Tests of a strong vision does this document violate most directly?',ans:2,exp:'Kotter\'s \'Communicable\' test requires that a vision can be explained in 5 minutes. A 45-page, jargon-filled manual is not easily communicable.',topic:'l3',opts:['A. Feasible', 'B. Focused', 'C. Communicable', 'D. Imaginable']},
{id:189,type:'mcq',applied:true,text:'[APPLIED] A university dean wants to reform the faculty promotion criteria. The dean creates a guiding coalition consisting exclusively of close associates who agree with every proposal, leaving out representatives from the student union and the research department. Why does this guiding coalition pose a risk to the transformation?',ans:1,exp:'Step 2 (Build a guiding coalition) requires recruiting the credible and the committed across levels. In the West African bank CEO case study, having only direct reports created an \'echo chamber\' that lacked broad trust and practical ideas.',topic:'l3',opts:['A. It is too diverse, which will lead to prolonged debates and delayed execution.', 'B. It creates an echo chamber that lacks the credibility and broad organizational commitment required to sustain transformation.', 'C. It violates the principle that coalitions should only be built by mandate from the university board.', 'D. It increases the speed of the transformation too much, causing operational instability.']},
{id:190,type:'mcq',applied:true,text:'[APPLIED] A technology startup boasts a written corporate value of \'radical transparency\' on its website (Level 2: Espoused Value) and builds open-plan offices with glass walls (Level 1: Visible Artefact). However, when employees raise concerns about project failures, they are privately reprimanded and excluded from future meetings. What does this indicate about the startup\'s culture based on Edgar Schein\'s model?',ans:1,exp:'True culture resides in Level 3 (Underlying Assumptions—what people actually do and how decisions get made under pressure). Here, the fear-based underlying assumption contradicts the superficial artefacts and espoused values.',topic:'l3',opts:['A. The open-plan office layout has successfully transformed the startup\'s culture.', 'B. The true culture is defined by its Level 3 Underlying Assumptions (fear of speaking up), which directly contradicts its Level 1 and Level 2 indicators.', 'C. The startup needs to draft a longer value statement to resolve the conflict.', 'D. Espoused values are the only level of culture that matters under pressure.']},
{id:191,type:'mcq',applied:true,text:'[APPLIED] When Howard Schultz returned as CEO of Starbucks in 2008, he chose to retrain U.S. store partners despite a loss of $6 million in a single day. According to the lecture, what is the primary leadership lesson of this action?',ans:1,exp:'The lesson of Starbucks 2008 is that leaders who model the sacrifice they ask of others earn a fundamentally different level of trust. This builds credibility for the transformation.',topic:'l3',opts:['A. Financial performance is irrelevant during a cultural turnaround.', 'B. Leaders who model the sacrifice they ask of others earn a fundamentally different level of trust.', 'C. Retraining is only effective when it is highly expensive.', 'D. Frontline staff are the primary source of drift and should be retrained regularly.']},
{id:192,type:'mcq',applied:false,text:'William Bridges argues that resistance to change is not logical, but human and psychological. Which of the following best describes the focus of Bridges\' transition management?',ans:1,exp:'Bridges focuses on the transition—the internal psychological reorientation that change demands. Managing this involves helping people let go of the old way and adapt to the new.',topic:'l3',opts:['A. Managing the physical relocation of office assets and digital data.', 'B. Helping people navigate the internal psychological process of letting go of the old way and adjusting to the new.', 'C. Speeding up the implementation of new processes using top-down mandates.', 'D. Restructuring the corporate hierarchy to eliminate redundant middle managers.']},
{id:193,type:'mcq',applied:false,text:'Dr. David Oyedepo is quoted in the lecture: \'Wisdom is applied knowledge, not just wise talk, but the know-how in one\'s field.\' What is the implication of this statement for a transformation leader?',ans:1,exp:'A leader who does not invest in learning cannot lead with wisdom. Transformation demands peak learning: continuous, applied, and purposeful know-how.',topic:'l3',opts:['A. A leader should focus on philosophical lectures rather than operational details.', 'B. Transformation demands peak learning that is continuous, applied, and purposeful to lead with wisdom.', 'C. A leader does not need to learn about the industry if they have a strong vision.', 'D. Wisdom is inherited and cannot be acquired through organizational learning.']},
{id:194,type:'mcq',applied:false,text:'Jeff Bezos\' sequencing of Amazon\'s growth (Bookstore -> Marketplace -> AWS) is used in the lecture to illustrate which transformation principle?',ans:1,exp:'Amazon\'s growth illustrates the \'Power of Phased Progress\' and sequencing. Leaders should resist the temptation to change everything at once, instead building capabilities step-by-step.',topic:'l3',opts:['A. The necessity of changing all parts of the organization simultaneously.', 'B. The power of phased progress, where each phase builds the capabilities and credibility required for the next.', 'C. The superiority of financial engineering over customer-centric business models.', 'D. The risk of expanding beyond a single core product line.']},
{id:195,type:'mcq',applied:false,text:'Dr. David Oyedepo states: \'Not trusting others and fear of a fall can paralyse leaders as much as followers.\' How does this lack of trust affect the coalition-building process?',ans:1,exp:'A leader who cannot trust others cannot build the coalition that transformation demands, as transformation is a collective endeavor requiring mutual trust.',topic:'l3',opts:['A. It makes the coalition more efficient by keeping decision-making centralized.', 'B. It prevents the leader from delegating and modeling the trust they ask others to extend, causing the coalition to fail.', 'C. It reduces the resistance from laggards by establishing a dominant leader.', 'D. It increases the speed of transformation by eliminating collaborative delays.']},
{id:196,type:'multi',applied:true,text:'[APPLIED] A technology startup is formulating a new long-term vision. The leadership team wants to ensure their vision statement is robust and actionable. According to John Kotter\'s change framework, select all of the six tests that a strong transformation vision must satisfy.',ans:[0, 1, 2],exp:'Kotter\'s six tests of a strong vision are: Imaginable, Desirable, Feasible, Focused, Flexible, and Communicable. \'Retributive\' is not one of Kotter\'s tests.',topic:'l3',opts:['A. Imaginable — creates a clear mental picture', 'B. Feasible — realistic and attainable', 'C. Flexible — allows room for adjustment', 'D. Retributive — imposes penalties for non-compliance']},
{id:197,type:'multi',applied:true,text:'[APPLIED] A manufacturing company is experiencing heavy employee pushback after introducing a new assembly line workflow. The change manager wants to use Prosci\'s ADKAR model to diagnose the individual-level change. Select all of the elements of the ADKAR model that represent stages an individual must go through to successfully transition.',ans:[0, 1, 2],exp:'The ADKAR model stands for: Awareness, Desire, Knowledge, Ability, and Reinforcement. \'Autocracy\' is not part of the ADKAR framework.',topic:'l3',opts:['A. Awareness of the need to change', 'B. Desire to support and participate in the change', 'C. Knowledge of how to change', 'D. Autocracy of the leadership hierarchy']},
{id:198,type:'multi',applied:false,text:'William Bridges outlines that people resist change not because of the change itself, but because of the psychological transitions and fears of personal loss. Select all of the primary categories of psychological loss that individuals experience during organizational transition as discussed in the lecture.',ans:[0, 1, 2],exp:'The lecture lists the fears of loss as: Loss of Status or Authority, Loss of Security and Predictability, Loss of Identity, Loss of Relationships, and Loss of Competence. \'Loss of Financial Liability\' is not listed.',topic:'l3',opts:['A. Loss of Status or Authority', 'B. Loss of Security and Predictability', 'C. Loss of Competence (fear of not knowing how to work in the new system)', 'D. Loss of Financial Liability']},
{id:199,type:'multi',applied:true,text:'[APPLIED] A public sector research group is studying the successful turnaround of the South African Revenue Service (SARS) between 1998 and 2008 led by Pravin Gordhan. Select all of the key leadership factors that directly contributed to the success of SARS according to the lecture\'s comparative analysis.',ans:[0, 1, 2],exp:'The lecture attributes SARS\' success to: clear institutional purpose (vision), leadership stability, deep investment in staff dignity (people investment), honest/purposeful communication, and long-term discipline. \'Substitution of financial engineering\' was a factor in Sears\' failure.',topic:'l3',opts:['A. Clear institutional purpose and vision', 'B. Consistent leadership stability over a decade', 'C. Deep investment in staff dignity and capability', 'D. Substitution of financial engineering for strategic transformation']},
{id:200,type:'multi',applied:false,text:'John Kotter\'s 8-step model for leading change is divided into a macro process. Select all of the steps that belong to the first half (Steps 1 through 4) of Kotter\'s model.',ans:[0, 1, 2],exp:'Steps 1 to 4 of Kotter\'s model are: 1. Create urgency, 2. Build a guiding coalition, 3. Form a strategic vision, and 4. Enlist a volunteer army. Step 5 belongs to the second half.',topic:'l3',opts:['A. Step 1: Create urgency', 'B. Step 2: Build a guiding coalition', 'C. Step 4: Enlist a volunteer army', 'D. Step 5: Remove barriers']},
{id:201,type:'multi',applied:false,text:'Kotter\'s 8-step model requires careful execution of the latter half of the process to sustain and embed the change. Select all of the steps that belong to the second half (Steps 5 through 8) of Kotter\'s change framework.',ans:[0, 1, 2],exp:'Steps 5 to 8 of Kotter\'s model are: 5. Remove barriers, 6. Generate short-term wins, 7. Sustain acceleration, and 8. Institute the change. Step 3 belongs to the first half.',topic:'l3',opts:['A. Step 5: Remove barriers', 'B. Step 6: Generate short-term wins', 'C. Step 8: Institute the change', 'D. Step 3: Form a strategic vision']},
{id:202,type:'multi',applied:true,text:'[APPLIED] A corporate consultant is auditing the culture of a mid-sized commercial bank using Edgar Schein\'s Organisational Culture Model. The consultant observes the open-office floor plan, reads the written value charter on \'collaboration\', and interviews staff who explain that decisions under pressure are actually made unilaterally by senior executives to avoid risk. Select all of the levels of Schein\'s model that are represented in this diagnostic.',ans:[0, 1, 2],exp:'Edgar Schein\'s Organisational Culture Model consists of exactly three levels: 1. Visible Artefacts (open office), 2. Espoused Values (written charter), and 3. Underlying Assumptions (unilateral decisions under pressure). There is no Level 4.',topic:'l3',opts:['A. Level 1: Visible Artefacts', 'B. Level 2: Espoused Values', 'C. Level 3: Underlying Assumptions', 'D. Level 4: External Affiliations']},
{id:203,type:'multi',applied:true,text:'[APPLIED] A marketing agency is launching a new generative AI copywriting tool. The change leader wants to segment the agency staff to roll out training effectively. According to Everett Rogers\' Diffusion of Innovations, select all of the adopter categories that the leader should target to build and maintain adoption momentum.',ans:[0, 1, 2],exp:'Everett Rogers\' model includes Innovators, Early Adopters, Early Majority, Late Majority, and Laggards. To build momentum, leaders focus energy on early adopters and early majority, showing results to late majority. Laggards should NOT receive early energy.',topic:'l3',opts:['A. Early Adopters — who serve as credible influencers', 'B. Early Majority — who follow credible peers', 'C. Late Majority — who are skeptical but adopt after seeing proof', 'D. Laggards — who are highly resistant and should receive 80% of early energy']},
{id:204,type:'multi',applied:false,text:'Dr. David Oyedepo emphasizes that \'it is attitudes that define altitudes in life.\' Select all of the specific attitudes defined by Oyedepo that a leader must develop to maximize their organizational impact.',ans:[0, 1, 2],exp:'Oyedepo\'s 5 Attitudes are: Attitude to God, Attitude to Life, Attitude to Work, Attitude to Money, and Attitude of Gratitude. \'Attitude of Isolation\' is incorrect; coalition and trust are required.',topic:'l3',opts:['A. Attitude to God (anchored beyond self)', 'B. Attitude to Work (work to be made, not just paid)', 'C. Attitude to Money (money serves the mission)', 'D. Attitude of Isolation (work alone to protect the vision)']},
{id:205,type:'multi',applied:false,text:'The \'Communication Covenant\' outlines critical non-negotiables in transformation communication. Select all of the non-negotiables that a leader must practice to build trust and ownership during change.',ans:[0, 1, 2],exp:'The three non-negotiables of the Communication Covenant are Clarity, Courage, and Two-way Dialogue. Polished euphemisms are a source of communication failure.',topic:'l3',opts:['A. Clarity — answering what is changing, why, and what it means for individuals', 'B. Courage — telling the truth, including the uncomfortable parts', 'C. Two-way Dialogue — establishing mechanisms for the organization to speak back', 'D. Unilateral Euphemism — using polished corporate language to minimize panic']},
{id:206,type:'short',applied:true,text:'[APPLIED] A legacy telecom firm is shifting its core business from physical line rentals to cloud-hosted VoIP services. This shift redefines their business model, operations, and cultural values. What specific term describes this type of deep paradigm shift, as opposed to incremental changes that only adjust existing processes?',ans:'Transformation',exp:'According to the lecture, while change adjusts existing processes and works within the current model, \'Transformation\' shifts the paradigm itself, redefines the model, and alters how an organization fundamentally operates.',topic:'l3'},
{id:207,type:'short',applied:false,text:'According to John Kotter\'s 8-step change framework, what is the critical first step that serves as the spark to ignite transformation by helping people feel that staying the same is the real risk?',ans:'Create Urgency',exp:'Step 1 of Kotter\'s model is \'Create Urgency\' (or \'Create urgency\'). It helps people feel that staying the same is the real risk, serving as the spark that ignites transformation.',topic:'l3'},
{id:208,type:'short',applied:true,text:'[APPLIED] A university implements a new digital grading system. The teachers understand the need for the system, want to use it, have been trained, and are capable of operating it. However, the system administrator fails to provide recognition or monitor compliance, causing teachers to slowly revert to Excel sheets. Which specific element of the ADKAR model is missing?',ans:'Reinforcement',exp:'The missing element is \'Reinforcement\' (R), which is required to sustain change through recognition, accountability, and monitoring, preventing regression to old habits.',topic:'l3'},
{id:209,type:'short',applied:false,text:'What is the name of the organizational culture model, formulated by Edgar Schein, that categorizes culture into three distinct levels: Visible Artefacts, Espoused Values, and Underlying Assumptions?',ans:'Schein\'s Model',exp:'Edgar Schein\'s Organisational Culture Model divides culture into Visible Artefacts, Espoused Values, and Underlying Assumptions. \'Schein\'s Model\' represents this framework.',topic:'l3'},
{id:210,type:'short',applied:false,text:'What leadership philosophy, pioneered by Robert Greenleaf in 1970 and supported by Dr. David Oyedepo, posits that the greatest leaders see themselves as servants first and focus on the well-being of the led?',ans:'Servant Leadership',exp:'Servant Leadership is the philosophy where leaders prioritize serving the needs of their team and the organization, absorbing discomfort and taking responsibility for failures.',topic:'l3'},
{id:211,type:'short',applied:false,text:'In the book \'Good to Great,\' Jim Collins describes a class of leaders who combine deep personal humility with fierce professional will. What term does Collins use for this level of leadership?',ans:'Level 5',exp:'Level 5 Leadership (or simply Level 5) is characterized by a paradoxical combination of deep personal humility and fierce professional will, which Collins and Oyedepo identify as the foundation of sustained impact.',topic:'l3'},
{id:212,type:'short',applied:true,text:'[APPLIED] A hospital wishes to implement a new patient check-in protocol. The project team seeks to identify the \'credible influencers\' within the nursing staff who can help convert their peers and build momentum. According to Everett Rogers\' adopter categories, what is the term for this specific group?',ans:'Early Adopters',exp:'Early Adopters are the credible influencers in Rogers\' Diffusion of Innovations model. Converting and elevating them is the key strategy for building transformation momentum.',topic:'l3'},
{id:213,type:'short',applied:false,text:'What specific organizational metaphor, based on the 1988 Piper Alpha North Sea oil disaster, describes the critical condition where staying in the current state is perceived as far more dangerous than taking a risky leap into the unknown?',ans:'Burning Platform',exp:'The \'Burning Platform\' is the metaphor used to describe the point at which an organization realizes that the status quo (staying on the platform) is unsustainable and change (jumping) is non-negotiable.',topic:'l3'},
{id:214,type:'short',applied:true,text:'[APPLIED] A software division leader scatters team energy across fifteen different tech initiatives, causing the core product overhaul to stall. According to the lecture, what term describes this failure to maintain focus on the core assignment?',ans:'Transformation Drift',exp:'Transformation Drift occurs when organizational energy is scattered across too many simultaneous initiatives, violating the principle of focus and the core assignment.',topic:'l3'},
{id:215,type:'short',applied:false,text:'According to Dr. David Oyedepo, every successful transformation begins with a clear picture of a different and better future. What specific term represents this discovery of plan and purpose that lies at the root of outstanding leadership?',ans:'Vision',exp:'Dr. David Oyedepo defines Vision as \'a discovery of God\'s plan and purpose... Every transformation begins with a clear picture of a different and better future.\'',topic:'l3'},
{id:216,type:'fill',applied:false,text:'In distinguishing between change and transformation, change _______ existing processes and works within the current model, whereas transformation _______ itself and redefines the model.',dropdowns:[['adjusts', 'redefines', 'eliminates'], ['shifts the paradigm', 'maintains the structure', 'stabilizes the process']],ans:['adjusts', 'shifts the paradigm'],exp:'According to the lecture, change adjusts existing processes and works within the current model, whereas transformation shifts the paradigm itself.',topic:'l3'},
{id:217,type:'fill',applied:false,text:'The Piper Alpha disaster occurred in the year _______ and demonstrated the metaphor of the _______, showing that transformation begins when people believe the present state is unsustainable.',dropdowns:[['1975', '1988', '2012'], ['Burning Platform', 'Growth Mindset', 'Guiding Coalition']],ans:['1988', 'Burning Platform'],exp:'The Piper Alpha disaster occurred in 1988 in the North Sea. It illustrates the \'Burning Platform\' metaphor, highlighting that urgency is the spark for transformation.',topic:'l3'},
{id:218,type:'fill',applied:true,text:'[APPLIED] A software leader wants to apply ADKAR to a CRM rollout. If the team understands why the CRM is needed, that represents _______. If they have the hands-on practice and coaching to run it daily, that represents _______.',dropdowns:[['Awareness', 'Desire', 'Knowledge'], ['Ability', 'Reinforcement', 'Knowledge']],ans:['Awareness', 'Ability'],exp:'In ADKAR, Awareness is the understanding of the need for change, and Ability is the capability to implement the change on a day-to-day basis.',topic:'l3'},
{id:219,type:'fill',applied:false,text:'John Kotter\'s six tests of a strong vision are that it must be: Imaginable, Desirable, Feasible, Focused, _______, and _______.',dropdowns:[['Flexible', 'Rigid', 'Expensive'], ['Communicable', 'Unilateral', 'Complex']],ans:['Flexible', 'Communicable'],exp:'Kotter\'s six tests of a strong vision are: Imaginable, Desirable, Feasible, Focused, Flexible, and Communicable.',topic:'l3'},
{id:220,type:'fill',applied:false,text:'William Bridges asserts that people do not resist the change itself, but rather the _______, which is the internal _______ reorientation that the change demands.',dropdowns:[['transition', 'structure', 'hierarchy'], ['psychological', 'financial', 'logistical']],ans:['transition', 'psychological'],exp:'William Bridges states that resistance is directed at the transition—the internal, psychological reorientation that individuals go through during change.',topic:'l3'},
{id:221,type:'fill',applied:false,text:'According to Edgar Schein\'s model, a new organizational chart represents _______, while the underlying values that drive decisions under pressure represent _______.',dropdowns:[['Visible Artefacts', 'Espoused Values', 'Underlying Assumptions'], ['Visible Artefacts', 'Espoused Values', 'Underlying Assumptions']],ans:['Visible Artefacts', 'Underlying Assumptions'],exp:'A new org chart is a Visible Artefact (Level 1), while how decisions get made under pressure represents Level 3 Underlying Assumptions.',topic:'l3'},
{id:222,type:'fill',applied:false,text:'Everett Rogers\' Diffusion of Innovations notes that the first to embrace anything new are the _______, whereas the skeptical group that requires proof and results is the _______.',dropdowns:[['Innovators', 'Early Adopters', 'Early Majority'], ['Late Majority', 'Laggards', 'Early Majority']],ans:['Innovators', 'Late Majority'],exp:'Innovators are the first to embrace the new, while the Late Majority is skeptical and requires proof/results before adopting.',topic:'l3'},
{id:223,type:'fill',applied:true,text:'[APPLIED] In rebuilding a major public institution, Pravin Gordhan\'s success at SARS was characterized by a _______, whereas the failed transformation of Sears Holdings under finance-led leadership was characterized by a _______.',dropdowns:[['clear institutional purpose', 'toxic stack ranking', 'culture of fear'], ['culture of fear', 'people investment', 'consistent leadership']],ans:['clear institutional purpose', 'culture of fear'],exp:'According to the lecture, SARS was driven by a clear institutional purpose, while Sears Holdings suffered from a culture of fear and short-term financial engineering.',topic:'l3'},
{id:224,type:'fill',applied:false,text:'Jim Collins states that Level 5 leaders possess a paradoxical combination of deep _______ and fierce _______.',dropdowns:[['personal Humility', 'professional Will', 'social Status'], ['professional Will', 'personal Humility', 'financial Ambition']],ans:['personal Humility', 'professional Will'],exp:'Level 5 leadership is defined by a paradoxical combination of deep personal humility and fierce professional will.',topic:'l3'},
{id:225,type:'fill',applied:true,text:'[APPLIED] A corporate leader wishes to communicate a new vision. According to Kotter, most leaders communicate the transformation vision _______ time(s) for every _______ time(s) they need to.',dropdowns:[['once', 'five', 'ten'], ['five', 'ten', 'twenty']],ans:['once', 'ten'],exp:'Kotter\'s findings indicate that leaders under-communicate, typically sharing the vision only once for every ten times they need to.',topic:'l3'},
{id:226,type:'mcq',applied:true,text:'[APPLIED] You have recently been appointed as a first-time independent non-executive director to the board of a major African telecommunications company. During your inaugural board meeting, the Chairman proposes that the company award a multi-million dollar infrastructure maintenance contract to a firm owned by his son-in-law. Although the bid is not the lowest and has several red flags, three senior directors immediately nod in agreement, while the Managing Director looks visibly uncomfortable but remains silent. Under corporate governance best practices, what is your immediate ethical and legal course of action, and in what order?',ans:2,exp:'Under the Duties of Conflict Disclosure and Independent Judgement, the director must ensure the conflict of interest is formally declared, the conflicted party recused, and a proper independent evaluation of the bids is conducted. Silence or go-along voting violates the Duty of Care and Duty of Loyalty to the organization.',topic:'l4',opts:['Confront the Chairman publicly during the meeting, accuse him of nepotism, demand an immediate vote of no confidence, and walk out of the boardroom to alert the press.', 'Say nothing during the meeting to respect the cultural deference to seniority, but privately request the Managing Director to quietly investigate the transaction afterwards.', 'Formally request a postponement of the decision, demand that the Chairman declare his conflict of interest in writing, recuse himself from discussions/voting, and require a competitive re-evaluation of the bids by the Audit and Risk Committee.', 'Vote in favor of the contract alongside the other directors to maintain boardroom consensus, but note your dissent in a personal diary for future legal protection.']},
{id:227,type:'mcq',applied:true,text:'[APPLIED] Consider a pharmaceutical company facing a crisis similar to the 1982 Johnson & Johnson Tylenol poisoning. A batch of the company\'s leading over-the-counter painkiller has been contaminated in a localized market, resulting in two fatalities. The CEO proposes to quietly isolate the affected batch and avoid a public recall, arguing that a national recall would cost over $150 million, wipe out the year\'s profits, and decimate the share price. As an independent director, you are asked to vote on this proposal. Consulting the company\'s ethical code and decision-making frameworks, what is the correct action?',ans:1,exp:'Following the Johnson & Johnson model (led by James Burke), ethical boards ask \'How do we protect the patient?\' rather than \'How do we protect the share price?\'. Prioritizing stakeholder safety builds long-term trust, while prioritizing the share price leads to reputational ruin and potential extinction.',topic:'l4',opts:['Agree with the CEO to protect shareholder value, since the contamination is currently localized and a public recall would cause unnecessary panic and financial ruin.', 'Reject the CEO\'s proposal, consult the company\'s ethical Credo, and vote for an immediate, nationwide recall and product exchange program, putting patient safety above short-term profit.', 'Propose a compromise where the company delays the recall for 30 days to allow insiders to liquidate their stock options before the public announcement.', 'Abstain from voting to avoid personal liability, allowing the executive directors to make the final operational decision.']},
{id:228,type:'mcq',applied:true,text:'[APPLIED] A fast-growing technology start-up is preparing for an IPO. The founder, who combinedly serves as both Chairman and CEO, presents a complex set of financial statements to the board, revealing that billions in debt have been offloaded to several off-balance-sheet \'Special Purpose Entities\' (SPEs) run by his close associates. When you ask for details, the founder tells you the structure is highly proprietary and that you must \'trust the auditors.\' The other directors are eager to sign off to meet the listing deadline. If you vote to approve these statements without an independent audit of the SPEs, which specific duties have you failed to uphold?',ans:0,exp:'By signing off on financial statements containing unexamined off-balance-sheet structures without understanding them, a director fails the Duty of Care (failing to act with the diligence of a prudent person) and the Duty of Independent Judgement (failing to challenge before concurring).',topic:'l4',opts:['The Duty of Care and the Duty of Independent Judgement, because you signed off on transactions you did not fully understand and deferred blindly to executive authority.', 'The Duty of Obedience and the Duty of Confidentiality, because you failed to protect the secret proprietary structure from public regulators.', 'The Duty of Stakeholder Sensitivity, because you did not prioritize the immediate financial compensation of the executive directors.', 'The Duty of Loyalty, because you failed to protect the Chairman\'s personal reputation and financial assets.']},
{id:229,type:'mcq',applied:true,text:'[APPLIED] You are an independent director on the board of a manufacturing firm. The company is seeking to acquire a strategic parcel of land for factory expansion. During the board discussion, you realize that the land is owned by a private trust of which your sister is a primary beneficiary. The board is unaware of this connection, and the transaction is highly favorable to your company. What is your legal and ethical obligation under the Duty of Conflict Disclosure?',ans:2,exp:'The Duty of Conflict Disclosure requires a director to declare any material personal interest in a transaction. The standard is whether a reasonable person might believe it could sway the director. The director must disclose the interest and recuse themselves from deliberations and voting.',topic:'l4',opts:['Say nothing and vote in favor of the acquisition, because the transaction is beneficial to the company and disclosing the relationship might stall the deal unnecessarily.', 'Disclose the relationship privately to the Chairman after the meeting has concluded, but vote in favor of the transaction during the formal session.', 'Immediately disclose the material personal interest to the board, request that it be formally recorded in the minutes, and recuse yourself from both the discussions and the vote.', 'Resign from the board immediately without explanation, to avoid any potential conflict of interest appearing on public records.']},
{id:230,type:'mcq',applied:true,text:'[APPLIED] A director of a retail company is sent a 600-page board packet containing detailed risk assessments, annual accounts, and merger agreements exactly one hour before a crucial board meeting. The Chairman starts the meeting by proposing a vote to approve the merger immediately, stating that the Audit Committee has already reviewed the papers and \'we are all busy people.\' The director votes to approve the merger. Later, it is revealed that the merger target had massive hidden liabilities that bankrupt the retail company. What governance failure has the director committed?',ans:1,exp:'The Duty of Care requires directors to read papers, attend meetings, ask questions, and think independently. A director who signs what he has not read has already failed this duty. Relying blindly on others without personal review is a core governance failure.',topic:'l4',opts:['Failure to uphold the Duty of Loyalty, because the director did not support the Chairman\'s strategic vision.', 'Failure to uphold the Duty of Care, because a director who signs what they have not read or understood has failed to exercise prudent diligence.', 'Failure to uphold the Duty of Obedience, because the director did not follow the company\'s internal voting bylaws.', 'Failure to uphold the Duty of Stakeholder Sensitivity, because the director did not consult the labor union before the vote.']},
{id:231,type:'mcq',applied:true,text:'[APPLIED] During a board meeting of a regional banking institution, a proposal is made to launch a high-interest savings product targeted at low-income rural communities. The product features hidden fees that legal counsel confirms are technically compliant with current consumer protection laws, but will likely lock vulnerable customers into debt spirals. The board\'s consensus is to approve. You strongly believe this product is exploitative and unethical. What should you do to exercise your Duty of Independent Judgement?',ans:1,exp:'The Duty of Independent Judgement requires the courage to dissent, challenge before concurring, and stand alone when standing alone is right. Disagreeing without disrespect and ensuring that dissent is formally minuted is the correct governance mechanism for a dissenting director.',topic:'l4',opts:['Quietly vote against the proposal but agree to support it in public to maintain boardroom harmony and protect the stock price.', 'Dissent openly during the meeting, present arguments against the product, demand that your dissent and reasoning be recorded in the minutes, and vote against the proposal.', 'Agree to the proposal on the condition that the bank donates 1% of the profits to rural charities, thereby balancing compliance with conscience.', 'Leapfrog the board and leak the confidential proposal to local advocacy groups to force the company to drop the product.']},
{id:232,type:'mcq',applied:true,text:'[APPLIED] The board of a consumer goods company is evaluating two supply chain strategies. Strategy A involves sourcing raw materials from local farmers at fair prices, which guarantees environmental sustainability but reduces net margins by 4%. Strategy B involves sourcing from a foreign conglomerate that utilizes intensive farming practices, which will boost net margins by 8% but displace local communities and deplete water tables. The board chooses Strategy B, stating that their primary legal duty is to maximize current quarterly dividends for shareholders. Which duty have the directors neglected?',ans:0,exp:'The Duty of Stakeholder Sensitivity requires directors to consider who bears the impact of their decisions, specifically weighing the consequences on employees, communities, and future generations. Restricting focus solely to short-term shareholder margins violates this sensitivity.',topic:'l4',opts:['Duty of Stakeholder Sensitivity, which requires weighing the impact of board decisions on employees, customers, local communities, and future generations.', 'Duty of Obedience, which requires prioritizing the immediate profits of the organization above all external laws and regulations.', 'Duty of Confidentiality, because the board discussed the environmental impacts of their suppliers in a public forum.', 'Duty of Loyalty, because they failed to protect the financial interest of the executive management team.']},
{id:233,type:'mcq',applied:true,text:'[APPLIED] You are an independent governance consultant reviewing a state-owned enterprise in an emerging African market. You discover that the board consists primarily of politically connected individuals who lack financial literacy or industry experience, the risk committee exists only on paper, and the Chairman is the brother of the supervising Minister. Decisions are made through informal patronage networks rather than structured board debates. Which specific African governance challenges are represented in this scenario?',ans:1,exp:'The lecture identifies five key governance challenges in Africa: concentrated ownership, weak institutional frameworks, cultural deference to seniority, corruption and patronage networks, and directors appointed for connections rather than competence.',topic:'l4',opts:['Excessive institutional frameworks and rigid adherence to Western-style risk models.', 'Weak institutional frameworks, cultural deference to seniority, patronage networks, and directors appointed for connections rather than competence.', 'A lack of capital and a lack of local business talent, making it impossible to form a competent board.', 'Over-regulation by regional authorities and a high concentration of foreign institutional shareholders.']},
{id:234,type:'mcq',applied:true,text:'[APPLIED] During an executive session, a director of an airline company is informed of a confidential, proprietary software development project that will optimize route planning and save the airline millions. Recognizing the value of this software, the director contacts a private software firm where he is a major shareholder, describes the project, and suggests they develop a similar product to sell to other airlines. Which director duty has been violated?',ans:1,exp:'The Duty of Loyalty dictates that opportunities discovered in the role belong to the role, and the company is not a personal asset. The Duty of Confidentiality dictates that no conversation in the boardroom belongs outside it, and strategy is not a personal possession.',topic:'l4',opts:['Duty of Stakeholder Sensitivity, because the software development will displace manual route planners.', 'Duty of Loyalty and Duty of Confidentiality, because opportunities discovered through the role belong to the role, and boardroom conversations are confidential.', 'Duty of Obedience, because the director failed to obtain a patent for the airline before disclosing the technology.', 'Duty of Care, because the director did not spend enough time analyzing the software code himself.']},
{id:235,type:'mcq',applied:true,text:'[APPLIED] A major commercial bank collapses during a banking crisis due to overexposure to toxic, highly structured derivative products. The regulatory investigation reveals that the bank\'s Risk Committee, comprised entirely of non-executive directors, met only once a year for a catered lunch and never asked for risk metrics, assuming the executive team \'knew what they were doing.\' This failure represents which specific issue highlighted by historical corporate crises?',ans:1,exp:'As seen in the 2008 Global Financial Crisis and Lehman Brothers, corporate failures often occur when boards \'fall asleep\' and boardrooms become ceremonies. The board has a core function to oversee risk and monitor performance, which cannot be delegated without oversight.',topic:'l4',opts:['The risk committee was overstepping its bounds and interfering with executive operations.', 'The board fell asleep and allowed the boardroom to become a mere ceremony, neglecting their core function of risk oversight.', 'The regulators failed to provide the board with the necessary derivative trading models.', 'The shareholders failed to vote on the specific risk parameters of the derivative products.']},
{id:236,type:'mcq',applied:true,text:'[APPLIED] A private university in West Africa wishes to structure its corporate governance to ensure long-term sustainability and academic excellence. The founders study nine global institutions, including Harvard, Oxford, and Yale. They establish a value-driven architecture consisting of a Board of Regents, an academic Senate, and College Boards, ensuring that character development is anchored in their governance. This institutional design reflects the governance model of which university?',ans:0,exp:'Covenant University, founded in 2002, built its governance framework after studying nine global institutions (including Harvard, Princeton, Yale, Oxford, Cambridge). Its architecture includes the Board of Regents, Senate, and College Boards, anchored by a value-driven framework.',topic:'l4',opts:['Covenant University', 'University of Ibadan', 'Ashesi University', 'University of Cape Town']},
{id:237,type:'mcq',applied:true,text:'[APPLIED] In a bid to maximize short-term profits before a major reporting deadline, the CEO of an industrial firm requests the Chief Engineer to skip a critical safety check on a pressure valve, promising him a promotion if the quarter\'s targets are met. The Chief Engineer refuses, citing his personal values and commitments. In terms of boardroom leadership, what does this scenario illustrate about the relationship between ethics and competence?',ans:1,exp:'As the lecture notes, \'Character Precedes Competence.\' Competence can be taught, but character must be cultivated. Ethics precedes policy and survives when rules go silent, guiding individuals to do what is right despite pressure.',topic:'l4',opts:['Competence must always precede character, because a highly competent engineer can fix any safety failure after it occurs.', 'Character precedes competence; professional competence can be taught, but character must be cultivated and stands firm when policies or pressures collide.', 'The Chief Engineer violated his Duty of Obedience by failing to execute the CEO\'s operational strategy.', 'The board should have used a rights-based test to fire the Chief Engineer for insubordination.']},
{id:238,type:'mcq',applied:true,text:'[APPLIED] The board of an investment fund is deciding whether to disclose a recent cyber-attack that exposed customer usernames but no financial data. The IT Director recommends keeping it quiet as they have patched the vulnerability. The board applies the \'Sunlight Test\' to guide their decision. What question must they ask themselves, and what is the correct action if they hesitate?',ans:1,exp:'The Sunlight Test asks: \'Would I be comfortable if this decision were reported publicly tomorrow?\' If yes, proceed. If hesitant, investigate the hesitation. If no, do not sign. What you cannot explain in daylight, do not do in darkness.',topic:'l4',opts:['They must ask: \'Is this disclosure legally required?\' If they hesitate, they should seek a court injunction to block any leak.', 'They must ask: \'Would I be comfortable if this decision were reported publicly on tomorrow\'s front page?\' If they hesitate, they must investigate the hesitation and not hide the incident.', 'They must ask: \'Will this disclosure reduce our share price?\' If they hesitate, they must delay disclosure until the next fiscal year.', 'They must ask: \'What would our competitors do?\' If they hesitate, they should copy the competitor\'s disclosure policy.']},
{id:239,type:'mcq',applied:true,text:'[APPLIED] A non-executive director of a retail company is invited to join the board of a direct logistics competitor. The director believes she can manage both roles by recusing herself whenever overlapping business interests are discussed. Under modern corporate governance codes (such as the Cadbury Report principles), why is this arrangement unacceptable?',ans:2,exp:'A director owes a Duty of Loyalty and Duty of Confidentiality to the organization. Holding board seats on competing companies creates an ongoing conflict of interest where opportunities and information from one role belong to that role, making joint loyalty impossible.',topic:'l4',opts:['It violates the Duty of Obedience because a director is legally prohibited from holding more than one board seat in any industry.', 'It compromises the separation of the Chairman and CEO roles within both organizations.', 'It creates a permanent, structural conflict of interest that compromises the Duty of Loyalty and Duty of Confidentiality, as information from one board cannot be easily segregated.', 'It violates the Duty of Stakeholder Sensitivity by ignoring the rights of the employees of the competitor.']},
{id:240,type:'mcq',applied:true,text:'[APPLIED] The CEO of an energy conglomerate presents a proposal to the board to write off a failed overseas exploration project by adjusting the accounting assumptions, effectively hiding the loss from public view. The CFO supports this to protect the company\'s credit rating. An independent director insists on full, transparent disclosure of the loss in the upcoming quarterly report. Which pillar of corporate governance is this director upholding?',ans:2,exp:'Disclosure and Transparency is one of the 5 Pillars of Corporate Governance. Upholding it ensures that financial statements reveal, rather than conceal, organizational performance and risks, preventing scandals like Enron.',topic:'l4',opts:['Board Composition and Structure', 'Risk Management Framework', 'Disclosure and Transparency', 'Shareholder and Stakeholder Engagement']},
{id:241,type:'mcq',applied:true,text:'[APPLIED] During a strategy retreat, a director asks: \'Before I was a director, I was a person. Does this proposed acquisition of a polluting chemical plant align with the values I have made before God, my family, and those I lead?\' What ethical framework is this director applying?',ans:1,exp:'The Covenant Test is described as the deepest frame of ethical decision-making. It filters decisions through a director\'s earliest commitments and values made before God, family, and the community, ensuring the boardroom does not overwrite the altar.',topic:'l4',opts:['The Utilitarian Test', 'The Covenant Test', 'The Justice Test', 'The Rights Test']},
{id:242,type:'mcq',applied:true,text:'[APPLIED] The board of a major food manufacturing company learns that a batch of baby formula contains trace amounts of an unapproved preservative. Although the level is safe under local laws, it violates international safety standards. The marketing team recommends selling the product in local markets to recover costs, while the legal team confirms no local laws will be broken. The board decides to destroy the batch. This decision is an application of:',ans:1,exp:'The choice between legal compliance and conscience-based action distinguishes Chairman A (who asks \'Is it legal?\') from Chairman B (who asks \'Is it right?\'). Restructuring or rejecting transactions based on conscience leads to long-term trust and legacy.',topic:'l4',opts:['Compliance-based governance, prioritizing legal permissions.', 'Conscience-based governance, prioritizing what is right over what is merely legal.', 'Shareholder primacy, prioritizing short-term financial returns.', 'Deference to seniority, prioritizing the marketing team\'s expertise.']},
{id:243,type:'mcq',applied:true,text:'[APPLIED] A newly appointed independent director of an investment firm discovers that the firm\'s risk models do not account for tail-risk events in subprime lending markets. When she raises this at the Risk Committee, she is told that the models are industry-standard and that challenging them would disrupt the management team\'s bonuses. Under the Duty of Care, what is her proper course of action?',ans:1,exp:'The Duty of Care requires the diligence of a prudent person, including asking the hard questions and thinking independently. If a director identifies a significant unmitigated risk, they must insist on independent validation and vote to protect the organization, rather than deferring to comfort.',topic:'l4',opts:['Accept the committee\'s explanation, since the models are industry-standard and she has fulfilled her duty by raising the question once.', 'Insist on an independent review of the risk models, demand that the risk parameters be formally updated, and vote against any new asset acquisitions until the risks are modeled.', 'Quietly resign from the board without documenting her concerns to avoid damaging the firm\'s market reputation.', 'Collaborate with the CFO to adjust the models privately without informing the full board of the potential vulnerabilities.']},
{id:244,type:'mcq',applied:true,text:'[APPLIED] In a property development firm, the CEO wants to purchase a tract of land from a company where the Chairman\'s wife holds a 30% equity stake. The Chairman discloses this conflict to the board and recuses himself. The CEO then pressures the remaining board members, reminding them that their future reappointments depend on his recommendation. If the board approves the transaction without independent valuation and market checks, what have they failed to exercise?',ans:2,exp:'The remaining board members failed to exercise the Duty of Independent Judgement. Directors must challenge before they concur, stand alone when standing alone is right, and resist pressure from executives regarding their votes or board tenure.',topic:'l4',opts:['The Duty of Confidentiality', 'The Duty of Obedience', 'The Duty of Independent Judgement', 'The Duty of Stakeholder Sensitivity']},
{id:245,type:'mcq',applied:true,text:'[APPLIED] A director of a retail company learns that a major supplier uses sweatshop labor in a country with weak labor regulations. The legal counsel confirms that importing these goods violates no local or international trade laws. The director insists that the company terminate the contract and find an ethical supplier. Which ethical test is the director applying by focusing on the fundamental human rights of the workers?',ans:1,exp:'The Rights Test in ethical decision-making asks: \'Does it respect the fundamental rights of all affected stakeholders?\' Even if legally compliant, exploiting weak labor laws violates the basic rights of workers.',topic:'l4',opts:['The Utilitarian Test', 'The Rights Test', 'The Common Good Test', 'The Virtue Test']},
{id:246,type:'mcq',applied:false,text:'Corporate governance is frequently characterized by the phrase: \'The board keeps its nose in the business and its fingers out of it.\' Which of the following statements correctly interprets this governance principle?',ans:1,exp:'Governance is \'Steering, not Rowing.\' The board\'s functions are directional (nose in the business to monitor and guide) rather than operational (fingers out of the business, leaving day-to-day execution to management).',topic:'l4',opts:['The board must actively manage the day-to-day operations and sales pipelines while leaving financial strategy to the CEO.', 'The board should set strategic direction, monitor performance, and oversee risk (steering), but must avoid interfering in daily operational execution (rowing).', 'The board\'s role is purely ceremonial, and they should only intervene when a major legal crisis occurs.', 'The board must micromanage the executive team\'s schedules to ensure maximum operational efficiency.']},
{id:247,type:'mcq',applied:false,text:'In the comparison between Ethics and Corporate Governance presented in the lecture, the two concepts are described as \'two halves of one whole.\' Which of the following pairings correctly aligns with this comparison?',ans:1,exp:'According to the lecture, Ethics represents the spirit, is invisible, personal, formed in private, and answers \'why\'. Governance represents the skeleton, is visible, institutional, written in policy, and answers \'how\'.',topic:'l4',opts:['Ethics is the skeleton (visible, written in policy); Governance is the spirit (invisible, formed in private).', 'Ethics is the spirit (invisible, personal, answers \'why\'); Governance is the skeleton (visible, institutional, answers \'how\').', 'Ethics answers \'how\' organizations structure committees; Governance answers \'why\' directors must care.', 'Ethics is institutional and policy-driven; Governance is personal and conscience-driven.']},
{id:248,type:'mcq',applied:false,text:'The Cadbury Committee was established in the UK in the early 1990s to investigate the financial aspects of corporate governance. Which historical event or crisis served as the immediate catalyst for this committee\'s formation?',ans:2,exp:'Modern corporate governance codes, starting with the Cadbury Report in 1992, were prompted by corporate failures. The UK was rocked by scandals in the early 1990s, specifically the BCCI collapse and Maxwell\'s plundering of pensions.',topic:'l4',opts:['The collapse of the South Sea Company in 1720.', 'The Wall Street Crash of 1929 and the subsequent Great Depression.', 'A series of major corporate scandals, including the collapse of the Bank of Credit and Commerce International (BCCI) and Robert Maxwell plundering pension funds.', 'The collapse of Lehman Brothers and the onset of the 2008 Global Financial Crisis.']},
{id:249,type:'mcq',applied:false,text:'Under the pillar of Accountability, when a major corporate failure or strategic mistake occurs, what is the expected behavior of an ethical and accountable board?',ans:1,exp:'Accountability means \'owning the outcome.\' An accountable board refuses the convenience of blame-shifting and welcomes scrutiny. It focuses on diagnosing systemic failures (\'What did we miss?\') rather than quick scapegoating.',topic:'l4',opts:['The board should immediately fire the low-level staff involved and release a press statement deflecting all responsibility.', 'The board must take ownership of the outcome and its consequences, asking \'What did we miss?\' before asking \'Whom do we fire?\'', 'The board should delay public disclosure and hire public relations consultants to manage and dilute the narrative.', 'The board should dissolve the Risk Committee to ensure that no single director can be held legally responsible.']},
{id:250,type:'mcq',applied:false,text:'Which of the following correctly identifies the Seven Duties of a Director that are held in common by boardrooms globally, as listed in the lecture?',ans:0,exp:'The seven duties are: Duty of Care, Duty of Loyalty, Duty of Obedience, Duty of Confidentiality, Duty of Conflict Disclosure, Duty of Stakeholder Sensitivity, and Duty of Independent Judgement.',topic:'l4',opts:['Care, Loyalty, Obedience, Confidentiality, Conflict Disclosure, Stakeholder Sensitivity, and Independent Judgement.', 'Care, Competence, Profitability, Shareholder Alignment, Compliance, Confidentiality, and Seniority Deference.', 'Diligence, Transparency, Integrity, Fairness, Independent Judgement, Compensation Maximization, and Public Relations.', 'Loyalty, Obedience, Strategy, Execution, Risk Mitigation, Financial Oversight, and CEO Support.']},
{id:251,type:'mcq',applied:false,text:'The lecture describes corporate governance as a \'child of crisis.\' Which timeline correctly maps the historical crises to the corporate governance developments they prompted?',ans:0,exp:'The historical progression of governance crises listed on Page 8 is: 1720 (South Sea Bubble), 1929 (Wall Street Crash), 1980s (Savings & Loan scandals), 2001 (Enron & WorldCom), and 2008 (Global Financial Crisis).',topic:'l4',opts:['1720 South Sea Bubble -> 1929 Wall Street Crash -> 1980s S&L scandals -> 2001 Enron/WorldCom -> 2008 Global Financial Crisis.', '1929 Wall Street Crash -> 1720 South Sea Bubble -> 2001 Enron -> 1980s S&L scandals -> 2008 Lehman Brothers.', '1980s S&L scandals -> 1720 South Sea Bubble -> 1929 Wall Street Crash -> 2008 GFC -> 2001 Enron.', '2001 Enron -> 2008 GFC -> 1929 Wall Street Crash -> 1720 South Sea Bubble -> 1980s S&L scandals.']},
{id:252,type:'mcq',applied:false,text:'In the comparison between the boardroom operations of Enron (2001) and Johnson & Johnson (1982), what was the fundamental difference in their decision-making focus that led to their different destinies?',ans:1,exp:'Page 22 highlights: \'Same Pressure. Two Questions. Two Destinies. Enron asked: "How do we protect the share price?" J&J asked: "How do we protect the patient?"\' The first led to extinction, the second to legacy.',topic:'l4',opts:['Enron asked \'How do we comply with the law?\', while J&J asked \'How do we lobby the regulators?\'', 'Enron asked \'How do we protect the share price?\', leading to extinction; J&J asked \'How do we protect the patient?\', producing a legacy of trust.', 'Enron prioritized employee compensation, while J&J prioritized shareholder dividends.', 'Enron focused on international expansion, while J&J focused on domestic market consolidation.']},
{id:253,type:'mcq',applied:false,text:'According to Sir Adrian Cadbury\'s insights and the principles of board composition, why is it critical that the roles of Chairman of the Board and CEO are separated?',ans:1,exp:'Page 25 notes: \'Concentrated Power is the mother of governance failure.\' The Chairman leads the board and holds management accountable (independent voice), while the CEO leads the management and executes strategy (insider voice).',topic:'l4',opts:['To reduce the financial compensation paid to a single individual.', 'Because concentrated power is the mother of governance failure; separation ensures the board can independently hold management accountable.', 'To allow the CEO to focus entirely on public relations while the Chairman manages the day-to-day operations.', 'Because the Chairman represents the company\'s lenders, while the CEO represents the company\'s equity investors.']},
{id:254,type:'mcq',applied:false,text:'Which of the following statements about the \'four pillars of ethical leadership\' is correct in terms of boardroom governance?',ans:0,exp:'Page 9 defines the 4 pillars of ethical leadership: Integrity, Accountability, Transparency, and Fairness. They are load-bearing, not decorative; remove one, and the house of governance tilts.',topic:'l4',opts:['The pillars are Integrity, Accountability, Transparency, and Fairness; they are load-bearing, and removing one tilts the house of governance.', 'The pillars are Integrity, Competence, Seniority, and Compliance; they are optional guidelines for private firms.', 'The pillars are Transparency, Fairness, Profitability, and Efficiency; they are designed to maximize short-term capital.', 'The pillars are Integrity, Obedience, Diligence, and Confidentiality; they are written by the CEO to guide staff.']},
{id:255,type:'mcq',applied:false,text:'How does the lecture define \'Boardroom Ethics\' as distinguished from \'Corporate Governance\'?',ans:1,exp:'Page 5 defines Boardroom Ethics as: \'The moral principles, values, and standards that guide the conduct of directors in the discharge of their duties. It is about who the director is, not just what the director does; it precedes policy.\'',topic:'l4',opts:['Boardroom Ethics is the formal system of committees and audits; Corporate Governance is the moral values of the CEO.', 'Boardroom Ethics refers to the moral principles, values, and standards that guide the conduct of directors; it is about who the director is, not just what they do.', 'Boardroom Ethics is the legal penalties applied to directors who fail; Corporate Governance is the voluntary code of ethics.', 'Boardroom Ethics is the written compliance policy; Corporate Governance is the unwritten cultural norm.']},
{id:256,type:'mcq',applied:false,text:'What is the core message of the quote by Dr. David Oyedepo: \'You don\'t grow big to manage well. You manage well to grow big\' in the context of corporate governance?',ans:1,exp:'The quote emphasizes that management discipline and governance frameworks must be established early. Sound management is what enables and sustains growth (\'manage well to grow big\'), rather than being a luxury adopted after growth.',topic:'l4',opts:['A company should delay implementing governance structures until it reaches a multi-national scale.', 'Good governance and management discipline are the precursors and foundations of growth, not the results of it.', 'Organizations must prioritize hiring sales executives over establishing risk management committees.', 'The size of the board of directors should expand in direct proportion to the company\'s revenue.']},
{id:257,type:'mcq',applied:false,text:'Under the 7 Tests of Ethical Decision-Making, which test focuses on whether a proposed board action provides the \'greatest good for the greatest number\' of people?',ans:2,exp:'The Utilitarian Test evaluates decisions based on utility, aiming for the greatest good for the greatest number of people. (Page 30).',topic:'l4',opts:['The Rights Test', 'The Justice Test', 'The Utilitarian Test', 'The Common Good Test']},
{id:258,type:'mcq',applied:false,text:'The \'Justice Test\' in the 7 Tests of Ethical Decision-Making primarily asks which of the following questions?',ans:1,exp:'The Justice Test focuses on fairness: \'Is it fair?\' and does it distribute benefits and burdens equitably among the affected stakeholders. (Page 30).',topic:'l4',opts:['Does this action respect the fundamental legal rights of our competitors?', 'Is the proposed action fair, and does it treat everyone affected equally or proportionately?', 'Will this action increase the tax revenue of the local government?', 'Would this decision survive the scrutiny of the local judiciary in a lawsuit?']},
{id:259,type:'mcq',applied:false,text:'In the context of the history of corporate governance, what does the collapse of Lehman Brothers in 2008 illustrate about boardroom dynamics?',ans:1,exp:'Page 27 highlights that in the 2008 crisis, boards did not understand their own products, risk committees existed only on paper, and executive pay rewarded short-term risk, leading to the collapse of Lehman Brothers.',topic:'l4',opts:['The board was overly cautious and failed to take enough risk to compete in derivative markets.', 'The board did not understand the complex financial products they were approving, and their risk committees existed only on paper.', 'The regulators forced the board to dissolve their risk committees, leading to unstructured decision-making.', 'The shareholders failed to approve the compensation packages of the non-executive directors.']},
{id:260,type:'mcq',applied:false,text:'According to the lecture, what is the role of \'Integrity\' as the first pillar of ethical leadership?',ans:1,exp:'Page 10 describes Integrity as: \'Word, Thought, and Action Aligned. Courage to disagree with the Chairman, discipline to read papers, honesty to admit what one does not understand, consistency between private life and public role.\'',topic:'l4',opts:['Integrity is the ability to maintain profitability under adverse economic conditions.', 'Integrity is the alignment of word, thought, and action, demonstrating courage to disagree, and consistency between private and public life.', 'Integrity is the technical competence required to draft accounting policies.', 'Integrity is the blind adherence to the Chairman\'s decisions during voting.']},
{id:261,type:'mcq',applied:false,text:'The Duty of Loyalty requires directors to act as stewards rather than owners. Which of the following is a violation of this duty?',ans:1,exp:'Opportunities discovered in the role belong to the role, and relationships formed through the role are not private assets. Treating them as personal ATMs or assets is a direct violation of the Duty of Loyalty. (Page 16).',topic:'l4',opts:['Rejecting a transaction that benefits a director\'s personal business interests but harms the company.', 'Treating opportunities and business relationships developed during the director\'s tenure as private assets.', 'Disclosing a personal conflict of interest and recusing oneself from the vote.', 'Reading board papers and demanding detailed financial information from the CEO.']},
{id:262,type:'mcq',applied:false,text:'What is the primary significance of the Quaker background of Sir Adrian Cadbury, as highlighted in the lecture?',ans:1,exp:'Sir Adrian Cadbury was a Quaker, chocolate manufacturer, and man of integrity. The lecture notes that he did not invent governance; he formalized what his family business had long practiced informally, demonstrating that character precedes formal code.',topic:'l4',opts:['It provided him with the financial capital to fund the Cadbury Committee.', 'It anchored his character and integrity, showing that his governance principles were formalized from informal family business practices of integrity.', 'It gave him political connections to pass the Cadbury Report into law in the UK Parliament.', 'It influenced him to recommend that all corporate boards be composed of religious leaders.']},
{id:263,type:'mcq',applied:false,text:'Under the five pillars of corporate governance architecture, which pillar specifically oversees the board committees (Audit, Risk, Remuneration, Nominations)?',ans:3,exp:'The 5 pillars of corporate governance are: 1) Board Composition and Structure, 2) Board Committees, 3) Risk Management Framework, 4) Disclosure and Transparency, and 5) Shareholder and Stakeholder Engagement. (Page 23).',topic:'l4',opts:['Risk Management Framework', 'Shareholder and Stakeholder Engagement', 'Board Composition and Structure', 'Board Committees']},
{id:264,type:'mcq',applied:false,text:'The lecture quotes George Washington: \'Responsibility is the price of greatness.\' Under which of the four pillars of ethical leadership is this quote cited?',ans:1,exp:'The quote \'Responsibility is the price of greatness\' by George Washington is cited under Pillar Two: Accountability on Page 11 of the lecture text.',topic:'l4',opts:['Integrity', 'Accountability', 'Transparency', 'Fairness']},
{id:265,type:'mcq',applied:false,text:'In the comparison between Chairman A and Chairman B on Page 3, Chairman A asks: \'Is it legal?\' and approves the transaction, while Chairman B asks: \'Is it right?\' and restructures it. What does this tale illustrate?',ans:0,exp:'The distance between Legal and Right is where character lives. Legal compliance (compliance) does not equal ethical rightness (conscience). Relying only on \'Is it legal?\' can lead to long-term failure.',topic:'l4',opts:['The distance between Legal and Right is where Character lives; legal compliance alone is insufficient for ethical leadership.', 'Legal compliance is the ultimate goal, and Chairman B wasted company resources by restructuring the deal.', 'Ethics and legality are identical, and both chairmen reached the same outcome in 5 years.', 'Chairman A was more successful because his transaction was approved faster.']},
{id:266,type:'mcq',applied:false,text:'The \'Sunlight is the best disinfectant\' principle is associated with which ethical leadership pillar, and what is its primary warning?',ans:2,exp:'Sunlight is the best disinfectant is listed under Pillar Three: Transparency. The warning is: \'Corruption feeds on Darkness. Transparency turns on the lights.\' Written disclosures and minutes must reveal, not conceal.',topic:'l4',opts:['Integrity; warning against public disagreement with the board.', 'Accountability; warning against taking responsibility for bad outcomes.', 'Transparency; warning that corruption feeds on darkness and transparency turns on the lights.', 'Fairness; warning against prioritizing minority shareholder interests.']},
{id:267,type:'mcq',applied:false,text:'Which of the following best describes the board\'s core function regarding executive management as listed under the \'Board\'s 6 Core Functions\'?',ans:0,exp:'The board\'s core functions are: Set Strategic Direction, Monitor Performance, Oversee Risk, Select and Succeed the CEO, Ensure compliance and integrity, and Protect Stakeholder Interests. (Page 24).',topic:'l4',opts:['Select and succeed the CEO.', 'Approve all daily purchase orders and logistics routes.', 'Write the software and product designs for the company.', 'Negotiate employee salaries directly with the labor union.']},
{id:268,type:'mcq',applied:false,text:'According to the \'Creed for Directors\' on Page 38, what is a director\'s primary call and purpose?',ans:2,exp:'The Creed for Directors states: \'I am called to add value — not extract it. I will read what I sign, ask what I do not understand, disagree when disagreement is right, disclose what may influence me, and protect those who cannot protect themselves.\'',topic:'l4',opts:['To maximize personal board sitting fees and extract network connections.', 'To protect the executive team from shareholder scrutiny and legal action.', 'To add value, not extract it; to read what they sign, ask questions, and protect the vulnerable.', 'To defer to senior directors and ensure boardroom consensus is maintained.']},
{id:269,type:'mcq',applied:false,text:'What is the primary warning conveyed by the Enron case study in 2001 regarding the role of the board of directors?',ans:1,exp:'Page 20 highlights: \'It did not begin in the accounting department. It began in the Boardroom — the moment directors stopped asking hard questions.\' Directors signed complex transactions (SPEs) they did not understand, and auditors were compromised.',topic:'l4',opts:['The board was too small to handle the complexity of the energy sector.', 'The collapse began in the boardroom the moment directors signed transactions they did not understand and stopped asking hard questions.', 'The board was too focused on regulatory compliance and ignored share price growth.', 'The board should have hired more consulting auditors to audit their internal transactions.']},
{id:270,type:'mcq',applied:false,text:'What does the quote by Dr. David Oyedepo, \'Nothing enhances worth like work,\' illustrate in the context of the Duty of Care?',ans:1,exp:'Under the Duty of Care (Page 15), Dr. Oyedepo\'s quote \'Nothing enhances worth like work\' reinforces that active diligence (reading papers, attending meetings, asking questions) is essential. A director\'s worth is enhanced by the diligent work they bring to the boardroom.',topic:'l4',opts:['A director\'s worth on a board is determined by their political connections.', 'Diligence, preparation, and active work (such as reading papers and attending meetings) are what make a director valuable and effective.', 'The board should replace all non-executive directors with full-time operational employees.', 'A director should focus on maximizing their personal working hours outside the boardroom.']},
{id:271,type:'multi',applied:true,text:'[APPLIED] A large agricultural corporation is considering building a chemical processing plant near a rural farming community. The local community has voiced concerns about soil contamination, but local laws do not require an environmental impact assessment for this type of plant. Which actions should the board take to satisfy their Duty of Stakeholder Sensitivity and the pillar of Fairness? (Select all that apply)',ans:[0, 2, 3],exp:'The Duty of Stakeholder Sensitivity and Fairness require boards to consider affected communities and future generations. Doing so involves voluntary environmental assessments (0), engaging in dialog (2), and evaluating multi-generational impacts (3). Relying only on weak local laws (1) violates these principles.',topic:'l4',opts:['Commission a voluntary, independent environmental impact assessment to assess soil risks.', 'Proceed with construction immediately, arguing that local legal compliance is sufficient and community concerns are outside their governance mandate.', 'Host open stakeholder engagement forums to listen to and address the community\'s concerns.', 'Assess the long-term impact of potential soil pollution on future generations of farmers in the area.']},
{id:272,type:'multi',applied:true,text:'[APPLIED] You are an independent director of a retail company. The CEO is pushing to acquire a boutique supply firm. During research, you discover that the boutique firm is owned by a partnership in which you hold a 5% silent interest. Which of the following steps must you take to comply with your Duty of Conflict Disclosure and Loyalty? (Select all that apply)',ans:[0, 1, 2],exp:'Managing a conflict of interest requires formal disclosure (0), recusal from discussions (1), and abstaining from the vote (2). Advising the CEO to benefit your private interest (3) is a direct breach of the Duty of Loyalty.',topic:'l4',opts:['Formally disclose your 5% silent interest to the board in writing.', 'Recuse yourself from participating in any board debates regarding the acquisition.', 'Abstain from voting on the resolution to approve the acquisition.', 'Quietly advise the CEO on how to structure the deal to ensure your partnership gets a premium price.']},
{id:273,type:'multi',applied:true,text:'[APPLIED] The risk committee of a regional commercial bank is reviewing its credit policies during an economic downturn. The risk officer reports that low-income borrowers are experiencing high default rates on short-term payday loans, which represent a highly profitable sector for the bank. Under the pillars of ethical leadership and stakeholder engagement, which of the following represent responsible board oversight? (Select all that apply)',ans:[0, 2],exp:'Responsible oversight requires analyzing social impacts (0) and ensuring fair debt collection (2). Hiding risk metrics (1) violates Transparency, and targeting vulnerable groups with debt (3) violates Fairness and Stakeholder Sensitivity.',topic:'l4',opts:['Evaluate the social impact of default rates on the local community alongside credit profitability.', 'Structure risk reports to conceal the default rates from public disclosures to protect the bank\'s credit rating.', 'Review the bank\'s debt collection practices to ensure they treat distressed borrowers with fairness and respect.', 'Instruct the marketing team to target rural communities with increased credit offers to offset the losses.']},
{id:274,type:'multi',applied:false,text:'Under corporate governance principles, which of the following are categorized as the Seven Duties of a Director that bind board members globally? (Select all that apply)',ans:[0, 1, 3],exp:'The seven duties are: Care, Loyalty, Obedience, Confidentiality, Conflict Disclosure, Stakeholder Sensitivity, and Independent Judgement. Share price maximization is not a formal legal duty of a director and can lead to governance failures if prioritized over other duties.',topic:'l4',opts:['Duty of Care', 'Duty of Loyalty', 'Duty of Share Price Maximization', 'Duty of Independent Judgement']},
{id:275,type:'multi',applied:false,text:'The lecture outlines \'The 4 Pillars of Ethical Leadership\' which hold the boardroom upright. Which of the following are included in these four load-bearing pillars? (Select all that apply)',ans:[0, 1, 3],exp:'The 4 pillars of ethical leadership are Integrity, Accountability, Transparency, and Fairness. Competence, while critical, is an operational/character trait but is not listed as one of the four core ethical leadership pillars.',topic:'l4',opts:['Integrity', 'Accountability', 'Competence', 'Transparency']},
{id:276,type:'multi',applied:false,text:'In the comparisons made between Ethics and Corporate Governance on Page 7, which of the following statements correctly align the two concepts? (Select all that apply)',ans:[0, 1, 2],exp:'Ethics is the spirit, invisible, formed in private, personal, and answers \'why\'. Governance is the skeleton, visible, written in policy, institutional, and answers \'how\'. Option 3 is incorrect because the roles are reversed.',topic:'l4',opts:['Ethics is the spirit; Governance is the skeleton.', 'Ethics is invisible; Governance is visible.', 'Ethics is personal; Governance is institutional.', 'Ethics answers \'how\'; Governance answers \'why\'.']},
{id:277,type:'multi',applied:false,text:'Which of the following are recognized in the lecture as major challenges facing corporate governance in the African business environment? (Select all that apply)',ans:[0, 1, 2],exp:'The governance challenges in Africa include concentrated ownership, weak institutional frameworks, cultural deference to seniority, corruption/patronage, and appointments based on connections rather than competence. Over-reliance on foreign directors is not listed as a challenge.',topic:'l4',opts:['Concentrated ownership (family or state-owned enterprises).', 'Weak institutional frameworks and corruption networks.', 'Cultural deference to seniority which can suppress independent boardroom dissent.', 'An over-reliance on foreign, independent non-executive directors.']},
{id:278,type:'multi',applied:false,text:'The 2008 Global Financial Crisis (GFC) provided critical lessons on board failures. According to the lecture, what were the primary governance failures that led to the crisis? (Select all that apply)',ans:[0, 1, 2],exp:'Page 27 lists GFC failures: boards not understanding their own products, risk committees existing only on paper, executive pay rewarding short-term risk, and regulators outpaced by innovation. Legal bans on shareholder voting are not mentioned.',topic:'l4',opts:['Boards did not understand their own complex financial products.', 'Risk committees existed only on paper rather than active oversight.', 'Executive pay structures rewarded short-term, excessive risk-taking.', 'Shareholders were legally barred from voting on director compensation.']},
{id:279,type:'multi',applied:false,text:'The lecture describes \'7 Tests of Ethical Decision-Making\' to guide directors through difficult decisions. Which of the following tests are part of this framework? (Select all that apply)',ans:[0, 1, 2],exp:'The seven tests are: Utilitarian, Rights, Justice, Common Good, Virtue, Sunlight, and Covenant. The \'Market Share Test\' is not an ethical decision-making test.',topic:'l4',opts:['The Rights Test', 'The Sunlight Test', 'The Covenant Test', 'The Market Share Test']},
{id:280,type:'multi',applied:false,text:'The Board of Directors has several core functions that are \'directional, not operational.\' Which of the following are included in the Board\'s 6 Core Functions? (Select all that apply)',ans:[0, 2, 3],exp:'The Board\'s core functions include setting strategic direction (0), overseeing risk and performance (2), selecting the CEO (3), ensuring compliance, and protecting stakeholders. Daily operational logistics (1) are the responsibility of executive management (rowing).',topic:'l4',opts:['Set Strategic Direction.', 'Manage daily customer service and inventory logistics.', 'Oversee Risk and monitor organizational performance.', 'Select and succeed the CEO.']},
{id:281,type:'short',applied:true,text:'[APPLIED] You are an independent director at a shipping company. You discover that a proposed route expansion will bypass local environmental standards by operating in international waters. What specific director duty requires you to speak up and challenge this practice, even if it is legally compliant?',ans:'Care',exp:'The Duty of Care requires directors to act with the diligence of a prudent person, asking tough questions, reading relevant reports, and thinking independently about risks.',topic:'l4'},
{id:282,type:'short',applied:true,text:'[APPLIED] When James Burke recalled 31 million Tylenol bottles in 1982, he based his decision on a foundational ethical document that defined the company\'s core commitments. What is the name of this corporate document?',ans:'Company Credo',exp:'James Burke consulted the company Credo, which prioritized patients, doctors, and nurses first, followed by employees, communities, and lastly, shareholders.',topic:'l4'},
{id:283,type:'short',applied:false,text:'According to the lecture, corporate governance is the structural framework of an organization, while ethics is the internal moral compass. What term does the lecture use to describe corporate governance in the \'Ethics vs. Governance\' table?',ans:'The Skeleton',exp:'The lecture describes corporate governance as the skeleton (visible, written in policy, institutional), whereas ethics is the spirit (invisible, formed in private, personal).',topic:'l4'},
{id:284,type:'short',applied:false,text:'What is the name of the specific director duty that requires a board member to put the interests of the organization above their own self-interest and treats opportunities found in the role as belonging to the organization?',ans:'Loyalty',exp:'The Duty of Loyalty requires directors to act as stewards, not owners. The company is not a personal ATM, and opportunities/relationships belong to the role.',topic:'l4'},
{id:285,type:'short',applied:false,text:'Which director duty requires directors to act in accordance with the law and the organization\'s constitution?',ans:'Obedience',exp:'The Duty of Obedience requires that directors act within the bounds of the law and the company\'s constitution, preventing ultra vires actions.',topic:'l4'},
{id:286,type:'short',applied:false,text:'Which specific director duty is described as \'the courage to dissent,\' requiring directors to challenge proposals, think before voting, and stand alone when necessary?',ans:'Independent Judgement',exp:'The Duty of Independent Judgement is the courage to dissent, challenge before concurring, and ensure that a chorus of easy agreement does not replace critical thinking.',topic:'l4'},
{id:287,type:'short',applied:false,text:'What is the name of the ethical test that asks the question: \'Would I be comfortable if this decision were reported publicly on the front page of tomorrow\'s newspaper?\'',ans:'Sunlight Test',exp:'The Sunlight Test evaluates transparency and public accountability. If a director is hesitant, they should investigate their hesitation; if no, they must not sign.',topic:'l4'},
{id:288,type:'short',applied:false,text:'Which ethical test represents the deepest frame, asking if a decision aligns with values made before God, family, and those the director leads?',ans:'Covenant Test',exp:'The Covenant Test filters boardroom decisions through a director\'s deepest personal commitments, ensuring that the boardroom does not overwrite the altar.',topic:'l4'},
{id:289,type:'short',applied:false,text:'According to Sir Adrian Cadbury\'s insights, what is the \'mother of corporate governance failure\'?',ans:'Concentrated Power',exp:'Concentrated power is the mother of governance failure. This is why modern codes advocate for the separation of the Chairman and CEO roles.',topic:'l4'},
{id:290,type:'short',applied:false,text:'Which of the four pillars of ethical leadership is described as \'the enemy of corruption\' and is supported by risk reports that name real risks?',ans:'Transparency',exp:'Transparency is the enemy of corruption. Sunlight is the best disinfectant; corruption feeds on darkness, and transparency turns on the lights.',topic:'l4'},
{id:291,type:'fill',applied:true,text:'[APPLIED] Consider a boardroom decision: Chairman A looks at a proposed transaction and asks, \'Is it _______?\' and immediately approves it when legal advisors say yes. Five years later, the company is ruined. Chairman B looks at a similar transaction and asks, \'Is it _______?\' and restructures it when lawyers are uncertain. Five years later, the company is thriving.',dropdowns:[['legal', 'profitable', 'fair', 'safe'], ['right', 'legal', 'acceptable', 'strategic']],ans:['legal', 'right'],exp:'The distance between legal compliance (\'Is it legal?\') and ethical conscience (\'Is it right?\') is where character lives. Relying purely on legal advice can lead to long-term failure, while conscience-driven restructuring produces legacy.',topic:'l4'},
{id:292,type:'fill',applied:false,text:'The four pillars of ethical leadership that hold the boardroom upright are Integrity (alignment of word, thought, and action), _______ (owning the outcomes of decisions), _______ (turning on the lights to combat corruption), and Fairness (ensuring the minority is heard as clearly as the majority).',dropdowns:[['Accountability', 'Competence', 'Loyalty', 'Obedience'], ['Transparency', 'Independence', 'Diligence', 'Authority']],ans:['Accountability', 'Transparency'],exp:'The 4 load-bearing pillars of ethical leadership are Integrity, Accountability, Transparency, and Fairness. Removing one tilts the house of governance.',topic:'l4'},
{id:293,type:'fill',applied:false,text:'The Cadbury Report of 1992 was born from crisis in the UK, prompted by corporate scandals such as the collapse of the _______ and the plundering of pensions by _______.',dropdowns:[['Bank of Credit and Commerce International', 'Lehman Brothers', 'Enron', 'South Sea Company'], ['Robert Maxwell', 'James Burke', 'Adrian Cadbury', 'Kenneth Lay']],ans:['Bank of Credit and Commerce International', 'Robert Maxwell'],exp:'Sir Adrian Cadbury chaired the committee after UK scandals in the early 1990s, specifically the collapse of the Bank of Credit and Commerce International (BCCI) and Robert Maxwell plundering pensions.',topic:'l4'},
{id:294,type:'fill',applied:false,text:'Under corporate governance best practices, the roles of Chairman and CEO must be separated. The Chairman is an independent voice who leads the _______ and holds management accountable, whereas the CEO is an insider voice who leads the _______ and executes corporate strategy.',dropdowns:[['board', 'management', 'regulators', 'shareholders'], ['management', 'board', 'operations', 'advisors']],ans:['board', 'management'],exp:'The Chairman leads the board of directors and holds management accountable. The CEO leads the management team and executes the strategy. Separation of these roles prevents concentrated power.',topic:'l4'},
{id:295,type:'fill',applied:false,text:'In 2001, America\'s 7th largest company, _______, collapsed because directors signed transactions they did not understand, debt was hidden in Special Purpose Entities, and auditors were compromised by lucrative _______ fees.',dropdowns:[['Enron', 'WorldCom', 'Lehman Brothers', 'Arthur Andersen'], ['Consulting', 'Audit', 'Brokerage', 'Legal']],ans:['Enron', 'Consulting'],exp:'Enron\'s collapse began when directors signed off on complex transactions they did not understand, and auditors were compromised by consulting fees, leading to a total failure of board oversight.',topic:'l4'},
{id:296,type:'fill',applied:false,text:'To prevent corporate failure, the board of directors must understand their core function as \'directional, not operational.\' As the governance maxim states, the board keeps its _______ in the business and its _______ out of it.',dropdowns:[['nose', 'eyes', 'hands', 'ears'], ['fingers', 'feet', 'minds', 'voices']],ans:['nose', 'fingers'],exp:'The board monitors, guides, and strategic-aligns (keeps its nose in the business) but leaves execution to management, avoiding micromanagement (keeps its fingers out of it).',topic:'l4'},
{id:297,type:'fill',applied:false,text:'The Duty of Conflict _______ requires directors to declare any material personal interest that could sway them, while the Duty of Stakeholder _______ requires directors to weigh the impact of their decisions on employees, communities, and future generations.',dropdowns:[['Disclosure', 'Obedience', 'Loyalty', 'Care'], ['Sensitivity', 'Diligence', 'Judgement', 'Integrity']],ans:['Disclosure', 'Sensitivity'],exp:'Conflict Disclosure (disclose and recuse where independence is compromised) and Stakeholder Sensitivity (weighing decisions\' impacts on employees, communities, and future generations) are crucial director duties.',topic:'l4'},
{id:298,type:'fill',applied:false,text:'Corporate governance history is a \'child of crisis.\' Early financial bubbles like the _______ in 1720 and the _______ in 1929 taught the world what happens when boards fall asleep.',dropdowns:[['South Sea Bubble', 'Wall Street Crash', 'Savings & Loan scandals', 'Global Financial Crisis'], ['Wall Street Crash', 'South Sea Bubble', 'Dot-com Crash', 'Great Recession']],ans:['South Sea Bubble', 'Wall Street Crash'],exp:'The timeline of governance crises begins with the South Sea Bubble of 1720 and the Wall Street Crash of 1929, each prompting new regulations to protect investors.',topic:'l4'},
{id:299,type:'fill',applied:false,text:'Governance challenges in Africa are shaped by context, including concentrated ownership, weak institutional frameworks, cultural deference to _______, and board appointments made for _______ rather than competence.',dropdowns:[['Seniority', 'Youth', 'Regulators', 'Shareholders'], ['Connections', 'Education', 'Wealth', 'Experience']],ans:['Seniority', 'Connections'],exp:'Cultural deference to seniority can stifle independent debate, and appointing board members based on connections rather than competence leads to weak board oversight in the African context.',topic:'l4'},
{id:300,type:'fill',applied:false,text:'Before sitting on a board, a prospective director should practice three disciplines: _______ (studying codes, reports, and cases), _______ (knowing personal values before they are tested), and _______ (practicing asking hard questions in small rooms first).',dropdowns:[['Read', 'Reflect', 'Rehearse', 'Research'], ['Reflect', 'Read', 'Rehearse', 'Recite'], ['Rehearse', 'Read', 'Reflect', 'Roleplay']],ans:['Read', 'Reflect', 'Rehearse'],exp:'The three disciplines of preparation are Read (study governance documents), Reflect (know values in advance), and Rehearse (practice dissent in small settings).',topic:'l4'},
{id:301,topic:'l5',type:'mcq',text:'[APPLIED] A local health organization in a rural region is deciding whether to expand its services from primary care to agricultural education because a new donor is offering funding specifically for farming initiatives. The organization\'s director argues that the funding will help sustain the overall organization, but senior staff fear that the expansion will dilute their primary medical focus. According to the lecture\'s framework, this dilemma describes the initiation of which organizational pitfall?',opts:['Founder Syndrome', 'Mission Drift', 'Donor Dependency', 'Impact Theater'],ans:1,exp:'Mission Drift almost always begins as a series of small \'yes\' answers to attractive opportunities (such as a grant that is slightly off-mission) which eventually results in the organization doing something it never set out to do.',applied:true},
{id:302,topic:'l5',type:'mcq',text:'[APPLIED] In the reconstruction era following a devastating regional conflict, a newly established NGO starts by distributing basic food rations and medical supplies to displaced families. Over the next decade, the organization introduces microfinance schemes to establish community-level cooperative businesses, transitions to influencing state policies by having their community school models adopted by the government, and eventually shapes global narratives on grassroots development. Which historically successful non-profit model and strategy is this scenario based on?',opts:['The Green Belt Movement\'s environmental focus', 'Sir Fazle Hasan Abed\'s founding and scaling of BRAC', 'Chess in Slums Africa\'s community empowerment model', 'Mother Teresa\'s Missionaries of Charity model'],ans:1,exp:'BRAC, founded by Sir Fazle Hasan Abed in Bangladesh in 1971, started with relief, built communities through microfinance, influenced systems via government-adopted education models, and shifted global cultural development thinking.',applied:true},
{id:303,topic:'l5',type:'mcq',text:'[APPLIED] A non-profit addressing homelessness has operated successfully for six years under a highly energetic founder. The founder makes all decisions, does not allow the board of trustees to review financial details, and tells the staff that \'we do not have time for administrative protocols because lives are at stake.\' As the organization scales, it experiences massive staff turnover and cannot secure multi-year institutional funding because of governance issues. Which pitfall does this represent?',opts:['Donor Dependency', 'Impact Theater', 'Founder Syndrome', 'Burnout Culture'],ans:2,exp:'Founder Syndrome is characterized by concentrated authority, a decorative rather than deliberative board, unmentionable succession planning, and the founder confusing themselves with the mission.',applied:true},
{id:304,topic:'l5',type:'mcq',text:'[APPLIED] An environmental organization in East Africa pays local women a small stipend to plant trees in degraded areas. This simple initiative scales to plant over 51 million trees, creates employment for tens of thousands of women, and addresses political and gendered issues. When global media coverage highlights the project, the founder deflects attention, focusing instead on the empowerment of the local women. Who is this leader and what was her movement?',opts:['Sir Fazle Hasan Abed and BRAC', 'Wangari Maathai and the Green Belt Movement', 'Tunde Onakoya and Chess in Slums Africa', 'Mother Teresa and Missionaries of Charity'],ans:1,exp:'Wangari Maathai founded the Green Belt Movement in Kenya in 1977. She paid rural women to plant trees, refused to be distracted, and focused global attention on the women on the ground.',applied:true},
{id:305,topic:'l5',type:'mcq',text:'[APPLIED] A youth organization in a low-income urban community uses a competitive strategy game as an entry point to engage marginalized children. The founder\'s premise is that while the game itself does not feed the children, it gives them the rare experience of being seen as capable, which transforms their self-worth and opens paths to scholarships and national recognition. In 2024, the founder raises over $1M through a high-profile marathon event in Times Square. Which leader and organization are described here?',opts:['Cosmas Maduka and Coscharis Group', 'R.G. LeTourneau and LeTourneau University', 'Tunde Onakoya and Chess in Slums Africa', 'Wangari Maathai and the Green Belt Movement'],ans:2,exp:'Tunde Onakoya founded Chess in Slums Africa in 2018 (Makoko, Oshodi, Ajegunle), using chess as a tool for cognitive empowerment and opportunity, culminating in a 60+ hour Times Square chess marathon raising over $1M in 2024.',applied:true},
{id:306,topic:'l5',type:'mcq',text:'[APPLIED] A reproductive health non-profit wants to reduce teenage pregnancy rates in a district. Their strategy is outlined as: \'We will hold monthly workshops on reproductive health, which will cause teen pregnancy to decline.\' After three years, local statistics show no change in pregnancy rates. According to the lecture\'s comparison of theories of change, what is the primary reason this intervention failed?',opts:['The organization did not secure celebrity endorsements or media campaigns.', 'The organization had a weak Theory of Change that assumed a simple linear outcome without specifying the mechanism, mentors, timeline, magnitude, and assumptions.', 'The local government actively opposed the distribution of pamphlets.', 'The workshops were conducted online instead of in-person, limiting accessibility.'],ans:1,exp:'The lecture compares a weak theory of change (\'workshops on reproductive health, and teen pregnancy will decline\') with a strong theory of change which specifies mechanisms, mentors, timeline, and magnitude.',applied:true},
{id:307,topic:'l5',type:'mcq',text:'[APPLIED] A recently appointed executive director of a middle-sized advocacy organization spends nearly half of their working time cultivating relationships with wealthy individuals, writing grant proposals, and attending corporate networking events. Some staff members complain that the director is neglecting internal operations and is too focused on fundraising. According to the lecture, how should the director\'s behavior be evaluated?',opts:['The director is showing early signs of Founder Syndrome and is concentrating power through financial control.', 'The director is correctly executing resource mobilization as a core leadership responsibility, which typically takes 30-50% of a senior leader\'s time.', 'The director is failing to manage internal staff and should delegate all fundraising to a dedicated department.', 'The director is practicing Impact Theater by focusing on external public relations rather than program delivery.'],ans:1,exp:'Resource mobilization is leadership work, not just a department. Senior leaders typically spend 30-50% of their time on fundraising, and there is no shame in doing so.',applied:true},
{id:308,topic:'l5',type:'mcq',text:'[APPLIED] A non-profit focused on literacy is preparing its annual report. The program manager lists: \'20 training workshops held, 500 literacy manuals printed, and 15 schools visited.\' The executive director requests that the manager revise the report to show what actually changed in the community as a result of these activities. Under the Logic Model framework, what category do the manager\'s current metrics belong to, and what should they be shifted toward?',opts:['They are Inputs, and should be shifted toward Activities to show the logic.', 'They are Outputs, and should be shifted toward Outcomes and Impact to show the changes in knowledge, behavior, or policy.', 'They are Outcomes, and should be shifted toward Inputs to show financial accountability.', 'They are Impacts, and should be shifted toward Outputs to show concrete physical targets.'],ans:1,exp:'Workshops held, manuals printed, and schools visited are Outputs (what the organization does/produces). Outcomes represent the changes (e.g., literacy rates improved, knowledge gained), and Impact is the long-term shift.',applied:true},
{id:309,topic:'l5',type:'mcq',text:'[APPLIED] A human rights organization has secured three large international grants that cover 90% of its budget. As a result, the leader shifts the organization\'s programs to align closely with the donor\'s global priority areas, and the staff spends most of their time preparing compliance reports. When a local crisis arises, the leader is unable to speak out because the donor\'s policies forbid political advocacy. What failure mode has this organization fallen into?',opts:['Founder Syndrome', 'Donor Dependency', 'Impact Theater', 'Mission Drift'],ans:1,exp:'Donor Dependency occurs when an organization\'s programs shift to match funder preferences, staff time tilts toward reporting, and the leader loses the freedom to disagree or respond to local needs.',applied:true},
{id:310,topic:'l5',type:'mcq',text:'[APPLIED] A non-profit leader pushes their project team to work late nights, weekends, and holidays to meet a donor\'s aggressive project timeline. The leader claims that \'our mission is sacred, and we must sacrifice our personal lives for the cause.\' Within six months, half the team resigns, and the remaining staff make critical errors in project delivery. According to the lecture\'s analysis of organizational culture, what does this situation demonstrate?',opts:['The natural and necessary cost of achieving high social impact.', 'A healthy culture of sacrifice that separates true leaders from regular workers.', 'Burnout culture, where the mission is used to justify exploiting staff, leading to worse decisions and a loss of moral authority.', 'Programmatic sustainability where organizational efficiency is maximized.'],ans:2,exp:'Burnout culture uses the mission to justify exploiting staff. It leads to poor decisions, harsh treatment of people, and loss of moral authority. You cannot pour from an empty vessel.',applied:true},
{id:311,topic:'l5',type:'mcq',text:'[APPLIED] An educational NGO claims to have \'transformed the lives of 10,000 students\' by distributing free notebooks to schools. Their social media pages are filled with professional videos of students holding notebooks. However, a local journalist discovers that many of these schools do not have teachers, and the notebooks are left unused in storage. Which failure mode does this scenario illustrate?',opts:['Founder Syndrome', 'Donor Dependency', 'Impact Theater', 'Mission Drift'],ans:2,exp:'Impact Theater occurs when an organization becomes highly skilled at telling its story but loses interest in whether the story is true or if real impact is occurring.',applied:true},
{id:312,topic:'l5',type:'mcq',text:'[APPLIED] A new non-profit leader is setting up a governance structure under CAMA 2020 in Nigeria. The legal advisor suggests incorporating the organization either as Incorporated Trustees or as a Company Limited by Guarantee. The leader asks how these legal forms compare to corporate models in terms of financial surpluses. What is the correct answer based on the lecture\'s definition of a non-profit?',opts:['Non-profits under CAMA 2020 are prohibited from generating any financial surplus or receiving donations.', 'Non-profits can generate surplus revenue, but it must be reinvested into the mission rather than distributed to owners or shareholders.', 'Non-profits must distribute at least 50% of their annual surplus to the founders as compensation.', 'Non-profits can distribute profit to their board of trustees, but not to the executive director.'],ans:1,exp:'A non-profit is an entity whose primary purpose is to advance a mission, not to distribute profit. Surplus revenue is reinvested into the mission (\'mission first, money second\').',applied:true},
{id:313,topic:'l5',type:'mcq',text:'[APPLIED] During a strategic review, the board of an environmental NGO asks the executive director to define the organization\'s \'Values.\' The director responds that values are simply the slogans printed on the organization\'s brochures. According to the lecture\'s framework of Mission, Vision, and Values, what is the correct definition of values that the director missed?',opts:['Values represent the financial targets and fundraising quotas for the next five years.', 'Values are the principles that the organization will not violate, even when it is costly to uphold them.', 'Values are the future outcomes the organization hopes to achieve if all its projects succeed.', 'Values are the present-tense descriptions of what the organization does, for whom, and why.'],ans:1,exp:'Values are defined as the principles that the organization will not violate, even when it is costly. Mission is present-tense, Vision is future-tense, and Values are the ethical tense.',applied:true},
{id:314,topic:'l5',type:'mcq',text:'[APPLIED] A non-profit leader is evaluating their organization\'s sustainability. They note that while they have high community trust and excellent program results (strong programmatic and environmental sustainability), they have no cash reserves and rely on a single donor who is phasing out funding. According to the Sustainability Quadrant, what is the status of this organization?',opts:['Stable, because community trust and programmatic quality are the only things that matter.', 'Fragile, because being strong in only one or two dimensions of the Sustainability Quadrant means the organization is vulnerable to collapse.', 'Resilient, because financial diversification can be easily achieved if program quality is high.', 'Sustainable, since environmental tailwinds will naturally attract new donors.'],ans:1,exp:'The Sustainability Quadrant includes four dimensions: Financial, Programmatic, Organizational, and Environmental. If an organization is strong in only one or two, it is fragile.',applied:true},
{id:315,topic:'l5',type:'mcq',text:'[APPLIED] A social change organization wants to measure the impact of its community dialogue sessions. The lead evaluator argues that because they cannot quantify \'restored dignity\' or \'civic awakening\' on a numerical dashboard, these outcomes should be excluded from reports. Based on the lecture\'s guidance on measurement, how should the leader respond?',opts:['Agree with the evaluator, since only quantifiable metrics are acceptable to modern institutional donors.', 'Reject the evaluator\'s view; the answer is not to abandon measurement or pretend everything can be quantified, but to combine numbers with stories.', 'Dismiss the evaluator and stop collecting quantitative data altogether, relying only on qualitative stories.', 'Change the organization\'s programs so that they only produce easily quantifiable outputs, such as pamphlets distributed.'],ans:1,exp:'The lecture notes that some of the most important changes (restored dignity, civic awakening) resist dashboards. The answer is to combine numbers with stories and be honest about what each can tell.',applied:true},
{id:316,topic:'l5',type:'mcq',text:'[APPLIED] A community-based organization in a highly volatile political region is forced to cancel its physical training sessions due to government restrictions. The executive director decides to immediately transition all training to a radio-based curriculum, despite having to rewrite the entire strategy. According to the six core competencies of non-profit leaders, which competency is the director demonstrating?',opts:['Vision Discipline', 'Resource Mobilization', 'Adaptive Decision-Making', 'Stewardship'],ans:2,exp:'Adaptive decision-making is critical because non-profit leaders operate under high uncertainty. Vision describes the destination, but strategy describes the route, and routes must change when obstacles arise.',applied:true},
{id:317,topic:'l5',type:'mcq',text:'[APPLIED] A non-profit leader is approached by a local business that offers to sponsor a clean-water project in exchange for the leader endorsing the business\'s controversial labor practices. The leader declines the offer, stating that maintaining the organization\'s moral standing is more important than the funding. Which dimension of non-profit leadership authority does this decision reflect?',opts:['Ownership & contracts, which dictate that non-profits must reject all corporate partnerships.', 'Moral credibility and trust, which are the primary sources of authority for non-profit leadership and must be preserved at all costs.', 'Customer transactions, which prioritize the financial returns of beneficiaries over corporate sponsors.', 'Market discipline, which requires non-profits to align with the most profitable corporate entities.'],ans:1,exp:'Unlike corporate leaders whose authority comes from ownership & contracts, a non-profit leader\'s authority comes from moral credibility & trust. Once lost, nothing else holds the organization together.',applied:true},
{id:318,topic:'l5',type:'mcq',text:'[APPLIED] An advocacy group wants to address chronic malnutrition in a low-income urban community. Instead of organizing another temporary food distribution drive, they set up a community garden and train local families in sustainable urban farming. Which principle of social change does this transition illustrate?',opts:['The difference between systemic change and cultural change, where systemic change focuses on farming.', 'The distinction between relief and social change; a one-time food distribution is relief, whereas a community learning to feed itself is change.', 'The shift from financial sustainability to environmental sustainability.', 'The driver of demographic change overriding economic pressure.'],ans:1,exp:'The lecture states: \'A one-time food distribution is relief. A community that learns to feed itself is change.\' Social change is a meaningful, durable shift in conditions, behaviors, structures, or beliefs.',applied:true},
{id:319,topic:'l5',type:'mcq',text:'[APPLIED] A non-profit leader is building a coalition to advocate for educational reform. The leader first asks, \'How can we make our organization the primary brand and lead partner in this campaign?\' instead of asking, \'Who else cares about this cause and how can we work together?\' According to the competency of Coalition Building, what mistake is the leader making?',opts:['They are failing to focus on corporate transactions to fund the campaign.', 'They are prioritizing the organization\'s growth and recognition over the cause itself, whereas effective coalition building puts the cause first.', 'They are neglecting the legal requirements of CAMA 2020 regarding partnerships.', 'They are failing to realize that coalition building must exclude government agencies.'],ans:1,exp:'Most social problems are too large for any single organization. Effective leaders ask \'Who else cares about this?\' before \'How do we grow?\' because the right question is about the cause, not the organization.',applied:true},
{id:320,topic:'l5',type:'mcq',text:'[APPLIED] A young activist wants to launch an NGO. They spend three months writing a complex business plan, designing a logo, and researching donor databases. However, they have not yet spoken to any members of the community they wish to serve to understand their unmet needs. According to Mother Teresa\'s approach to vision discipline cited in the lecture, what is the activist missing?',opts:['A strong corporate background and formal business credentials.', 'Vision discipline begins with identifying a real, currently unmet need and asking, \'Whose pain am I willing to live near?\' rather than focusing on administrative planning.', 'The activist should have registered the organization under CAMA 2020 first.', 'The activist is missing a diversified fundraising department.'],ans:1,exp:'Mother Teresa did not start with a strategic plan; she began with the question, \'Whose pain am I willing to live near?\' Vision is anchored in a real, currently unmet need.',applied:true},
{id:321,topic:'l5',type:'mcq',text:'According to the opening pages of the Lecture 5 material, why is the conversation around non-profit leadership and social change particularly critical in the current global era?',opts:['Because corporate salaries have reached an all-time high, making non-profits less attractive to graduates.', 'Because compounding crises such as widening regional inequality, eroding public trust in institutions, and deepening education and mental health gaps cannot be solved by any single sector alone.', 'Because governments have expanded their reach to every local community, leaving non-profits to focus only on cultural narratives.', 'Because market forces have successfully resolved most economic gaps, shifting non-profit focus purely to scientific research.'],ans:1,exp:'The lecture states that we live in an era of compounding crises that no single sector can solve alone. Governments cannot reach everywhere, and markets will not go everywhere.'},
{id:322,topic:'l5',type:'mcq',text:'The thesis of Lecture 5 asserts a fundamental distinction between non-profit leadership and other leadership disciplines. Which of the following statements matches the lecture\'s thesis?',opts:['Non-profit leadership is essentially corporate leadership adapted for a smaller building.', 'Non-profit leadership is government leadership without the high salary and pension benefits.', 'Non-profit leadership is its own discipline—a craft to be learned, where leadership is the difference between activity and impact.', 'Non-profit leadership relies entirely on accidental social change and charismatic personalities.'],ans:2,exp:'Page 3 states: \'Leadership is the difference between activity and impact. Non-profit leadership is its own discipline. It is not corporate leadership in a smaller building... it is a craft to be learned.\''},
{id:323,topic:'l5',type:'mcq',text:'Under the CAMA 2020 legal framework referenced in the lecture, which two primary legal forms are available for non-profit organizations in Nigeria?',opts:['Limited Liability Partnership and Sole Proprietorship', 'Incorporated Trustees and Company Limited by Guarantee', 'Public Limited Company and Cooperative Society', 'Private Unlimited Company and Joint Venture'],ans:1,exp:'Page 4 notes that legal forms vary under CAMA 2020, specifically mentioning \'Incorporated Trustees\' and \'Company Limited by Guarantee\' as examples.'},
{id:324,topic:'l5',type:'mcq',text:'What are the five mission domains explicitly listed in the lecture as spanning the work of non-profit organizations?',opts:['Financial, Technological, Agricultural, Medical, and Legal', 'Social, Educational, Religious, Scientific, and Cultural', 'Political, Industrial, Commercial, Environmental, and Military', 'Local, National, Regional, Continental, and Global'],ans:1,exp:'Page 4 states: \'Mission domains span Social, Educational, Religious, Scientific, and Cultural work.\''},
{id:325,topic:'l5',type:'mcq',text:'How does the lecture define the concept of \'non-profit leadership\' as a \'disciplined art\'?',opts:['The art of managing public relations to maximize donor contributions while minimizing tax liabilities.', 'The disciplined art of converting a social vision into measurable, sustainable change by mobilizing people and resources, while maintaining moral credibility and mission integrity over time.', 'The practice of running an organization strictly through volunteer labor to eliminate operational costs.', 'The process of lobbying government institutions to take over the financial liabilities of the non-profit.'],ans:1,exp:'Page 5 provides this exact definition of non-profit leadership. It combines rigor with judgment to convert vision into sustainable change.'},
{id:326,topic:'l5',type:'mcq',text:'In comparing Corporate and Non-profit leadership, the lecture outlines key differences in the \'Resource model\' dimension. Which of the following correctly describes this difference?',opts:['Corporate relies on government grants; Non-profit relies on customer transactions.', 'Corporate relies on customer transactions; Non-profit relies on donor relationships.', 'Corporate relies on volunteer labor; Non-profit relies on equity investments.', 'Corporate relies on long-term debt; Non-profit relies on equity crowdfunding.'],ans:1,exp:'Page 6 shows a table where the resource model for Corporate is \'Customer transactions\' and for Non-profit is \'Donor relationships.\''},
{id:327,topic:'l5',type:'mcq',text:'Peter F. Drucker is quoted in the lecture regarding the difficulty of leading non-profit organizations. What reason does the lecture give for this difficulty?',opts:['Non-profits are too small to attract professional managers.', 'Non-profits have no single bottom line and must satisfy multiple groups with competing expectations, meaning the discipline must come from the leader.', 'Non-profits are heavily taxed compared to corporate entities.', 'Non-profits are legally barred from hiring full-time staff.'],ans:1,exp:'Page 7 states that non-profits have no single bottom line; they must satisfy donors, beneficiaries, staff, regulators, and the public. \'Difficulty is the price of meaning.\''},
{id:328,topic:'l5',type:'mcq',text:'How does the lecture define \'Social Change\' and distinguish it from simple \'relief\'?',opts:['Social change is temporary financial assistance, while relief is long-term economic development.', 'Social change is a meaningful, durable shift in the conditions, behaviors, structures, or beliefs of a society, whereas relief is a temporary intervention like a one-time food distribution.', 'Social change is driven only by technology, while relief is driven only by charismatic leaders.', 'Social change is legal reform, while relief is the slow accumulation of changed minds.'],ans:1,exp:'Page 8 defines social change as meaningful and durable, contrasting a one-time food distribution (relief) with a community learning to feed itself (change).'},
{id:329,topic:'l5',type:'mcq',text:'The lecture identifies four levels of social change. What are these four levels in order of scope from individual to societal?',opts:['Local, Regional, National, and International', 'Primary, Secondary, Tertiary, and Quaternary', 'Individual, Community, Systemic, and Cultural', 'Economic, Political, Environmental, and Technological'],ans:2,exp:'Page 9 outlines the four levels: Individual (knowledge/skill), Community (practices/capacities), Systemic (policies/structures), and Cultural (beliefs/narratives).'},
{id:330,topic:'l5',type:'mcq',text:'In the case study of BRAC, how did the organization demonstrate impact at the \'Systemic\' level of social change?',opts:['By distributing basic relief packages to war victims in 1971.', 'By developing microfinance programs to build community capacity.', 'By influencing government educational policies and having their education models adopted by governments.', 'By changing global development thinking and development narratives.'],ans:2,exp:'Page 10 states that BRAC \'influenced systems through education models adopted by governments.\''},
{id:331,topic:'l5',type:'mcq',text:'What is a \'Theory of Change\' as described in the lecture, and why is it essential for a non-profit leader?',opts:['A financial spreadsheet that predicts the organization\'s cash flow over ten years.', 'A leader\'s explicit hypothesis about how their activities will produce the outcomes they seek, without which the organization is essentially guessing.', 'A legal document required by CAMA 2020 to verify the board structure.', 'A marketing campaign designed to increase donor engagement.'],ans:1,exp:'Page 11 defines a Theory of Change as the leader\'s explicit hypothesis about how activities produce outcomes. \'A weak theory of change is a strategy waiting to fail.\''},
{id:332,topic:'l5',type:'mcq',text:'The lecture lists several \'Drivers of Social Change.\' Which of the following is NOT one of the drivers listed on Page 13 of the text?',opts:['Shifts in technology and economic pressure', 'Demographic change and organized movements', 'Charismatic leadership and legal reform', 'Corporate profit distribution and market deregulation'],ans:3,exp:'Page 13 lists shifts in technology, economic pressure, demographic change, charismatic leadership, organized movements, legal reform, and the slow accumulation of changed minds. It does not list corporate profit distribution.'},
{id:333,topic:'l5',type:'mcq',text:'How does the competency of \'Stewardship\' frame the non-profit leader\'s relationship with the organization\'s assets and people?',opts:['The leader is the owner of the mission and resources, and the staff are instruments of the leader.', 'The leader is a steward, not an owner: the mission belongs to the cause, resources belong to those who entrusted them, and staff belong to themselves.', 'The leader must prioritize donor satisfaction over staff well-being in all circumstances.', 'The leader\'s primary role is to maximize the organization\'s physical assets and reserve capital.'],ans:1,exp:'Page 16 explains that the leader is a steward, not an owner, and must honor relationships without treating stakeholders instrumentally.'},
{id:334,topic:'l5',type:'mcq',text:'In the Green Belt Movement case study, what did Wangari Maathai observe that others missed regarding the environmental challenges in Kenya in 1977?',opts:['That the problem was purely technical and required imported tree species.', 'That the environmental problem of firewood scarcity had deep political and gendered roots.', 'That the government had sufficient funds to execute reforestation without community involvement.', 'That rural women were unwilling to participate in environmental work.'],ans:1,exp:'Page 23 notes that Maathai saw that while the problem looked environmental, its roots were political and gendered, and she addressed it by empowering rural women.'},
{id:335,topic:'l5',type:'mcq',text:'According to the counter-example \'When Charisma Fails,\' what structural flaws led to the collapse of the well-funded education non-profit within seven years?',opts:['A lack of donor funding and celebrity support.', 'The founder concentrated power, refused board strength, and treated criticism as betrayal.', 'The government intervened and took over the school sites.', 'The organization diversified its revenue streams too quickly.'],ans:1,exp:'Page 26 explains that the organization collapsed because the founder concentrated power, had a decorative board, and rejected criticism. \'Charisma without structure is a fuse.\''},
{id:336,topic:'l5',type:'mcq',text:'How does the lecture differentiate between a non-profit\'s \'Mission\' and \'Vision\' in Framework 1?',opts:['Mission is future-oriented; Vision is present-oriented.', 'Mission describes what we do, for whom, and why (present tense); Vision describes what the world looks like if we succeed (future tense).', 'Mission is ethical; Vision is financial.', 'Mission belongs to the board; Vision belongs to the founder.'],ans:1,exp:'Page 27 defines Mission as present tense (what we do, for whom, why) and Vision as future tense (what the world looks like if we succeed).'},
{id:337,topic:'l5',type:'mcq',text:'What are the five elements of \'The Logic Model\' framework in order from resources to long-term impact?',opts:['Funding, Staff, Partnerships, Time, and Reforestation', 'Inputs, Activities, Outputs, Outcomes, and Impact', 'Mission, Vision, Values, Operations, and Governance', 'Planning, Execution, Measurement, Reporting, and Evaluation'],ans:1,exp:'Page 29 outlines the Logic Model elements: Inputs, Activities, Outputs, Outcomes, and Impact.'},
{id:338,topic:'l5',type:'mcq',text:'What are the four dimensions of \'The Sustainability Quadrant\' that every non-profit must monitor?',opts:['Local, National, Regional, and Global', 'Planning, Implementation, Evaluation, and Adaptation', 'Financial, Programmatic, Organizational, and Environmental', 'Donors, Beneficiaries, Regulators, and Staff'],ans:2,exp:'Page 30 lists the four dimensions as Financial, Programmatic, Organizational, and Environmental sustainability.'},
{id:339,topic:'l5',type:'mcq',text:'How does Pitfall 1 (Mission Drift) typically begin in a non-profit organization?',opts:['With a sudden change of the executive director by the board.', 'As a series of small \'yes\' answers to attractive opportunities, such as a grant that is slightly off-mission.', 'With an immediate loss of all donor funding.', 'By strictly adhering to the original logic model.'],ans:1,exp:'Page 28 and 32 state that mission drift almost always begins as a series of small \'yes\' answers to attractive opportunities.'},
{id:340,topic:'l5',type:'mcq',text:'Under Pitfall 3 (Donor Dependency), what is the long-term risk of relying on one or two large funders?',opts:['The organization will be forced to pay taxes on the donations.', 'The organization\'s programs shift to match funder preferences, the leader loses the freedom to disagree, and independence dies.', 'The board of trustees will be dissolved under CAMA 2020.', 'The founder will be replaced by a corporate executive.'],ans:1,exp:'Page 34 states that donor dependency captures an organization, causing programs to shift, staff time to tilt to reporting, and the leader to lose independence.'},
{id:341,topic:'l5',type:'mcq',text:'The lecture notes that some of the most important social changes \'resist dashboards.\' What does this mean for non-profit evaluation?',opts:['Leaders should stop measuring programs altogether.', 'Important changes like restored dignity or cultural shifts cannot be easily quantified; therefore, leaders must combine numbers with stories.', 'Donors will reject any qualitative descriptions of social change.', 'Quantitative metrics are the only valid form of social impact measurement.'],ans:1,exp:'Page 31 discusses how changes like restored dignity or civic awakening resist dashboards, requiring a combination of numbers and stories.'},
{id:342,topic:'l5',type:'mcq',text:'In the \'Personal Resilience\' competency, what does the phrase \'You cannot pour from an empty vessel\' imply for non-profit leaders?',opts:['Leaders must not distribute funds until the bank account is full.', 'Burnout is endemic, and self-care is a leadership responsibility because a depleted leader makes worse decisions and loses moral authority.', 'Non-profits must recruit volunteers before hiring full-time staff.', 'The organization must establish a trust fund before executing programs.'],ans:1,exp:'Page 20 outlines that self-care is a leadership responsibility because depletion leads to poor decisions and loss of moral authority.'},
{id:343,topic:'l5',type:'mcq',text:'In the Green Belt Movement case study, what was the \'simple idea\' that led to decades of disciplined execution and a Nobel Peace Prize?',opts:['Providing free solar panels to rural families.', 'Paying rural women a stipend to plant trees.', 'Building high schools for girls in Nairobi.', 'Establishing microfinance banks in urban slums.'],ans:1,exp:'Page 21 explains that Wangari Maathai started in 1977 by paying rural women a stipend to plant trees.'},
{id:344,topic:'l5',type:'mcq',text:'According to Page 37 of the lecture text, why does the non-profit sector exist at all?',opts:['Because governments and markets have decided to delegate all social welfare to volunteer networks.', 'Because governments cannot reach every gap, markets will not serve every need, and some things must be done that nobody else will do.', 'Because non-profits offer higher salaries and better career progression than corporate firms.', 'Because it is a legal requirement under CAMA 2020 for all citizens to run an NGO.'],ans:1,exp:'Page 37 states that governments cannot reach everywhere and markets will not go everywhere. The sector exists for what others will not do.'},
{id:345,topic:'l5',type:'mcq',text:'According to the conclusion of Lecture 5, where does a person\'s non-profit leadership truly begin?',opts:['When they register their organization under CAMA 2020.', 'When they receive their first international grant.', 'When they answer what need they are willing to meet even when nobody is watching, paying, or applauding.', 'When they are elected to a corporate board of directors.'],ans:2,exp:'Page 38 concludes that leadership begins with the question of what need you are willing to meet when no one is watching, paying, or applauding.'},
{id:346,topic:'l5',type:'multi',text:'[APPLIED] A community organization is designing an initiative to reduce plastic waste in a coastal city. The project manager wants to ensure the program has a strong, detailed Theory of Change rather than a weak one. Select ALL elements that the manager must explicitly define to build a \'strong\' theory of change according to the lecture\'s examples:',opts:['The specific mechanism of change (e.g., training trusted mentors, providing bin access)', 'The specific actors and target population involved', 'The timeline for the outcomes to manifest', 'The magnitude of the expected change (e.g., 30% reduction)', 'The underlying assumptions or evidence backing the links', 'The celebrity endorsements and social media marketing channels'],ans:[0, 1, 2, 3, 4],exp:'Page 12 states that a strong theory of change names the mechanism, the actors, the timeline, the magnitude, and the assumptions, distinguishing it from a weak version which merely asserts activities and outcomes.',applied:true},
{id:347,topic:'l5',type:'multi',text:'[APPLIED] A non-profit is experiencing severe operational difficulties. The board suspects \'Founder Syndrome\' is occurring. Select ALL symptoms from the list below that would confirm the presence of Founder Syndrome according to the lecture:',opts:['Authority is highly concentrated in the founder rather than distributed.', 'The board of trustees is decorative and does not actively deliberate or hold the founder accountable.', 'Succession planning is treated as an unmentionable topic.', 'The founder frequently confuses their personal identity with the mission of the organization.', 'The organization relies heavily on earned income activities to sustain operations.', 'Program decisions are made strictly based on rigorous external evaluations.'],ans:[0, 1, 2, 3],exp:'Page 33 identifies the symptoms of Founder Syndrome: concentrated authority, decorative board, unmentionable succession, and the founder confusing themselves with the mission.',applied:true},
{id:348,topic:'l5',type:'multi',text:'[APPLIED] A national development NGO wants to evaluate its long-term work using BRAC\'s multi-level change model. Select ALL the correct pairings of BRAC\'s activities and their corresponding levels of social change as described in the lecture:',opts:['Relief for individuals - Individual level', 'Microfinance for communities - Community level', 'Education models adopted by governments - Systemic level', 'Shaping global development thinking - Cultural level', 'Providing free food packages indefinitely - Systemic level', 'Establishing local chess tournaments - Cultural level'],ans:[0, 1, 2, 3],exp:'Page 10 lists the four levels BRAC worked at: relief for individuals, microfinance for communities, education models adopted by governments (systemic), and contributing to a cultural shift in global development thinking.',applied:true},
{id:349,topic:'l5',type:'multi',text:'According to the comparison table on Page 6 of the lecture, what are the three key dimensions in which Corporate leadership differs from Non-profit leadership?',opts:['Measure of success (Financial return vs Social impact)', 'Source of authority (Ownership & contracts vs Moral credibility & trust)', 'Resource model (Customer transactions vs Donor relationships)', 'Legal registration under CAMA 2020', 'Use of digital technology and social media'],ans:[0, 1, 2],exp:'Page 6 details the dimensions: Measure of success, Source of authority, and Resource model, showing how they differ between corporate and non-profit settings.'},
{id:350,topic:'l5',type:'multi',text:'Under the \'Drucker Insight\' on Page 7, who are the competing groups of stakeholders that a non-profit leader must satisfy, making these organizations demanding to lead?',opts:['Donors', 'Beneficiaries', 'Staff', 'Regulators', 'The general public', 'Corporate shareholders'],ans:[0, 1, 2, 3, 4],exp:'Page 7 states: \'They must satisfy donors, beneficiaries, staff, regulators, and the public. Expectations from each group often compete.\''},
{id:351,topic:'l5',type:'multi',text:'The lecture lists several core competencies of a non-profit leader on Page 14. Select ALL competencies that are explicitly part of this list:',opts:['Vision discipline', 'Resource mobilization', 'Coalition building', 'Personal resilience and self-care', 'Academic credentialing', 'Profit maximization'],ans:[0, 1, 2, 3],exp:'Page 14 lists the six competencies: Vision discipline, Stewardship & stakeholder management, Resource mobilization, Coalition building, Adaptive decision-making, and Personal resilience & self-care.'},
{id:352,topic:'l5',type:'multi',text:'In the case study of Wangari Maathai and the Green Belt Movement, what lessons are drawn regarding her leadership approach on Page 23?',opts:['The problem looked environmental, but its roots were political and gendered.', 'She started with one need and one action.', 'She accepted years of harassment without abandoning the work.', 'When global attention came, she amplified the women on the ground rather than herself.', 'She focused on building corporate partnerships with logging companies'],ans:[0, 1, 2, 3],exp:'Page 23 outlines these lessons from Maathai: environmental issues had political/gendered roots, started with one action, withstood harassment, and amplified grassroots women.'},
{id:353,topic:'l5',type:'multi',text:'Under Framework 1 (Page 27), what are the three questions that every well-led non-profit should be able to answer to align its Mission, Vision, and Values?',opts:['What do we do, for whom, and why? (Mission)', 'What does the world look like if we succeed? (Vision)', 'What principles will we not violate, even when it is costly? (Values)', 'How much money do we need to raise this quarter?', 'Who is the founder and how can we highlight them?'],ans:[0, 1, 2],exp:'Page 27 lists the three questions corresponding to Mission, Vision, and Values.'},
{id:354,topic:'l5',type:'multi',text:'According to Page 35 of the lecture, what are the two negative failure modes that often travel together when a leader stops doing \'inner work\'?',opts:['Impact theater', 'Burnout culture', 'Founder Syndrome', 'Donor dependency', 'Mission drift'],ans:[0, 1],exp:'Page 35 states that \'Impact theater\' and \'Burnout culture\' are two failure modes that travel together, signaling a leader who has stopped doing inner work.'},
{id:355,topic:'l5',type:'multi',text:'Under Pitfall 1 (Mission Drift) and Pitfall 2 (Founder Syndrome), what are the recommended prevention strategies mentioned in the lecture?',opts:['Discipline in saying no and regular mission audits (for Mission Drift)', 'Distributing authority from year one and building a board that can fire the founder (for Founder Syndrome)', 'Concentrating all financial decision-making in the founder\'s office', 'Shifting program activities to match donor preferences immediately'],ans:[0, 1],exp:'Page 32 and 33 recommend discipline in saying no/regular audits to prevent mission drift, and distributing authority/building an independent board to prevent founder syndrome.'},
{id:356,topic:'l5',type:'short',text:'[APPLIED] A non-profit leader in Lagos wants to ensure their organization has a clear visual representation on a single page showing how their funding and activities lead directly to output metrics and long-term societal changes. What is the name of this specific management framework?',ans:'Logic Model',exp:'Page 29 defines the Logic Model as a one-page diagram that links what you do to what changes (Inputs, Activities, Outputs, Outcomes, Impact).',applied:true},
{id:357,topic:'l5',type:'short',text:'[APPLIED] A youth empowerment NGO in Nigeria is trying to register under the CAMA 2020 legal framework. They do not want to be structured as a company limited by guarantee, but prefer a traditional board of trustees to hold their assets. Which specific CAMA 2020 legal form should they select?',ans:'Incorporated Trustees',exp:'Page 4 mentions Incorporated Trustees as one of the legal forms under CAMA 2020 for non-profit organizations.',applied:true},
{id:358,topic:'l5',type:'short',text:'[APPLIED] A new non-profit leader wants to design a clear statement that answers the question: \'What does the world look like if we succeed?\' in the future tense. What is the term for this statement?',ans:'Vision',exp:'Page 27 states that Vision answers \'What does the world look like if we succeed?\' in the future tense.',applied:true},
{id:359,topic:'l5',type:'short',text:'Which global development organization, founded in Bangladesh in 1971 by Sir Fazle Hasan Abed, represents a classic case study of operating at all four levels of social change over fifty years?',ans:'BRAC',exp:'Page 10 details BRAC as the case study representing four levels of change over fifty years.'},
{id:360,topic:'l5',type:'short',text:'What is the two-word version of the term (omitting the word \'of\') used for the leader\'s explicit hypothesis about how their activities will produce outcomes?',ans:'Theory Change',exp:'Page 11 defines a Theory of Change (in two words: Theory Change) as the leader\'s explicit hypothesis about how activities produce outcomes.'},
{id:361,topic:'l5',type:'short',text:'What is the specific term used on Page 35 of the lecture to describe the failure mode where an organization becomes highly skilled at telling its story but loses interest in whether that story is true?',ans:'Impact Theater',exp:'Page 35 defines impact theater as when the organization becomes skilled at storytelling but loses interest in the truth of the impact.'},
{id:362,topic:'l5',type:'short',text:'Which Nobel Peace Prize laureate founded the Green Belt Movement in Kenya in 1977?',ans:'Wangari Maathai',exp:'Page 21 introduces Wangari Maathai as the founder of the Green Belt Movement.'},
{id:363,topic:'l5',type:'short',text:'What is the term used in the lecture to describe the organizational failure mode where authority is concentrated in the founder, the board is decorative, and succession planning is unmentionable?',ans:'Founder Syndrome',exp:'Page 33 defines the symptoms of Founder Syndrome.'},
{id:364,topic:'l5',type:'short',text:'What is the first and lowest level of social change in the four-level hierarchy, which focuses on changes in a single person\'s knowledge, skill, or well-being?',ans:'Individual',exp:'Page 9 lists \'Individual\' as the first level of social change.'},
{id:365,topic:'l5',type:'short',text:'According to the comparison table on Page 6, what is the primary \'Measure of success\' for a corporate organization?',ans:'Financial return',exp:'Page 6 compares corporate (Financial return) and non-profit (Social impact) success measures.'},
{id:366,topic:'l5',type:'fill',text:'[APPLIED] An international aid group is evaluating its programs in West Africa. The evaluator notes that their emergency soup kitchen represents a form of _______, whereas their long-term project to establish cooperative community farming represents true _______.',dropdowns:[['relief', 'development', 'sustainability', 'advocacy'], ['relief', 'change', 'charity', 'reform']],ans:['relief', 'change'],exp:'Page 8 states: \'A one-time food distribution is relief. A community that learns to feed itself is change.\'',applied:true},
{id:367,topic:'l5',type:'fill',text:'[APPLIED] A non-profit founder in Lagos is struggling to say \'no\' to prestigious but unrelated donor grants. The board warns that if they accept a grant that is slightly off-mission, it will trigger the start of _______, which will result in the organization experiencing _______ five years later.',dropdowns:[['Mission Drift', 'Founder Syndrome', 'Donor Dependency', 'Impact Theater'], ['organizational decay', 'loss of purpose', 'doing something it never set out to do', 'financial collapse']],ans:['Mission Drift', 'doing something it never set out to do'],exp:'Page 28 and 32 detail how Mission Drift begins as small \'yes\' answers and leads to doing what was never set out.',applied:true},
{id:368,topic:'l5',type:'fill',text:'According to the lecture, \'governments _______ reach everywhere; markets _______ go everywhere.\'',dropdowns:[['cannot', 'will not', 'do not', 'should not'], ['cannot', 'will not', 'do not', 'should not']],ans:['cannot', 'will not'],exp:'Page 2 states: \'Governments CANNOT reach everywhere; markets will not go everywhere.\''},
{id:369,topic:'l5',type:'fill',text:'In comparing leadership roles, \'corporate success is measured by _______, while non-profit success is measured by _______.\'',dropdowns:[['financial return', 'social impact', 'market share', 'customer loyalty'], ['financial return', 'social impact', 'donor relationship', 'moral credibility']],ans:['financial return', 'social impact'],exp:'Page 6 table compares the measures of success: Corporate (Financial return) vs Non-profit (Social impact).'},
{id:370,topic:'l5',type:'fill',text:'Peter F. Drucker famously stated that \'non-profits are the most _______ organizations to lead\' because they have no single _______.',dropdowns:[['demanding', 'rewarding', 'complex', 'difficult'], ['bottom line', 'funding source', 'mission statement', 'board of directors']],ans:['demanding', 'bottom line'],exp:'Page 7 states: \'Non-profits are the most demanding organizations to lead... They have no single bottom line.\''},
{id:371,topic:'l5',type:'fill',text:'The lecture warns that \'a weak theory of change is a _______ waiting to _______.\'',dropdowns:[['strategy', 'mission', 'plan', 'program'], ['fail', 'stall', 'collapse', 'drift']],ans:['strategy', 'fail'],exp:'Page 11 states: \'A weak theory of change is a strategy waiting to fail.\''},
{id:372,topic:'l5',type:'fill',text:'When analyzing the Green Belt Movement, \'the problem looked _______, but its roots were _______ and gendered.\'',dropdowns:[['environmental', 'agricultural', 'political', 'economic'], ['environmental', 'political', 'social', 'cultural']],ans:['environmental', 'political'],exp:'Page 23 notes: \'The problem looked environmental — but its roots were political and gendered.\''},
{id:373,topic:'l5',type:'fill',text:'In the counter-example of a collapsed non-profit, the author summarizes the lesson as: \'Charisma without _______ is a _______.\'',dropdowns:[['structure', 'funding', 'governance', 'vision'], ['fuse', 'disaster', 'failure', 'trap']],ans:['structure', 'fuse'],exp:'Page 26 concludes: \'Charisma without structure is a fuse.\''},
{id:374,topic:'l5',type:'fill',text:'Under the Sustainability Quadrant, a non-profit must monitor four dimensions: financial, programmatic, _______, and _______.',dropdowns:[['organizational', 'social', 'cultural', 'operational'], ['environmental', 'political', 'strategic', 'legal']],ans:['organizational', 'environmental'],exp:'Page 30 lists the four dimensions: Financial, Programmatic, Organizational, and Environmental.'},
{id:375,topic:'l5',type:'fill',text:'Regarding leadership well-being, the lecture stresses that \'burnout is _______ in the sector\' and \'you cannot pour from an _______.\'',dropdowns:[['endemic', 'common', 'temporary', 'unavoidable'], ['empty vessel', 'exhausted mind', 'empty cup', 'overworked staff']],ans:['endemic', 'empty vessel'],exp:'Page 20 states: \'Burnout is endemic in the sector... You cannot pour from an empty vessel.\''},
{id:376,type:'mcq',applied:true,text:'[APPLIED] A newly promoted regional director at a prominent logistics firm insists that because she holds the formal title, the team must comply with all her directives without question. She focuses on administrative control and sitting in the corner office rather than taking responsibility for the team\'s output. According to Dr. David Oyedepo\'s quote on the \'leadership illusion\' and the distinction between authority and influence, what is the core failure of this director\'s approach?',ans:1,exp:'Dr. David Oyedepo stated, \'Leadership is not occupying a seat — it is accomplishing a feat.\' The regional director has fallen into the leadership illusion by believing her title is the proof of her leadership rather than its starting point. She has confused being in charge (authority/title) with taking responsibility and delivering feats (influence/leadership).',topic:'l6',opts:['She fails to realize that authority is earned through competence, whereas titles only assign temporary control.', 'She confuses occupying a seat of authority with achieving team results, neglecting that true leadership is demonstrated by feat and responsibility.', 'She overlooks the necessity of maintaining strict boundaries between individual contributions and collective team goals.', 'She violates Tuckman\'s model by attempting to bypass the Forming stage of team development entirely.']},
{id:377,type:'mcq',applied:true,text:'[APPLIED] During a massive corporate restructuring, a financial institution transitions 84% of its workforce into cross-functional teams. However, after six months, performance metrics plummet, and employee survey results indicate that less than 20% of these teams have competent leadership. According to the Deloitte Global Human Capital Trends (2023) data, what does this gap represent, and what is the strategic lesson for organizational leaders?',ans:0,exp:'The Deloitte Global Human Capital Trends (2023) shows that while 84% of organizations have redesigned work around teams, less than 20% have the team leadership to match. This team leadership gap represents a significant opportunity and demonstrates that restructuring into teams must be accompanied by active team leadership development, as \'leaders are made, not endowed.\'',topic:'l6',opts:['It represents a team leadership gap, indicating that merely redesigning work around teams is insufficient without actively developing matching team leadership capacity.', 'It represents an autonomy gap, suggesting that teams should be given complete freedom without any central directional authority.', 'It represents a individual-collective gap, showing that individual performance metrics should take precedence over team-level outcomes.', 'It represents a generational gap, indicating that Baby Boomers and Millennials cannot collaborate effectively under team-based structures.']},
{id:378,type:'mcq',applied:false,text:'Tuckman\'s Model outlines the developmental stages of a team (Forming, Storming, Norming, and Performing). When a team leader attempts to accelerate this journey, they must understand that leadership capacity is not a static trait but an ongoing process. Which of the following statements best aligns with Dr. David Oyedepo\'s philosophy on leadership capacity as it relates to team development?',ans:1,exp:'Dr. David Oyedepo stated, \'Leadership capacity is about development — not endowment.\' This means that leaders are made through deliberate effort and learning, and their key role is to accelerate the team\'s developmental journey through the Tuckman model (Forming, Storming, Norming, Performing) by building and growing leadership skills.',topic:'l6',opts:['Leadership capacity is entirely an endowment, meaning team leaders are born with the ability to manage conflict during the Storming stage.', 'Leadership capacity is about development — not endowment, which means a leader\'s job is to actively facilitate and guide the team through each stage.', 'Leadership capacity is irrelevant once a team reaches the Norming stage, as the team becomes self-governing.', 'Leadership capacity relies solely on establishing a rigid hierarchy to prevent the Storming phase from occurring.']},
{id:379,type:'mcq',applied:true,text:'[APPLIED] A software engineering team at a high-pressure Lagos-based startup is working on a critical system migration. Although several senior developers notice potential flaws in the new architecture, they choose to remain silent during meetings because they fear being ridiculed or blamed by the lead architect. According to the findings of Google\'s Project Aristotle (which studied 180 teams over 2 years), what critical element is missing from this team, and what is its impact?',ans:2,exp:'Google\'s Project Aristotle found that the #1 predictor of team effectiveness was Psychological Safety — the belief that the team is safe for interpersonal risk-taking. In this scenario, the fear of ridicule or blame prevents developers from raising concerns, which undermines safety and leads to a higher risk of project failure.',topic:'l6',opts:['Role clarity is missing, which prevents the developers from understanding who is responsible for architecture reviews.', 'Shared vision is missing, which prevents the developers from aligning on the project\'s ultimate launch goals.', 'Psychological safety is missing, which acts as the number one predictor of team effectiveness and allows for interpersonal risk-taking.', 'Disciplined communication is missing, which prevents the team from documenting decisions in an asynchronous format.']},
{id:380,type:'mcq',applied:true,text:'[APPLIED] An elite research laboratory operates without any permanent director. Instead, leadership of project phases rotates dynamically among team members depending on who has the most relevant expertise for the current phase. This structure has allowed the lab to consistently out-innovate competitors. Which principle of team leadership is this lab demonstrating, and what is its core tenet?',ans:3,exp:'The Orpheus Principle, inspired by the Orpheus Chamber Orchestra (which has operated for 50+ years without a permanent conductor), states that leadership follows competence, not hierarchy. Leadership rotates to whoever is most prepared and matches the task, proving that the best team leaders sometimes follow.',topic:'l6',opts:['The Lencioni Principle, which asserts that minimizing the fear of conflict is the most critical factor in team performance.', 'The Oyedepo Principle, which states that a leader\'s worth is defined by their core contributions rather than their complements.', 'The Tuckman Principle, which argues that teams must go through Storming before they can achieve high performance.', 'The Orpheus Principle, which asserts that leadership follows competence, not hierarchy, and that who leads should match the task rather than the org chart.']},
{id:381,type:'mcq',applied:false,text:'The Five Pillars of high-performing teams include Shared Vision, Psychological Safety, Role Clarity, Disciplined Communication, and Accountability Without Blame. If an organization maintains high standards and psychological safety, but fails to define individual roles and boundaries, which of the following is the most likely consequence for the team\'s structure?',ans:1,exp:'The lecture states that the five pillars are interconnected, and removing one weakens the structure. Specifically, under Pillar 3 (Role Clarity), the lecture notes that \'Duplication + Uncovered Functions = Team Failure.\' Even if safety and standards are high, a lack of role clarity leads to inefficient overlap and missed responsibilities.',topic:'l6',opts:['The team will experience high toxicity and defensive behaviors because members will blame each other for project failures.', 'The team structure weakens, leading to duplication of efforts and uncovered functions, which ultimately results in team failure.', 'The team will fall into a state of passivity and complacency because safety alone removes all performance pressure.', 'The team will suffer from relationship conflict, which is impossible to resolve without a strict, permanent organizational hierarchy.']},
{id:382,type:'mcq',applied:true,text:'[APPLIED] A regional healthcare provider is struggling to align its staff, as a recent internal survey reveals that only 41% of its employees understand the organization\'s core purpose and values. The leadership team decides to draft a one-page document detailing their purpose, metrics, and roles. According to the Gallup (2022) data and the Day 1 actions recommended in the lecture, what is this document called, and what is its purpose?',ans:2,exp:'Gallup (2022) research shows that only 41% of employees know what their organization stands for. To address this lack of Shared Vision (Pillar 1), the lecture recommends a Day 1 Action: build a one-page team charter containing Purpose, Metrics, and Roles.',topic:'l6',opts:['A contribution menu, designed to offer multiple valid formats for remote and generational communication.', 'A Tuckman acceleration plan, designed to move the team rapidly from the Forming stage to the Performing stage.', 'A one-page team charter, designed to build a shared vision by outlining purpose, metrics, and roles on Day 1.', 'A discipline equation sheet, designed to enforce consistency in small acts and establish leader credibility.']},
{id:383,type:'mcq',applied:true,text:'[APPLIED] A manager at a tech startup is proud of the fact that his team never argues, decisions are reached instantly, and everyone always agrees. However, the team\'s latest product launch was a failure because obvious bugs were ignored. When asked about psychological safety, the manager claims he has established it by keeping the environment completely free of disagreement. How does this manager\'s definition of safety compare to the true nature of psychological safety?',ans:1,exp:'Pillar 2 (Psychological Safety) explains that Safety IS raising hard questions, admitting mistakes, and challenging ideas openly. Safety IS NOT avoiding conflict or always agreeing. Keeping the environment artificial and avoiding disagreement is not psychological safety; it leads to groupthink and failure.',topic:'l6',opts:['His definition is correct; psychological safety is primarily about maintaining harmony and avoiding conflict at all costs.', 'His definition is incorrect; psychological safety is about raising hard questions, admitting mistakes, and challenging ideas openly, not avoiding conflict or always agreeing.', 'His definition is partially correct, but he failed to realize that safety should only be granted to senior developers.', 'His definition is incorrect because safety can only exist in teams that have a flat hierarchy like the Orpheus Chamber Orchestra.']},
{id:384,type:'mcq',applied:true,text:'[APPLIED] A marketing agency is experiencing friction because two senior designers are constantly clashing over who has the final say on client pitches, while at the same time, administrative tasks are being neglected. According to Dr. David Oyedepo\'s quote on a man\'s worth and the structural failure of teams, what is the core issue here?',ans:2,exp:'Pillar 3 (Role Clarity) highlights that \'Duplication + Uncovered Functions = Team Failure.\' It quotes Dr. Oyedepo: \'What defines a man\'s worth is in his core — not his complements.\' When roles are not clear, members duplicate efforts (conflict) while other critical tasks are ignored (uncovered functions).',topic:'l6',opts:['The team is suffering from relationship conflict, which must be resolved by replacing the designers with remote Gen Z workers.', 'The team has too much task conflict, which is preventing them from establishing a shared vision and a team charter.', 'The team is suffering from duplication of efforts (designers clashing) and uncovered functions (administrative tasks neglected), stemming from a lack of role clarity.', 'The leader has failed to establish transformational leadership, meaning the team is stuck in a transactional compliance mindset.']},
{id:385,type:'mcq',applied:true,text:'[APPLIED] A project director manages a software development office of 100 employees. Due to poor documentation, vague email updates, and lack of explicit next steps at the end of meetings, the office frequently repeats work and misses deadlines. According to the McKinsey (2023) research cited in the lecture, what is the estimated annual financial cost of this miscommunication, and what is the key communication lesson?',ans:0,exp:'McKinsey (2023) research states that miscommunication costs a 100-person company $420,000 per year. The lesson is: \'Communicate clearly — not more.\' This can be achieved through habits like documenting decisions, closing with next steps, and allowing asynchronous input.',topic:'l6',opts:['It costs $420,000 per year; the lesson is that teams should communicate clearly, not necessarily more.', 'It costs $1,000,000 per year; the lesson is that teams should increase the frequency and volume of their meetings.', 'It costs $420,000 per year; the lesson is that all communication must be done synchronously to avoid digital misreading.', 'It costs $120,000 per year; the lesson is that leaders should eliminate emails and only use Figma links.']},
{id:386,type:'mcq',applied:false,text:'Patrick Lencioni\'s model, \'The Five Dysfunctions of a Team,\' identifies core barriers that prevent teams from achieving high performance. According to Lencioni\'s hierarchy, which of the following represents the most foundational dysfunction (at the very bottom of the pyramid) upon which all other dysfunctions are built?',ans:2,exp:'Patrick Lencioni\'s Five Team Dysfunctions, from bottom to top, are: Absence of Trust (bottom/foundational), Fear of Conflict, Lack of Commitment, Avoidance of Accountability, and Inattention to Results (top). Absence of Trust is the foundational dysfunction.',topic:'l6',opts:['Inattention to Results', 'Avoidance of Accountability', 'Absence of Trust', 'Fear of Conflict']},
{id:387,type:'mcq',applied:false,text:'Within Patrick Lencioni\'s model of team dysfunctions, there is a clear logical progression between the different levels of dysfunction. Which of the following statements best describes the causal relationship between a team\'s \'Fear of Conflict\' and its \'Lack of Commitment\'?',ans:0,exp:'Lencioni\'s model shows that when teams have a Fear of Conflict, they cannot engage in passionate, unfiltered debate. Without this debate, team members do not feel heard, resulting in a Lack of Commitment to decisions because they have not bought in.',topic:'l6',opts:['A fear of conflict prevents team members from engaging in open debate, which means they cannot buy-in or commit to decisions.', 'A lack of commitment makes team members fearful of having personal conflicts with the leader.', 'A fear of conflict directly leads to an absence of trust, which is the immediate cause of inattention to results.', 'A lack of commitment forces the leader to avoid accountability, which creates a fear of conflict.']},
{id:388,type:'mcq',applied:true,text:'[APPLIED] A manager of a client-relations team ensures that team members feel extremely safe to speak up, admit errors, and share concerns without fear of criticism. However, she does not enforce deadlines, set high performance expectations, or challenge low-quality work. According to the accountability formula described in the lecture, what atmosphere is created in this team, and why?',ans:2,exp:'The formula for accountability is: High Standards + Psychological Safety = Accountability. According to the lecture: High Standards alone -> Toxicity; Safety alone -> Passivity; Both together -> Excellence. Since the manager has safety but low standards, the team falls into Passivity.',topic:'l6',opts:['Excellence, because high psychological safety automatically leads to high accountability.', 'Toxicity, because team members feel safe but are constantly stressed by the lack of structure.', 'Passivity, because the team has high psychological safety but low standards.', 'Groupthink, because safety prevents the team from engaging in task conflict.']},
{id:389,type:'mcq',applied:true,text:'[APPLIED] An engineering director sets extremely aggressive quarterly KPIs, tracks individual metrics daily, and demands flawlessness. However, when developers make mistakes, they are publicly reprimanded, causing team members to hide errors and point fingers. According to the accountability formula, what environment does this director create, and what is the fix?',ans:0,exp:'The accountability formula states: \'High Standards + Safety = Accountability/Excellence.\' It also notes that \'High Standards alone -> Toxicity.\' Since this director enforces high standards but has low safety (reprimands, hiding errors), the environment is Toxic. The fix is to build psychological safety.',topic:'l6',opts:['Toxicity, created by high standards combined with low psychological safety; the fix is to increase psychological safety.', 'Passivity, created by low standards combined with high safety; the fix is to increase standards.', 'Groupthink, created by excessive consensus; the fix is to appoint a rotating Devil\'s Advocate.', 'Status quo, created by transactional culture; the fix is to transition to transformational leadership.']},
{id:390,type:'mcq',applied:false,text:'Harvard Business Review (2016) research states that 81% of employees serve on multiple teams simultaneously. For team leaders, this multi-task reality has significant implications. Which of the following is a key action a leader must take to respect their team members\' time under this reality?',ans:2,exp:'With 81% of employees serving on multiple teams, attention is divided and competing priorities are real. The lecture states: \'Protecting focus is a leadership act. Clarity of priority is a form of respect for your team\'s time.\'',topic:'l6',opts:['Enforce strict Type 1 (leader decides alone) decision-making for all tasks to save time.', 'Schedule more frequent synchronous meetings to ensure everyone is aligned daily.', 'Protect focus and provide clear priorities as a leadership act of respect.', 'Require team members to spend 100% of their working hours in the main office.']},
{id:391,type:'mcq',applied:true,text:'[APPLIED] A Lagos-based fintech startup launched an initiative to gather product ideas. The Baby Boomer managers prepared detailed slide decks and expected formal presentations, while the Gen Z team members dropped quick voice notes and Figma links into a Slack channel. Neither group recognized the other\'s contribution as legitimate, leading to a standstill. What solution should the team lead implement to bridge this gap?',ans:1,exp:'The lecture highlights this Lagos fintech team case study. The fix for this generational communication gap is to introduce a \'contribution menu\' — offering multiple valid formats for sharing ideas. The lesson is that silence ≠ disengagement, and a different format does not mean less commitment.',topic:'l6',opts:['Establish a strict rule that all contributions must be slide decks, matching the Boomers\' stability core.', 'Create a contribution menu that outlines multiple valid formats for sharing ideas.', 'Replace the Baby Boomer managers with Gen Z workers to match the hybrid speed requirement.', 'Introduce a peer mentorship program where Gen Z team members teach Boomers how to use Slack.']},
{id:392,type:'mcq',applied:true,text:'[APPLIED] A multinational advisory firm operates on a hybrid model, with half the team in the office and the other half working remotely. The remote team members feel isolated (consistent with the Gallup 2024 stat that 22% of remote workers feel isolated) and frequently misinterpret the tone of written messages. Meanwhile, in-office workers receive better project assignments. What dynamics are at play here, and what is the required shift?',ans:1,exp:'The scenario describes remote/hybrid work challenges: Proximity Bias (in-office members get disproportionate credit), Loneliness (22% feel isolated), and Digital Misreading (tone lost in text). The lecture states that hybrid teams do not need less leadership; they need more \'Intentional Leadership.\'',topic:'l6',opts:['Groupthink and relationship conflict; the team needs to transition to a transactional culture.', 'Proximity bias, loneliness, and digital misreading; the team needs more intentional leadership.', 'Storming and norming friction; the team needs to build a one-page team charter immediately.', 'Duplication and uncovered functions; the team needs to establish clear task boundaries.']},
{id:393,type:'mcq',applied:false,text:'Karen Jehn\'s 1995 research on team conflict identifies two distinct types: Task Conflict and Relationship Conflict. According to this research and the guidelines in the lecture, how should a high-performing team handle these two types of conflict to optimize decision-making and trust?',ans:2,exp:'Task Conflict (disagreement about \'what to do or how\') generates better decisions when managed well and should be cultivated. Relationship Conflict (personal animosity & friction) destroys trust & performance and should be minimized. Karen Jehn (1995) showed that normalizing idea challenge while protecting personal dignity leads to better decisions.',topic:'l6',opts:['Both task and relationship conflict should be minimized to ensure complete harmony.', 'Task conflict should be minimized, while relationship conflict should be cultivated to build empathy.', 'Task conflict should be cultivated because it generates better decisions, while relationship conflict must be minimized because it destroys trust.', 'Both task and relationship conflict should be cultivated to challenge status quo assumptions.']},
{id:394,type:'mcq',applied:true,text:'[APPLIED] A design team at a leading marketing agency has a habit of quickly agreeing on the first creative concept proposed, fearing that debating other options will slow them down. To prevent groupthink, the team leader decides to apply research from Charlan (UC Berkeley) on dissent. Which of the following practices should the leader implement?',ans:2,exp:'Charlan (UC Berkeley) showed that teams that institutionalize dissent make significantly better decisions. To prevent groupthink, the lecture recommends: assigning a rotating Devil\'s Advocate, making disagreement a norm, and rewarding those who ask uncomfortable questions. \'The most dangerous team always agrees.\'',topic:'l6',opts:['Introduce a transaction exchange model to reward fast compliance with bonuses.', 'Enforce a Type 1 decision-making protocol where the leader makes all final decisions alone.', 'Assign a rotating \'Devil\'s Advocate\' role to make disagreement a norm and reward uncomfortable questions.', 'Switch the entire team to fully remote work to reduce face-to-face interaction.']},
{id:395,type:'mcq',applied:false,text:'The concept of \'Self-Leadership First\' asserts that a team leader\'s inner world directly shapes the team\'s outer reality. If a leader fails to manage their own internal states, which of the following mappings correctly represents how the leader\'s deficiencies translate into negative team dynamics?',ans:1,exp:'The lecture states under \'Self-Leadership First\': \'Your inner world becomes your team\'s outer reality: Your Stress -> becomes team anxiety; Your Ambiguity -> becomes team\'s confusion; Your Blame -> becomes team defensiveness; Your Energy -> becomes team atmosphere.\' This matches option 1.',topic:'l6',opts:['Leader\'s Stress -> Team Defensiveness; Leader\'s Ambiguity -> Team Atmosphere; Leader\'s Blame -> Team Anxiety.', 'Leader\'s Stress -> Team Anxiety; Leader\'s Ambiguity -> Team\'s Confusion; Leader\'s Blame -> Team Defensiveness.', 'Leader\'s Stress -> Team\'s Confusion; Leader\'s Ambiguity -> Team Defensiveness; Leader\'s Blame -> Team Anxiety.', 'Leader\'s Stress -> Team Defensiveness; Leader\'s Ambiguity -> Team Anxiety; Leader\'s Blame -> Team\'s Confusion.']},
{id:396,type:'mcq',applied:false,text:'Under \'The Discipline Equation,\' the lecture discusses the cost of sustained leadership. It quotes Jim Rohn\'s perspective on discipline versus regret. How is this concept structured, and what is its ultimate benefit according to the lecture?',ans:1,exp:'Jim Rohn\'s quote is: \'The pain of discipline weighs ounces. The pain of regret weighs tonnes.\' The lecture notes that consistency in small acts (like preparing before meetings, following through on commitments, doing the important over the urgent) builds the credibility no title can grant.',topic:'l6',opts:['The pain of discipline weighs tonnes, while the pain of regret weighs ounces; it builds formal authority.', 'The pain of discipline weighs ounces, while the pain of regret weighs tonnes; consistency in small acts builds credibility.', 'Discipline requires preparing during meetings, which saves time; it eliminates the Storming stage.', 'Discipline means focusing solely on urgent tasks rather than important tasks; it creates a transactional culture.']},
{id:397,type:'mcq',applied:true,text:'[APPLIED] A critical cybersecurity breach occurs in a banking software system, requiring immediate action within minutes to prevent massive data theft. The engineering director has no time to gather input or build consensus. According to the five types of team decisions outlined in the lecture, which decision type should the director employ in this situation, and why?',ans:1,exp:'The lecture lists \'Leader decides alone\' (Type 1) as appropriate for \'Crisis, time pressure.\' In a critical cybersecurity breach, there is no time for consensus or input, making Type 1 the correct decision model to apply.',topic:'l6',opts:['Type 3 (Team consensus), because security protocols affect all employees equally.', 'Type 1 (Leader decides alone), because it is a crisis situation with severe time pressure.', 'Type 2 (Leader decides with input), because cybersecurity is highly complex.', 'Type 4 (Subgroup decides), because the security team has specialized domain knowledge.']},
{id:398,type:'mcq',applied:true,text:'[APPLIED] A company is deciding whether to pivot its core business model, a choice that involves strategic complexity and deeply held organizational values. The CEO decides to make the final decision alone in his office without consulting anyone, leading to a loss of team commitment and widespread confusion. Why was this decision-making approach a failure, according to the lecture?',ans:1,exp:'The lecture states that \'Most leadership failures happen when Type 1 is applied to situations that deserve Types 2–5.\' A strategic, complex, values-laden decision deserves Type 2 (Leader decides with input) rather than Type 1 (Leader decides alone).',topic:'l6',opts:['The CEO should have used Type 3 (Team consensus) because pivots affect all employees equally.', 'The CEO applied Type 1 (Leader decides alone) to a situation that deserved Type 2 (Leader decides with input).', 'The CEO should have delegated the decision to a subgroup (Type 4) because strategic pivots are technical.', 'The CEO failed to realize that strategic pivots should be decided by individual department heads (Type 5).']},
{id:399,type:'mcq',applied:false,text:'The \'Attitude-Culture Link\' explains that culture is the shadow of the leader\'s character. According to SHRM (2024) statistics, what percentage of employees who quit cited their manager\'s attitude as the primary reason, and what does this emphasize?',ans:1,exp:'SHRM (2024) research shows that 84% of employees who quit cited their manager\'s attitude as the primary reason. This highlights how heavily a leader\'s character shadow affects retention and underscores the need for leaders to model engagement, trust, stewardship, abundance, and resilience.',topic:'l6',opts:['41% of employees; it emphasizes that most employees do not understand their company\'s vision.', '84% of employees; it emphasizes that a leader\'s modeled attitudes directly impact employee retention.', '22% of employees; it emphasizes that remote workers suffer from a lack of emotional support.', '17.4% of employees; it emphasizes that hybrid work structures lead to higher attrition rates.']},
{id:400,type:'mcq',applied:false,text:'The lecture identifies three distinct mentalities regarding a person\'s attitude to work: Slave, Worker, and Leader. Which of the following options correctly pairs each mentality with its corresponding behavioral description?',ans:2,exp:'According to the table on Page 24 of the lecture text: Slave mentality \'Waits to be forced\'; Worker mentality \'Works to earn\'; Leader mentality \'Works to build.\' The lecture also quotes Dr. Oyedepo: \'It is better to be made than to be paid,\' and advises: \'Work to Learn — not just to earn.\'',topic:'l6',opts:['Slave: Works to earn; Worker: Waits to be forced; Leader: Works to build.', 'Slave: Waits to be forced; Worker: Works to build; Leader: Works to learn.', 'Slave: Waits to be forced; Worker: Works to earn; Leader: Works to build.', 'Slave: Works to learn; Worker: Works to earn; Leader: Works to build.']},
{id:401,type:'mcq',applied:true,text:'[APPLIED] A software team lead notices that her developers are highly competent but lack the confidence to take on broader responsibilities, making the team overly dependent on her. To build leadership capacity from within, she wants to use \'safe-to-fail projects\' as suggested in the lecture. What does this tool entail?',ans:1,exp:'Under \'Developing Leaders Within Your Team,\' the lecture lists four tools. One of them is \'Safe-to-Fail Projects,\' described as \'small experiments where people can stretch and learn.\' This allows them to build capacity without risking catastrophic project failure.',topic:'l6',opts:['Assigning highly critical, client-facing projects to junior members to see if they can handle extreme stress.', 'Running small, low-risk experiments where team members can stretch their skills, make mistakes, and learn without major consequences.', 'Moving team members through different organizational departments, such as HR and sales, for a day.', 'Creating a formal training program where team members watch video lectures on Lencioni\'s dysfunctions.']},
{id:402,type:'mcq',applied:false,text:'A meta-analysis of 63 studies in 2023 compared Transactional and Transformational leadership cultures. According to the findings of this research, which of the following is an outcome associated with teams working under transformational leadership?',ans:1,exp:'The 2023 meta-analysis of 63 studies shows that teams under transformational leadership (characterized by motivation through mission, results through commitment, and a culture of growth) report significantly higher creativity, job satisfaction, and going beyond what\'s required.',topic:'l6',opts:['Significantly higher compliance, lower risk-taking, and status quo preservation.', 'Significantly higher creativity, job satisfaction, and going beyond what is required.', 'Reduced need for psychological safety and lower standards of accountability.', 'A shift from collective team goals to individual-focused transactional exchanges.']},
{id:403,type:'mcq',applied:false,text:'In the section titled \'The Power of One,\' the lecture discusses how individual contribution is never neutral. It highlights Dr. David Oyedepo\'s perspective on the impact of a single committed individual. What is the core message of this section?',ans:1,exp:'The lecture states: \'Your Contribution Is Never Neutral. One voice changes a decision. One prepared member shifts a team\'s direction. One accountable person raises the standard for everyone.\' It quotes Dr. Oyedepo: \'One man with the hand of God upon him is all that is needed...\' and concludes, \'You are a Critical Variable.\'',topic:'l6',opts:['A single person\'s effort is insignificant compared to the collective Tuckman stages.', 'A single prepared and accountable individual can act as a critical variable that shifts a team\'s direction and raises standards.', 'A single manager with formal authority is the only person who can make strategic decisions.', 'A single team member should be assigned as the permanent conductor to maintain stability.']},
{id:404,type:'mcq',applied:true,text:'[APPLIED] In the case study of Amara\'s team at a Lagos logistics firm, the company has just transitioned to a hybrid work model. In meetings, the two Baby Boomer supervisors dominate the conversation, the two Millennial analysts communicate in a private WhatsApp group that Amara cannot access, and the two Gen Z interns have remained silent for three weeks. Which of the five pillars is most immediately at risk here?',ans:2,exp:'The case study highlights key communication and generational issues. Proximity/hybrid shifts have fractured communication: supervisors dominate, analysts use an exclusive backchannel (WhatsApp), and interns are silent. This directly threatens Disciplined Communication (Pillar 4).',topic:'l6',opts:['Shared Vision, because the company\'s long-term business goals have not been updated.', 'Role Clarity, because the team is duplicating software development functions.', 'Disciplined Communication, because the team has fragmented communication channels and lack of inclusive participation.', 'Accountability, because the supervisors are blaming the analysts for project failures.']},
{id:405,type:'mcq',applied:false,text:'The lecture provides specific, measurable outcomes that good team leadership produces within an organization. Which of the following options correctly matches a leadership practice with its corresponding statistical outcome?',ans:1,exp:'Page 29 lists: \'Psychological safety -> 76% more engaged employees\', \'Transformational leadership -> 40% higher creativity\', \'Mentorship culture -> 94% improved retention\', and \'Clear vision and roles -> 2x productivity.\' This matches option 1.',topic:'l6',opts:['Psychological safety -> 40% higher creativity; Transformational leadership -> 76% more engaged employees.', 'Mentorship culture -> 94% improved retention; Clear vision and roles -> 2x productivity.', 'Clear vision and roles -> 76% more engaged employees; Psychological safety -> 2x productivity.', 'Transformational leadership -> 94% improved retention; Mentorship culture -> 40% higher creativity.']},
{id:406,type:'mcq',applied:false,text:'The lecture concludes with \'The Leader\'s Creed,\' which challenges leaders with the motto: \'Leave Every Room Better Than You Found It.\' According to the text, what is the underlying posture behind this creed?',ans:1,exp:'Under \'The Leader\'s Creed,\' the text states: \'Leave Every Room Better Than You Found It. This is not Arrogance. This is the posture of a leader who has taken responsibility for their own contribution.\'',topic:'l6',opts:['A posture of arrogance, showing that a leader\'s knowledge is superior to the team\'s.', 'A posture of a leader who has taken responsibility for their own contribution.', 'A posture that prioritizes individual achievements over collective team goals.', 'A posture of compliance, ensuring that rules and status quo are strictly maintained.']},
{id:407,type:'mcq',applied:true,text:'[APPLIED] A newly assembled engineering team is experiencing friction because two developers are working on the exact same database module, while no one has set up the server monitoring tools. The team leader realizes that while they have high-talent individuals, they lack a clear mapping of primary contributions. How should the leader address this issue using the concepts from Pillar 3 (Role Clarity)?',ans:2,exp:'Pillar 3 states that every team member must have a primary contribution, and high-performing teams share role diversity and awareness. To solve duplication (working on the same module) and uncovered functions (no server monitoring), the leader must establish role clarity.',topic:'l6',opts:['Conduct weekly 1:1 task updates and assign more slide deck presentations.', 'Establish a contribution menu to allow developers to work in whatever format they prefer.', 'Map core roles to define primary contributions, ensuring diversity and awareness to prevent duplication and uncovered functions.', 'Transition to a transactional leadership model where developers are paid extra for server monitoring.']},
{id:408,type:'mcq',applied:true,text:'[APPLIED] A team lead frequently arrives late to weekly meetings, checks emails during others\' presentations, and fails to follow up on action items. Despite this, he complains that his team lacks discipline and commitment. According to the section on \'Self-Leadership First\' and \'The Discipline Equation,\' what is the primary cause of the team\'s poor behavior?',ans:1,exp:'Self-leadership is the foundation of team leadership. The leader\'s inner world shapes the team\'s outer reality. Failing to lead oneself (arriving late, checking emails, breaking commitments) destroys the leader\'s credibility because consistency in small acts is what builds it.',topic:'l6',opts:['The team is in the Storming phase of the Tuckman model, which naturally causes poor commitment.', 'The leader is failing to lead himself first, and his lack of personal discipline and consistency is casting a negative shadow that destroys credibility.', 'The team lacks a contribution menu, which prevents them from communicating asynchronously.', 'The leader is using Type 2 decision making instead of Type 1 decision making.']},
{id:409,type:'mcq',applied:false,text:'When comparing the \'Storming\' and \'Norming\' stages of the Tuckman Model, which of the following statements best describes the key difference in team dynamics between these two phases?',ans:1,exp:'In Tuckman\'s model, Forming is the start, Storming is the phase of conflict, friction, and testing boundaries, Norming is where agreements, rules, and roles are established, and Performing is where the team achieves high productivity.',topic:'l6',opts:['Storming is characterized by high alignment on roles, whereas Norming is characterized by complete autonomy and lack of leadership.', 'Storming involves friction and testing boundaries, whereas Norming is characterized by established agreements, role clarity, and co-created rules.', 'Storming represents peak performance and productivity, while Norming is the initial stage of team formation.', 'Storming is where leadership rotates based on competence, while Norming is where hierarchy is rigidly established.']},
{id:410,type:'mcq',applied:true,text:'[APPLIED] A hybrid team lead notices that a remote software tester has become increasingly quiet in group chats. In a recent text exchange, the tester reacted defensively to a simple question about bug reports, causing a project delay. According to the remote work challenges in the lecture, what issues are likely occurring, and how should the leader intervene?',ans:1,exp:'The tester shows symptoms of remote work challenges: isolation/loneliness (22% of remote workers feel isolated) and digital misreading (tone lost in text). The leader needs to use Intentional Leadership to address these issues directly rather than assuming disengagement.',topic:'l6',opts:['The tester has a slave mentality; the leader should enforce compliance using Type 1 decision-making.', 'The tester is experiencing loneliness and digital misreading; the leader should practice intentional leadership by calling the tester to clarify tone and offer support.', 'The team has too much task conflict; the leader should replace the tester with an in-office Boomer manager.', 'The team has role duplication; the leader should draft a new team charter to redefine coding standards.']},
{id:411,type:'mcq',applied:true,text:'[APPLIED] A software startup team is deciding which complex cloud database architecture to adopt. Instead of letting the senior database engineers make the choice, the team leader insists on achieving team-wide consensus (Type 3 decision). After three weeks of heated debates and confusion among non-technical members, no decision is made. What was the leader\'s error?',ans:1,exp:'According to the five types of team decisions: \'Subgroup decides\' (Type 4) is appropriate for a \'Specialised or technical domain.\' Forcing team consensus (Type 3) on a highly technical decision leads to confusion and gridlock among non-experts.',topic:'l6',opts:['The leader should have made the decision alone (Type 1) to save time, as cloud architecture is a crisis.', 'The leader applied team consensus (Type 3) to a specialized or technical domain that should have been decided by a subgroup (Type 4).', 'The leader should have allowed each individual developer to choose their own database (Type 5).', 'The leader failed to establish a contribution menu before initiating the debate.']},
{id:412,type:'mcq',applied:false,text:'In cross-generational teams, communication gaps frequently emerge due to differing expectations and formats. The lecture emphasizes the lesson: \'Silence ≠ disengagement. Different format ≠ less commitment.\' Which of the following is the most accurate implication of this lesson for a team leader?',ans:2,exp:'The lesson \'Silence ≠ disengagement. Different format ≠ less commitment\' means that leaders must not misinterpret a team member\'s style (e.g., using Figma/voice notes instead of slide decks, or participating asynchronously rather than dominating live meetings) as a lack of effort or capability.',topic:'l6',opts:['A leader must force all team members to use the same communication format to ensure commitment.', 'A leader should interpret silence as a lack of interest and reassign the silent member\'s tasks.', 'A leader must recognize that team members from different generations express commitment and ideas through different, yet equally valid, formats.', 'A leader should avoid remote arrangements because text-based communication always represents low engagement.']},
{id:413,type:'mcq',applied:false,text:'Pillar 4 (Disciplined Communication) outlines the hidden costs of poor communication and offers habits of the best teams. Which of the following represents the three core habits of the best-performing teams identified in the lecture?',ans:0,exp:'Page 12 states: \'Three Habits of the best teams: Document decisions; Close with explicit next steps; Allow asynchronous input before live discussions.\' These habits help reduce the high cost of miscommunication.',topic:'l6',opts:['Document decisions, close with explicit next steps, and allow asynchronous input before live discussions.', 'Enforce daily standups, use slide decks exclusively, and limit all discussions to in-office members.', 'Establish rotating conductors, mandate consensus on all choices, and eliminate text-based tools.', 'Review individual metrics, hold weekly 1:1 task updates, and assign a permanent Devil\'s Advocate.']},
{id:414,type:'mcq',applied:true,text:'[APPLIED] During a post-mortem meeting for a failed product launch, the team lead openly takes responsibility for the poor strategic decisions she made, while publicly highlighting and praising the hard work and creative solutions of her junior designers. Which attitudes from the Attitude-Culture Link is this lead demonstrating?',ans:1,exp:'Under the \'Attitude-Culture Link\' (Page 23), the five attitudes are modeled. Taking responsibility (absorbing blame) and praising others (giving credit) models Trust. Celebrating others\' wins models Abundance.',topic:'l6',opts:['Engagement and Stewardship, by treating work as a calling and managing resources.', 'Trust and Abundance, by absorbing blame, giving credit, and celebrating others\' wins.', 'Resilience and Autonomy, by staying composed and freeing the team\'s execution.', 'Stewardship and Compliance, by enforcing standards and following hierarchy.']},
{id:415,type:'mcq',applied:true,text:'[APPLIED] A senior system administrator is the only person in a department who knows how to configure the company\'s core servers. He refuses to document his processes or train others, believing this makes him indispensable. According to the section on \'Developing Leaders Within Your Team,\' what is the leadership failure here?',ans:1,exp:'The lecture states: \'Stop hoarding Knowledge. Start multiplying capacity.\' By keeping information to himself to maintain his own status, the administrator limits team capacity and fails to develop other leaders, violating the growth culture.',topic:'l6',opts:['He is failing to practice self-leadership, which causes relationship conflict.', 'He is hoarding knowledge and failing to multiply capacity, which limits team growth and resilience.', 'He is violating the Orpheus Principle by not conducting weekly 1:1 growth reviews.', 'He is applying Type 4 decision making instead of Type 5 decision making.']},
{id:416,type:'mcq',applied:false,text:'The Orpheus Chamber Orchestra is famous for its unique organizational structure, having operated for over 50 years with no permanent conductor. Which of the following statements best describes how leadership is exercised in this orchestra according to the Orpheus Principle?',ans:1,exp:'The Orpheus Chamber Orchestra has no permanent conductor. Leadership rotates to whoever is most prepared and matches the task, demonstrating that leadership follows competence, not hierarchy.',topic:'l6',opts:['Decisions are made entirely by the most senior musician, who holds the permanent title of conductor.', 'Leadership rotates dynamically based on who is most prepared and competent for the specific task at hand.', 'The orchestra uses a strict democratic vote for every single musical note during rehearsals.', 'Leadership is delegated to external managers who monitor performance from the administrative office.']},
{id:417,type:'mcq',applied:true,text:'[APPLIED] A project lead is launching a new cross-functional team. On Day 1, he gathers the members to co-create a one-page document that defines the team\'s core purpose, metrics of success, and individual roles. According to the lecture, what is the strategic value of this specific Day 1 action?',ans:1,exp:'A one-page team charter (Purpose. Metrics. Roles.) is the recommended Day 1 Action to build a Shared Vision (Pillar 1) and role clarity, addressing the common lack of alignment where only 41% of employees understand their organization\'s purpose.',topic:'l6',opts:['It accelerates the Storming phase by eliminating all task conflicts before they occur.', 'It builds a Shared Vision (Pillar 1) and role clarity, addressing the fact that only 41% of employees know what their organization stands for.', 'It establishes a transactional leadership culture by documenting the compliance exchange.', 'It implements a contribution menu for remote and hybrid work environments.']},
{id:418,type:'mcq',applied:true,text:'[APPLIED] A department manager implements rigorous quality standards for all deliverables and conducts thorough design reviews. At the same time, she cultivates an environment where developers are encouraged to speak up about errors immediately and challenge flawed ideas without fear of negative career impacts. According to Lencioni and the accountability formula, what outcome will this combination produce?',ans:2,exp:'The formula is: High Standards + Psychological Safety = Accountability/Excellence. When both are high, the team achieves Excellence. High standards alone lead to Toxicity, and safety alone leads to Passivity.',topic:'l6',opts:['Toxicity, because high standards always create a highly stressful and anxious environment.', 'Passivity, because psychological safety removes all pressure from developers to meet deadlines.', 'Excellence, because high standards are combined with high psychological safety to create true accountability.', 'Groupthink, because safety encourages members to always agree and avoid conflict.']},
{id:419,type:'mcq',applied:false,text:'According to the Deloitte Global Human Capital Trends (2023) report cited in the lecture, 84% of organizations have redesigned their work around teams. What is the corresponding percentage of organizations that actually have the team leadership capacity to match this redesign?',ans:1,exp:'Deloitte (2023) report states that while 84% of organizations have redesigned work around teams, \'Less than 20% have the team leadership to match.\' This gap is highlighted as an opportunity.',topic:'l6',opts:['Less than 41%', 'Less than 20%', 'Exactly 50%', 'Less than 10%']},
{id:420,type:'mcq',applied:false,text:'Under the \'Attitude-Culture Link\' section, the lecture discusses how a manager\'s attitude acts as a shadow of their character and directly affects retention. According to the SHRM (2024) survey, which of the following is true?',ans:1,exp:'The SHRM (2024) statistic states that \'84% of employees who quit cited their manager\'s attitude as the primary reason,\' showing that culture is the shadow of the leader\'s character.',topic:'l6',opts:['22% of employees leave because of digital misreading in hybrid teams.', '84% of employees who quit cited their manager\'s attitude as the primary reason.', 'Only 41% of employees quit due to a lack of shared vision and role clarity.', 'Less than 20% of employees quit because of a lack of transformational leadership.']},
{id:421,type:'multi',applied:true,text:'[APPLIED] A regional manager is designing a hybrid work policy for a newly formed team spread across different locations. To ensure high performance, she wants to establish disciplined communication habits as outlined in the lecture. Select all communication habits that the leader should implement based on the best practices of high-performing teams.',ans:[0, 1, 2],exp:'The three communication habits of the best teams are: documenting decisions, closing with explicit next steps, and allowing asynchronous input before live discussions. Restricting communication to slide decks is incorrect and can exacerbate generational gaps.',topic:'l6',opts:['Document decisions clearly for future reference.', 'Allow asynchronous input before holding live discussions.', 'Close all meetings with explicit next steps.', 'Mandate that all communication formats must be restricted to slide decks.']},
{id:422,type:'multi',applied:true,text:'[APPLIED] A director of a project management office wants to address the \'Team Leadership Gap\' identified in the Deloitte 2023 report. She aims to select new project leads who demonstrate true team leadership rather than just administrative management. Select all core characteristics of true team leadership according to the lecture.',ans:[0, 1],exp:'The lecture defines team leadership as: \'Influencing, coordinating, and developing a group toward shared goals — while enabling every member to contribute and grow.\' It requires balancing authority vs influence and direction vs autonomy, not relying on raw titles or bypassing natural team stages like storming.',topic:'l6',opts:['Influencing, coordinating, and developing a group toward shared goals.', 'Enabling every member to contribute and grow.', 'Relying solely on formal authority and title to force compliance.', 'Bypassing the Tuckman model stages to avoid team storming.']},
{id:423,type:'multi',applied:false,text:'Tuckman\'s Model provides a framework for understanding how teams evolve over time. To effectively accelerate a team\'s journey toward peak performance, a leader must recognize each stage of the model. Select all correct stages of the Tuckman Model of team development as listed in the lecture.',ans:[0, 1, 2, 3],exp:'The Tuckman Model describes the team development journey through four key stages in order: Forming, Storming, Norming, and Performing. A leader\'s job is to accelerate this journey.',topic:'l6',opts:['Forming', 'Storming', 'Norming', 'Performing']},
{id:424,type:'multi',applied:false,text:'Patrick Lencioni\'s book \'The Five Dysfunctions of a Team\' outlines barriers that prevent teams from achieving their full potential. To build a highly accountable and cohesive team, a leader must understand how these dysfunctions are structured. Select all correct statements regarding Lencioni\'s five team dysfunctions.',ans:[0, 1, 2],exp:'Lencioni\'s Five Team Dysfunctions from bottom to top are: Absence of Trust (bottom), Fear of Conflict, Lack of Commitment, Avoidance of Accountability, and Inattention to Results (top). Fear of Conflict is the second dysfunction from the bottom, not the top.',topic:'l6',opts:['Absence of Trust is the foundational dysfunction at the bottom of the pyramid.', 'Avoidance of Accountability sits above Lack of Commitment in the hierarchy.', 'Inattention to Results sits at the very top of the pyramid.', 'Fear of Conflict sits at the top of the pyramid as the final dysfunction.']},
{id:425,type:'multi',applied:false,text:'The \'Attitude-Culture Link\' emphasizes that culture is the shadow of the leader\'s character, and that team members \'catch\' their work attitudes directly from what their leaders model. Select all the positive attitudes that a team leader must model according to the lecture text.',ans:[0, 1, 2, 3, 4],exp:'According to Page 23 of the lecture text, there are five attitudes leaders must model: model Engagement (treat work as a calling), model Trust (give credit, absorb blame), model Stewardship (manage resources responsibly), model Abundance (celebrate others\' wins), and model Resilience (stay composed under pressure).',topic:'l6',opts:['Model Engagement by treating work as a calling.', 'Model Trust by giving credit and absorbing blame.', 'Model Stewardship by managing resources responsibly.', 'Model Abundance by celebrating others\' wins.', 'Model Resilience by staying composed under pressure.']},
{id:426,type:'multi',applied:false,text:'For the first time in history, organizations host four generations simultaneously. To manage communication and collaboration effectively, team leaders must understand generational profiles and expectations. Select all correct pairings of generations and their core expectations according to the Pew Research Center & Deloitte (2023) source.',ans:[0, 1, 2, 3],exp:'The table on Page 15 of the lecture text lists the four generations and their core expectations: Baby Boomers expect stability and hierarchy; Generation X expects autonomy and pragmatism; Millennials expect purpose and collaboration; Generation Z expects speed, flexibility, and inclusion.',topic:'l6',opts:['Baby Boomers (1946–1964): Stability, hierarchy', 'Generation X (1965–1980): Autonomy, pragmatism', 'Millennials (1981–1996): Purpose, collaboration', 'Generation Z (1997–2012): Speed, flexibility, inclusion']},
{id:427,type:'multi',applied:false,text:'Developing leadership capacity within a team is a key responsibility of a team leader to ensure long-term effectiveness and resilience. Select all the specific tools listed in the lecture for actively developing leaders inside your team.',ans:[0, 1, 2, 3],exp:'Page 25 of the lecture text lists four tools for developing leaders: Weekly 1:1s (focused on growth), Skills Rotation, Peer Mentorship Pairs, and Safe-to-Fail Projects. The goal is to stop hoarding knowledge and start multiplying capacity.',topic:'l6',opts:['Weekly 1:1s focused on growth, not just task updates.', 'Skills Rotation to move people through different functions deliberately.', 'Peer Mentorship Pairs for structured internal knowledge transfer.', 'Safe-to-Fail Projects to let people learn and stretch in small experiments.']},
{id:428,type:'multi',applied:false,text:'The principle of \'Self-Leadership First\' states that a leader cannot give what they do not have, and that their inner world becomes their team\'s outer reality. Select all correct mappings of a leader\'s internal state to the corresponding team dynamic as described in the lecture.',ans:[0, 1, 2, 3],exp:'Under \'Self-Leadership First\' (Page 20), the lecture lists: \'Your Stress -> becomes team anxiety; Your Ambiguity -> becomes team\'s confusion; Your Blame -> becomes team defensiveness; Your Energy -> becomes team atmosphere.\' Leading oneself efficiently is the first step of team leadership.',topic:'l6',opts:['Leader\'s Stress becomes team anxiety.', 'Leader\'s Ambiguity becomes team\'s confusion.', 'Leader\'s Blame becomes team defensiveness.', 'Leader\'s Energy becomes team atmosphere.']},
{id:429,type:'multi',applied:false,text:'Conflict in teams can either act as a destructive force or a constructive catalyst depending on how it is managed. Select all correct statements regarding Task Conflict and Relationship Conflict based on the Karen Jehn (1995) research cited in the lecture.',ans:[0, 1, 2, 3],exp:'Task conflict concerns the content of work (\'what to do or how\') and generates better decisions. Relationship conflict involves personal friction and destroys trust. Karen Jehn (1995) showed that teams that normalize idea challenge while protecting personal dignity make significantly better decisions.',topic:'l6',opts:['Task Conflict involves disagreement about what to do or how, and it generates better decisions when managed well.', 'Relationship Conflict involves personal animosity and friction, and it destroys trust and performance.', 'Task Conflict should be cultivated in teams to prevent groupthink.', 'Relationship Conflict should be minimized in teams to protect personal dignity.']},
{id:430,type:'multi',applied:true,text:'[APPLIED] Consider the case study of Amara\'s team at a Lagos logistics firm: the company is hybrid; Boomer supervisors dominate meetings; Millennial analysts communicate in a private WhatsApp group; Gen Z interns are silent. Select all appropriate, immediate leadership actions Amara should take based on the lecture\'s principles.',ans:[0, 1, 2],exp:'Amara needs to apply intentional leadership to resolve hybrid challenges. Setting meeting norms helps silent interns and dominating Boomers. Unifying channels addresses the analysts\' backchannel. A contribution menu bridges the generational format gap. Forcing in-office work does not address the underlying team dynamics and ignores hybrid realities.',topic:'l6',opts:['Introduce a contribution menu offering multiple valid formats for sharing ideas.', 'Establish structured meeting norms to prevent dominating voices and encourage participation from silent interns.', 'Address the communication gap by integrating the private WhatsApp channel into a unified team platform.', 'Abolish remote work entirely and require all team members to work in the office to force physical interaction.']},
{id:431,type:'short',applied:true,text:'[APPLIED] A world-renowned software consultancy operates without any designated managers. Instead, leadership of different client engagements rotates dynamically based on who has the most relevant expertise. What specific team leadership concept, exemplified by a famous conductorless chamber orchestra, is this consultancy applying?',ans:'Orpheus Principle',exp:'The Orpheus Principle (named after the Orpheus Chamber Orchestra) states that leadership follows competence, not hierarchy, and that who leads should match the task rather than the org chart.',topic:'l6'},
{id:432,type:'short',applied:false,text:'What critical team characteristic did Google\'s Project Aristotle identify as the number one predictor of team effectiveness, defined as the belief that the team is safe for interpersonal risk-taking?',ans:'Psychological Safety',exp:'Google\'s Project Aristotle studied 180 teams over 2 years and found that Psychological Safety was the single most important predictor of team effectiveness.',topic:'l6'},
{id:433,type:'short',applied:false,text:'In the Tuckman Model of team development, what is the name of the second stage, which is characterized by friction, boundary-testing, and conflict before team agreements and norms are established?',ans:'Storming',exp:'The Tuckman Model stages are Forming, Storming, Norming, and Performing. Storming is the stage of friction and testing where conflict must be managed to reach Norming.',topic:'l6'},
{id:434,type:'short',applied:true,text:'[APPLIED] An executive team at an investment bank regularly assigns one member to challenge all strategic assumptions and ask uncomfortable questions during board meetings to prevent groupthink. What is the name of this rotating role?',ans:'Devil\'s Advocate',exp:'Assigning a rotating Devil\'s Advocate role is a practice recommended in the lecture to institutionalize dissent and prevent groupthink, leading to better decision-making.',topic:'l6'},
{id:435,type:'short',applied:false,text:'What type of leadership culture motivates team members through a shared mission, results in deep commitment, and focuses on a culture of growth, yielding higher creativity and satisfaction?',ans:'Transformational',exp:'A Transformational leadership culture (as opposed to Transactional) motivates through mission, drives commitment, and fosters growth, which results in significantly higher creativity and job satisfaction.',topic:'l6'},
{id:436,type:'short',applied:false,text:'To establish a Shared Vision (Pillar 1) on Day 1, what specific one-page document should a team build to outline its purpose, metrics, and roles?',ans:'Team Charter',exp:'The lecture recommends building a \'one-page team charter\' on Day 1 containing purpose, metrics, and roles to establish a shared vision and align the team.',topic:'l6'},
{id:437,type:'short',applied:true,text:'[APPLIED] A remote employee at an advertising agency is passed over for a promotion in favor of a less-qualified colleague who works from the physical corporate headquarters. What specific hybrid work bias is this remote employee a victim of?',ans:'Proximity Bias',exp:'Proximity Bias is the tendency in remote or hybrid teams where in-office members get disproportionate credit and career advantages simply because they are physically close to leaders.',topic:'l6'},
{id:438,type:'short',applied:false,text:'What concept from the lecture asserts that a leader cannot give what they do not have, stating that leading others successfully in any field must begin with leading oneself first?',ans:'Self-Leadership',exp:'Self-leadership is the foundation of team leadership. It states: \'Before you lead your team, lead yourself.\' A leader\'s inner world directly shapes the team\'s outer reality.',topic:'l6'},
{id:439,type:'short',applied:true,text:'[APPLIED] An analyst at an energy firm goes beyond his defined task descriptions, proposing new workflows and taking responsibility to build capacity rather than just waiting to be told what to do. According to the three workplace mentalities, which mentality does this analyst exhibit?',ans:'Leader',exp:'The three mentalities are: Slave (waits to be forced), Worker (works to earn), and Leader (works to build). The analyst acts with a Leader mentality because he works to build.',topic:'l6'},
{id:440,type:'short',applied:false,text:'What specific term describes the type of team conflict that involves disagreement about \'what to do or how\' and generates better decisions when managed well, and should therefore be cultivated in teams?',ans:'Task Conflict',exp:'Task Conflict is disagreement about the content and goals of the work. When managed well, it acts as a catalyst for better decisions and should be cultivated.',topic:'l6'},
{id:441,type:'fill',applied:false,text:'According to the lecture, the formula for real accountability states that _______ combined with _______ yields Excellence. If a leader enforces high standards alone, it leads to _______.',dropdowns:[['High Standards', 'Psychological Safety', 'Transactional Leadership', 'Autonomy'], ['High Standards', 'Psychological Safety', 'Transactional Leadership', 'Autonomy'], ['Toxicity', 'Passivity', 'Groupthink', 'Status quo']],ans:['High Standards', 'Psychological Safety', 'Toxicity'],exp:'The accountability formula is: High Standards + Psychological Safety = Accountability/Excellence. The lecture states: \'High Standards alone -> Toxicity; Safety alone -> Passivity; Both together -> Excellence.\'',topic:'l6'},
{id:442,type:'fill',applied:false,text:'The Orpheus Principle asserts that leadership follows _______, not hierarchy. Furthermore, it dictates that who leads should match the _______, not the org chart.',dropdowns:[['competence', 'seniority', 'titles', 'relationships'], ['task', 'schedule', 'budget', 'preferences']],ans:['competence', 'task'],exp:'The Orpheus Principle states that: (1) Leadership follows competence, not hierarchy; (2) Who leads should match the task, not the org chart. This allows teams to rotate leadership dynamically based on qualifications.',topic:'l6'},
{id:443,type:'fill',applied:false,text:'In terms of generational expectations in the workplace, Generation X expects _______, whereas Generation Z expects _______.',dropdowns:[['Autonomy, pragmatism', 'Stability, hierarchy', 'Purpose, collaboration', 'Speed, flexibility, inclusion'], ['Autonomy, pragmatism', 'Stability, hierarchy', 'Purpose, collaboration', 'Speed, flexibility, inclusion']],ans:['Autonomy, pragmatism', 'Speed, flexibility, inclusion'],exp:'According to Pew Research & Deloitte (2023), Generation X core expectation is \'Autonomy, pragmatism\' while Generation Z core expectation is \'Speed, flexibility, inclusion.\'',topic:'l6'},
{id:444,type:'fill',applied:true,text:'[APPLIED] During innovation hours at a Lagos fintech team, Baby Boomers prepared _______ to share their ideas, while Gen Z team members dropped voice notes and _______ directly into the group chat.',dropdowns:[['slide decks', 'word documents', 'spreadsheets', 'emails'], ['Figma links', 'GitHub commits', 'PDF reports', 'Trello boards']],ans:['slide decks', 'Figma links'],exp:'The case study highlights that Boomers prepared slide decks while Gen Z used voice notes and Figma links, representing a generational communication format gap where neither group initially recognized the other\'s contribution format.',topic:'l6'},
{id:445,type:'fill',applied:false,text:'When a leader faces a crisis or severe time pressure, they should use a decision-making model where the _______, but for strategic, complex, and values-laden decisions, they should use a model where the _______.',dropdowns:[['leader decides alone', 'leader decides with input', 'team consensus is required', 'subgroup decides'], ['leader decides alone', 'leader decides with input', 'team consensus is required', 'subgroup decides']],ans:['leader decides alone', 'leader decides with input'],exp:'The five types of team decisions state that \'Leader decides alone\' is appropriate for \'Crisis, time pressure\', while \'Leader decides with input\' is appropriate for \'Strategic, complex, values-laden\' situations.',topic:'l6'},
{id:446,type:'fill',applied:false,text:'According to the attitude-culture link, a leader must model Stewardship by managing resources responsibly, and model _______ by celebrating others\' wins, because culture is the _______ of the leader\'s character.',dropdowns:[['Abundance', 'Resilience', 'Engagement', 'Trust'], ['shadow', 'reflection', 'result', 'foundation']],ans:['Abundance', 'shadow'],exp:'Celebrating others\' wins models Abundance. The lecture states: \'Culture is the shadow of the leader\'s character,\' emphasizing that a manager\'s modeled attitudes directly shape organizational culture.',topic:'l6'},
{id:447,type:'fill',applied:false,text:'The Tuckman Model describes the team development journey. The model states that teams progress from Forming, to _______, to Norming, and finally to _______.',dropdowns:[['Storming', 'Performing', 'Adjourning', 'Cooperating'], ['Storming', 'Performing', 'Adjourning', 'Cooperating']],ans:['Storming', 'Performing'],exp:'The stages of the Tuckman Model in order are: Forming → Storming → Norming → Performing. The leader\'s job is to accelerate this journey.',topic:'l6'},
{id:448,type:'fill',applied:false,text:'A workplace attitude where an employee works to build represents a _______ mentality, whereas an attitude of working merely to earn represents a _______ mentality.',dropdowns:[['Leader', 'Worker', 'Slave', 'Manager'], ['Leader', 'Worker', 'Slave', 'Manager']],ans:['Leader', 'Worker'],exp:'The three mentalities are: Slave (waits to be forced), Worker (works to earn), and Leader (works to build). The lecture advises to work to learn, not just to earn.',topic:'l6'},
{id:449,type:'fill',applied:false,text:'According to the ILO (2024), _______ of the global workforce operates remotely or in hybrid arrangements, which presents challenges such as Proximity Bias, isolation, and _______ in written texts.',dropdowns:[['17.4%', '20%', '41%', '84%'], ['Digital Misreading', 'Groupthink', 'Role Clashes', 'Transactional Exchange']],ans:['17.4%', 'Digital Misreading'],exp:'The ILO (2024) statistics state that 17.4% of the global workforce operates remotely/hybrid, introducing challenges like Proximity Bias, loneliness (22% feel isolated), and digital misreading where tone is lost in text.',topic:'l6'},
{id:450,type:'fill',applied:false,text:'In Patrick Lencioni\'s five team dysfunctions model, the lack of commitment is immediately preceded by _______ and followed by _______.',dropdowns:[['Fear of Conflict', 'Absence of Trust', 'Avoidance of Accountability', 'Inattention to Results'], ['Fear of Conflict', 'Absence of Trust', 'Avoidance of Accountability', 'Inattention to Results']],ans:['Fear of Conflict', 'Avoidance of Accountability'],exp:'Lencioni\'s Five Team Dysfunctions in ascending order are: Absence of Trust, Fear of Conflict, Lack of Commitment, Avoidance of Accountability, and Inattention to Results. Therefore, Lack of Commitment is preceded by Fear of Conflict and followed by Avoidance of Accountability.',topic:'l6'},
{id:451,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A tech startup CEO, Sarah, is under pressure from investors to release a new version of their app despite knowing it has minor security vulnerabilities. Consequentialist analysis suggests the release will generate immediate profits and please shareholders, while Virtue Ethics focuses on what kind of leader she becomes by choosing to compromise. If Sarah prioritizes short-term revenue over user trust, which of the following best describes her mindset according to the lecture\'s contrast of leadership definitions?',opts:['Contribution mindset, as she is providing a product to the market.', 'Extraction mindset, since she views her position and the company\'s product as a prize to get profit rather than a responsibility to protect users.', 'Transactional mindset, because she is negotiating a benefit with her investors.', 'Transforming mindset, as she is elevating the value of the startup.'],ans:1,exp:'Sarah is displaying an extraction mindset, which is characterized by the question \'What can I get?\' and viewing the position as a prize, making it highly corruption-prone. A contribution mindset, by contrast, asks \'What can I give?\' and views position as responsibility.'},
{id:452,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A regional director of a non-profit organization, Kwame, discovers that his team is inflating success metrics to secure a renewal of a critical development grant. Kwame knows that if they lose the grant, several local projects will shut down, harming the community. A consequentialist analysis would focus on the community benefit, but Kwame decides to report the true metrics because he believes that honesty is a duty that cannot be universalized into a rule of lying. Kwame\'s decision is best explained by which ethical framework?',opts:['Consequentialism', 'Deontology', 'Virtue Ethics', 'Biblical Reasoning'],ans:1,exp:'Kwame\'s decision is guided by Kant\'s Categorical Imperative (Deontology), asking if he could will metric inflation to be a universal law, and refusing to treat stakeholders as mere means to an end, regardless of the outcome.'},
{id:453,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] During a national audit of a state-owned enterprise, a senior auditor is offered an all-expenses-paid family vacation by a contractor whose records show major discrepancies. The auditor, who is a devout Christian, recalls the biblical pattern of Gehazi in 2 Kings 5:27 and refuses the gift immediately, realizing that taking a bribe under the guise of a private gift carries severe communal and personal consequences. Which of the following best captures the specific consequence of Gehazi\'s corruption as cited in the lecture?',opts:['He was executed alongside his family.', 'He was forced to return the wealth and became impoverished.', 'He became a leper as a physical manifestation of his compromised character.', 'He ended his own life in remorse.'],ans:2,exp:'The lecture notes that Gehazi extorted a bribe using his master\'s name and became a leper (2 Kgs 5:27). This demonstrates that biblical moral patterns warn that corruption is never private and always carries severe consequences.'},
{id:454,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A procurement officer at a construction firm is evaluating bids for a major infrastructure project. An old school friend who runs one of the bidding companies sends the officer a high-end smartphone as a \'belated birthday gift\' before the bids are finalized. The officer accepts it, thinking \'it is just a small gift, it won\'t affect my judgment.\' According to the five stages of the anatomy of corruption, which stage is the officer currently in?',opts:['Rationalisation', 'Small Compromise', 'Habituation', 'Escalation'],ans:1,exp:'Accepting a minor gift or signing off on a slightly questionable invoice represents Stage 1: Small Compromise, which is where corruption quietly and predictably begins before escalating.'},
{id:455,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] An executive at an engineering firm is pressured by the sales team to pay a \'facilitation fee\' to a foreign port official to expedite the clearance of equipment. The sales manager argues, \'Everyone in this industry does it, and if we don\'t, our projects will stall and workers will be laid off.\' By using the phrase \'everyone does it\' to justify the payment, which stage of the anatomy of corruption is the executive navigating?',opts:['Small Compromise', 'Habituation', 'Rationalisation', 'Escalation'],ans:2,exp:'Stage 2 of the anatomy of corruption is Rationalisation, where the leader justifies the action using statements like \'Everyone does it\' or \'It is the cost of doing business\' to quiet their conscience.'},
{id:456,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A CEO of a major retail chain decides to implement a strict safety audit across all warehouses after reading about Paul O\'Neill\'s tenure at Alcoa in 1987. The board of directors is concerned that focusing heavily on safety metrics will hurt short-term profits. However, the CEO insists that a leader\'s genuine obsession sets the organization\'s culture. Based on the Alcoa case study, what is the expected outcome of such a culture-first approach?',opts:['Safety improved, but the company\'s profits stagnated for several years.', 'Safety improved, and the company achieved record profits within a year as alignment and trust grew.', 'The company faced high employee turnover due to excessive safety protocols.', 'The CEO was replaced by the board due to poor financial performance.'],ans:1,exp:'Under Paul O\'Neill, Alcoa declared worker safety as the number one priority, which led to improved alignment, trust, and ultimately record profits within a year. Culture follows the leader\'s genuine obsession.'},
{id:457,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A mayor of a developing city wants to restructure the municipal license department to minimize corruption. The department currently has one clerk who approves all commercial licenses, has complete discretion over who gets approved, and is not required to publish any reports. Which formula from the lecture should the mayor apply to diagnose this system, and what does it suggest?',opts:['Burns\' transforming leadership model; it suggests appealing to the clerk\'s higher moral values.', 'Robert Klitgaard\'s formula: Corruption = (Monopoly + Discretion) - Accountability; it suggests that corruption is highly probable due to the clerk\'s monopoly and lack of oversight.', 'Treviño\'s moral manager matrix; it suggests that the clerk is ethically neutral.', 'Bandura\'s social learning theory; it suggests that the clerk will learn from their peers.'],ans:1,exp:'Klitgaard\'s formula states that Corruption = (Monopoly + Discretion) - Accountability. Having a single clerk with sole approval power and no public oversight makes corruption highly probable, demonstrating that good character alone is not sufficient without structural systems.'},
{id:458,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A newly appointed minister of finance in a post-conflict nation wants to emulate Rwanda\'s successful anti-corruption strategy from the early 2000s. The minister wants to reform the government procurement system. According to the lecture\'s description of Rwanda\'s reforms, which combination of practices should the minister prioritize to replicate these results?',opts:['Increasing the discretionary powers of local officials and providing higher salaries.', 'Digitalised procurement, mandatory asset declarations, and strict enforcement.', 'Outsourcing procurement to private international firms and reducing public audits.', 'Implementing a grace period for officials to return stolen funds without penalty.'],ans:1,exp:'Rwanda became one of Africa\'s least corrupt nations by 2013 by implementing digitalised procurement, asset declarations, and rigorous enforcement. This aligns with Klitgaard\'s systems approach.'},
{id:459,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A vice president of a pharmaceutical company is trying to decide whether to recall a drug that has shown very rare but serious side effects. Under a purely consequentialist (utilitarian) moral lens, how would the VP analyze the situation to determine the right course of action?',opts:['By asking if recalling the drug is a duty that should be made a universal law.', 'By assessing who will benefit, who will be harmed, and who is the most vulnerable among the patients and stakeholders.', 'By focusing on how this decision will shape the moral character and habits of the executive team.', 'By checking if the action complies with local regulatory laws and scriptures.'],ans:1,exp:'Consequentialism is the ethics of outcomes, focusing on the core questions: Who benefits? Who is harmed? Who is most vulnerable in this decision? It is associated with Bentham and Mill.'},
{id:460,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A director at a state university, Dr. Benson, refuses to accept a cash payment from a parent to guarantee their child\'s admission. Dr. Benson makes this decision not because of the risk of getting caught, but because he believes it is fundamentally wrong and treats other qualified applicants as mere means to financial gain. This decision reflects the NUC accreditation moment of Dr. Oyedepo and is an application of which ethical framework?',opts:['Consequentialism', 'Deontology', 'Virtue Ethics', 'Transactional Leadership'],ans:1,exp:'Deontology (Kant\'s categorical imperative) focuses on whether an action is categorically right or wrong, refusing to treat people as means to an end, similar to Dr. Oyedepo\'s refusal to bribe NUC officials.'},
{id:461,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A project manager, Maria, observes a colleague submitting falsified travel expense reports. Maria decides not to report it because she wants to avoid conflict and keep a peaceful working environment. According to Treviño et al. (2000), how will Maria\'s team perceive her leadership style if she remains silent about this wrongdoing?',opts:['As a moral manager who prioritizes team harmony.', 'As an ethically neutral leader, because silence on wrongdoing communicates that such behavior is acceptable.', 'As a transforming leader who trusts her team members\' integrity.', 'As a transactional leader who exchanges compliance for peace.'],ans:1,exp:'Treviño\'s model states that without active moral management (explicit expectations, visible modeling, and rewards/consequences), followers perceive the leader as \'ethically neutral.\' Silence is leadership that permits wrong.'},
{id:462,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] An engineering team leader, Chen, notices that junior engineers are copying code from open-source libraries without proper attribution, violating company policy. Chen decides to hold a team meeting, clarify the policy, and publicly reward a developer who documented all external sources. According to Treviño\'s framework, which dimensions of leadership is Chen demonstrating?',opts:['Moral Person only, because he knows the policy is right.', 'Moral Manager only, because he is focused on enforcement.', 'Both Moral Person and Moral Manager, by modeling values and actively communicating expectations and rewarding integrity.', 'Neither, as code attribution is a technical rather than ethical issue.'],ans:2,exp:'Chen possesses internal moral values (Moral Person) and actively communicates expectations, models them, and uses rewards to shape culture (Moral Manager). This builds a complete ethical leadership model.'},
{id:463,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A finance officer, David, works in a ministry where minor embezzlement of office supply budgets is common and widely ignored. David wants to resist this culture. According to Bandura\'s theory of ethical socialisation, which action will have the greatest impact on shaping the ethical behavior of the junior staff under David\'s supervision?',opts:['Writing and distributing a detailed 50-page code of conduct manual.', 'Modeling ethical behavior personally and ensuring staff apprentice under leaders of integrity.', 'Organizing a mandatory weekend seminar on the legal definitions of corruption.', 'Asking staff to sign an annual compliance pledge.'],ans:1,exp:'Bandura\'s theory of social learning shows that people watch and internalize the standards of those they admire, work alongside, or answer to. Ethical behavior is learned through observation, not policy manuals.'},
{id:464,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A corporate executive, Sarah, is tempted to divert company funds into a private offshore account to buy a luxury estate. She rationalizes that the company is highly profitable and won\'t miss the funds. However, she refrains because she realizes that she is a steward of these resources, which are held in trust, and she is vertically accountable. This reasoning aligns with which dimension of moral reasoning from the lecture?',opts:['Consequentialism', 'Deontology', 'Virtue Ethics', 'Biblical Reasoning'],ans:3,exp:'Biblical moral reasoning emphasizes vertical accountability (delegated authority from God), stewardship of resources held in trust, justice, and transformed desires of the heart.'},
{id:465,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A hospital administrator is faced with a shortage of ventilators during a public health crisis. Under pressure to decide who receives a ventilator, the administrator decides to allocate them to patients with the highest probability of survival, aiming to maximize the total number of lives saved. Which moral lens is the administrator primarily using?',opts:['Consequentialism', 'Deontology', 'Virtue Ethics', 'Biblical Reasoning'],ans:0,exp:'The administrator is applying consequentialism (utilitarianism), which seeks to produce the greatest good (survival) for the greatest number of people, focusing purely on outcomes.'},
{id:466,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A young business graduate, Tunde, starts a venture with the goal of \'making as much money as possible, by any means necessary, to achieve status.\' According to the lecture\'s comparison of \'Money Craze\' and \'Impact Crave,\' what is the primary risk associated with Tunde\'s current mindset?',opts:['He will fail to secure venture capital due to lack of a technical plan.', 'He is highly prone to corruption because he views position and business as a platform for personal accumulation rather than public responsibility.', 'He will struggle to recruit competent employees who prefer transactional exchanges.', 'He will be unable to apply Klitgaard\'s formula to his organization.'],ans:1,exp:'The \'Money Craze\' mindset focuses on accumulation, viewing position as a prize for personal gain, which makes a leader highly prone to corruption. The \'Impact Crave\' mindset makes corruption unnecessary as the leader focuses on contribution.'},
{id:467,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A municipal mayor, Helen, is accused of awarding a road construction contract to her brother\'s firm, which submitted an overpriced bid. Helen defends herself by stating that the extra funds will help her brother\'s family and that \'blood is thicker than water.\' According to the lecture\'s discussion of corruption, what is the fundamental moral problem with Helen\'s action?',opts:['It violates local zoning regulations.', 'It is a betrayal of the leader-follower relationship, treating public power as a personal advantage rather than a moral obligation.', 'It is a transactional exchange that fails to elevate the followers\' moral standards.', 'It is a consequentialist choice that benefits the local community.'],ans:1,exp:'Joanne Ciulla argues that the power asymmetry in leadership is a moral obligation, and corruption is a betrayal of the leader-follower relationship, treating entrusted power as personal advantage.'},
{id:468,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] An international logistics company, LogisticsCorp, operates in a country where customs officials routinely demand bribes to clear shipments. The company\'s compliance officer refuses to pay, even though it results in delayed shipments and financial losses. The officer states: \'We must build a character of honesty through daily decisions under pressure, because rules can be gamed but character cannot be faked.\' This officer\'s perspective is best aligned with:',opts:['Consequentialism', 'Deontology', 'Virtue Ethics', 'Transactional Leadership'],ans:2,exp:'Virtue Ethics (Aristotelian) focuses on character development, habits formed through practice, and daily decisions, emphasizing that character cannot be faked under pressure and rules can be gamed.'},
{id:469,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A director of a research institute is deciding whether to publish a study that contradicts the interests of their major corporate sponsor. The sponsor has threatened to pull funding if the study is published. The director decides to publish, stating: \'If we lose our funding, we lose money. If we lose our reputation, we lose something precious. But if we lose our character, we have lost everything.\' This statement reflects the philosophy of which figure cited in the lecture?',opts:['Dr. David Oyedepo', 'Billy Graham', 'Joanne Ciulla', 'Paul O\'Neill'],ans:1,exp:'This quote is explicitly attributed to Billy Graham in Module 3 of the lecture notes: \'If you lose money, you have lost something. If you lose your health, you have lost something precious. But if you lose your character, you have lost everything.\''},
{id:470,topic:'l7',type:'mcq',applied:true,text:'[APPLIED] A governmental agency director, Chief Alabi, holds absolute power over the distribution of agricultural subsidies, can approve or deny claims without writing justifications, and operates without any external auditing. Under Klitgaard\'s formula, which adjustment would most effectively reduce the probability of corruption in Chief Alabi\'s agency?',opts:['Giving Chief Alabi more discretion to expedite subsidy approvals.', 'Increasing Chief Alabi\'s monopoly over the subsidy distribution process.', 'Reducing Chief Alabi\'s monopoly, limiting his discretion, and increasing accountability through independent audits.', 'Appealing to Chief Alabi\'s religious values through training.'],ans:2,exp:'Klitgaard\'s formula is Corruption = (Monopoly + Discretion) - Accountability. To reduce the probability of corruption, the agency must reduce monopoly and discretion, and increase accountability.'},
{id:471,topic:'l7',type:'mcq',applied:false,text:'According to the introductory slides of Lecture 7, when an African Head of State was asked to identify the greatest problems facing the continent, he cited one specific word three times in succession. Which of the following represents the term and its significance as discussed by Dr. Oyedepo?',opts:['Corruption; because it is the systemic root of economic stagnation.', 'Leadership; because the crisis is fundamentally developmental, caused by a lack of trained, purposeful leaders.', 'Poverty; because economic deprivation drives institutional collapse.', 'Education; because without human capital development, no nation can progress.'],ans:1,exp:'The lecture cites an African Head of State saying: \'Number 1, Leadership. Number 2, Leadership. Number 3, Leadership.\' This highlights that Africa\'s greatest problem is leadership and that the crisis is developmental.'},
{id:472,topic:'l7',type:'mcq',applied:false,text:'In Module 1, Dr. Oyedepo redefines leadership by contrasting it with mere position. He argues that leadership is not about occupying a seat, but about accomplishing a feat. According to this framework, which of the following contrasts correctly represents the \'Extraction Mindset\' versus the \'Contribution Mindset\'?',opts:['Extraction mindset focuses on \'What can I give?\', while Contribution mindset focuses on \'What can I get?\'', 'Extraction mindset views position as a responsibility, while Contribution mindset views it as a prize.', 'Extraction mindset asks \'What can I get?\' and views position as a prize, whereas Contribution mindset asks \'What can I give?\' and views position as a responsibility.', 'Extraction mindset is purpose-driven, while Contribution mindset is profit-driven.'],ans:2,exp:'The lecture slides state that the Extraction Mindset asks \'What can I get?\' and views position as a prize, making it corruption-prone. The Contribution Mindset asks \'What can I give?\' and views position as a responsibility, making it corruption-resistant.'},
{id:473,topic:'l7',type:'mcq',applied:false,text:'Module 1 defines three core terms that are foundational to fighting corruption. Which of the following sets of definitions matches the lecture\'s specific explanations of Ethics, Integrity, and Corruption?',opts:['Ethics is obeying the law; Integrity is being honest when watched; Corruption is grand theft.', 'Ethics is choosing right over wrong even when wrong is more profitable; Integrity is the alignment between stated values and actual behaviour; Corruption is the abuse of entrusted power for private gain.', 'Ethics is moral philosophy; Integrity is spiritual maturity; Corruption is the bribe paid to public officials.', 'Ethics is personal values; Integrity is financial transparency; Corruption is the systemic failure of accountability.'],ans:1,exp:'Slide 6 defines: Ethics as choosing right over wrong even when wrong is more profitable; Integrity as alignment between stated values and actual behavior; Corruption as the abuse of entrusted power for private gain. It notes that corruption starts with a small compromise.'},
{id:474,topic:'l7',type:'mcq',applied:false,text:'Joanne Ciulla, in her 2003 book \'The Ethics of Leadership\', poses a central question regarding what constitutes \'good\' leadership. According to Ciulla\'s analysis, the word \'good\' in this context must simultaneously encompass which two distinct dimensions?',opts:['Financial success and public popularity.', 'Technical competence and moral soundness.', 'Political influence and charismatic communication.', 'Strategic vision and administrative efficiency.'],ans:1,exp:'Ciulla argues that \'good\' means two things: technically competent and morally sound. Effectiveness without ethics is manipulation at scale.'},
{id:475,topic:'l7',type:'mcq',applied:false,text:'In discussing the relationship between effectiveness and ethics, the lecture addresses \'The Hitler Problem\' raised by Joanne Ciulla. What is the core lesson of this problem for students of leadership?',opts:['Leadership is only effective if it achieves its goals, regardless of the ethical cost.', 'A leader can be highly effective at mobilizing people and resources but still be catastrophic in moral outcome, proving that effectiveness without ethics is manipulation.', 'Dictatorial leaders are structurally more efficient than democratic leaders.', 'Ethical leaders are rarely effective in high-pressure political environments.'],ans:1,exp:'The Hitler problem demonstrates that a leader can be technically effective at mobilizing people but morally catastrophic, showing that effectiveness without ethics is manipulation.'},
{id:476,topic:'l7',type:'mcq',applied:false,text:'The lecture notes emphasize that the relationship between a leader and a follower is inherently asymmetrical, creating a moral obligation. Why does this power asymmetry exist, and what does it oblige the leader to do?',opts:['It exists because leaders have superior education; it obliges them to train their followers.', 'It exists because leaders hold power over followers\' livelihoods, futures, and dignity; it obliges them to treat this power as a responsibility rather than a personal advantage.', 'It exists because of organizational hierarchy; it obliges followers to obey unconditionally.', 'It exists because of spiritual delegation; it obliges the leader to act as an intermediary.'],ans:1,exp:'The lecture slides state: \'Leaders hold power over followers\' livelihoods, futures, dignity. That asymmetry is a moral obligation — not a personal advantage.\' Corruption is a betrayal of this relationship.'},
{id:477,topic:'l7',type:'mcq',applied:false,text:'In Module 1, the \'Ethics of Authenticity\' is discussed by contrasting those who \'Perform Integrity\' with those who \'Possess Integrity.\' Which of the following examples is used in the lecture to illustrate a leader who possessed integrity through long-term consistency?',opts:['Paul O\'Neill, who managed safety at Alcoa.', 'Nelson Mandela, who spent 27 years in prison and was released with the exact same values he went in with.', 'Benjamin Franklin, who spent his lunch money on books.', 'Michael Faraday, who studied science under humblest conditions.'],ans:1,exp:'The lecture notes state: \'Mandela: 27 years in prison. Released with the same values he went in with. That consistency is integrity.\' Performs integrity represents acting ethical only when watched.'},
{id:478,topic:'l7',type:'mcq',applied:false,text:'Ethical maturity in leadership is defined not as choosing a single moral lens, but as being fluent in four distinct dimensions of moral reasoning. Which of the following correctly pairs each moral dimension with its core diagnostic question?',opts:['Consequentialism - Is this right?; Deontology - What will this build?; Virtue Ethics - Who benefits?; Biblical - What does the law say?', 'Consequentialism - What will this produce?; Deontology - Is this categorically right?; Virtue Ethics - What kind of leader am I becoming?; Biblical - Am I faithful to the One who entrusted this?', 'Consequentialism - Who is harmed?; Deontology - What is the custom?; Virtue Ethics - What is legal?; Biblical - What is the profit?', 'Consequentialism - What is the cost?; Deontology - What is my duty?; Virtue Ethics - What is my legacy?; Biblical - What is the church\'s policy?'],ans:1,exp:'Slide 11 lists the four dimensions: Consequentialism (What will this produce?), Deontology (Is this categorically right?), Virtue Ethics (What kind of leader am I becoming?), and Biblical Reasoning (Am I faithful to the One who entrusted this?).'},
{id:479,topic:'l7',type:'mcq',applied:false,text:'While consequentialism (utilitarianism) focuses on maximizing the greatest good for the greatest number, the lecture warns of a specific danger when this logic is used corruptly. What is this danger?',opts:['It can lead to paralysis by analysis when trying to calculate outcomes.', 'A corrupt official can use selective consequentialist logic to justify embezzlement by arguing that the diverted funds were used to build a community hospital.', 'It ignores the rights of the majority in favor of the minority.', 'It relies too heavily on divine intervention rather than human effort.'],ans:1,exp:'The lecture notes point out: \'The danger: A corrupt official who argues diverted funds built a hospital is using consequentialist logic — selectively and dishonestly.\' This shows the limits of outcome-only reasoning.'},
{id:480,topic:'l7',type:'mcq',applied:false,text:'Immanuel Kant\'s Deontology focuses on the concept of duty and the Categorical Imperative. According to the lecture, why is corruption considered \'categorically wrong\' under Kantian deontology?',opts:['Because it reduces public revenues and increases tax burdens on citizens.', 'Because it reduces citizens to mere instruments (means) of personal gain rather than treating them as ends in themselves.', 'Because it violates the spiritual laws of seedtime and harvest.', 'Because it is punishable by modern legal systems like the EFCC.'],ans:1,exp:'Kant\'s deontology states that we must treat people as ends, never as means. Corruption reduces citizens to instruments of personal gain, which is categorically wrong, regardless of the outcome.'},
{id:481,topic:'l7',type:'mcq',applied:false,text:'Virtue Ethics, associated with Aristotle, shifts the moral focus from specific actions to character. According to the lecture, how is character formed, and what does this imply for a leader\'s choices?',opts:['Character is innate and cannot be changed; leaders are born with it.', 'Character is formed through the accumulation of small daily decisions and practices; the habits formed today become automatic responses under pressure tomorrow.', 'Character is established by memorizing company policies and code of conduct manuals.', 'Character is formed only during major crises that test a leader\'s survival instincts.'],ans:1,exp:'Aristotle\'s virtue ethics states that virtues are formed through practice. Character is the accumulated outcome of small daily decisions, and habits shape responses under pressure. Rules can be gamed, but character cannot be faked.'},
{id:482,topic:'l7',type:'mcq',applied:false,text:'Biblical moral reasoning is presented as a framework that deepens secular ethical theories. Which of the following is NOT one of the core elements of biblical reasoning discussed in the lecture notes?',opts:['Vertical accountability, where authority is delegated by God rather than owned.', 'Stewardship, where resources are held in trust rather than used for personal gain.', 'Justice, especially the prophetic condemnation of the exploitation of the poor.', 'Transactional exchange, where compliance is rewarded with financial prosperity.'],ans:3,exp:'Transactional exchange is not a part of biblical moral reasoning. The four elements are: Vertical accountability (Rom 13:1), Stewardship (Matt 25:14), Justice (Amos 5:24), and Transformed desire (Pro 4:23).'},
{id:483,topic:'l7',type:'mcq',applied:false,text:'How does the lecture explain the relationship between secular ethical frameworks and Biblical moral reasoning?',opts:['They are in direct opposition, and a leader must choose only the Biblical framework.', 'Biblical reasoning grounds and deepens secular frameworks (e.g., grounding Kantian dignity in the Imago Dei, and virtue in sanctification).', 'Secular frameworks are superior because they apply to non-religious organizations.', 'Biblical reasoning is only applicable in faith-based institutions.'],ans:1,exp:'Slide 16 shows that Biblical reasoning deepens secular frameworks: Kantian dignity becomes Imago Dei, concern for the poor is grounded in God\'s identification with the marginalized, virtue becomes sanctification, and accountability systems are grounded in the fact that nothing is private before God.'},
{id:484,topic:'l7',type:'mcq',applied:false,text:'In Module 2, three biblical pattern studies are analyzed to show the roots and consequences of corruption. Which of the following correctly pairs the leader, their corrupt act, and their subsequent consequence?',opts:['Achan - Extorted a bribe using master\'s name - Became a leper.', 'Gehazi - Hoarded forbidden wealth - Family executed.', 'Judas - Betrayed trust for 30 pieces of silver - Ended in suicide.', 'Gehazi - Betrayed trust - Family executed.'],ans:2,exp:'Table on page 19: Achan hoarded forbidden wealth (family executed, Josh 7:25); Gehazi extorted a bribe (became a leper, 2 Kgs 5:27); Judas betrayed trust for 30 pieces of silver (suicide, Matt 27:3-8).'},
{id:485,topic:'l7',type:'mcq',applied:false,text:'The lecture outlines the \'Anatomy of Corruption\' in five distinct stages. Which of the following lists these stages in their correct chronological order?',opts:['Rationalisation → Small Compromise → Habituation → Escalation → Exposure & Collapse.', 'Small Compromise → Rationalisation → Habituation → Escalation → Exposure & Collapse.', 'Small Compromise → Habituation → Rationalisation → Escalation → Exposure & Collapse.', 'Rationalisation → Habituation → Small Compromise → Escalation → Exposure & Collapse.'],ans:1,exp:'Slide 20 lists the five stages: 1. Small Compromise, 2. Rationalisation, 3. Habituation, 4. Escalation, 5. Exposure & Collapse. This shows how corruption quietly and predictably escalates from small acts.'},
{id:486,topic:'l7',type:'mcq',applied:false,text:'The 2008 Siemens AG case study is used in Module 2 to illustrate what happens when corruption becomes systemic. What was the central issue in this case, and what was the outcome?',opts:['Product safety failures that led to a fine of $1.6 billion.', 'Bribery was treated as \'the cost of doing business\' in over 65 countries, resulting in a $1.6 billion fine and destroyed careers.', 'Insider trading by executives that led to the collapse of the company.', 'Anti-competitive monopoly practices that were prosecuted by the European Union.'],ans:1,exp:'Siemens AG paid bribes in 65+ countries as \'the cost of doing business,\' resulting in a $1.6 billion fine, destroyed careers, and years of rebuilding. It demonstrates that corrupt systems eventually implode.'},
{id:487,topic:'l7',type:'mcq',applied:false,text:'Module 2 discusses the societal and organizational consequences of corruption. According to the lecture, who actually pays for a leader\'s corruption?',opts:['Only the leader pays, because they lose their position and legacy.', 'The organization pays the fines, but society remains unaffected.', 'The public pays as institutional trust erodes, competent people leave, development stalls, and poverty multiplies.', 'The competitor firms pay because they are shut out of contracts.'],ans:2,exp:'Page 22 states that the consequences of corruption include: institutional trust erodes, competent people leave, development stalls, poverty multiplies, and legacy is destroyed. The public is the ultimate casualty.'},
{id:488,topic:'l7',type:'mcq',applied:false,text:'In Module 3, the lecture emphasizes that character is the foundation of leadership. According to the quote by Billy Graham, what is the relative loss associated with losing money, health, and character?',opts:['Losing money is losing everything; losing character is losing nothing.', 'Losing money is losing something; losing health is losing something precious; but losing character is losing everything.', 'Losing health is the greatest loss because a leader cannot function without physical strength.', 'Losing character can be compensated for by acquiring wealth and influence.'],ans:1,exp:'Billy Graham is quoted: \'If you lose money, you have lost something. If you lose your health, you have lost something precious. But if you lose your character, you have lost everything.\' This shows character is paramount.'},
{id:489,topic:'l7',type:'mcq',applied:false,text:'Dr. Oyedepo identifies five attitudes that define ethical leaders. Which of the following correctly describes the ethical implication of the leader\'s attitude toward \'Work\' and \'Money\'?',opts:['Work is to earn money; Money belongs to the leader.', 'Work is a platform to gain position; Money is for personal consumption.', 'Work is done to learn, not just to earn; Money is viewed as resources held in trust.', 'Work is delegated to others; Money is accumulated for future security.'],ans:2,exp:'Table on page 25: Attitude to Work (works to learn, not just to earn); Attitude to Money (resources held in trust). The attitude to money is the most frequent trigger of corruption.'},
{id:490,topic:'l7',type:'mcq',applied:false,text:'In Module 3, the \'Money Attitude\' is described as the most dangerous orientation in leadership. Dr. Oyedepo contrasts \'Accumulation\' with \'Stewardship.\' Which of the following is a characteristic of the \'Stewardship\' orientation?',opts:['Viewing resources as belonging exclusively to the leader.', 'Viewing position as a platform for personal gain.', 'Believing that what the leader has is never enough.', 'Viewing resources as held in trust, position as public responsibility, and having what is sufficient for the task.'],ans:3,exp:'Page 26 contrasts: Accumulation (resources belong to me, position = personal gain, never enough) vs. Stewardship (resources held in trust, position = public responsibility, sufficient for the task). Love of money is a character problem.'},
{id:491,topic:'l7',type:'mcq',applied:false,text:'James MacGregor Burns (1978) distinguishes between Transactional and Transforming leadership. According to the lecture, why is transactional leadership more prone to corruption?',opts:['Because it requires high levels of emotional intelligence that most leaders lack.', 'Because it is based on an exchange of benefits for compliance, appealing to self-interest, which easily transitions into bribery.', 'Because it completely ignores organizational hierarchy and rules.', 'Because it requires the leader to be a moral manager.'],ans:1,exp:'Transactional leadership involves exchange of benefit for compliance and appeals to self-interest, which is corruption-prone, whereas transforming leadership elevates both leader and follower morally and is corruption-dissonant.'},
{id:492,topic:'l7',type:'mcq',applied:false,text:'The lecture quotes Ralph Waldo Emerson on the \'Habit Loop of Character\' to explain how destiny is formed. What is the correct sequence of the loop as described in this quote?',opts:['Sow a habit → reap a thought; sow a character → reap a destiny.', 'Sow a thought → reap a habit; sow a habit → reap a character; sow a character → reap a destiny.', 'Sow a destiny → reap a character; sow a character → reap a habit.', 'Sow a rule → reap compliance; sow compliance → reap culture.'],ans:1,exp:'Emerson\'s quote is: \'Sow a thought → reap a habit; sow a habit → reap a character; sow a character → reap a destiny.\' This shows private decisions determine public outcomes.'},
{id:493,topic:'l7',type:'mcq',applied:false,text:'Paul O\'Neill\'s tenure at Alcoa is used to show that culture follows the leader\'s genuine obsession. How does Dr. Oyedepo apply this to ethical leadership in Module 4?',opts:['He suggests that leaders should delegate the task of building an ethical culture to HR.', 'He states that leaders can delegate functions, but they cannot delegate leadership itself; ethical culture must be owned personally.', 'He recommends writing detailed policy documents and audits.', 'He suggests that profits must always be prioritized over safety.'],ans:1,exp:'Dr. Oyedepo is quoted: \'Leaders can delegate functions — but not leadership itself.\' Ethical culture cannot be outsourced or delegated; it must be personally modeled and owned.'},
{id:494,topic:'l7',type:'mcq',applied:false,text:'Treviño et al. (2000) introduced the distinction between a \'Moral Person\' and a \'Moral Manager.\' What is the main consequence if a leader is a Moral Person but fails to be a Moral Manager?',opts:['Followers will perceive the leader as highly ethical and imitate them.', 'Followers will see the leader as \'ethically neutral\' and assume that silence on wrongdoing implies approval.', 'The leader will be forced to resign due to lack of technical competence.', 'The organization will experience immediate financial collapse.'],ans:1,exp:'Without the moral manager dimension (active modeling, communicating expectations, and enforcing consequences), followers see the leader as \'ethically neutral.\' Silence is leadership that permits wrong.'},
{id:495,topic:'l7',type:'mcq',applied:false,text:'Module 4 discusses how purpose provides ethical resilience. Based on Sinek\'s and Aquino & Reed\'s (2002) work, why are purpose-driven leaders more resistant to corruption?',opts:['Because they are typically paid higher salaries, reducing financial pressure.', 'By having a clear \'why\' and moral identity central to their self-concept, compromise feels like betraying who they are.', 'Because they are less likely to be audited by regulatory authorities.', 'Because they focus entirely on transactional exchanges.'],ans:1,exp:'Page 35 notes that a clear \'why\' filters choices, and when moral identity is central, compromise feels like betraying who you are. Corruption thrives when leaders are defined by position/status.'},
{id:496,topic:'l7',type:'multi',applied:true,text:'[APPLIED] A senior software architect, Aisha, discovers that her company\'s database system contains a back door that allows unauthorized access to customer data. She is considering reporting this to a regulator, but knows it might lead to severe financial penalties for her company and potential job cuts. If Aisha applies all four dimensions of moral reasoning (Consequentialism, Deontology, Virtue Ethics, and Biblical Reasoning) to analyze this situation, which of the following statements represent correct applications of these lenses? (Select all that apply)',opts:['Consequentialism would analyze who is harmed by the backdoor versus who benefits, and seek to protect the vulnerable customer base.', 'Deontology would evaluate whether leaving a security backdoor is a practice that can be willed as a universal law.', 'Virtue Ethics would ask: \'What kind of professional and moral leader am I becoming by remaining silent about this vulnerability?\'', 'Biblical Reasoning would view the customer data as a stewardship assignment and Aisha\'s authority as delegated responsibility under vertical accountability.'],ans:[0, 1, 2, 3],exp:'All four statements represent correct applications of the moral reasoning lenses: Consequentialism evaluates benefits/harms, Deontology checks universalizability, Virtue Ethics focuses on character formation, and Biblical Reasoning highlights stewardship and vertical accountability.'},
{id:497,topic:'l7',type:'multi',applied:true,text:'[APPLIED] A newly hired logistics director at a state cargo port, Chukwu, is informed by his team that customs clearance can be accelerated if they pay informal \'tips\' to inspectors. His team tells him: \'This is just standard practice, it makes everyone\'s lives easier, and the company benefits from faster deliveries.\' Chukwu wants to address this situation. According to Robert Klitgaard\'s formula and the 5 Pillars of Anti-Corruption Architecture, which actions should Chukwu take to systematically reduce corruption at the port? (Select all that apply)',opts:['Increase the discretionary power of individual customs inspectors to make quick decisions.', 'Implement digitalised tracking and procurement systems to reduce the monopoly and discretion of inspectors.', 'Provide safe reporting channels for whistleblowers to report bribery demands without fear of retaliation.', 'Establish clear, consistent consequences for any employee or inspector caught paying or receiving bribes, regardless of their rank.'],ans:[1, 2, 3],exp:'To reduce corruption using Klitgaard\'s formula, monopoly and discretion must be reduced while accountability is increased. This is done by digitizing tracking (reducing monopoly/discretion). The 5 Pillars also support safe reporting and consistent consequences, while increasing inspector discretion would increase corruption.'},
{id:498,topic:'l7',type:'multi',applied:true,text:'[APPLIED] A school board president, Mrs. Davis, is reviewing bids for a new school building. One contractor secretly offers to build a free swimming pool for Mrs. Davis\'s private residence if their bid is selected. Mrs. Davis is tempted but declines. According to the \'Ethics of Authenticity\' and \'Moral Person vs. Moral Manager\' concepts, what must Mrs. Davis do to transition from merely possessing integrity as a \'Moral Person\' to acting as a \'Moral Manager\' in this scenario? (Select all that apply)',opts:['She must keep the bribe attempt confidential to protect the contractor\'s reputation.', 'She must visibly model her values by rejecting the offer and documenting the incident.', 'She must explicitly communicate the board\'s expectations regarding bribery to all bidding contractors.', 'She must implement systems to reward vendors who demonstrate transparency and report the corrupt vendor to the authorities.'],ans:[1, 2, 3],exp:'A Moral Manager goes beyond internal values by modeling values visibly, communicating expectations explicitly, and enforcing consequences or rewards. Keeping the bribe confidential does not model values or communicate standards to others.'},
{id:499,topic:'l7',type:'multi',applied:true,text:'[APPLIED] A regional director of a public health agency, Dr. Ibrahim, is investigating a case where clinic managers are selling free government-provided malaria drugs to patients. Dr. Ibrahim wants to design an intervention based on Bandura\'s theory of ethical socialisation and the Siemens case study. Which of the following strategies should Dr. Ibrahim implement? (Select all that apply)',opts:['Ensure that clinic managers apprentice under senior medical leaders who demonstrate exemplary integrity.', 'Establish clear, public rewards for clinics that maintain 100% free drug distribution.', 'Treat the sale of free drugs as a minor \'cost of doing business\' to avoid disrupting clinic operations.', 'Create a transparent, digitized drug tracking system so that drug distribution is visible to the public.'],ans:[0, 1, 3],exp:'Bandura\'s ethical socialisation highlights that behavior is learned through observing and apprenticing under admired leaders. Rewarding integrity is a key moral manager action. Digitization increases transparency. Treating it as \'the cost of doing business\' is a dangerous rationalization, as seen in the Siemens AG case study.'},
{id:500,topic:'l7',type:'multi',applied:false,text:'The lecture notes outline Robert Klitgaard\'s classic formula (1988) for understanding corruption as a systemic problem rather than just a moral one. According to this formula, which factors increase the probability of corruption in an institution? (Select all that apply)',opts:['High levels of monopoly held by a single officer.', 'Broad discretionary powers granted to an officer without guidelines.', 'A lack of accountability and oversight systems.', 'High levels of moral reasoning and ethical training.'],ans:[0, 1, 2],exp:'Klitgaard\'s formula is Corruption = Monopoly + Discretion - Accountability. Therefore, high monopoly, high discretion, and low accountability increase the probability of corruption. Moral reasoning and ethical training are individual characteristics and do not increase systemic corruption.'},
{id:501,topic:'l7',type:'multi',applied:false,text:'In Module 3, James MacGregor Burns (1978) defines two different leadership models: Transactional and Transforming. Which of the following characteristics are associated with Transforming Leadership? (Select all that apply)',opts:['Both the leader and the follower are elevated morally through their interaction.', 'It is based on a simple exchange of benefits (e.g., votes for favors) for compliance.', 'It appeals to higher values, mission, and collective purpose rather than self-interest.', 'It is structurally corruption-dissonant because it aligns action with moral principles.'],ans:[0, 2, 3],exp:'Transforming leadership elevates both leader and follower morally, appeals to higher values, and is structurally corruption-dissonant. Transactional leadership appeals to self-interest and is based on exchange of benefits for compliance, which makes it corruption-prone.'},
{id:502,topic:'l7',type:'multi',applied:false,text:'According to the lecture notes, what are the five pillars of a robust anti-corruption architecture that a leader must implement to build an ethical culture? (Select all that apply)',opts:['Personal modeling of ethical behavior without double standards.', 'Rewarding integrity publicly and providing safe reporting channels for whistleblowers.', 'Ensuring consistent consequences, especially eliminating top-level impunity.', 'Maximizing transparency through open books and open processes.'],ans:[0, 1, 2, 3],exp:'All options represent pillars of anti-corruption architecture: Model personally, Reward integrity, Safe reporting, Consistent consequences, and Transparency, as detailed in Module 4 (Slide 32).'},
{id:503,topic:'l7',type:'multi',applied:false,text:'The lecture contrasts the \'Money Craze\' mindset with the \'Impact Crave\' mindset. Which of the following statements correctly describe the \'Impact Crave\' mindset? (Select all that apply)',opts:['It is characterized by the question \'What can I build?\' rather than \'What can I get?\'', 'It views position as a platform for service and contribution rather than a prize for accumulation.', 'It makes corruption unnecessary because the leader\'s worth is defined by what they add, not what they have.', 'It prioritizes short-term financial gains for shareholders over safety.'],ans:[0, 1, 2],exp:'The \'Impact Crave\' mindset focuses on contribution (\'What can I build?\', position as platform, corruption unnecessary). The \'Money Craze\' is focused on accumulation (\'What can I get?\', position as prize, corruption tempting). Prioritizing short-term gains over safety represents the Money Craze.'},
{id:504,topic:'l7',type:'multi',applied:false,text:'In Module 1, the lecture presents the \'Ethics of Authenticity\' by comparing leaders who perform integrity with those who possess it. What are the key characteristics of a leader who merely \'Performs Integrity\'? (Select all that apply)',opts:['They are ethical only when they are being watched or monitored.', 'They treat values as a PR tool or marketing strategy rather than an internal compass.', 'They collapse under pressure and compromise their stated values.', 'They maintain the same values even in prison, like Nelson Mandela.'],ans:[0, 1, 2],exp:'A leader who performs integrity is ethical only when watched, uses values as PR, and collapses under pressure. A leader who possesses integrity is ethical regardless, uses values as a compass, and holds firm under pressure (like Nelson Mandela).'},
{id:505,topic:'l7',type:'multi',applied:false,text:'In Module 4, Dr. Oyedepo outlines five decision qualities that an ethical leader must exhibit under pressure. Which of the following are among these five qualities? (Select all that apply)',opts:['Thoughtful: making considered decisions rather than reactive ones.', 'Right: choosing principled actions rather than convenient ones.', 'Firm: holding to the decision even under intense pressure.', 'Tough: making painful but necessary choices.'],ans:[0, 1, 2, 3],exp:'The five qualities of ethical decision-making under pressure are: Thoughtful, Right, Firm, Timely, and Tough. All four choices represent these qualities.'},
{id:506,topic:'l7',type:'short',applied:true,text:'[APPLIED] A corporate auditor, Joseph, is offered a bribe by a manager to overlook an unauthorized transaction. Joseph refuses, asking himself: \'What kind of person and professional am I becoming by making this daily choice?\' Which specific ethical framework from the lecture is Joseph using to guide his character development?',ans:'Virtue Ethics',exp:'Virtue Ethics (associated with Aristotle) focuses on character development, habits formed through practice, and asks \'What kind of person should I be?\' rather than focusing on rules or consequences.'},
{id:507,topic:'l7',type:'short',applied:true,text:'[APPLIED] A municipal director of public works is the sole official who can approve construction permits, possesses full discretion on approvals, and has no oversight or reporting duties. Under Robert Klitgaard\'s formula, which specific organizational property represents the director\'s unchecked, single-handed control over this process?',ans:'Monopoly',exp:'In Robert Klitgaard\'s formula (Corruption = Monopoly + Discretion - Accountability), \'Monopoly\' represents a single official or office having sole control over a transaction or approval process.'},
{id:508,topic:'l7',type:'short',applied:false,text:'Which moral framework, associated with Jeremy Bentham and John Stuart Mill, focuses on outcomes and asks who benefits, who is harmed, and who is most vulnerable in a decision?',ans:'Consequentialism',exp:'Consequentialism is the ethical framework that focuses on the outcomes of actions, arguing that the right action is the one that produces the greatest good for the greatest number.'},
{id:509,topic:'l7',type:'short',applied:false,text:'What specific term does Dr. Oyedepo use to define the alignment between a leader\'s stated values and their actual behavior?',ans:'Integrity',exp:'Integrity is defined in Module 1 as the alignment between stated values and actual behavior (i.e. doing what you say you believe).'},
{id:510,topic:'l7',type:'short',applied:false,text:'What specific term is defined by Dr. Oyedepo as choosing right over wrong, even when wrong is more profitable?',ans:'Ethics',exp:'Ethics is defined in Module 1 as choosing right over wrong, even when wrong is more profitable.'},
{id:511,topic:'l7',type:'short',applied:false,text:'Which ethical framework, associated with Immanuel Kant, emphasizes duty and the Categorical Imperative, arguing that certain actions are wrong regardless of their outcomes?',ans:'Deontology',exp:'Deontology is the ethical framework that focuses on duty, rules, and the Categorical Imperative, asserting that actions are right or wrong in themselves.'},
{id:512,topic:'l7',type:'short',applied:false,text:'According to the lecture notes, what specific leadership model described by James MacGregor Burns is based on an exchange of benefits for compliance and is highly corruption-prone?',ans:'Transactional Leadership',exp:'Transactional leadership is based on an exchange of benefits for compliance and appeals to self-interest, making it highly corruption-prone.'},
{id:513,topic:'l7',type:'short',applied:false,text:'What specific leadership model described by James MacGregor Burns morally elevates both the leader and the follower and is structurally corruption-dissonant?',ans:'Transforming Leadership',exp:'Transforming leadership elevates both leader and follower morally and appeals to higher values, making it structurally corruption-dissonant.'},
{id:514,topic:'l7',type:'short',applied:false,text:'What is the first stage in the five-stage \'Anatomy of Corruption\' outlined in the lecture notes, where the process of ethical decay quietly and predictably begins?',ans:'Small Compromise',exp:'The anatomy of corruption begins with Stage 1: Small Compromise, which represents minor actions like accepting a small gift or signing off on a slightly questionable invoice.'},
{id:515,topic:'l7',type:'short',applied:false,text:'According to Treviño et al. (2000), a leader must possess two dimensions: they must be a moral person, and they must also be what other type of manager to actively shape an ethical culture?',ans:'Moral Manager',exp:'Treviño argues that leaders must be both a Moral Person (possessing good values) and a Moral Manager (actively modeling, communicating, and enforcing values) to shape an ethical culture.'},
{id:516,topic:'l7',type:'fill',applied:false,text:'According to Dr. Oyedepo\'s lecture notes on redefining leadership, an _______ mindset asks \'What can I get?\' and views position as a prize, whereas a _______ mindset asks \'What can I give?\' and views position as a responsibility.',dropdowns:[['extraction', 'contribution', 'transactional', 'transforming'], ['extraction', 'contribution', 'transactional', 'transforming']],ans:['extraction', 'contribution'],exp:'Slide 7 contrasts the Extraction Mindset (asks \'What can I get?\' and views position as a prize) with the Contribution Mindset (asks \'What can I give?\' and views position as responsibility).'},
{id:517,topic:'l7',type:'fill',applied:false,text:'Joanne Ciulla, in \'The Ethics of Leadership\' (2003), argues that \'good\' leadership means two things: being _______ competent and _______ sound. She warns that effectiveness without ethics is manipulation at scale.',dropdowns:[['technically', 'morally', 'politically', 'financially'], ['technically', 'morally', 'spiritually', 'intellectually']],ans:['technically', 'morally'],exp:'Joanne Ciulla argues that \'good\' means both technically competent and morally sound. Effectiveness without ethics is manipulation at scale.'},
{id:518,topic:'l7',type:'fill',applied:false,text:'The lecture contrasts Mandela\'s 27 years in prison, representing someone who _______ integrity, with leaders who behave ethically only when watched, representing those who _______ integrity.',dropdowns:[['possesses', 'performs', 'simulates', 'ignores'], ['possesses', 'performs', 'evades', 'rejects']],ans:['possesses', 'performs'],exp:'Nelson Mandela represents possessing integrity (ethical regardless of whether someone is watching, values as a compass), while performing integrity represents behaving ethically only when watched (values as PR).'},
{id:519,topic:'l7',type:'fill',applied:false,text:'In the analysis of the roots of corruption in Module 2, the biblical character _______ is cited for extorting a bribe using his master\'s name and becoming a leper, while _______ is cited for betraying trust for 30 pieces of silver and ending in suicide.',dropdowns:[['Gehazi', 'Achan', 'Judas', 'Ananias'], ['Gehazi', 'Achan', 'Judas', 'Demas']],ans:['Gehazi', 'Judas'],exp:'Gehazi extorted a bribe using his master\'s name and became a leper (2 Kgs 5:27), whereas Judas betrayed trust for 30 pieces of silver and ended in suicide (Matt 27:3-8).'},
{id:520,topic:'l7',type:'fill',applied:false,text:'The five stages of the anatomy of corruption progress from a small compromise to _______, where the leader quietens their conscience by saying \'everyone does it\', which leads to _______, where the conscience is silenced and the behavior becomes normal.',dropdowns:[['rationalisation', 'habituation', 'escalation', 'exposure'], ['rationalisation', 'habituation', 'escalation', 'exposure']],ans:['rationalisation', 'habituation'],exp:'Stage 2 is Rationalisation, where the leader justifies the act to quiet their conscience. Stage 3 is Habituation, where the conscience is completely silenced and the behavior becomes normal.'},
{id:521,topic:'l7',type:'fill',applied:false,text:'Billy Graham\'s quote on character warns: \'If you lose money, you have lost something. If you lose your health, you have lost something _______; but if you lose your character, you have lost _______.\'',dropdowns:[['valuable', 'precious', 'important', 'useful'], ['something', 'precious', 'everything', 'nothing']],ans:['precious', 'everything'],exp:'Billy Graham\'s exact quote is: \'If you lose money, you have lost something. If you lose your health, you have lost something precious. But if you lose your character, you have lost everything.\''},
{id:522,topic:'l7',type:'fill',applied:false,text:'James MacGregor Burns (1978) contrasts transaction and transformation, stating that transactional leadership is _______, whereas transforming leadership is structurally _______.',dropdowns:[['corruption-prone', 'corruption-resistant', 'ethically neutral', 'highly stable'], ['corruption-prone', 'corruption-resistant', 'dissonant', 'neutral']],ans:['corruption-prone', 'dissonant'],exp:'Transactional leadership is corruption-prone due to its reliance on self-interested exchange. Transforming leadership is structurally corruption-dissonant (or resistant) because it appeals to higher values.'},
{id:523,topic:'l7',type:'fill',applied:false,text:'Robert Klitgaard\'s (1988) systems formula defines that corruption is equal to monopoly plus _______ minus _______.',dropdowns:[['discretion', 'accountability', 'responsibility', 'transparency'], ['discretion', 'accountability', 'responsibility', 'transparency']],ans:['discretion', 'accountability'],exp:'Klitgaard\'s formula states that Corruption = Monopoly + Discretion - Accountability.'},
{id:524,topic:'l7',type:'fill',applied:false,text:'Treviño et al. (2000) explain that a leader who has good values internally is a moral person, but without the _______ manager dimension, followers see the leader as ethically _______.',dropdowns:[['moral', 'transforming', 'transactional', 'cultural'], ['neutral', 'sound', 'compromised', 'competent']],ans:['moral', 'neutral'],exp:'Treviño notes that without the moral manager dimension, followers see the leader as \'ethically neutral\' and interpret silence as permission.'},
{id:525,topic:'l7',type:'fill',applied:false,text:'In Module 4, Sinek notes that a clear _______ filters choices that contradict your core reason for leading, while Aquino and Reed (2002) argue that when being moral is central to your _______, compromise feels like betraying who you are.',dropdowns:[['why', 'vision', 'mission', 'goal'], ['identity', 'career', 'reputation', 'position']],ans:['why', 'identity'],exp:'Simon Sinek emphasizes having a clear \'why\' to filter choices, and Aquino & Reed emphasize \'moral identity\' as central to self-concept.'},
{id:526,type:'mcq',applied:true,text:'[APPLIED] A software development team is falling behind its release schedule. The CTO examines Git commit metrics and concludes the engineers are underperforming and lack discipline. Meanwhile, the Project Manager looks at the JIRA backlog and argues that the delay is due to the product team constantly changing requirements mid-sprint. Under Susan Raines\' framework, what source of conflict does this represent?',ans:0,exp:'Data Conflict arises when parties lack the information necessary to make decisions, are misinformed, disagree on which data is relevant, or interpret information differently. Here, the CTO and PM are looking at different metrics (Git commits vs JIRA backlog) and drawing different conclusions.',topic:'l8',opts:['Data Conflict, because the two leaders are looking at different sets of information and interpreting facts differently.', 'Structural Conflict, because the CTO and Project Manager have conflicting reporting lines and organizational roles.', 'Interest Conflict, because the developers want more time to write clean code while the CTO wants a fast market release.', 'Relationship Conflict, because there is an underlying lack of trust between the engineering team and product management.']},
{id:527,type:'mcq',applied:true,text:'[APPLIED] In a mid-sized e-commerce firm, the Marketing Department is evaluated and rewarded based on the absolute number of leads they generate monthly. The Sales Department is evaluated on the percentage of leads they convert into paying customers. Sales constantly complains that Marketing generates low-quality leads, while Marketing complains Sales is too lazy to close deals. Which source of conflict is this?',ans:1,exp:'Structural Conflict is caused by forces external to the people in dispute, such as physical layout, resource constraints, organizational structure, roles, authority, or conflicting reward systems. In this case, the conflicting incentive systems (lead volume vs conversion rate) drive the dispute.',topic:'l8',opts:['Relationship Conflict, since there is public finger-pointing and historical resentment between the departments.', 'Structural Conflict, because the conflict is driven by the organizational structure, resource allocation, and conflicting incentive systems.', 'Values Conflict, because the two departments hold fundamentally different views on what constitutes success in the business.', 'Data Conflict, since both teams are using different reporting dashboards to measure their monthly performance.']},
{id:528,type:'mcq',applied:true,text:'[APPLIED] Two product designers are collaborating on a new medical device. Designer A insists on a physical, tactile dial for adjusting dosages, arguing that older patients need tactile feedback to feel secure (a psychological and procedural interest). Designer B insists on a touchscreen to reduce manufacturing costs and assembly steps (a substantive interest). What source of conflict does this represent?',ans:2,exp:'Interest Conflict is caused by competition over perceived or actual incompatible needs. These needs can be substantive (money, resources), procedural (the way things are done), or psychological (trust, respect, security). Here, tactile feedback (psychological/procedural) conflicts with manufacturing cost (substantive).',topic:'l8',opts:['Values Conflict, because the designers disagree on the ethical responsibility of design accessibility.', 'Relationship Conflict, because the designers are letting their professional egos and history interfere with the design process.', 'Interest Conflict, because the dispute is driven by competing underlying needs, including substantive (cost) and psychological/procedural (tactile feedback) interests.', 'Data Conflict, because they lack user-testing data to prove which interface is safer for patients.']},
{id:529,type:'mcq',applied:true,text:'[APPLIED] Two senior engineers, Alex and Jordan, have worked at the same firm for a decade. Five years ago, Jordan publicly blamed Alex for a server outage that caused a client to walk away. Since then, they refuse to work on the same projects, interpret every email from each other as passive-aggressive, and criticize each other\'s work during peer reviews. Which source of conflict is this?',ans:3,exp:'Relationship Conflict is caused by strong emotions, misperceptions or stereotypes, poor communication or miscommunication, and repetitive negative behaviors. The historical incident and subsequent lack of trust and passive-aggressive behavior characterize relationship conflict.',topic:'l8',opts:['Data Conflict, since their dispute is centered on who was actually responsible for the historical server outage.', 'Structural Conflict, because the firm lacks a clear policy on how to handle project assignments and peer reviews.', 'Values Conflict, because the two engineers have different professional ethics regarding accountability and public blame.', 'Relationship Conflict, because the conflict is driven by strong negative emotions, historical stereotypes, and broken trust between the parties.']},
{id:530,type:'mcq',applied:true,text:'[APPLIED] The Executive Director of an educational nonprofit wants to accept a $100,000 corporate sponsorship from a major fast-food chain to fund a local literacy program. However, the Program Director strongly objects, arguing that accepting money from a company that promotes unhealthy diets for children violates the core mission and ethical standing of the nonprofit. Which source of conflict is this?',ans:0,exp:'Values Conflict is caused by incompatible belief systems. Values are deeply held beliefs that people use to explain and justify their views. The dispute over whether it is ethical to accept money from a fast-food chain for an educational nonprofit is a values conflict.',topic:'l8',opts:['Values Conflict, because it is caused by fundamental differences in beliefs, ethics, and the core mission of the nonprofit.', 'Interest Conflict, because the Executive Director\'s substantive interest in funding conflicts with the Program Director\'s career goals.', 'Structural Conflict, because there is no clear hierarchy defining who has the final say on corporate partnerships.', 'Data Conflict, because they do not have research showing the impact of the fast-food brand\'s association on child literacy.']},
{id:531,type:'mcq',applied:true,text:'[APPLIED] Two departments are fighting over the use of a shared lab space during the upcoming weekend. Both demand exclusive access. If the manager applies the \'Positions vs. Interests\' lesson from the Orange Story, which of the following represents the most likely sub-optimal, position-based outcome?',ans:0,exp:'In the Orange Story, cutting the orange in half (the compromise) was a positional solution that gave each sister only 50% of what they could have had. In this scenario, splitting the weekend hours equally is a position-based compromise that leaves both departments short of their actual needs.',topic:'l8',opts:['Splitting the weekend hours equally, resulting in both departments having insufficient time to complete their runs.', 'Giving the entire weekend to the department with the senior director to maintain the hierarchy.', 'Discovering that Department A needs the lab to run dark-sensitive optical tests while Department B needs it for vibration tests, allowing joint usage.', 'Canceling both projects for the weekend to prevent favoritism and maintain team harmony.']},
{id:532,type:'mcq',applied:true,text:'[APPLIED] During a high-stakes budget meeting, the Head of Operations tells the Head of HR, \'Your department is completely self-absorbed; you always demand more budget for staff retreats while the rest of us are struggling to buy basic equipment!\' Applying Principle 1 of Getting to Yes, how should the HR Head respond?',ans:1,exp:'Principle 1 of Getting to Yes states that negotiators should separate the people from the problem. This means attacking the issue, not the person, and affirming the relationship while addressing the substance. HR\'s response acknowledges Operations\' pressure (relationship/empathy) and pivots to joint problem-solving (substance).',topic:'l8',opts:['Defend the HR department\'s record by listing the retention rates and criticizing the Operations department\'s equipment management.', 'Affirm the relationship and focus on the shared problem: \'I understand you are feeling the pressure of tight equipment budgets, so let\'s look at how we can optimize our overall spending together.\'', 'Refuse to continue the negotiation until the Head of Operations apologizes for the personal attack and unprofessional language.', 'Suggest that they split the remaining unallocated budget in half to avoid further personal clashes.']},
{id:533,type:'mcq',applied:true,text:'[APPLIED] A hospital administrator is negotiating a new contract with the nursing staff\'s union. The union\'s position is: \'We demand a strict ban on working more than four consecutive 12-hour shifts.\' The administrator\'s position is: \'We cannot agree to this cap because it destroys our scheduling flexibility.\' What is the admin\'s best action to apply Principle 2 of Getting to Yes?',ans:1,exp:'Principle 2 is \'Focus on Interests, Not Positions.\' Stating a demand (strict ban) is a position. To find the underlying interest (fatigue, patient safety, family balance), the admin must ask \'Why?\' or \'Why not?\' to understand the need beneath the demand.',topic:'l8',opts:['Hire temporary agency nurses to demonstrate that the hospital can bypass the union\'s scheduling constraints.', 'Ask the union representatives why this cap is important to the nurses and what specific concerns they have about fifth shifts.', 'Offer a 15% pay premium for the fifth consecutive shift to test if the nurses will drop their demand for cash.', 'Insist that scheduling flexibility is an industry standard and that the union must accept a compromise of five shifts.']},
{id:534,type:'mcq',applied:true,text:'[APPLIED] A tech startup\'s co-founder wants to leave the company immediately and demands that the remaining founder buy out their 25% share for $500,000 in cash. The remaining founder wants to keep the cash in the business for growth. They are stuck in a zero-sum battle. Which action represents a proper application of Principle 3?',ans:1,exp:'Principle 3 is \'Invent Options for Mutual Gain.\' This involves expanding the pie before dividing it, brainstorming creative options that satisfy both parties\' interests (leaving founder gets value; remaining founder keeps operational cash flow) before committing to a decision.',topic:'l8',opts:['The remaining founder refuses the request, forcing the leaving founder to file a lawsuit to liquidate the company.', 'Both parties brainstorm creative alternatives, such as paying the $500,000 over five years with interest, or converting equity into licensing royalties.', 'The remaining founder appeals to the leaving founder\'s loyalty, urging them to stay for another year for the sake of the team.', 'They hire an independent evaluator to determine the exact market value of the shares and split the difference.']},
{id:535,type:'mcq',applied:true,text:'[APPLIED] A freelance app developer and a client are disputing the payment for extra features added during development. The client offers $1,000, arguing that the app took only a few extra hours. The developer demands $4,000, arguing the work was highly complex. How should they resolve this using Principle 4 of Getting to Yes?',ans:1,exp:'Principle 4 is \'Use Objective Criteria.\' This means anchoring the agreement in independent standards, industry benchmarks, or precedents, rather than letting pressure, threats, or stubbornness dictate the outcome. Consulting regional market rates and original contract rates represents objective criteria.',topic:'l8',opts:['Agree to split the difference at $2,500 to preserve the relationship and complete the project deployment.', 'Consult independent regional development rates, industry averages for similar feature sets, and the original contract\'s hourly rate.', 'The developer should lock the client out of the app\'s hosting environment until the client pays the full $4,000.', 'The client should threaten to hire a different developer to rebuild the features if the price is not reduced to $1,000.']},
{id:536,type:'mcq',applied:true,text:'[APPLIED] A manufacturing company is negotiating a contract renewal with a major raw material supplier who is demanding a 20% price increase. The manufacturer has recently vetted three alternative suppliers who can deliver the same quality material at a 5% lower rate than the current price. What does this represent?',ans:2,exp:'A BATNA (Best Alternative to a Negotiated Agreement) is the course of action a party will take if negotiations fail. Having multiple validated, cheaper alternative suppliers represents a strong BATNA, giving the manufacturer the power to walk away from a bad deal.',topic:'l8',opts:['A weak BATNA, because the manufacturer will have to disrupt operations to onboard new suppliers.', 'A positional concession, because the manufacturer is focusing on price rather than building long-term relationships.', 'A strong BATNA, allowing the manufacturer to negotiate from confidence, set a credible floor, and walk away if terms are unfavorable.', 'A process agreement, because the manufacturer has structured alternative channels to bypass the supplier\'s demands.']},
{id:537,type:'mcq',applied:true,text:'[APPLIED] A freelance graphic designer is negotiating a retainer contract with a major client. The designer has no other active clients, is behind on rent, and has no savings. The client offers a rate that is 30% below the designer\'s standard fee. In this scenario, what is the effect of the designer\'s BATNA?',ans:1,exp:'A weak BATNA (having no alternative clients, urgent bills, no savings) means the negotiator has no viable walk-away option. This forces them to negotiate from fear and accept low rates or poor terms that run counter to their interests.',topic:'l8',opts:['It is strong, because the designer can leverage the client\'s need for high-quality graphics.', 'It is weak, meaning the designer will likely negotiate from fear and accept terms that run against their long-term interests.', 'It is irrelevant, because the designer can use tactical empathy to force the client to pay the full standard rate.', 'It represents a process agreement that forces both parties to seek an objective industry benchmark.']},
{id:538,type:'mcq',applied:true,text:'[APPLIED] A project manager is addressing an engineer who has missed several critical sprint deadlines. The engineer gets defensive, raising their voice: \'You are constantly breathing down my neck, checking my commits every hour, and treating me like an intern!\' What is the PM\'s best response using Tactical Empathy?',ans:1,exp:'Tactical Empathy involves understanding the feelings and mindset of the other party in the moment and communicating that understanding back to them without judgment. Reflecting the feeling of being micromanaged and undervalued demonstrates tactical empathy, which de-escalates the amygdala\'s threat response.',topic:'l8',opts:['Explain the business logic: \'I have to monitor you because your delays are impacting our client deliverables.\'', 'Reflect the engineer\'s feelings: \'It seems like you feel micromanaged, and that my constant follow-ups make you feel distrusted and undervalued.\'', 'Assert authority: \'I am your manager, and it is my job to verify that you are actually working during business hours.\'', 'Suggest a compromise: \'If you commit to finishing your tasks on time, I will agree to only check your progress once a day.\'']},
{id:539,type:'mcq',applied:true,text:'[APPLIED] An employee is furious because a new manager was hired externally to lead their department, bypassing the employee\'s internal application. The employee complains, \'I\'ve worked here for six years, worked late, and now I report to someone who doesn\'t even know our product!\' Which of the following is a correct application of Labelling?',ans:1,exp:'Labelling is identifying and naming the other party\'s emotion without judgment. It uses formulas like \'It sounds like...\', \'It seems like...\', or \'It looks like...\'. Naming the feeling that their dedication has been overlooked disarms the emotion.',topic:'l8',opts:['Saying: \'Why does reporting to an external hire make you feel so insecure about your product knowledge?\'', 'Saying: \'It sounds like you feel your years of dedication and loyalty to this company have been completely overlooked.\'', 'Saying: \'You need to realize that the new manager has extensive industry experience that will help us all scale.\'', 'Saying: \'I understand your frustration, but the decision was made by the board and we must support our new leader.\'']},
{id:540,type:'mcq',applied:true,text:'[APPLIED] A client is threatening to cancel their software subscription, telling the account manager, \'Your support team took three days to resolve our database issue, which is completely unacceptable!\' How should the account manager respond using the Mirroring technique?',ans:0,exp:'Mirroring is a counterintuitive technique where you repeat the last three critical words (or 1-3 words) of what the person said, with a slight upward inflection. In this case, repeating \'Completely unacceptable?\' prompts the client to keep speaking and expand on their thoughts.',topic:'l8',opts:['Saying: \'Completely unacceptable?\' with a slight upward, questioning inflection to invite the client to elaborate.', 'Saying: \'It seems like you are angry because the support turnaround time impacted your business operations.\'', 'Saying: \'I apologize for the delay. We had a server outage that slowed down our entire queue that day.\'', 'Saying: \'Our standard SLA is 72 hours, so technically our team responded within the agreed timeframe.\'']},
{id:541,type:'mcq',applied:true,text:'[APPLIED] A division head wants to gain the alignment of a resistant department manager on a series of budget cuts. Instead of asking a question aimed at getting a \'Yes\' (which can trigger defensive compliance), the division head wants to utilize the safety of \'No.\' Which question should they ask?',ans:0,exp:'Conventional training pushes for \'yes,\' but \'yes\' can feel like trap or compliance. A \'No\' makes people feel in control and safe. Asking \'Are you opposed to...\' allows the manager to say \'No\' (meaning they are open to it), initiating real negotiation in a safe space.',topic:'l8',opts:['Are you opposed to exploring ways we can streamline our department budgets without compromising core employee benefits?', 'Do you agree that we must cut our department budgets by 10% before the end of the quarter?', 'Can we sign off on this budget proposal today so we don\'t look disorganized to the executive board?', 'Would you say that our department is currently spending money efficiently on non-essential projects?']},
{id:542,type:'mcq',applied:true,text:'[APPLIED] A director has to announce to their team that their remote-work policy is being scaled back from four days to two days a week. Before taking questions, the director states: \'I know you probably think we don\'t trust you, that we are ignoring your work-life balance, and that this is a step backward for our culture.\' What technique is this?',ans:2,exp:'An Accusation Audit is proactively listing all the negative thoughts, feelings, or criticisms the other party might have about you or your decision, and naming them first. This defuses their emotional impact and shows self-awareness and courage.',topic:'l8',opts:['Process Agreement, because it structures the communication ground rules before the debate starts.', 'Values Conflict Diagnosis, because it identifies the mismatch between leadership values and employee values.', 'Accusation Audit, because the director proactively lists all the negative assumptions the team might hold to defuse them.', 'Tactical Sympathy, because the director is apologizing for the corporate policy change and agreeing with their anger.']},
{id:543,type:'mcq',applied:true,text:'[APPLIED] A small software company is negotiating a partnership with a massive conglomerate. The conglomerate wants to rush into discussing intellectual property ownership and revenue splits. The software company\'s CEO insists on first establishing the timeline, how meetings will be run, and how disagreements will be escalated. What lever from Deepak Malhotra\'s work is this?',ans:1,exp:'Malhotra\'s second lever is Process: agreeing on how to decide before agreeing on what to decide. By structuring the negotiation process, the weaker party builds early trust, sets boundaries, and prevents being overwhelmed on substantive issues.',topic:'l8',opts:['Framing, because the CEO is changing the language and setting of the negotiation to project power.', 'Process, because the CEO is establishing an agreement on how decisions will be made before addressing the substance.', 'Deep Empathy, because the CEO is seeking to understand the internal political constraints of the conglomerate.', 'BATNA, because the CEO is strengthening their alternative options before engaging in the deal.']},
{id:544,type:'mcq',applied:true,text:'[APPLIED] In a dispute over a promotion, an employee is upset about not getting a manager title. The director reframes the discussion: \'Instead of viewing this as a title denial, let\'s look at this as a temporary development track where you will lead our highest-visibility project to build the case for your promotion next year.\' What is the primary benefit of this reframing?',ans:1,exp:'Framing changes how a deal or situation is presented without altering the underlying substance. Shifting the frame from a zero-sum win-lose title battle to a developmental path turns a defensive dispute into a forward-looking collaborative effort.',topic:'l8',opts:['It forces the employee to accept a lower salary by using positional authority.', 'It shifts the focus from a zero-sum, win-lose scenario (getting the title now or not) to a collaborative, developmental path.', 'It establishes a formal grievance procedure to protect the company from legal liability.', 'It allows the director to avoid using tactical empathy by focusing purely on logical objectives.']},
{id:545,type:'mcq',applied:true,text:'[APPLIED] A senior partner at a law firm notices that a junior associate always agrees with their feedback immediately, saying \'Yes, of course, I will change it.\' However, the associate\'s billable hours are declining, and they recently made several careless errors. What risk of power dynamics does this situation illustrate?',ans:0,exp:'In unequal power conflicts, the stronger party risks creating false \'agreement\' which is actually compliance. Subordinates may suppress their real concerns or disagreements to avoid conflict with authority, leading to hidden resentment, low morale, and performance drops.',topic:'l8',opts:['The risk of creating false \'agreement\' (compliance) where the weaker party hides their real conflict and frustration due to fear of authority.', 'The risk of violating Principle 4 of Getting to Yes by relying on industry benchmarks instead of personal opinion.', 'The risk of data conflict, where the senior partner lacks the billing data necessary to evaluate the associate.', 'The risk of using tactical empathy, which can encourage the associate to feel overly comfortable and slack off.']},
{id:546,type:'mcq',applied:false,text:'In the study of organizational leadership and conflict resolution, Dr. Susan S. Raines defines conflict as \'a perceived incompatibility of interests, needs, or goals between two or more parties.\' Why is the word \'perceived\' considered the most critical element in this definition?',ans:1,exp:'The word \'perceived\' is key because conflict can exist before any real difference does. It is based on the perspectives of the parties involved, meaning subjective interpretations can spark a conflict even if objective reality does not warrant one.',topic:'l8',opts:['It implies that conflict is always an illusion and can be resolved by ignoring it.', 'It highlights that conflict can exist and cause real damage before any objective difference actually occurs.', 'It suggests that only one party needs to be aware of the incompatibility for conflict to disappear.', 'It limits the scope of conflict to data-driven and structural disputes in the workplace.']},
{id:547,type:'mcq',applied:false,text:'Dr. Susan S. Raines\' research provides a stark metric regarding the operational burden of conflict on organizational leaders. According to her findings, what is the average percentage of their working time that managers spend dealing directly with conflict-related issues?',ans:2,exp:'According to Dr. Susan S. Raines, managers spend an average of 40% of their time managing conflict-related issues. This underscores that managing conflict is a primary leadership responsibility, not an occasional distraction.',topic:'l8',opts:['15% of their working hours.', '25% of their working hours.', '40% of their working hours.', '60% of their working hours.']},
{id:548,type:'mcq',applied:false,text:'The lecture notes contrast the long-term organizational consequences of ignoring conflict versus managing it constructively. Which of the following pairs of outcomes accurately reflects the difference between these two leadership pathways?',ans:1,exp:'If ignored, conflict leads to: productivity collapse, talent exit, toxic culture, and eroded leadership credibility. If managed well, it leads to: deepened trust, emerging innovation, strengthened relationships, and advanced strategic goals.',topic:'l8',opts:['If ignored, talent exits and relationships strengthen; if managed well, trust deepens and culture turns toxic.', 'If ignored, productivity collapses and culture turns toxic; if managed well, trust deepens and innovation emerges.', 'If ignored, credibility erodes and strategic goals advance; if managed well, relationships strengthen and talent exits.', 'If ignored, trust deepens and innovation emerges; if managed well, productivity collapses and culture turns toxic.']},
{id:549,type:'mcq',applied:false,text:'According to the lecture notes, how should leaders view the occurrence of conflict within their organizations, and what is the consequence of failing to address it?',ans:1,exp:'The notes state: \'Conflict Is a Leadership Test, Not a Leadership Interruption.\' Furthermore, they state that \'Unmanaged conflict is a form of Abdicating Leadership,\' meaning a leader cannot ignore conflict and remain effective.',topic:'l8',opts:['It is a sign of operational failure; failing to eliminate it immediately shows a lack of control.', 'It is a leadership test, not a leadership interruption; ignoring it is an abdication of leadership.', 'It is a temporary distraction that should be delegated to HR; leaders must focus only on strategic goals.', 'It is a positive sign of healthy alignment; ignoring it allows the natural team hierarchy to resolve it.']},
{id:550,type:'mcq',applied:false,text:'Dr. Susan S. Raines identifies five primary sources of conflict. Which of these sources is defined as stemming from issues like roles, authority, resources, reporting lines, and physical or organizational boundaries?',ans:1,exp:'Structural Conflict is caused by forces external to the people in dispute, such as roles, authority, resources, physical boundaries, or reporting lines. Identifying this root is critical because treating it as a relationship issue will not solve the structural problem.',topic:'l8',opts:['Data Conflict', 'Structural Conflict', 'Interest Conflict', 'Values Conflict']},
{id:551,type:'mcq',applied:false,text:'When two parties in an organization find themselves in conflict because they possess different information, disagree on which data is relevant, or interpret the same set of facts in completely opposite ways, which source of conflict is at play?',ans:0,exp:'Data Conflict arises when there is a lack of information, misinformation, disagreement on what data is relevant, or differing interpretations of data. It is resolved by aligning on information sources and analysis methods.',topic:'l8',opts:['Data Conflict', 'Relationship Conflict', 'Interest Conflict', 'Values Conflict']},
{id:552,type:'mcq',applied:false,text:'Which of the five sources of conflict is characterized by fundamental differences in beliefs, ethics, ideology, or the core organizational mission, and is typically the most difficult to resolve through compromise?',ans:2,exp:'Values Conflict is caused by incompatible belief systems, ethics, or missions. Because values define identity, they are highly resistant to compromise and require techniques like reframing or finding higher-level shared principles.',topic:'l8',opts:['Interest Conflict', 'Relationship Conflict', 'Values Conflict', 'Structural Conflict']},
{id:553,type:'mcq',applied:false,text:'The lecture notes state: \'Wrong Diagnosis = Wrong Treatment\' regarding the five sources of conflict. Which of the following is a direct consequence of a leader misdiagnosing the source of a conflict?',ans:1,exp:'If a leader misdiagnoses a conflict (e.g., treating a structural conflict caused by overlapping roles as a relationship conflict caused by personality clashes), the intervention (like relationship counseling) will fail because the root cause (role ambiguity) remains unaddressed.',topic:'l8',opts:['It automatically weakens the leader\'s BATNA in future contract negotiations.', 'It leads to ineffective interventions, such as attempting to resolve a structural resource issue with relationship team-building.', 'It forces the organization to transition immediately from a suppression culture to a constructive culture.', 'It shifts the negotiation from interest-based bargaining to positional bargaining.']},
{id:554,type:'mcq',applied:false,text:'The landmark work \'Getting to Yes\' emphasizes the distinction between positions and interests. How do the authors distinguish between these two concepts, and why is this distinction vital for a mediator?',ans:1,exp:'Positions are concrete demands or statements (\'I want X\'). Interests are the underlying needs, desires, and fears that drive those demands. Uncovering interests allows negotiators to find creative options that satisfy both parties, which is impossible if they remain stuck on rigid positions.',topic:'l8',opts:['Positions are the underlying needs that motivate people; interests are the concrete demands they state.', 'Positions are what people say they want; interests are what they actually need. Focusing on interests allows for creative win-win solutions.', 'Positions are negotiable; interests are non-negotiable values that must be decided by objective criteria.', 'Positions are based on logic; interests are based on emotion. A leader must ignore interests to remain neutral.']},
{id:555,type:'mcq',applied:false,text:'In \'Getting to Yes\', Roger Fisher, William Ury, and Bruce Patton define negotiation in a way that shifts it away from combat. Which of the following is their fundamental definition of negotiation?',ans:1,exp:'Fisher, Ury, and Patton define negotiation simply as \'a basic means of getting what you want from others.\' It is a back-and-forth communication designed to reach an agreement when you and the other side have some interests that are shared and others that are opposed.',topic:'l8',opts:['A formal dispute resolution mechanism used when mediation fails.', 'A basic means of getting what you want from others.', 'A process of compromising until both sides are equally dissatisfied.', 'A strategic game where the party with the strongest BATNA wins.']},
{id:556,type:'mcq',applied:false,text:'Positional bargaining is identified as the most common mistake in negotiation. Which of the following is NOT one of the four reasons listed in the lecture notes for why positional bargaining fails?',ans:3,exp:'The four reasons positional bargaining fails are: 1) Produces unwise agreements, 2) Is inefficient, 3) Damages relationships, and 4) Escalates with more parties. Using objective criteria is a *solution* (Principle 4 of Getting to Yes), not a reason why positional bargaining fails.',topic:'l8',opts:['It produces unwise agreements that focus on demands rather than actual needs.', 'It is highly inefficient because both sides dig in and stall to protect their egos.', 'It damages relationships by turning a problem-solving exercise into a contest of will.', 'It requires the use of objective criteria, which depersonalizes the decision-making process.']},
{id:557,type:'mcq',applied:false,text:'The framework of \'Getting to Yes\' rests on four foundational principles designed to transform negotiation from combat into collaboration. Which of the following lists these four principles correctly?',ans:2,exp:'The four principles are: 1) Separate the people from the problem; 2) Focus on interests, not positions; 3) Invent options for mutual gain; 4) Insist on using objective criteria. These form the core of interest-based negotiation.',topic:'l8',opts:['1) Focus on positions, 2) Separate relationship from substance, 3) Expand the BATNA, 4) Use subjective opinions.', '1) Attack the person, 2) Focus on interests, 3) Invent options for zero-sum gain, 4) Let stubbornness decide.', '1) Separate people from the problem, 2) Focus on interests, not positions, 3) Invent options for mutual gain, 4) Use objective criteria.', '1) Establish authority, 2) Build process agreements, 3) Perform accusation audits, 4) Enforce formal dispute resolution.']},
{id:558,type:'mcq',applied:false,text:'Principle 1 of \'Getting to Yes\' highlights that every negotiator has two primary interests: in the substance of the deal and in the relationship with the other party. What is the core instruction for managing these two dimensions?',ans:2,exp:'The lecture notes state: \'Two dimensions in every conflict: The Relationship <> The Substance. Affirm the Relationship. Then address the issue.\' Conflating the person with the problem leads to poor decisions and damaged relationships.',topic:'l8',opts:['Sacrifice the relationship if the substance is critical to the organization\'s strategic goals.', 'Merge them together so that the strength of the relationship dictates the substance of the agreement.', 'Affirm the relationship, making the other party feel valued, while addressing the substantive issue directly.', 'Maintain absolute silence on the relationship to prevent emotional bias from affecting the substance.']},
{id:559,type:'mcq',applied:false,text:'To effectively focus on interests rather than positions, a negotiator must uncover the needs beneath the stated demands. What specific questioning techniques are recommended in the lecture notes to surface these interests?',ans:1,exp:'To surface interests, you must ask \'Why?\' (Why is this important to you?) and \'Why not?\' (What concerns you about my proposal?). Listening more than speaking and watching for emotion also helps identify underlying needs.',topic:'l8',opts:['Ask \'What is your final offer?\' and \'When will you sign?\'', 'Ask \'Why?\' to understand their needs, and \'Why not?\' to discover their concerns about your proposal.', 'Ask \'Who authorized this?\' and \'What is your legal precedent?\'', 'Ask \'How much will this cost?\' and \'What is your alternative supplier rate?\'']},
{id:560,type:'mcq',applied:false,text:'When applying Principle 3 (Invent Options for Mutual Gain), leaders often fail because they fall into zero-sum thinking. What is a key rule of option invention designed to overcome this barrier?',ans:1,exp:'Rules for Option Invention include suspending judgment during brainstorming and avoiding premature commitments. This prevents critical evaluation from stifling creativity, allowing more options to be generated, which increases the room for agreement.',topic:'l8',opts:['Make firm commitments to options as soon as they are proposed to build trust.', 'Suspend judgment and separate the act of brainstorming options from the act of deciding on them.', 'Limit the number of options to two to avoid confusing the parties and stalling the talks.', 'Ensure that the options focus strictly on dividing the existing resources equally.']},
{id:561,type:'mcq',applied:false,text:'Principle 4 of \'Getting to Yes\' advises negotiators to use objective criteria. What is the psychological and operational benefit of anchoring a resolution in independent standards rather than subjective pressure?',ans:1,exp:'Objective criteria (like industry benchmarks, policy precedent, or expert opinions) depersonalize the decision. Neither party has to back down to the other\'s sheer willpower; instead, they both submit to a neutral, fair standard, preserving ego and relationship.',topic:'l8',opts:['It ensures that the more powerful party gets their way without looking like a bully.', 'It depersonalizes the decision, allowing both parties to feel they agreed to a standard larger than themselves rather than yielding to pressure.', 'It eliminates the need for active listening and tactical empathy, making the negotiation faster.', 'It guarantees that both parties will get 100% of their positional demands.']},
{id:562,type:'mcq',applied:false,text:'The acronym BATNA stands for \'Best Alternative to a Negotiated Agreement.\' According to the lecture notes, how does a negotiator\'s BATNA directly determine their bargaining power?',ans:1,exp:'Your BATNA is your walk-away option. A strong BATNA (attractive alternatives) gives you confidence and a credible floor, allowing you to reject unfavorable terms. A weak BATNA (no alternatives) creates fear of failure, forcing you to accept terms that damage your interests.',topic:'l8',opts:['A strong BATNA allows you to demand concessions without offering any in return.', 'A strong BATNA allows you to negotiate from confidence, walk away from bad deals, and set a credible floor; a weak BATNA forces you to negotiate from fear.', 'A strong BATNA is based on values; a weak BATNA is based on data and structural constraints.', 'A strong BATNA is only useful if the other party is unaware of it, allowing you to use it as a surprise threat.']},
{id:563,type:'mcq',applied:false,text:'Chris Voss, author of \'Never Split the Difference,\' critiques the Harvard negotiation framework for ignoring a critical human dimension. What is this dimension, and what is the danger of ignoring it?',ans:2,exp:'Voss argues that humans are not purely rational actors. Emotion, identity, ego, and fear shape positions more than logic. Ignoring these emotional realities does not neutralize them; it escalates the conflict. Leaders who address only logic miss the real conflict.',topic:'l8',opts:['The financial dimension; ignoring it leads to unprofitable, though emotionally satisfying, agreements.', 'The structural dimension; ignoring it leads to role confusion and overlapping reporting lines.', 'The emotional dimension; humans are not purely rational, and ignoring identity, ego, and fear escalates the conflict.', 'The temporal dimension; ignoring it leads to efficient but low-quality compromises.']},
{id:564,type:'mcq',applied:false,text:'Tactical Empathy is defined as the FBI\'s most powerful negotiation tool. Which of the following statements accurately describes what Tactical Empathy is, and what it is NOT?',ans:1,exp:'Tactical Empathy is NOT agreement or sympathy. It is the active, accurate perception of the other party\'s emotional state and mindset, and the clear communication of that perception back to them. When people feel heard, their amygdala de-escalates, opening the door to problem-solving.',topic:'l8',opts:['It is agreeing with the other party\'s demands and expressing deep sympathy for their personal struggles.', 'It is understanding the feelings and mindset of the other party in the moment and communicating that understanding back, without requiring agreement or sympathy.', 'It is a logical analysis of the other party\'s BATNA and presenting it to them to show their weak position.', 'It is pretending to share the other party\'s values to gain their trust and force a compromise.']},
{id:565,type:'mcq',applied:false,text:'What is the neurological basis for using Tactical Empathy in high-stakes conflict resolution, as outlined in the lecture notes?',ans:1,exp:'Neuroscience shows that when a person feels genuinely heard, the amygdala (the brain\'s threat and emotional center) deactivates. This lowers anxiety and defensiveness, allowing the rational brain to engage. Thus, emotional de-escalation must precede logical problem-solving.',topic:'l8',opts:['It stimulates the prefrontal cortex to immediately analyze objective criteria and ignore emotional bias.', 'When people feel heard, the brain\'s threat center (amygdala) deactivates, meaning de-escalation must precede problem-solving.', 'It triggers a release of adrenaline, forcing the other party to make rapid, pressure-based concessions.', 'It bypasses the emotional brain entirely, forcing the negotiator to focus on positional bargaining.']},
{id:566,type:'mcq',applied:false,text:'Labelling is a verbal technique used to disarm negative emotions by naming them. According to the lecture notes, what is the formula for a label, and what is its primary effect?',ans:1,exp:'Labelling uses neutral formulas centered on the other person: \'It seems like...\', \'It sounds like...\', \'It looks like...\'. Naming the emotion without using \'I\' or placing judgment disarms it, as \'emotion named is emotion disarmed.\'',topic:'l8',opts:['Formula: \'I think you are...\' or \'You need to...\'; effect: establishes the leader\'s psychological dominance.', 'Formula: \'It seems like...\', \'It sounds like...\', or \'It looks like...\'; effect: disarms the emotion by naming it without judgment.', 'Formula: \'Why are you...\' or \'What is your...\'; effect: forces the other party to explain their irrational behavior.', 'Formula: \'We agree that...\' or \'You promise to...\'; effect: locks the other party into a formal commitment.']},
{id:567,type:'mcq',applied:false,text:'How is the technique of \'Mirroring\' executed in a negotiation, and what is its psychological purpose?',ans:1,exp:'Mirroring in FBI terms is repeating the last 3 critical words (or 1-3 words) of what the person just said, using a questioning upward inflection. This signals active listening and prompts the speaker to expand, often revealing their true, underlying interests.',topic:'l8',opts:['It involves mimicking the physical body language and hand gestures of the other party to build subconscious trust.', 'It involves repeating the last three critical words of what the person said, with a slight upward inflection, to encourage them to keep talking and reveal deeper concerns.', 'It involves reflecting their core values back to them in a formal process agreement.', 'It involves demanding that the other party mirror your concessions to maintain a fair, 50-50 split.']},
{id:568,type:'mcq',applied:false,text:'Conventional negotiation training emphasizes pushing for a \'Yes.\' Why does Chris Voss argue that pushing for \'Yes\' can be counterproductive, and why is \'No\' more powerful?',ans:1,exp:'Voss explains that \'yes\' is often given to escape pressure (compliance or appeasement) without real commitment. Saying \'No\' gives the speaker a sense of safety and control. Once they feel protected by their right to say no, they are more open to listening and collaborating.',topic:'l8',opts:['A \'Yes\' is always a binding contract, whereas \'No\' is an informal opinion that can be easily changed.', 'A \'Yes\' can be mere compliance or appeasement under pressure, whereas \'No\' makes people feel in control and safe, which is where real negotiation begins.', 'A \'Yes\' triggers the amygdala\'s threat center, whereas \'No\' immediately deactivates it.', 'A \'Yes\' leads to structural conflict, whereas \'No\' focuses the parties on values and mission.']},
{id:569,type:'mcq',applied:false,text:'What is the primary function of an \'Accusation Audit\' in conflict-resilient leadership, and why does it work?',ans:1,exp:'An Accusation Audit involves identifying and speaking the other party\'s worst thoughts and fears about you or the situation before they do. Naming these accusations yourself defuses them, signals self-awareness and courage, and disarms their attack.',topic:'l8',opts:['It is a formal audit of the employee\'s performance metrics to justify a disciplinary action.', 'It is proactively listing all the negative things the other party might be thinking or feeling about you, and naming them first to neutralize their ammunition.', 'It is a mediation technique where the leader lists all the rules the disputing parties have violated.', 'It is a post-conflict review designed to update organizational structures and policies.']},
{id:570,type:'mcq',applied:false,text:'Deepak Malhotra outlines three specific levers for \'Negotiating the Impossible\' when traditional power and financial incentives fail to break a deadlock. Which of the following lists these three levers correctly?',ans:2,exp:'Malhotra\'s three levers for negotiating impossible, deadlocked conflicts are: 1) Framing (how the deal is presented), 2) Process (how we decide before what we decide), and 3) Deep Empathy (understanding the other side\'s unique constraints).',topic:'l8',opts:['1) Positions, 2) Interests, 3) BATNA', '1) Data Alignment, 2) Role Clarity, 3) Active Listening', '1) Framing, 2) Process, 3) Deep Empathy', '1) Mediation, 2) Grievance, 3) Learning']},
{id:571,type:'multi',applied:true,text:'[APPLIED] A tech startup is experiencing intense friction. The CTO has been ignoring complaints from developers about unrealistic deadlines, leading to key engineers resigning. According to Susan Raines\' analysis of what happens when conflict is ignored versus managed well, which of the following outcomes are typical of the \'If Ignored\' path?',ans:[0, 1, 2, 5],exp:'According to Raines\' comparison, ignoring conflict leads to: productivity collapse, talent exit, toxic culture, and eroded leadership credibility. Trust deepening and innovation emerging are outcomes of conflict that is managed well.',topic:'l8',opts:['Productivity collapses.', 'Talent exits.', 'Culture turns toxic.', 'Trust deepens.', 'Innovation emerges.', 'Leadership credibility erodes.']},
{id:572,type:'multi',applied:true,text:'[APPLIED] During a contract renewal negotiation between a logistics provider and a manufacturer, the manufacturer demands a 20% discount (Position). The logistics provider wants to maintain its margin but is open to creative options. According to the Getting to Yes framework, which of the following would be considered valid \'Interests\' rather than \'Positions\'?',ans:[0, 2, 4],exp:'Options 1, 3, and 5 are interests because they describe the underlying needs, fears, or goals (lowering supply chain costs, protecting reputation, covering fuel costs). Options 2 and 4 are positions because they are specific demands (20% discount, 3-year contract).',topic:'l8',opts:['The manufacturer needs to lower its overall supply chain costs by $50,000 this quarter to meet board budget targets.', 'The manufacturer demands a flat 20% discount on all shipping routes.', 'The manufacturer wants to ensure guaranteed shipping capacity during peak season to protect their customer delivery reputation.', 'The logistics provider requires a signed 3-year exclusivity contract.', 'The logistics provider needs to cover rising fuel costs to maintain minimum profitability standards.']},
{id:573,type:'multi',applied:true,text:'[APPLIED] A school board is mediating a conflict between the principal and the teachers\' union. They want to establish \'Objective Criteria\' to resolve a salary and workload dispute. Which of the following would qualify as objective criteria under Principle 4 of Getting to Yes?',ans:[0, 2, 4],exp:'Objective criteria must be independent standards that are not controlled by either party. Neighboring benchmarks, state laws/precedents, and the official inflation rate are objective. Personal opinions and opening demands are subjective pressures.',topic:'l8',opts:['Average salary benchmarks from neighboring school districts of similar size.', 'The school board president\'s personal opinion of what is fair.', 'State-mandated educational policies and budget precedents.', 'The union representative\'s opening demand for a 15% salary increase.', 'The consumer price index (inflation rate) for the local region over the past year.']},
{id:574,type:'multi',applied:true,text:'[APPLIED] A team leader is preparing for a difficult performance review with an underperforming employee who is known to get highly defensive. The leader wants to use Chris Voss\'s techniques, specifically \'Labelling\' and \'Accusation Audit,\' to manage the emotional climate. Which of the following statements represent correct implementations of these techniques?',ans:[0, 1, 4],exp:'Option 1 is an Accusation Audit (proactively naming negative thoughts). Options 2 and 5 are correct labels (\'It seems like...\', \'It sounds like...\' naming the emotion). Options 3 and 4 are defensive/confrontational and do not represent tactical empathy.',topic:'l8',opts:['Accusation Audit: \'I know you probably think I am out to get you, that I don\'t see how hard you work, and that this review is unfair.\'', 'Labelling: \'It seems like you feel frustrated that your efforts aren\'t translating into the results we expect.\'', 'Direct Question: \'Why are you always so defensive when we talk about your metrics?\'', 'Logical Rebuttal: \'You need to stop feeling overlooked because we treat everyone equally here.\'', 'Labelling: \'It sounds like you\'re worried about your job security here.\'']},
{id:575,type:'multi',applied:true,text:'[APPLIED] In a post-merger integration, two departments are fighting over who controls client data. The integration leader wants to implement a Process Agreement before tackling the database control. Which of the following actions are consistent with creating a Process Agreement?',ans:[0, 2, 3],exp:'A process agreement focuses on the road, not the destination. Agreeing on speaking order, timelines, and evaluation criteria are process agreements. Deciding on ownership or forcing a 50-50 share are substantive decisions.',topic:'l8',opts:['Agreeing on who will speak first and how much time each side has in the joint meetings.', 'Deciding immediately that Department A will own the database to save time.', 'Agreeing on the timeline and milestones for making the final decision.', 'Establishing the criteria that will be used to evaluate the final proposals.', 'Forcing the departments to accept a 50-50 database share.']},
{id:576,type:'multi',applied:false,text:'According to Dr. Susan S. Raines\' 4-component Conflict Management System, what are the primary focuses of the \'Prevention\' component? Select all that apply.',ans:[0, 2, 4],exp:'The Prevention component focuses on building firewalls before the fire. This includes role clarity, transparent communication, fair processes, and inclusive decisions. Grievance/arbitration fall under Formal Dispute Resolution, and peer feedback falls under Early Intervention.',topic:'l8',opts:['Role clarity and clear job expectations.', 'Grievance procedures and formal arbitration.', 'Transparent communication channels.', 'Peer feedback mechanisms.', 'Inclusive decision-making processes.']},
{id:577,type:'multi',applied:false,text:'Under Dr. Susan S. Raines\' Conflict Management System, which of the following activities and mechanisms fall directly under the \'Early Intervention\' component? Select all that apply.',ans:[1, 2, 3],exp:'Early Intervention aims to catch conflicts before they escalate. This includes one-on-ones, peer feedback, and facilitated dialogue. Grievance filings and binding arbitration are part of Formal Dispute Resolution.',topic:'l8',opts:['Formal grievance filings.', 'One-on-one meetings between managers and employees.', 'Peer feedback mechanisms.', 'Facilitated dialogue between disputing parties.', 'Binding arbitration.']},
{id:578,type:'multi',applied:false,text:'What are the primary risks associated with the more powerful party in an unequal power conflict (such as a Leader vs. Subordinate or Founder vs. Board) as detailed in the lecture notes? Select all that apply.',ans:[0, 1, 2],exp:'The risks for the stronger party are: 1) using authority to end conflict without resolving it, 2) creating false \'agreement\' (compliance), and 3) failing to make it safe for the weaker party to speak. Subordinate BATNA and structural misdiagnosis are not listed as power dynamic risks.',topic:'l8',opts:['Using positional authority to end the conflict without resolving the underlying issue.', 'Creating false \'agreement\' which is actually compliance.', 'Failing to make it genuinely safe for the less powerful to speak.', 'Unintentionally strengthening the subordinate\'s BATNA.', 'Misdiagnosing all conflicts as structural.']},
{id:579,type:'multi',applied:false,text:'According to Dr. David Oyedepo\'s Covenant Perspective and the self-discipline tools outlined in the lecture notes, which of the following are recommended practices for managing internal conflict before addressing external conflict? Select all that apply.',ans:[0, 1, 2],exp:'The 3 self-discipline tools are: 1) The Pause (3-second delay), 2) The Reframe (constructive interpretation), and 3) The Question (replacing reactions with curious questions). Pulling rank and positional bargaining violate these discipline principles.',topic:'l8',opts:['Using \'The Pause\' (3 seconds before responding) to disrupt the reactive cycle.', 'Reframing the situation to find the most constructive interpretation.', 'Replacing reactive statements with curious questions.', 'Pulling rank immediately to maintain organizational order.', 'Engaging in positional bargaining to protect the leader\'s ego.']},
{id:580,type:'multi',applied:false,text:'What are the markers of a \'Constructive Conflict Culture\' compared to a \'Suppression Culture\' within a healthy organization, as outlined in the lecture notes? Select all that apply.',ans:[0, 1, 2, 4],exp:'Markers of a constructive conflict culture include: concerns raised early, direct and respectful disagreement, leaders modeling accountability, and celebrating resolution rather than just superficial harmony. Hiding conflict is a marker of a suppression culture.',topic:'l8',opts:['Concerns are raised early, not suppressed.', 'Disagreement is expressed directly and respectfully.', 'Leaders model accountability and acknowledge their own errors.', 'Conflict is hidden to maintain a harmonious appearance.', 'Resolution is celebrated, not just harmony.']},
{id:581,type:'short',applied:true,text:'[APPLIED] During a high-stakes negotiation between an independent contractor and a corporate client, the client demands that the contractor sign a non-compete clause. The contractor realizes that if they cannot reach an agreement, they will simply work with their alternative client, a direct competitor who offered them a contract yesterday. What is the negotiation term that represents this walk-away alternative?',ans:'BATNA',exp:'BATNA (Best Alternative to a Negotiated Agreement) is the negotiator\'s walk-away option if the current negotiation fails. In this scenario, the alternative contract is the contractor\'s BATNA.',topic:'l8'},
{id:582,type:'short',applied:true,text:'[APPLIED] A team leader is mediating a dispute between two designers. Designer A insists, \'I must have the cover page in blue!\' Designer B insists, \'No, it must be in red!\' They are arguing over their positions. What is the specific negotiation term used by Fisher and Ury to describe the underlying needs, desires, concerns, or fears (e.g., Designer A wants blue to convey trust; Designer B wants red to grab attention)?',ans:'Interests',exp:'Interests are the underlying needs, desires, concerns, and fears that motivate people, whereas positions are the concrete demands they make. Focusing on interests is Principle 2 of Getting to Yes.',topic:'l8'},
{id:583,type:'short',applied:true,text:'[APPLIED] In a highly emotional workplace dispute, a manager listens to an angry employee who feels passed over for a promotion. The manager says, \'It seems like you feel your contributions have been completely ignored and that you are frustrated about your career path here.\' The manager is naming the emotion without judgment. What is this specific FBI negotiation technique called?',ans:'Labelling',exp:'Labelling is the technique of identifying and naming the other party\'s emotion without judgment, using phrases like \'It seems like...\' or \'It sounds like...\'. This disarms the emotion.',topic:'l8'},
{id:584,type:'short',applied:false,text:'What is the term Roger Fisher, William Ury, and Bruce Patton use to describe the common negotiation mistake where parties argue over demands, dig in their heels, stall, and damage relationships?',ans:'Positional Bargaining',exp:'Positional Bargaining is the classic, inefficient negotiation method where parties trade concessions on rigid demands (\'I want X\' vs \'We give you Y\'), which often damages relationships.',topic:'l8'},
{id:585,type:'short',applied:false,text:'According to Dr. Susan S. Raines, which source of conflict arises from fundamental differences in belief, ethics, or organizational mission, and is highly resistant to compromise?',ans:'Values Conflict',exp:'Values Conflict is driven by fundamental differences in core beliefs, ethics, or mission. It is difficult to resolve because values represent a person\'s identity.',topic:'l8'},
{id:586,type:'short',applied:false,text:'What is the specific term used for the FBI\'s most powerful negotiation tool, defined as accurate perception of the other party\'s feelings and mindset, clearly communicated back to them in the moment?',ans:'Tactical Empathy',exp:'Tactical Empathy is understanding the feelings and mindset of the other party in the moment, and communicating that understanding back. It is not agreement or sympathy.',topic:'l8'},
{id:587,type:'short',applied:false,text:'Which negotiation technique involves repeating the last three critical words that the other person said, with a slight upward inflection, to encourage them to keep talking and elaborate?',ans:'Mirroring',exp:'Mirroring is repeating the last 1 to 3 critical words of the other person with a questioning inflection, which encourages them to elaborate and feel heard.',topic:'l8'},
{id:588,type:'short',applied:false,text:'What is the term for the technique of proactively listing all the negative things the other party might be thinking or feeling about you and naming them first to disarm them?',ans:'Accusation Audit',exp:'An Accusation Audit is proactively listing the negative assumptions or criticisms the other party might hold and speaking them first to neutralize their ammunition.',topic:'l8'},
{id:589,type:'short',applied:false,text:'Which lever of Deepak Malhotra\'s \'Negotiating the Impossible\' framework is focused on agreeing on how to decide before agreeing on what to decide, allowing parties to build momentum?',ans:'Process',exp:'The \'Process\' lever focuses on structuring how negotiations are conducted (schedules, rules, escalations) before discussing the substantive details of the deal.',topic:'l8'},
{id:590,type:'short',applied:false,text:'In Dr. Susan S. Raines\' four-component conflict management system, which component focuses on actions like role clarity, transparent communication, fair processes, and inclusive decisions?',ans:'Prevention',exp:'Prevention is the cheapest and first component of Raines\' framework, focusing on building firewalls (role clarity, transparency) to prevent conflicts from starting.',topic:'l8'},
{id:591,type:'fill',applied:true,text:'[APPLIED] A manager is dealing with a team that has different interpretations of project delay data. One group blames QA, while another blames Dev. According to Susan Raines, this represents a _______ conflict. To address this, the manager must use objective benchmarks rather than letting _______ decide.',dropdowns:[['Data', 'Structural', 'Values', 'Relationship'], ['stubbornness', 'precedent', 'arbitration', 'process']],ans:['Data', 'stubbornness'],exp:'A conflict over different interpretations of facts is a Data Conflict. Principle 4 of Getting to Yes states that negotiators should let standards and objective criteria, rather than stubbornness, decide.',topic:'l8'},
{id:592,type:'fill',applied:true,text:'[APPLIED] An executive is preparing for a hostile board meeting. To defuse the board\'s anger before they start criticizing, the executive uses a/an _______. During the meeting, when a director makes an emotional demand, the executive uses _______ to label the emotion and lower the amygdala\'s threat response.',dropdowns:[['Accusation Audit', 'Process Agreement', 'BATNA evaluation', 'Zero-sum frame'], ['Tactical Empathy', 'Positional Bargaining', 'Objective Criteria', 'Arbitration']],ans:['Accusation Audit', 'Tactical Empathy'],exp:'Proactively listing negative thoughts before they are spoken is an Accusation Audit. De-escalating emotions by understanding and communicating back the mindset in the moment is Tactical Empathy.',topic:'l8'},
{id:593,type:'fill',applied:true,text:'[APPLIED] Two tech firms are stuck in a deadlocked negotiation. Substance is completely blocked. The mediator decides to shift the focus and draft a _______ to outline the meeting schedule and ground rules. Additionally, the mediator reframes the deal to shift from a divided loss to a _______.',dropdowns:[['Process Agreement', 'Formal Dispute Resolution', 'BATNA', 'Accusation Audit'], ['shared gain', 'zero-sum compromise', 'positional victory', 'values alignment']],ans:['Process Agreement', 'shared gain'],exp:'A Process Agreement helps when substance is stuck, building trust and momentum. Reframing the negotiation changes the presentation of the deal, shifting the focus from a divided loss to a shared gain.',topic:'l8'},
{id:594,type:'fill',applied:false,text:'Dr. Susan S. Raines defines conflict as a \'perceived incompatibility of interests, needs, or goals between two or more parties.\' In this definition, the word _______ is key because conflict can exist before any real difference does. Furthermore, Raines asserts that conflict is not dysfunction, but rather _______ in motion.',dropdowns:[['perceived', 'incompatibility', 'interests', 'parties'], ['diversity', 'harmony', 'division', 'evolution']],ans:['perceived', 'diversity'],exp:'\'Perceived\' is the key word because subjective perceptions can create conflict before objective differences occur. Raines states that conflict is not dysfunction, but \'diversity in motion.\'',topic:'l8'},
{id:595,type:'fill',applied:false,text:'In *Getting to Yes*, the first principle is to separate the _______ from the _______. This acknowledges that there are two dimensions in every conflict: the relationship and the substance.',dropdowns:[['people', 'interests', 'positions', 'standards'], ['problem', 'process', 'outcome', 'substance']],ans:['people', 'problem'],exp:'Principle 1 of Getting to Yes is \'Separate People from the Problem.\' This teaches leaders to attack the issue (the problem) rather than the person (the people) to protect the relationship.',topic:'l8'},
{id:596,type:'fill',applied:false,text:'When negotiating, positions are what people _______, whereas interests are what people _______. This distinction is illustrated by the Orange Story where both sisters demanded the same fruit.',dropdowns:[['say', 'need', 'demand', 'hide'], ['need', 'say', 'want', 'fear']],ans:['say', 'need'],exp:'Positions are what people say (their demands). Interests are what they need (their underlying motivations). In the Orange Story, both sisters said they wanted the whole orange (position), but one needed the peel and the other needed the juice (interests).',topic:'l8'},
{id:597,type:'fill',applied:false,text:'A negotiator with a _______ BATNA negotiates from confidence and can walk away from bad deals, whereas one with a _______ BATNA negotiates from fear and accepts terms against their interests.',dropdowns:[['strong', 'weak', 'neutral', 'flexible'], ['weak', 'strong', 'unstable', 'fixed']],ans:['strong', 'weak'],exp:'A strong BATNA provides confidence and walk-away power because the negotiator has attractive alternatives. A weak BATNA means having no good alternatives, forcing the negotiator to accept poor terms out of fear.',topic:'l8'},
{id:598,type:'fill',applied:false,text:'Chris Voss notes that \'yes\' can often be compliance or appeasement, whereas _______ makes people feel in control, meaning that real negotiation begins after a/an _______.',dropdowns:[['No', 'Yes', 'Agreement', 'Concession'], ['no', 'yes', 'compromise', 'label']],ans:['No', 'no'],exp:'According to Voss, saying \'No\' makes people feel in control and safe. Pushing for \'yes\' breeds resistance, whereas starting from a position where they can say \'no\' allows the real negotiation to begin safely.',topic:'l8'},
{id:599,type:'fill',applied:false,text:'Deepak Malhotra proposes three levers for negotiating the impossible: _______, which changes how the deal is presented; _______, which focuses on how to decide before what to decide; and deep empathy.',dropdowns:[['Framing', 'BATNA', 'Labelling', 'Prevention'], ['Process', 'Arbitration', 'Mediation', 'Compromise']],ans:['Framing', 'Process'],exp:'Malhotra\'s three levers are Framing (changing how the deal is presented without altering the substance) and Process (agreeing on the decision-making framework first), along with Deep Empathy.',topic:'l8'},
{id:600,type:'fill',applied:false,text:'In Dr. Susan S. Raines\' four-component conflict management system, the third component is _______, which includes mediation and arbitration, while the fourth component is _______, which involves post-conflict review to update structures.',dropdowns:[['Formal Dispute Resolution', 'Early Intervention', 'Prevention', 'Learning'], ['Learning', 'Prevention', 'Early Intervention', 'Formal Dispute Resolution']],ans:['Formal Dispute Resolution', 'Learning'],exp:'Raines\' system consists of: 1) Prevention, 2) Early Intervention, 3) Formal Dispute Resolution (grievance, mediation, arbitration), and 4) Learning (post-conflict review to update policies).',topic:'l8'}
];

const FC=[
{term:'The Leadership Covenant — Core Definition',def:'Ecclesiastes 10:5–18 provides 5 non-negotiable terms governing leadership emergence and sustained impact. A covenant = this is what you must DO to get what you must HAVE. Each term is both a condition and a key.',lec:'Lecture 1'},
{term:'Leadership — Oyedepo\'s Definition',def:'"Leadership is not about leading people; it is essentially about taking the lead in a given task... taking the lead in meeting the needs." Leadership IS accomplishing a feat, NOT occupying a seat.',lec:'Lecture 1'},
{term:'Three Myths of Leadership',def:'Myth 1: Leaders are born (capacity is developed). Myth 2: Leadership can be inherited (it must be earned — always). Myth 3: Leadership is a position (it is the product of outstanding contribution in a field).',lec:'Lecture 1'},
{term:'Africa\'s Leadership Crisis',def:'An African Head of State replied: "Number 1, Leadership. Number 2, Leadership. Number 3, Leadership." The crisis is developmental — not resources or geography — but a lack of trained, purposeful leaders.',lec:'Lecture 1'},
{term:'Term 1: Vision',def:'"A discovery of God\'s plan and purpose for one\'s life; a discovery of one\'s mission on earth." Vision answers: "What must I do?" — NOT "What can I get?" It is mission-driven clarity, value addition, not name-making.',lec:'Lecture 1'},
{term:'Three Pathways to Vision',def:'1. Divine Encounter — a defining calling moment (Moses, Paul). 2. Passion — the restlessness pointing to the problem you\'re created to solve (Nehemiah). 3. Gifting — what you do effortlessly that creates value for others.',lec:'Lecture 1'},
{term:'Leaders vs Workers',def:'Leaders are purpose-driven; Workers are profit-driven. A person chasing money builds for today; a person chasing a mission builds for generations. "Leaders are simply need-meeters!" — Dr Oyedepo.',lec:'Lecture 1'},
{term:'Term 2: Wisdom',def:'"Wisdom is not common sense; wisdom is acquired sense." Wisdom = applied knowledge in your field. Vision tells you WHERE to go; Wisdom teaches you HOW to get there — and how to STAY there. It is the principal raw material for the making of a leader.',lec:'Lecture 1'},
{term:'Three Tools That Build Wisdom',def:'1. Reading — "every star has a trade secret." 2. Mentorship / Laddership — every leader rises on the shoulders of those before them. 3. Meditation & Thinking Through — what you read is not profitable until it is digested.',lec:'Lecture 1'},
{term:'Faraday Case Study (Wisdom)',def:'Virtually no formal education. Apprentice bookbinder who devoured scientific texts. Lab assistant to Prof Humphrey Davy. Eventually surpassed his mentor. Leading man of science at age 44. "The knowledge marketplace has no apartheid."',lec:'Lecture 1'},
{term:'Benjamin Franklin Case Study (Wisdom + Sacrifice)',def:'Only 2 years of formal schooling. Spent his lunch money on books as a printing apprentice, day after day. Became philosopher, scientist, diplomat. Founded the University of Pennsylvania. "He invested in himself when no one else would."',lec:'Lecture 1'},
{term:'Term 3: Self-Discipline',def:'"Possessing a sense of mission in the pursuit of life... operating as demanded, not as convenient in the pursuit of any given task." Three expressions: operating without supervision; investing time; being a law to oneself.',lec:'Lecture 1'},
{term:'Jim Rohn Quote on Discipline',def:'"There are two types of pain — the pain of discipline and the pain of regret. Discipline weighs ounces while regret weighs tonnes." Frames why self-discipline is not optional for the covenant leader.',lec:'Lecture 1'},
{term:'4 Zones of Self-Discipline',def:'1. Self-Management — govern yourself before anything else. 2. Time Management — one year = 8,736 hours; time is an asset of equality. 3. Task Management (Focus) — protect your core assignment. 4. Resource Management — manage well to grow big.',lec:'Lecture 1'},
{term:'The Uniform Principle',def:'Einstein: same grey suit daily (focus on physics). Steve Jobs: black turtleneck + blue jeans (eliminate decision fatigue). Obama: grey or blue suits only (preserve mental energy). Discipline lives in small daily choices.',lec:'Lecture 1'},
{term:'Protect the Core',def:'"Every leader has one assignment that generates all others." A doctor who lets the vegetable garden become his focus loses medicine. Neglecting the core to chase complements is the most common cause of stalled leadership potential.',lec:'Lecture 1'},
{term:'Term 4: Diligence',def:'"Our working knowledge of the truth will never be a substitute for diligence. Every accomplishment is at the cost of commitment. Nothing works without someone at work." Without diligence, vision is a balloon dream — inflated but weightless.',lec:'Lecture 1'},
{term:'Law of Diligence (Gen 8:22)',def:'"You cannot withdraw more than you deposit." The covenant of seedtime and harvest is universal and inescapable. Wishful thinking produces nothing. Only those running with vision today become people of impact tomorrow.',lec:'Lecture 1'},
{term:'LeTourneau Case Study (Diligence)',def:'Roadside mechanic, no formal engineering training. Observed inefficiency of animals for earth-moving. Invented the Digger. Supplied over 50% of earth-moving equipment worldwide. "Diligent observation + committed work = world-changing innovation."',lec:'Lecture 1'},
{term:'Small Beginnings Pattern',def:'Cosmas Maduka (₦300 → one of Africa\'s wealthiest). Sam Walton (small-town store → Walmart, 2.2m employees). Henry Heinz (bankrupt first venture → Heinz Ketchup global brand). Pattern: small beginnings + faithful diligence = extraordinary outcomes.',lec:'Lecture 1'},
{term:'A Great Coach Cannot Make a Star',def:'A coach provides opportunity, not results. Under the same coach: some become stars, others stay average. The difference is never the coach — it is always the player\'s level of commitment. Even Christ had a son of perdition among his protégés.',lec:'Lecture 1'},
{term:'Term 5: Sacrifice',def:'"There is no star without a scar, and the scar of every star is sacrifice." Sacrifice is intentional — giving up something of present value for something of greater future value. 5th and highest covenant term — where stars are separated from the merely diligent.',lec:'Lecture 1'},
{term:'Sacrifice vs Diligence',def:'Diligence does your best. Sacrifice goes BEYOND your best. Einstein declined Israel presidency; Billy Graham refused political appointments. "It is paying the abnormal price that makes a world-changer."',lec:'Lecture 1'},
{term:'Global Impact Has a Global Price Tag',def:'"Global impact in any field is at a global cost to the beneficiary." No world-changer runs a normal schedule, possesses normal habits, or lives a normal lifestyle. The greater the intended impact, the greater the sacrifice required.',lec:'Lecture 1'},
{term:'James Owen (4-Word Formula)',def:'Asked his coach how to become a sports star. Coach: Determination, Dedication, Discipline, Sacrifice. James Owen followed faithfully — 3 gold medals at the 1923 Berlin Olympics; long jump record unbroken for 22 years.',lec:'Lecture 1'},
{term:'Decision-Making in the Covenant',def:'"Decision-making is what makes a leader." It is non-transferable — it cannot be delegated. A covenant unused is a covenant wasted. The 5 terms remain theoretical until a decision activates them.',lec:'Lecture 1'},
{term:'The Conclusion: Level Playing Field',def:'The only real variable between those who rise and those who remain is HOW they use what they have. Not talent, not luck, not background. The difference is the consistent, disciplined, sacrificial application of the 5 covenant terms over time.',lec:'Lecture 1'},
{term:'Personal Covenant Commitment Table',def:'Vision = the problem I exist to solve. Wisdom = the knowledge gap I must close. Discipline = the daily habit I will build. Diligence = the task I will pursue this week. Sacrifice = what I am willing to give up. "A covenant not written is a covenant not made."',lec:'Lecture 1'},
{term:'When You Stop Learning, You Start Dying',def:'Abraham Lincoln: "I don\'t think much of a man who is not wiser today than he was yesterday." The moment learning stops → relevance begins to decay. Every great leader is a committed reader. Every committed reader is a potential leader.',lec:'Lecture 1'},
{term:'Task Management Focus Principle',def:'"Only those who stay focused on their task end up as front-liners." Protect your core assignment fiercely. The enemy is prestigious distraction that looks like opportunity.',lec:'Lecture 1'},
{term:'Resource Management Principle',def:'"You don\'t grow big to manage well; you manage well to grow big." — Dr Oyedepo. Good stewardship of what you currently have is the qualification for greater resources.',lec:'Lecture 1'},
{term:'Passion as Vision Pathway',def:'"Passion is a pointer to the problem you\'re created to solve." (Mike Murdock). Nehemiah had no formal vision — only restlessness about Jerusalem\'s broken walls. That restlessness WAS his assignment.',lec:'Lecture 1'},
{term:'Gifting as Vision Pathway',def:'"What do you do effortlessly that creates value for others?" Every person carries a divine deposit. Develop it and deploy it — this is your lane.',lec:'Lecture 1'},
{term:'Time — An Asset of Equality',def:'One year = only 8,736 hours. "Time is an asset of equality; while some invest it, others squander it." Time management is the second zone of self-discipline.',lec:'Lecture 1'},
{term:'Wisdom — Acquired, Not Given',def:'Wisdom requires acquisition: reading (in your field), mentorship (rising on others\' shoulders), and meditation (digesting what you\'ve learned). "Schooling is but for a season, but learning is for a lifetime." — Dr Oyedepo.',lec:'Lecture 1'},
{term:'The Leader\'s Lens (SF vs PF)',def:'Every leader carries a lens — either Problem-Focused (PF) or Solution-Focused (SF). PF: Identify → Diagnose → Fix → creates problem-saturated environment. SF: "What you focus on grows." The difference is discipline of attention.',lec:'Lecture 2'},
{term:'PF Lens Consequences',def:'PF lens: difficulties always spotlighted; strengths become invisible; people feel perpetually inadequate. Manager A: "Let\'s go through what went wrong" → team becomes defensive → blame → demoralised.',lec:'Lecture 2'},
{term:'SF Origins',def:'Developed in Milwaukee, 1980s by Steve de Shazer and Insoo Kim Berg at the Brief Family Therapy Center. Core insight: you do not need to fully understand a problem to help someone move past it. Shift from "Problem Talk" to "Solution Talk."',lec:'Lecture 2'},
{term:'SIMPLE Framework (Jackson & McKergow)',def:'S=Solutions not problems; I=In-between (progress already happening); M=Make use of what\'s there; P=Possibilities (future-focused); L=Language shapes reality; E=Every case is different. Brought rigour to what had been largely a clinical model.',lec:'Lecture 2'},
{term:'Assumption 1: Every Team Has Strengths',def:'"The answer is already in the Room." SF leader\'s job: surface and amplify — not import from outside. Look for existing: competencies, relationships, small wins and successes.',lec:'Lecture 2'},
{term:'Assumption 2: Small Changes Create Momentum',def:'Leaders wait for the "big intervention." De Shazer & Berg: small behavioural shifts, once noticed and reinforced, ripple outward. Jackson & McKergow: "small actions, big effects." "The next useful step is enough."',lec:'Lecture 2'},
{term:'Assumption 3: Bright Spots (If It\'s Working, Do More)',def:'Heath & Heath (Switch, 2010): find the "bright spots." Bright Spots = exceptions to the problem that already contain the seeds of the solution. Not wishful thinking — a disciplined analytical move that fast-tracks action.',lec:'Lecture 2'},
{term:'Jerry Sternin — Vietnam Case Study',def:'Did NOT analyse causes of malnutrition. Found families whose children were ALREADY thriving. Asked what they were doing differently. Replicated their practices. Result: 65% of children better nourished within 6 months.',lec:'Lecture 2'},
{term:'Assumption 4: The Future Is Co-Created',def:'People move more sustainably toward outcomes they articulate themselves. The most capable teams participated in IMAGINING the future, not just executing it. SF leadership is fundamentally collaborative. Leader = co-author, not scriptwriter.',lec:'Lecture 2'},
{term:'What SF Is NOT',def:'NOT ignoring problems or pretending they don\'t exist. NOT toxic positivity or forced optimism. NOT avoiding accountability or difficult conversations. Understanding a problem in depth is not a prerequisite for solving it.',lec:'Lecture 2'},
{term:'Tool 1: The Miracle Question (MQ)',def:'"Suppose tonight, while you sleep, a miracle happens and the problem is solved. When you wake up — what would be different?" Purpose: shift people from problem ownership to preferred-future authorship.',lec:'Lecture 2'},
{term:'MQ Case Study (Logistics Company)',def:'Team debating "culture problem" for months — no resolution. Facilitator introduced MQ. In 40 minutes: described a good working day in specific detail, identified 3 concrete differences, those became action priorities. "No consultant had surfaced this clarity in months of workshops."',lec:'Lecture 2'},
{term:'Tool 2: Scaling Questions (SQ)',def:'"On a scale of 1 to 10, where 10 is the best it could be; where are things right now?" Developed to bypass the need for a full problem analysis. Power lies in the follow-up questions.',lec:'Lecture 2'},
{term:'SQ Follow-Up Sequence',def:'1. "What makes it a 4 and not a 1?" — surfaces what\'s already working. 2. "What would a 5 look like?" — generates a specific, achievable next step. 3. "What would need to happen to get from 4 to 5?" — shifts ownership to the coachee.',lec:'Lecture 2'},
{term:'Why Scaling Questions Work',def:'Give people a vocabulary for progress without requiring them to claim total success or admit total failure. Particularly effective where BLAME CULTURE makes honest self-assessment difficult. Creates "safe traction."',lec:'Lecture 2'},
{term:'Tool 3: Exception-Finding (EF)',def:'"Tell me about a time when the problem didn\'t happen — or happened less. What was different?" Exceptions are rarely random — they contain the seeds of the solution. Task of SF Leader: don\'t explain the problem — UNDERSTAND the exception.',lec:'Lecture 2'},
{term:'EF Case Study (Hospital Department)',def:'Chronic conflict between two senior nurses. Coach asked each separately: "Think of a shift where things went well between you. What was different?" Both independently named the same exception. Conflict dropped significantly within 6 weeks.',lec:'Lecture 2'},
{term:'Tool 4: Strengths Amplification',def:'Generic Praise ("Great job!") — quickly discounted. SF Compliment: Specific + Observed + connected to Outcome. Co-constructing Competence — naming a strength helps the person begin to identify as someone who has it, making the behaviour more likely to recur.',lec:'Lecture 2'},
{term:'SF Compliment Example',def:'"When the brief arrived at short notice, you reorganised priorities without being asked — and without visible panic. That calm initiative keeps us credible with clients." Specific: reorganised priorities. Observed: without being asked / without panic. Outcome: credibility with clients.',lec:'Lecture 2'},
{term:'Four SF Tools — At a Glance',def:'MQ → Clarifies preferred future. SQ → Creates movement without full diagnosis. EF → Surfaces existing solutions. SA → Anchors and reinforces competence. Four tools, one direction of travel.',lec:'Lecture 2'},
{term:'Rider, Elephant, Path Framework',def:'Heath & Heath. Rider = Rational mind (needs direction and clear plan). Elephant = Emotional mind (needs motivation and vivid destination). Path = Environment (needs to make right behaviour easier). Most change programmes address ONLY the Rider.',lec:'Lecture 2'},
{term:'SF Tools and Change',def:'MQ → Elephant (vivid, appealing destination). SQ → Rider (manageable next step). EF → Path (shaped by revealing favourable terrain). "Find the Feeling — don\'t ARGUE people into change; help them EXPERIENCE the pull of a possible future."',lec:'Lecture 2'},
{term:'SF Restructuring Case Study',def:'Standard approach: information sessions explaining why → resistance hardened. SF approach: "What would this department look like at its best in five years?" and "What do we already have that we\'d want to build on?" → staff became co-authors → resistance softened.',lec:'Lecture 2'},
{term:'SF Stand-Up Ritual',def:'A five-minute shift that changes team culture. Shifts from: "What\'s blocking us? What went wrong?" TO: "What\'s gone well since we last met? What\'s our clearest next step forward?" Takes no additional time. Repeated: shifts collective attention, confidence, and momentum.',lec:'Lecture 2'},
{term:'SF Retrospective',def:'Three questions: (1) What worked well? (2) What made it work? (3) What would we carry forward? Shifts from "what failed and who caused it" to "what succeeded and how do we replicate it." Same learning — far less defensiveness — far more ownership.',lec:'Lecture 2'},
{term:'SF Performance Conversation',def:'PF: lead with catalogue of failures → defensive → heat not light → verdict. SF: "There are things not working — and I think we both know that. But let\'s spend most of our time on what a better situation would look like..." Person leaves with direction, not verdict.',lec:'Lecture 2'},
{term:'Doing SF vs Being SF',def:'"Doing SF" = applying tools when a situation calls for it. "Being SF" = habitually looking for strengths, exceptions, and preferred futures as a default way of seeing. The goal: make solution-focused thinking instinctive.',lec:'Lecture 2'},
{term:'Building SF Habits',def:'"Motivation alone won\'t sustain practice. Environment will." Build habits through: team rituals making SF questions the default (SF stand-up, SF retrospective), meeting structures opening with strengths before problems, regular check-ins using scaling questions as a progress habit.',lec:'Lecture 2'},
{term:'When SF Has Limits',def:'SF is NOT for: technical problem-solving (safety defects need root-cause analysis), rigorous accountability (discriminatory conduct needs direct investigation), financial forensics (irregularities demand diagnosis). SF is most powerful for human dynamics, motivation, goal-setting, and change.',lec:'Lecture 2'},
{term:'The Risk of Premature SF',def:'"Don\'t reach for the Miracle Question too quickly." Distinction between "not dwelling on problems" and "dismissing them." Reaching for SF tools too early can feel DISMISSIVE when a team is grieving, carrying justified anger, or processing a significant failure.',lec:'Lecture 2'},
{term:'Even Great Questions Fail Inside Bad Systems',def:'SF tools are blunted in systems that: consistently punish initiative, reward blame over learning, discourage honest conversation. "Redesigning the environment is as important as motivating the Rider and engaging the Elephant."',lec:'Lecture 2'},
{term:'Cultural Considerations for SF',def:'SF tools\' assumptions about personal agency do not translate uniformly across all cultural settings. Collective decision-making may be the norm; deferring to authority may make "what do you want?" feel presumptuous; indirect communication requires adapting question language.',lec:'Lecture 2'},
{term:'SF and Other Leadership Frameworks',def:'SF complements: Transformational leadership (both orient toward inspiring shared future); Adaptive leadership (both engage people in authoring solutions); Servant leadership (both centre needs and strengths of those being led). SF sharpens the CONVERSATIONS within these frameworks.',lec:'Lecture 2'},
{term:'SF Closing Questions',def:'"What would your leadership look like at its best? What\'s one thing already moving in that direction?" These two questions embody the SF approach: preferred future (MQ) + existing bright spot (EF). Lead with curiosity, not conclusions.',lec:'Lecture 2'},
{term:'Language Shapes Reality (L in SIMPLE)',def:'De Shazer: shift from "Problem Talk" to "Solution Talk." L in SIMPLE: Language shapes reality. Sustained problem talk creates a problem-saturated environment. Solution talk opens possibility. Every question a leader asks is a vote for what the team focuses on next.',lec:'Lecture 2'},
];

let mode='study',sessionQs=[],cur=0,answers={},multiSel={},score=0;
let examMode=false,timerInt=null,secLeft=0,reviewMode=false;
let flashList=[],fcIdx=0;
let selTopics=['all'];
let deferredPrompt=null;
let checked={}; // stores whether a question has been clicked 'Check Answer' in Study Mode

// PWA installation trigger
window.addEventListener('beforeinstallprompt',(e)=>{
  e.preventDefault();deferredPrompt=e;
  const btn=document.getElementById('pwa-install-btn');
  if(btn){
    btn.style.display='block';
    btn.onclick=()=>{
      btn.style.display='none';
      deferredPrompt.prompt();
      deferredPrompt.userChoice.then(res=>{
        if(res.outcome==='accepted')console.log('App Installed');
        deferredPrompt=null;
      });
    };
  }
});

// =====================================================================
// INIT
// =====================================================================
document.addEventListener('DOMContentLoaded',()=>{
  document.getElementById('s-qs').textContent=QB.length;
  document.getElementById('s-fc').textContent=FC.length;
  document.getElementById('s-lec').textContent=TOPICS.length-1;
  buildChips();
});

function buildChips(){
  const c=document.getElementById('topic-chips');c.innerHTML='';
  TOPICS.forEach(t=>{
    const el=document.createElement('div');
    el.className='chip'+(t.id==='all'?' active':'');
    el.textContent=t.label;el.dataset.id=t.id;
    el.onclick=()=>toggleChip(t.id,el);
    c.appendChild(el);
  });
}

function toggleChip(id,el){
  if(id==='all'){
    selTopics=['all'];
    document.querySelectorAll('#topic-chips .chip').forEach(c=>c.classList.toggle('active',c.dataset.id==='all'));
    return;
  }
  selTopics=selTopics.filter(x=>x!=='all');
  document.querySelector('#topic-chips .chip[data-id="all"]').classList.remove('active');
  if(selTopics.includes(id)){
    selTopics=selTopics.filter(x=>x!==id);el.classList.remove('active');
    if(!selTopics.length){selTopics=['all'];document.querySelector('#topic-chips .chip[data-id="all"]').classList.add('active');}
  }else{selTopics.push(id);el.classList.add('active');}
}

// Check validation of active session count/timer settings
function pickMode(m,el){
  mode=m;
  document.querySelectorAll('.mode-btn').forEach(b=>b.classList.remove('active'));
  el.classList.add('active');
  
  const countRow=document.getElementById('count-row');
  const timerField=document.getElementById('timer-field');
  const qCountInput=document.getElementById('q-count');
  const qTimeInput=document.getElementById('q-time');
  
  if(m==='scenario'){
    countRow.style.display='flex';
    timerField.style.display='flex';
    qCountInput.value=70;
    qCountInput.disabled=true;
    qTimeInput.value=45;
    qTimeInput.disabled=true;
  }else{
    qCountInput.disabled=false;
    qTimeInput.disabled=false;
    countRow.style.display=m==='flash'?'none':'flex';
    timerField.style.display=m==='exam'?'flex':'none';
  }
}

// =====================================================================
// START SESSION
// =====================================================================
function startSession(){
  const tf=selTopics.includes('all')?null:selTopics;
  if(mode==='flash'){
    flashList=tf?FC.filter(f=>tf.some(t=>{
      const map={
        l1:'Lecture 1',l2:'Lecture 2',l3:'Lecture 3',l4:'Lecture 4',
        l5:'Lecture 5',l6:'Lecture 6',l7:'Lecture 7',l8:'Lecture 8'
      };
      return f.lec===map[t];
    })):FC.slice();
    shuffle(flashList);fcIdx=0;
    showArea('flash');renderFC();
    return;
  }
  let pool=tf?QB.filter(q=>tf.includes(q.topic)):QB.slice();
  if(mode==='scenario'){
    pool=pool.filter(q=>q.applied);
  }
  shuffle(pool);
  
  let reqCount=20;
  if(mode==='scenario'){
    reqCount=70;
  }else{
    reqCount=parseInt(document.getElementById('q-count').value)||20;
  }
  const n=Math.min(reqCount,pool.length);
  sessionQs=pool.slice(0,n);
  cur=0;answers={};multiSel={};score=0;reviewMode=false;checked={};
  examMode=(mode==='exam'||mode==='scenario');
  showArea('quiz');buildMap();renderQ();
  
  const finishBtn = document.getElementById('btn-finish');
  if (finishBtn) {
    finishBtn.textContent = examMode ? '⚑ Finish Exam' : '⚑ Finish Session';
    finishBtn.onclick = examMode ? gradeExam : showResults;
  }
  
  if(examMode){
    let mins=30;
    if(mode==='scenario'){
      mins=45;
    }else{
      mins=parseInt(document.getElementById('q-time').value)||0;
    }
    if(mins>0){secLeft=mins*60;startTimer();}
  }
}

function shuffle(a){
  for(let i=a.length-1;i>0;i--){
    const j=Math.floor(Math.random()*(i+1));
    [a[i],a[j]]=[a[j],a[i]];
  }
}

// =====================================================================
// RENDER QUESTION
// =====================================================================
function renderQ(){
  const q=sessionQs[cur];
  document.getElementById('q-counter').textContent=`Q ${cur+1} / ${sessionQs.length}`;
  document.getElementById('prog-fill').style.width=`${(cur/sessionQs.length)*100}%`;
  const topicLabel=TOPICS.find(t=>t.id===q.topic)?.label||'';
  document.getElementById('q-topic-pill').textContent=topicLabel.includes(':')?topicLabel.split(':')[1].trim():topicLabel;
  const tp=document.getElementById('q-type-pill');
  const typeMap={mcq:'MCQ',multi:'Multi-Select',short:'Short Answer',fill:'Fill-in',match:'Matching'};
  const tc={mcq:'mcq',multi:'multi',short:'short',fill:'fill',match:'applied'};
  const label=q.applied?'APPLIED':typeMap[q.type];
  const cls=q.applied?'applied':tc[q.type];
  tp.textContent=label;tp.className='q-type-pill '+cls;

  // Clear options and explanation
  const opts=document.getElementById('q-options');opts.innerHTML='';
  const expl=document.getElementById('q-explanation');expl.classList.remove('show');
  
  // Set question text
  if(q.type!=='fill'){
    document.getElementById('q-text').textContent=q.text;
  }
  
  const saved=answers[cur];
  const showExplanationMode=(checked[cur]&&!examMode)||reviewMode;
  
  if(q.type==='mcq'||q.type==='multi'){
    const isMulti=q.type==='multi';
    q.opts.forEach((optText,i)=>{
      const btn=document.createElement('button');
      btn.className='opt';
      const ltr=String.fromCharCode(65+i);
      btn.innerHTML=`<span class="opt-key">${ltr}</span><span style="flex:1">${optText}</span>`;
      if(showExplanationMode){
        btn.disabled=true;
        if(i===q.ans||(isMulti&&q.ans.includes(i)))btn.classList.add('correct');
        else if(saved===i||(isMulti&&Array.isArray(saved)&&saved.includes(i)))btn.classList.add('wrong');
      }else if(saved!==undefined){
        const isSel=isMulti?(multiSel[cur]||[]).includes(i):saved===i;
        if(isSel)btn.classList.add('selected');
      }
      btn.onclick=()=>{
        if(showExplanationMode)return;
        if(!examMode&&!isMulti)selectMCQ(btn,i,q);
        else if(!examMode&&isMulti)toggleMulti(btn,i);
        else if(examMode&&!isMulti)examSelectMCQ(btn,i);
        else examToggleMulti(btn,i);
      };
      opts.appendChild(btn);
    });
    if(showExplanationMode)showExpl(q);
  }else if(q.type==='short'){
    const ta=document.createElement('input');
    ta.type='text';ta.className='fill-inp';ta.placeholder='Type your 1-2 word answer...';
    ta.value=saved||'';
    ta.oninput=()=>{answers[cur]=ta.value;updCheck();};
    if(showExplanationMode){
      ta.disabled=true;
      const isCorrect=String(saved||'').trim().toLowerCase()===String(q.ans).trim().toLowerCase();
      if(isCorrect){
        ta.style.borderColor='var(--moss)';
        ta.style.background='var(--moss-light)';
      }else{
        ta.style.borderColor='var(--maroon)';
        ta.style.background='#f6e3e0';
      }
      expl.innerHTML=`<strong>Model Answer:</strong> ${q.ans}<br><br><strong>Explanation:</strong> ${q.exp}`;
      expl.classList.add('show');
    }
    opts.appendChild(ta);
  }else if(q.type==='fill'){
    document.getElementById('q-text').textContent='';
    const parts=q.text.split('_______');
    const wrap=document.createElement('div');wrap.className='fill-wrap';
    
    // Read selections without saving array on render to prevent automatic answer state tracking
    const currentAnswers=saved||Array(q.dropdowns.length).fill('');
    
    parts.forEach((part,i)=>{
      wrap.appendChild(document.createTextNode(part));
      if(i<parts.length-1){
        const sel=document.createElement('select');
        sel.className='fill-select';
        
        const placeholder=document.createElement('option');
        placeholder.value='';
        placeholder.textContent='Select...';
        placeholder.disabled=true;
        placeholder.selected=!currentAnswers[i];
        sel.appendChild(placeholder);
        
        const optsList=q.dropdowns[i]||[];
        optsList.forEach(optVal=>{
          const opt=document.createElement('option');
          opt.value=optVal;
          opt.textContent=optVal;
          if(currentAnswers[i]===optVal){
            opt.selected=true;
          }
          sel.appendChild(opt);
        });
        sel.onchange=()=>{
          if(!answers[cur])answers[cur]=Array(q.dropdowns.length).fill('');
          answers[cur][i]=sel.value;
          updCheck();
        };
        if(showExplanationMode){
          sel.disabled=true;
          if(currentAnswers[i]===q.ans[i]){
            sel.style.borderColor='var(--moss)';
            sel.style.background='var(--moss-light)';
          }else{
            sel.style.borderColor='var(--maroon)';
            sel.style.background='#f6e3e0';
          }
        }
        wrap.appendChild(sel);
      }
    });
    opts.appendChild(wrap);
    if(showExplanationMode){
      expl.innerHTML=`<strong>Answer:</strong> ${q.ans.join(' / ')}<br><br>${q.exp}`;
      expl.classList.add('show');
    }
  }else if(q.type==='match'){
    document.getElementById('q-text').textContent=q.text;
    const wrap=document.createElement('div');
    wrap.className='match-wrap';
    
    const currentAnswers=saved||Array(q.left.length).fill('');
    const matchOptions = q.right.map((val, idx) => ({text: val, index: idx}));
    matchOptions.sort((a,b) => a.text.localeCompare(b.text));
    
    q.left.forEach((leftItem, i)=>{
      const row=document.createElement('div');
      row.className='match-row';
      
      const leftCol=document.createElement('div');
      leftCol.className='match-left';
      leftCol.textContent=leftItem;
      
      const arrow=document.createElement('span');
      arrow.className='match-arrow';
      arrow.textContent='→';
      
      const sel=document.createElement('select');
      sel.className='match-select';
      
      const placeholder=document.createElement('option');
      placeholder.value='';
      placeholder.textContent='— Select —';
      placeholder.disabled=true;
      placeholder.selected=(currentAnswers[i]==='');
      sel.appendChild(placeholder);
      
      matchOptions.forEach(optData=>{
        const opt=document.createElement('option');
        opt.value=optData.index;
        opt.textContent=optData.text;
        if(currentAnswers[i]!=='' && Number(currentAnswers[i])===optData.index){
          opt.selected=true;
        }
        sel.appendChild(opt);
      });
      
      sel.onchange=()=>{
        if(!answers[cur])answers[cur]=Array(q.left.length).fill('');
        answers[cur][i]=sel.value !== '' ? Number(sel.value) : '';
        updCheck();
      };
      
      if(showExplanationMode){
        sel.disabled=true;
        const correctIndex = q.ans[i];
        if(currentAnswers[i]!=='' && Number(currentAnswers[i])===correctIndex){
          sel.style.borderColor='var(--moss)';
          sel.style.background='var(--moss-light)';
        }else{
          sel.style.borderColor='var(--maroon)';
          sel.style.background='#f6e3e0';
        }
      }
      
      row.appendChild(leftCol);
      row.appendChild(arrow);
      row.appendChild(sel);
      wrap.appendChild(row);
    });
    opts.appendChild(wrap);
    if(showExplanationMode){
      const matchLines = q.left.map((item, idx) => `<strong>${item}</strong> → ${q.right[q.ans[idx]]}`).join('<br>');
      expl.innerHTML=`<strong>Correct Matches:</strong><br>${matchLines}<br><br><strong>Explanation:</strong> ${q.exp}`;
      expl.classList.add('show');
    }
  }
  updCheck();
  document.getElementById('btn-prev').disabled=(cur===0);
  document.getElementById('btn-next').disabled=false;
  triggerFeedback();
  updMap();
}

function showExpl(q){
  const el=document.getElementById('q-explanation');
  if(q.type==='fill'){
    el.innerHTML=`<strong>Answer:</strong> ${q.ans.join(' / ')}<br><br><strong>Explanation:</strong> ${q.exp}`;
  }else if(q.type==='short'){
    el.innerHTML=`<strong>Model Answer:</strong> ${q.ans}<br><br><strong>Explanation:</strong> ${q.exp}`;
  }else if(q.type==='match'){
    const matchLines = q.left.map((item, idx) => `<strong>${item}</strong> → ${q.right[q.ans[idx]]}`).join('<br>');
    el.innerHTML=`<strong>Correct Matches:</strong><br>${matchLines}<br><br><strong>Explanation:</strong> ${q.exp}`;
  }else{
    el.innerHTML=`<strong>Explanation:</strong> ${q.exp}`;
  }
  el.classList.add('show');
}

function triggerFeedback(){
  const q=sessionQs[cur];
  const saved=answers[cur];
  const fb=document.getElementById('q-feedback-banner');
  if(!fb)return;
  
  fb.className='q-feedback-banner';
  fb.textContent='';
  
  // Feedback banner only triggers if checked
  if(!checked[cur]||examMode){
    return;
  }
  
  let ok=false;
  if(q.type==='mcq')ok=saved===q.ans;
  else if(q.type==='multi')ok=Array.isArray(saved)&&[...saved].sort().join(',')===([...q.ans]).sort().join(',');
  else if(q.type==='short')ok=String(saved).trim().toLowerCase()===String(q.ans).trim().toLowerCase();
  else if(q.type==='fill')ok=Array.isArray(saved)&&saved.every((v,i)=>v===q.ans[i]);
  else if(q.type==='match')ok=Array.isArray(saved)&&saved.every((v,i)=>v!==''&&Number(v)===q.ans[i]);
  
  if(ok){
    fb.classList.add('show-correct');
    fb.textContent='✓ Correct Decision — Excellent Leadership!';
  }else{
    fb.classList.add('show-wrong');
    fb.textContent='✗ Learning Opportunity — Study the Concept Below';
  }
}

// In study mode, selecting MCQ highlights the option and enables Check Answer (rather than immediately checking it)
function selectMCQ(btn,idx,q){
  if(checked[cur])return;
  answers[cur]=idx;
  document.querySelectorAll('#q-options .opt').forEach(o=>o.classList.remove('selected'));
  btn.classList.add('selected');
  updCheck();
  updMap();
}

function toggleMulti(btn,idx){
  if(checked[cur])return;
  if(!multiSel[cur])multiSel[cur]=[];
  const s=multiSel[cur];
  if(s.includes(idx)){
    multiSel[cur]=s.filter(x=>x!==idx);
    btn.classList.remove('selected');
  }else{
    s.push(idx);
    btn.classList.add('selected');
  }
  answers[cur]=multiSel[cur];
  updCheck();
}

// Check answer validation for study mode (always active for unchecked questions)
function updCheck(){
  const q=sessionQs[cur];
  const btn=document.getElementById('btn-check');
  if(examMode||reviewMode){btn.disabled=true;return;}
  if(checked[cur]){btn.disabled=true;return;}
  
  btn.disabled=false;
}

function examSelectMCQ(btn,idx){
  document.querySelectorAll('#q-options .opt').forEach(o=>o.classList.remove('selected'));
  btn.classList.add('selected');
  answers[cur]=idx;
  updCheck();
  updMap();
}

// Previous question navigation
function prevQ(){
  if(cur>0){cur--;renderQ();}
}

function examToggleMulti(btn,idx){
  if(!multiSel[cur])multiSel[cur]=[];
  const s=multiSel[cur];
  if(s.includes(idx)){
    multiSel[cur]=s.filter(x=>x!==idx);
    btn.classList.remove('selected');
  }else{
    s.push(idx);
    btn.classList.add('selected');
  }
  answers[cur]=[...multiSel[cur]];
  updCheck();
  updMap();
}

function checkAnswer(){
  const q=sessionQs[cur];
  checked[cur]=true;
  
  if(q.type==='mcq'){
    const val=answers[cur];
    if(val===q.ans)score++;
    document.querySelectorAll('#q-options .opt').forEach((o,i)=>{
      o.disabled=true;
      if(i===q.ans)o.classList.add('correct');
      else if(val===i)o.classList.add('wrong');
    });
    showExpl(q);
    document.getElementById('btn-next').disabled=false;
    document.getElementById('btn-check').disabled=true;
  }else if(q.type==='multi'){
    const sel=(multiSel[cur]||[]).slice().sort().join(',');
    const correct=[...q.ans].sort().join(',');
    answers[cur]=multiSel[cur]||[];
    if(sel===correct)score++;
    document.querySelectorAll('#q-options .opt').forEach((o,i)=>{
      o.disabled=true;
      if(q.ans.includes(i))o.classList.add('correct');
      else if((multiSel[cur]||[]).includes(i))o.classList.add('wrong');
    });
    showExpl(q);
    document.getElementById('btn-next').disabled=false;
    document.getElementById('btn-check').disabled=true;
  }else if(q.type==='fill'){
    const val=answers[cur]||Array(q.dropdowns.length).fill('');
    answers[cur]=val;
    const isCorrect=Array.isArray(val)&&val.length===q.ans.length&&val.every((v,i)=>v===q.ans[i]);
    if(isCorrect)score++;
    document.querySelectorAll('.fill-select').forEach((sel,i)=>{
      sel.disabled=true;
      if(val[i]===q.ans[i]){
        sel.style.borderColor='var(--moss)';
        sel.style.background='var(--moss-light)';
      }else{
        sel.style.borderColor='var(--maroon)';
        sel.style.background='#f6e3e0';
      }
    });
    showExpl(q);
    document.getElementById('btn-next').disabled=false;
    document.getElementById('btn-check').disabled=true;
  }else if(q.type==='short'){
    const val=answers[cur]||'';
    answers[cur]=val;
    const isCorrect=String(val).trim().toLowerCase()===String(q.ans).trim().toLowerCase();
    if(isCorrect)score++;
    const inp=document.querySelector('.fill-inp');
    if(inp){
      inp.disabled=true;
      if(isCorrect){
        inp.style.borderColor='var(--moss)';
        inp.style.background='var(--moss-light)';
      }else{
        inp.style.borderColor='var(--maroon)';
        inp.style.background='#f6e3e0';
      }
    }
    showExpl(q);
    document.getElementById('btn-next').disabled=false;
    document.getElementById('btn-check').disabled=true;
  }else if(q.type==='match'){
    const val=answers[cur]||Array(q.left.length).fill('');
    answers[cur]=val;
    const isCorrect=Array.isArray(val)&&val.length===q.ans.length&&val.every((v,i)=>v!==''&&Number(v)===q.ans[i]);
    if(isCorrect)score++;
    document.querySelectorAll('.match-select').forEach((sel,i)=>{
      sel.disabled=true;
      if(val[i]!==''&&Number(val[i])===q.ans[i]){
        sel.style.borderColor='var(--moss)';
        sel.style.background='var(--moss-light)';
      }else{
        sel.style.borderColor='var(--maroon)';
        sel.style.background='#f6e3e0';
      }
    });
    showExpl(q);
    document.getElementById('btn-next').disabled=false;
    document.getElementById('btn-check').disabled=true;
  }
  triggerFeedback();
  updMap();updSess();
}

function nextQ(){
  if(cur<sessionQs.length-1){cur++;renderQ();}
  else{if(examMode)gradeExam();else showResults();}
}

function gradeExam(){
  score=0;
  sessionQs.forEach((q,i)=>{
    const a=answers[i];
    if(q.type==='mcq'&&a===q.ans)score++;
    else if(q.type==='multi'){
      if(Array.isArray(a)&&[...a].sort().join(',')===([...q.ans]).sort().join(','))score++;
    }else if(q.type==='short'){
      if(a&&String(a).trim().toLowerCase()===String(q.ans).trim().toLowerCase())score++;
    }else if(q.type==='fill'){
      if(Array.isArray(a)&&a.length===q.ans.length&&a.every((val,idx)=>val===q.ans[idx]))score++;
    }else if(q.type==='match'){
      if(Array.isArray(a)&&a.length===q.ans.length&&a.every((val,idx)=>val!==''&&Number(val)===q.ans[idx]))score++;
    }
  });
  clearTimer();showResults();
}

function showResults(){
  clearTimer();
  const total=sessionQs.length,pct=Math.round(score/total*100);
  document.getElementById('r-score').textContent=score;
  document.getElementById('r-total').textContent=`/ ${total}`;
  document.getElementById('r-msg').textContent=pct>=80?'Excellent Work!':pct>=60?'Good Effort!':'Keep Studying!';
  document.getElementById('r-sub').textContent=`You scored ${score} of ${total} (${pct}%). `+(pct>=80?'Strong command of the material.':pct>=60?'Review the missed topics and try again.':'Go back through the lectures and try another session.');
  document.getElementById('s-sess').textContent=`${score}/${total}`;
  showArea('result');
}

// Review graded questions at end of session
function reviewSession(){
  reviewMode=true;
  examMode=false;
  cur=0;
  showArea('quiz');
  buildMap();
  renderQ();
  document.getElementById('btn-check').classList.add('hidden');
  document.getElementById('btn-next').disabled=false;
}

// =====================================================================
// QUESTION MAP
// =====================================================================
function buildMap(){
  const m=document.getElementById('q-map');m.innerHTML='';
  sessionQs.forEach((_,i)=>{
    const d=document.createElement('div');
    d.className='qdot'+(i===0?' cur':'');
    d.textContent=i+1;
    d.onclick=()=>{cur=i;renderQ();};
    m.appendChild(d);
  });
}

function updMap(){
  document.querySelectorAll('.qdot').forEach((d,i)=>{
    d.className='qdot';
    if(i===cur)d.classList.add('cur');
    if(answers[i]!==undefined){
      if(examMode){d.classList.add('answered');}
      else{
        if(checked[i]){
          const q=sessionQs[i];let ok=false;
          if(q.type==='mcq')ok=answers[i]===q.ans;
          else if(q.type==='multi')ok=Array.isArray(answers[i])&&[...answers[i]].sort().join(',')===([...q.ans]).sort().join(',');
          else if(q.type==='short')ok=String(answers[i]).trim().toLowerCase()===String(q.ans).trim().toLowerCase();
          else if(q.type==='fill')ok=Array.isArray(answers[i])&&answers[i].every((val,idx)=>val===q.ans[idx]);
          else if(q.type==='match')ok=Array.isArray(answers[i])&&answers[i].every((val,idx)=>val!==''&&Number(val)===q.ans[idx]);
          d.classList.add(ok?'ok':'wrong');
        }else{
          d.classList.add('answered');
        }
      }
    }
  });
}

// =====================================================================
// TIMER
// =====================================================================
function startTimer(){
  const box=document.getElementById('timer-box');
  box.classList.remove('hidden','timer-safe','timer-warning','timer-danger');
  box.textContent=fmtSec(secLeft);
  
  updTimerColor();
  
  timerInt=setInterval(()=>{
    secLeft--;
    box.textContent=fmtSec(secLeft);
    updTimerColor();
    if(secLeft<=0){clearTimer();gradeExam();}
  },1000);
}

function updTimerColor(){
  const box=document.getElementById('timer-box');
  box.classList.remove('timer-safe','timer-warning','timer-danger');
  if(secLeft>300){
    box.classList.add('timer-safe');
  }else if(secLeft>60){
    box.classList.add('timer-warning');
  }else{
    box.classList.add('timer-danger');
  }
}

function clearTimer(){if(timerInt){clearInterval(timerInt);timerInt=null;}}
function fmtSec(s){const m=Math.floor(s/60),sec=s%60;return `${m}:${sec<10?'0':''}${sec}`;}

// =====================================================================
// FLASHCARDS
// =====================================================================
function renderFC(){
  if(!flashList.length)return;
  const f=flashList[fcIdx];
  document.getElementById('fc-counter').textContent=`Card ${fcIdx+1} / ${flashList.length}`;
  document.getElementById('fc-prog').style.width=`${((fcIdx+1)/flashList.length)*100}%`;
  document.getElementById('fc-term').textContent=f.term;
  document.getElementById('fc-def').textContent=f.def;
  document.getElementById('fc-lec-front').textContent=f.lec;
  document.getElementById('fc-lec-back').textContent=f.lec;
  document.getElementById('fc').classList.remove('flipped');
}
function flipCard(){document.getElementById('fc').classList.toggle('flipped');}
function fcNav(d){fcIdx=Math.max(0,Math.min(flashList.length-1,fcIdx+d));renderFC();}

// =====================================================================
// PANEL SWITCHING
// =====================================================================
function showArea(name){
  const showHeader = (name === 'landing' || name === 'result');
  document.querySelectorAll('.site-header, .stats-ledger').forEach(el => {
    if (el.classList.contains('stats-ledger')) {
      el.style.display = showHeader ? 'grid' : 'none';
    } else {
      el.style.display = showHeader ? 'block' : 'none';
    }
  });
  document.getElementById('landing').style.display=name==='landing'?'block':'none';
  document.getElementById('quiz-area').style.display=name==='quiz'?'block':'none';
  document.getElementById('flash-area').style.display=name==='flash'?'block':'none';
  document.getElementById('result-area').style.display=name==='result'?'block':'none';
}

// Register service worker if supported
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('./sw.js')
      .then(reg => console.log('Service Worker registered'))
      .catch(err => console.log('Service Worker registration failed', err));
  });
}

function endSession(){clearTimer();backToLanding();}

function backToLanding(){
  clearTimer();multiSel={};reviewMode=false;checked={};
  const box=document.getElementById('timer-box');
  box.classList.add('hidden');box.classList.remove('urgent','timer-safe','timer-warning','timer-danger');
  showArea('landing');
}

function updSess(){
  document.getElementById('s-sess').textContent=`${score}/${sessionQs.length}`;
}
